import { render, screen, fireEvent, waitFor, act } from '@testing-library/react'
import { MemoryRouter } from 'react-router-dom'
import JobSearch from '../pages/JobSearch'
import { jobsApi, jobTrackerApi } from '../services/api'
import toast from 'react-hot-toast'

// Mock react-hot-toast
vi.mock('react-hot-toast', () => ({
  default: {
    success: vi.fn(),
    error: vi.fn(),
    custom: vi.fn(),
  },
}))

// Mock API services
vi.mock('../services/api', () => ({
  jobsApi: {
    search: vi.fn(),
  },
  jobTrackerApi: {
    getAll: vi.fn(() => Promise.resolve({ trackedJobs: [] })),
    track: vi.fn(),
  },
}))

describe('JobSearch page', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  test('renders JobSearch page components', async () => {
    render(
      <MemoryRouter>
        <JobSearch />
      </MemoryRouter>
    )

    expect(screen.getByText('Find Your Dream Job')).toBeInTheDocument()
    expect(screen.getByPlaceholderText(/Job title, keywords, or company.../i)).toBeInTheDocument()

    await waitFor(() => {
      expect(jobTrackerApi.getAll).toHaveBeenCalled()
    })
  })

  test('resets filters when "Reset Filters" button is clicked', async () => {
    jobsApi.search.mockResolvedValue({
      data: [{ id: '1', title: 'Software Engineer', company: 'Test Company' }]
    })

    render(
      <MemoryRouter>
        <JobSearch />
      </MemoryRouter>
    )

    await waitFor(() => {
      expect(jobTrackerApi.getAll).toHaveBeenCalled()
    })

    // Open filters
    const filterToggle = screen.getByRole('button', { name: /Toggle Filters/i })
    fireEvent.click(filterToggle)

    // Verify Job Type default is 'All Types'
    const jobTypeSelect = screen.getByLabelText(/Job Type/i)
    expect(jobTypeSelect.value).toBe('All Types')

    // Change value
    fireEvent.change(jobTypeSelect, { target: { value: 'Full-time' } })
    expect(jobTypeSelect.value).toBe('Full-time')

    // Click Reset Filters
    const resetBtn = screen.getByRole('button', { name: /Reset Filters/i })
    await act(async () => {
      fireEvent.click(resetBtn)
    })

    // Verify it changed back to 'All Types'
    expect(jobTypeSelect.value).toBe('All Types')
  })

  test.each([
    ['matchScore', 82, '82%'],
    ['match_percentage', 68, '68%'],
    ['matchPercentage', '82', '82%'],
  ])('renders API-provided match score badge from %s on job cards', async (field, value, expectedScore) => {
    jobsApi.search.mockResolvedValue({
      data: [{ id: '1', title: 'Frontend Developer', company: 'Test Company', [field]: value }]
    })

    render(
      <MemoryRouter>
        <JobSearch />
      </MemoryRouter>
    )

    fireEvent.change(screen.getByPlaceholderText(/Job title, keywords, or company.../i), {
      target: { value: 'frontend' }
    })
    fireEvent.click(screen.getByRole('button', { name: /^Search$/i }))

    expect(await screen.findByText(expectedScore)).toBeInTheDocument()
    expect(screen.getByLabelText(new RegExp(`${expectedScore} .* Based on your resume`))).toBeInTheDocument()
  })
})

import { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { motion } from "framer-motion";
import { Brain, ChevronDown } from "lucide-react";

import {
    LayoutDashboard,
    Search,
    Bell,
    Mail,
    GraduationCap,
    Users,
    FileText,
    Globe,
    LogOut,
    Settings,
    User,
    ShieldCheck,
    Sun,
    Moon,
    Zap,
    Rocket,
    Briefcase,
    GitMerge
} from "lucide-react";
import { useAuth } from "../hooks/useAuth";
import { useTheme } from "../hooks/useTheme";
import { generateRandomString, generateCodeChallenge } from "../utils/pkce";
import {
    Sidebar,
    SidebarBody,
    SidebarLink,
    SidebarDivider,
} from "./ui/Sidebar";
import { useSidebar } from "../hooks/useSidebar";
import { cn } from "../lib/utils";

const navLinks = [
    {
        label: "Dashboard",
        href: "/dashboard",
        icon: <LayoutDashboard className="w-5 h-5 shrink-0" />,
    },
    {
        label: "Resume Builder",
        href: "/hub/resume",
        icon: <FileText className="w-5 h-5 shrink-0" />,
    },
    {
        label: "Job Finder",
        href: "/hub/jobs",
        icon: <Briefcase className="w-5 h-5 shrink-0" />,
    },
    {
        label: "Portfolio Builder",
        href: "/hub/portfolio",
        icon: <Globe className="w-5 h-5 shrink-0" />,
    },
    {
        label: "Project Visualizer",
        href: "/project-visualizer",
        icon: <GitMerge className="w-5 h-5 shrink-0" />,
    },
    {
        label: "Career Growth",
        href: "/hub/career",
        icon: <GraduationCap className="w-5 h-5 shrink-0" />,
    },
    {
        label: "Community Hub",
        href: "/hub/community",
        icon: <Users className="w-5 h-5 shrink-0" />,
    },
    {
        label: "Profile",
        href: "/profile",
        icon: <User className="w-5 h-5 shrink-0" />,
    },
    {
        label: "Security",
        href: "/security",
        icon: <ShieldCheck className="w-5 h-5 shrink-0" />,
    },
    {
        label: "Settings",
        href: "/settings",
        icon: <Settings className="w-5 h-5 shrink-0" />,
    },
    {
        label: "Admin Panel",
        href: "/admin",
        icon: <ShieldCheck className="w-5 h-5 shrink-0 text-blue-500" />,
    }
];


function Logo() {
    const { open, animate } = useSidebar();

    return (
        <div className={cn(
            "flex items-center gap-3 py-2 group",
            !open && animate ? "px-0 justify-center" : "px-1 justify-start"
        )}>
            <div className="w-10 h-10 shrink-0 flex items-center justify-center p-1.5 rounded-xl group-hover:scale-110 transition-transform">
                <img src="/speed.png" alt="careerpilot" className="w-full h-full object-contain" />
            </div>
            <motion.div
                animate={{
                    display: animate ? (open ? "flex" : "none") : "flex",
                    opacity: animate ? (open ? 1 : 0) : 1,
                }}
                transition={{ duration: 0.2 }}
                className="flex items-center gap-2"
            >
                <span className="text-xl font-bold text-foreground tracking-tight whitespace-pre">
                    careerpilot
                </span>
            </motion.div>
        </div>
    );
}

function UserSection() {
    const { user, logout } = useAuth();
    const { open, animate, setOpen } = useSidebar();
    const { theme, toggleTheme } = useTheme();
    const navigate = useNavigate();
    const [openRouterKey, setOpenRouterKey] = useState(null);

    useEffect(() => {
        setOpenRouterKey(localStorage.getItem('openRouterApiKey'));
    }, []);

    const handleOpenRouterConnect = async () => {
        if (openRouterKey) {
            localStorage.removeItem('openRouterApiKey');
            setOpenRouterKey(null);
            return;
        }

        const verifier = generateRandomString();
        sessionStorage.setItem('or_code_verifier', verifier);
        const challenge = await generateCodeChallenge(verifier);
        
        const callbackUrl = `${window.location.origin}/auth/openrouter/callback`;
        const openRouterUrl = `https://openrouter.ai/auth?callback_url=${encodeURIComponent(callbackUrl)}&code_challenge=${challenge}&code_challenge_method=S256`;
        
        window.location.href = openRouterUrl;
    };

    const handleLogout = async () => {
        try {
            await logout();
            navigate("/login");
        } catch (error) {
            console.error("Logout error:", error);
        }
    };

    if (!user) return null;

    const displayName = user.displayName || user.email?.split("@")[0] || "User";
    const initials = displayName.charAt(0).toUpperCase();

    return (
        <div className="space-y-3">
            <SidebarDivider />
            <div
                className={cn(
                    "flex items-center gap-3 rounded-2xl bg-muted/50 border border-border transition-all hover:bg-muted",
                    !open && animate ? "p-2 justify-center" : "p-3"
                )}
            >
                <div className="w-10 h-10 rounded-xl bg-primary/20 flex items-center justify-center shrink-0 border border-primary/20">
                    <span className="text-primary font-bold text-base">{initials}</span>
                </div>
                <motion.div
                    animate={{
                        display: animate ? (open ? "block" : "none") : "block",
                        opacity: animate ? (open ? 1 : 0) : 1,
                    }}
                    transition={{ duration: 0.2 }}
                    className="flex-1 min-w-0"
                >
                    <p className="text-sm font-bold text-foreground truncate">
                        {displayName}
                    </p>
                    <p className="text-xs text-muted-foreground font-medium truncate">{user.email}</p>
                </motion.div>
            </div>
            <button
                onClick={toggleTheme}
                className={cn(
                    "flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-all duration-300 w-full text-muted-foreground hover:text-foreground hover:bg-muted cursor-pointer",
                    !open && animate ? "px-0 justify-center" : "justify-start"
                )}
            >
                {theme === 'dark' ? <Sun className="w-5 h-5 shrink-0" /> : <Moon className="w-5 h-5 shrink-0" />}
                <motion.span
                    animate={{
                        display: animate ? (open ? "inline-block" : "none") : "inline-block",
                        opacity: animate ? (open ? 1 : 0) : 1,
                    }}
                    transition={{ duration: 0.2 }}
                    className="text-sm font-semibold whitespace-pre"
                >
                    {theme === 'dark' ? 'Light Mode' : 'Dark Mode'}
                </motion.span>
            </button>
            <button
                onClick={handleOpenRouterConnect}
                className={cn(
                    "flex items-center gap-3 w-full py-3 px-4 rounded-2xl text-muted-foreground hover:text-foreground hover:bg-muted transition-all cursor-pointer font-bold",
                    !open && animate && "justify-center"
                )}
            >
                <Zap className={cn("w-5 h-5 shrink-0", openRouterKey && "text-indigo-500")} />
                <motion.span
                    animate={{
                        display: animate ? (open ? "inline-block" : "none") : "inline-block",
                        opacity: animate ? (open ? 1 : 0) : 1,
                    }}
                    transition={{ duration: 0.2 }}
                    className="text-sm font-bold whitespace-pre"
                >
                    {openRouterKey ? 'OpenRouter Connected' : 'Connect OpenRouter'}
                </motion.span>
            </button>
            <button
                onClick={() => {
                    handleLogout();
                    setOpen(false);
                }}
                className={cn(
                    "flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-semibold transition-all duration-300 w-full cursor-pointer hover:text-destructive hover:bg-destructive/10",
                    !open && animate ? "px-0 justify-center" : "justify-start"
                )}
            >
                <LogOut className="w-5 h-5 shrink-0" />
                <motion.span
                    animate={{
                        display: animate ? (open ? "inline-block" : "none") : "inline-block",
                        opacity: animate ? (open ? 1 : 0) : 1,
                    }}
                    transition={{ duration: 0.2 }}
                    className="text-sm font-semibold whitespace-pre"
                >
                    Logout
                </motion.span>
            </button>
        </div>
    );
}

export default function AppSidebar() {
    const [open, setOpen] = useState(false);
const [openAI, setOpenAI] = useState(false);
const location = useLocation();

useEffect(() => {
    setOpen(false);
}, [location.pathname]);

    return (
        <Sidebar open={open} setOpen={setOpen}>
            <SidebarBody className="justify-between gap-6 bg-card border-r border-border">
                <div className="flex flex-col flex-1 overflow-y-auto overflow-x-hidden scrollbar-hide">
                    <Logo />
                    <SidebarDivider />
                    <div className="flex flex-col gap-1">
                        {navLinks.map((link) => (
                            <SidebarLink
                                key={link.href}
                                link={link}
                                onClick={() => setOpen(false)}
                                className="text-muted-foreground hover:text-foreground hover:bg-muted font-semibold transition-all rounded-xl"
                            />
                        ))}
                    </div>
                     {/* AI Tools Collapsible */}
<div className="mt-2">
    <button
        onClick={() => setOpenAI(!openAI)}
        className="flex items-center justify-between w-full px-4 py-3 rounded-xl text-muted-foreground hover:text-foreground hover:bg-muted font-semibold transition-all"
    >
        <div className="flex items-center gap-3">
            <Brain className="w-5 h-5 shrink-0" />
            <span>AI Tools</span>
        </div>

        <ChevronDown
            className={cn(
                "w-4 h-4 transition-transform duration-300",
                openAI && "rotate-180"
            )}
        />
    </button>

    <motion.div
        initial={false}
        animate={{
            height: openAI ? "auto" : 0,
            opacity: openAI ? 1 : 0,
        }}
        transition={{ duration: 0.3 }}
        className="overflow-hidden ml-4 flex flex-col gap-1"
    >
        <SidebarLink
            link={{
                label: "Skill Gap Analyzer",
                href: "/skill-gap",
                icon: <Brain className="w-4 h-4 shrink-0" />,
            }}
            onClick={() => setOpen(false)}
        />

        <SidebarLink
            link={{
                label: "Career Trajectory",
                href: "/career-path",
                icon: <Brain className="w-4 h-4 shrink-0" />,
            }}
            onClick={() => setOpen(false)}
        />

        <SidebarLink
            link={{
                label: "Salary Estimator",
                href: "/salary-estimate",
                icon: <Brain className="w-4 h-4 shrink-0" />,
            }}
            onClick={() => setOpen(false)}
        />
        
        <SidebarLink
            link={{
                label: "Project Visualizer",
                href: "/project-visualizer",
                icon: <GitMerge className="w-4 h-4 shrink-0" />,
            }}
            onClick={() => setOpen(false)}
        />
    </motion.div>
</div>
                </div>
                <UserSection />
            </SidebarBody>
        </Sidebar>
    );
}

import React, { useState, useEffect } from 'react'
import { resumeApi } from '../services/api'
import { Sparkles, TrendingUp, AlertCircle, ArrowUpRight, BarChart3, Star, Layers } from 'lucide-react'
import toast from 'react-hot-toast'
import { motion } from 'framer-motion'

export default function AtsProgressChart({ resumeId }) {
  const [history, setHistory] = useState([])
  const [loading, setLoading] = useState(true)
  const [hoveredPoint, setHoveredPoint] = useState(null)

  useEffect(() => {
    fetchHistory()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [resumeId])

  const fetchHistory = async () => {
    try {
      setLoading(true)
      const res = await resumeApi.getAtsHistory(resumeId)
      setHistory(res.data || [])
    } catch (err) {
      toast.error('Failed to load ATS progression history')
    } finally {
      setLoading(false)
    }
  }

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <div className="w-8 h-8 border-4 border-muted border-t-primary rounded-full animate-spin"></div>
      </div>
    )
  }

  if (history.length === 0) {
    return (
      <div className="border border-dashed border-border rounded-2xl p-10 text-center text-muted-foreground bg-card/10">
        <BarChart3 className="w-12 h-12 mx-auto mb-3 opacity-55" />
        <p className="text-sm mb-2">No ATS score history logged yet.</p>
        <p className="text-xs">Analyze your resume in the preview tab to start tracking progress!</p>
      </div>
    )
  }

  // Calculate Key metrics
  const startingScore = history[0].atsScore
  const currentScore = history[history.length - 1].atsScore
  const totalDifference = currentScore - startingScore
  const totalOptimizations = history.length
  
  // Latest log data
  const latestLog = history[history.length - 1]
  const breakdown = latestLog.scoreBreakdown || {}
  const keywordScore = breakdown.keywordMatch ?? breakdown.projects ?? 0
  const formattingScore = breakdown.formatting ?? breakdown.summary ?? 0
  const experienceScore = breakdown.experienceRelevance ?? breakdown.experience ?? 0
  const skillsScore = breakdown.skillsAlignment ?? breakdown.skills ?? 0
  const educationScore = breakdown.educationMatch ?? breakdown.education ?? 0

  // Chart Dimensions
  const width = 600
  const height = 240
  const paddingLeft = 40
  const paddingRight = 20
  const paddingTop = 20
  const paddingBottom = 35

  const chartWidth = width - paddingLeft - paddingRight
  const chartHeight = height - paddingTop - paddingBottom

  // Coordinates calculation
  const getCoordinates = () => {
    if (history.length === 0) return []
    if (history.length === 1) {
      return [{ x: paddingLeft + chartWidth / 2, y: paddingTop + chartHeight - (history[0].atsScore / 100) * chartHeight, ...history[0] }]
    }

    return history.map((point, index) => {
      const x = paddingLeft + (index / (history.length - 1)) * chartWidth
      const y = paddingTop + chartHeight - (point.atsScore / 100) * chartHeight
      return { x, y, ...point }
    })
  }

  const points = getCoordinates()

  // Generate SVG path string
  const generatePath = () => {
    if (points.length < 2) return ''
    return points.reduce((path, p, idx) => {
      return idx === 0 ? `M ${p.x} ${p.y}` : `${path} L ${p.x} ${p.y}`
    }, '')
  }

  // Generate path string for gradient area underneath
  const generateAreaPath = () => {
    if (points.length < 2) return ''
    const linePath = generatePath()
    return `${linePath} L ${points[points.length - 1].x} ${paddingTop + chartHeight} L ${points[0].x} ${paddingTop + chartHeight} Z`
  }

  const linePath = generatePath()
  const areaPath = generateAreaPath()

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric'
    })
  }

  return (
    <div className="space-y-6">
      {/* Overview stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-card/30 border border-border p-4 rounded-2xl flex flex-col justify-between">
          <span className="text-xs font-semibold text-muted-foreground">Starting Score</span>
          <div className="flex items-baseline gap-1 mt-2">
            <span className="text-2xl font-bold text-foreground">{startingScore}</span>
            <span className="text-xs text-muted-foreground">pts</span>
          </div>
        </div>

        <div className="bg-card/30 border border-border p-4 rounded-2xl flex flex-col justify-between">
          <span className="text-xs font-semibold text-muted-foreground">Current ATS Score</span>
          <div className="flex items-baseline gap-1 mt-2">
            <span className="text-2xl font-bold text-primary">{currentScore}</span>
            <span className="text-xs text-muted-foreground">pts</span>
          </div>
        </div>

        <div className="bg-card/30 border border-border p-4 rounded-2xl flex flex-col justify-between">
          <span className="text-xs font-semibold text-muted-foreground">Total Improvement</span>
          <div className="flex items-center gap-1.5 mt-2">
            <span className={`text-2xl font-bold ${totalDifference >= 0 ? 'text-green-400' : 'text-red-400'}`}>
              {totalDifference >= 0 ? `+${totalDifference}` : totalDifference}
            </span>
            {totalDifference > 0 && <ArrowUpRight className="w-5 h-5 text-green-400" />}
          </div>
        </div>

        <div className="bg-card/30 border border-border p-4 rounded-2xl flex flex-col justify-between">
          <span className="text-xs font-semibold text-muted-foreground">Optimizations Logged</span>
          <div className="flex items-baseline gap-1 mt-2">
            <span className="text-2xl font-bold text-foreground">{totalOptimizations}</span>
            <span className="text-xs text-muted-foreground">runs</span>
          </div>
        </div>
      </div>

      {/* Main Chart Panel */}
      <div className="grid lg:grid-cols-3 gap-6">
        {/* SVG Progress Graph */}
        <div className="lg:col-span-2 bg-card/40 border border-border rounded-2xl p-5 relative overflow-hidden flex flex-col justify-between">
          <div className="flex items-center justify-between mb-4">
            <h4 className="text-sm font-bold text-foreground flex items-center gap-1.5">
              <TrendingUp className="w-4 h-4 text-primary" />
              ATS Score Progression
            </h4>
            <span className="text-[10px] text-muted-foreground px-2 py-0.5 rounded bg-muted/60 border border-border/50">
              Interactive Hover
            </span>
          </div>

          <div className="relative w-full overflow-x-auto">
            <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto min-w-[500px]">
              <defs>
                <linearGradient id="chartGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="var(--primary)" stopOpacity="0.25" />
                  <stop offset="100%" stopColor="var(--primary)" stopOpacity="0.0" />
                </linearGradient>
                <filter id="glowEffect" x="-20%" y="-20%" width="140%" height="140%">
                  <feGaussianBlur stdDeviation="3" result="blur" />
                  <feComposite in="SourceGraphic" in2="blur" operator="over" />
                </filter>
              </defs>

              {/* Grid Lines */}
              {[0, 25, 50, 75, 100].map(val => {
                const y = paddingTop + chartHeight - (val / 100) * chartHeight
                return (
                  <g key={val}>
                    <line
                      x1={paddingLeft}
                      y1={y}
                      x2={width - paddingRight}
                      y2={y}
                      stroke="var(--border)"
                      strokeWidth="0.5"
                      strokeDasharray="4,4"
                    />
                    <text
                      x={paddingLeft - 8}
                      y={y + 3}
                      fill="var(--muted-foreground)"
                      fontSize="9"
                      textAnchor="end"
                      fontWeight="bold"
                    >
                      {val}
                    </text>
                  </g>
                )
              })}

              {/* Horizontal Dates Label */}
              {points.map((p, idx) => (
                <text
                  key={idx}
                  x={p.x}
                  y={height - paddingBottom + 16}
                  fill="var(--muted-foreground)"
                  fontSize="8"
                  textAnchor="middle"
                >
                  {formatDate(p.createdAt)}
                </text>
              ))}

              {points.length > 1 && (
                <>
                  {/* Fill Area */}
                  <path d={areaPath} fill="url(#chartGradient)" />

                  {/* Line Path */}
                  <path
                    d={linePath}
                    fill="none"
                    stroke="var(--primary)"
                    strokeWidth="3.5"
                    strokeLinecap="round"
                    filter="url(#glowEffect)"
                  />
                </>
              )}

              {/* Points */}
              {points.map((p, idx) => (
                <g key={idx}>
                  <circle
                    cx={p.x}
                    cy={p.y}
                    r={hoveredPoint?.id === p.id ? "7" : "4.5"}
                    fill={hoveredPoint?.id === p.id ? "var(--primary)" : "var(--background)"}
                    stroke="var(--primary)"
                    strokeWidth="2.5"
                    style={{ transition: 'all 0.15s ease' }}
                    onMouseEnter={() => setHoveredPoint(p)}
                    onMouseLeave={() => setHoveredPoint(null)}
                    className="cursor-pointer"
                  />
                </g>
              ))}
            </svg>
          </div>

          {/* Interactive Tooltip HUD */}
          <div className="mt-3 p-3 bg-muted/40 border border-border/80 rounded-xl min-h-[60px] flex items-center justify-between text-xs transition-all">
            {hoveredPoint ? (
              <div className="flex justify-between items-center w-full">
                <div className="space-y-0.5">
                  <p className="font-semibold text-foreground">Role: {hoveredPoint.jobRole}</p>
                  <p className="text-muted-foreground text-[10px]">Analyzed: {new Date(hoveredPoint.createdAt).toLocaleString()}</p>
                </div>
                <div className="text-right">
                  <p className="text-lg font-bold text-primary">{hoveredPoint.atsScore}%</p>
                  <p className="text-[10px] text-muted-foreground">{hoveredPoint.improvementsCount} improvements suggested</p>
                </div>
              </div>
            ) : (
              <p className="text-muted-foreground italic text-center w-full">Hover over any graph point to inspect specific run details.</p>
            )}
          </div>
        </div>

        {/* Latest score category breakdown */}
        <div className="bg-card/40 border border-border rounded-2xl p-5 flex flex-col justify-between">
          <div>
            <h4 className="text-sm font-bold text-foreground mb-4 flex items-center gap-1.5">
              <Layers className="w-4 h-4 text-secondary" />
              Latest Category Levels
            </h4>

            <div className="space-y-3.5">
              {[
                { name: 'Keyword Match', score: keywordScore },
                { name: 'Formatting & Layout', score: formattingScore },
                { name: 'Experience Relevance', score: experienceScore },
                { name: 'Skills Alignment', score: skillsScore },
                { name: 'Education Alignment', score: educationScore },
              ].map((category, idx) => (
                <div key={idx} className="space-y-1">
                  <div className="flex justify-between text-xs">
                    <span className="text-muted-foreground">{category.name}</span>
                    <span className="font-semibold text-foreground">{category.score}%</span>
                  </div>
                  <div className="h-1.5 bg-muted rounded-full overflow-hidden">
                    <motion.div
                      initial={{ width: 0 }}
                      animate={{ width: `${category.score}%` }}
                      transition={{ duration: 0.8 }}
                      className={`h-full rounded-full ${
                        category.score >= 80 ? 'bg-green-500' :
                        category.score >= 60 ? 'bg-yellow-500' :
                        category.score >= 40 ? 'bg-orange-500' : 'bg-red-500'
                      }`}
                    />
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="mt-4 pt-3 border-t border-border flex items-center gap-2 text-xs text-muted-foreground leading-snug">
            <AlertCircle className="w-4 h-4 text-primary shrink-0" />
            <span>Scores correspond to: <strong className="text-foreground">{latestLog.jobRole}</strong></span>
          </div>
        </div>
      </div>

      {/* Smart Resume Improvement Recommendations */}
      <div className="bg-card/40 border border-border rounded-2xl p-5">
        <h4 className="text-sm font-bold text-foreground mb-3 flex items-center gap-1.5">
          <Sparkles className="w-4.5 h-4.5 text-yellow-400" />
          Smart Recommendations & Insights
        </h4>

        <div className="grid md:grid-cols-2 gap-4">
          <div className="p-4 bg-muted/20 border border-border rounded-xl space-y-2">
            <div className="flex items-center gap-2 text-xs font-semibold text-foreground">
              <span className="w-2 h-2 rounded-full bg-green-400" />
              Trend Analysis
            </div>
            <p className="text-xs text-muted-foreground leading-relaxed">
              {totalDifference > 0 ? (
                `Great work! Your ATS optimization efforts have resulted in a significant score surge of +${totalDifference} points, from initial ${startingScore} to ${currentScore}. Keep focusing on keyword density to hit 90+.`
              ) : totalDifference === 0 ? (
                `Your score has remained stable at ${currentScore}. Try targeting more specific industry keywords or enhancing the experience bullet points using STAR format to boost the score.`
              ) : (
                `Your score declined by ${Math.abs(totalDifference)} points, likely due to changing job roles or removal of key skills. Re-add relevant keywords to recover your score.`
              )}
            </p>
          </div>

          <div className="p-4 bg-muted/20 border border-border rounded-xl space-y-2">
            <div className="flex items-center gap-2 text-xs font-semibold text-foreground">
              <span className="w-2 h-2 rounded-full bg-primary" />
              Target Optimization Areas
            </div>
            <ul className="text-xs text-muted-foreground list-disc list-inside space-y-1.5">
              {keywordScore < 80 && (
                <li>Keyword Match is at {keywordScore}%. Tailor resume to include missing target terms.</li>
              )}
              {experienceScore < 80 && (
                <li>Experience score is {experienceScore}%. Quantify achievements with metrics.</li>
              )}
              {skillsScore < 80 && (
                <li>Skills alignment is {skillsScore}%. Align core skills with job criteria.</li>
              )}
              {latestLog.missingKeywords && latestLog.missingKeywords.length > 0 && (
                <li>Missing Keywords: {latestLog.missingKeywords.slice(0, 4).join(', ')}</li>
              )}
              {keywordScore >= 80 && experienceScore >= 80 && skillsScore >= 80 && (
                <li>Your resume sections are highly optimized! Try adding custom sections or formatting tweaks.</li>
              )}
            </ul>
          </div>
        </div>
      </div>
    </div>
  )
}

import React, { useState, useEffect } from 'react';
import { ArrowUp } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const BackToTop = () => {
  const [isVisible, setIsVisible] = useState(false);

  const toggleVisibility = () => {
    if (window.scrollY > 300) {
      setIsVisible(true);
    } else {
      setIsVisible(false);
    }
  };

  const scrollToTop = () => {
    window.scrollTo({
      top: 0,
      behavior: 'smooth',
    });
  };

  useEffect(() => {
    window.addEventListener('scroll', toggleVisibility);
    return () => {
      window.removeEventListener('scroll', toggleVisibility);
    };
  }, []);

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.button
          initial={{ opacity: 0, scale: 0.8 }}
          animate={{ opacity: 1, scale: 1 }}
          exit={{ opacity: 0, scale: 0.8 }}
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.9 }}
          onClick={scrollToTop}
          className="fixed bottom-8 right-8 z-50 p-3 bg-primary text-primary-foreground rounded-full shadow-lg hover:shadow-xl transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2 focus:ring-offset-background"
          aria-label="Back to top"
        >
          <ArrowUp size={24} />
        </motion.button>
      )}
    </AnimatePresence>
  );
};

export default BackToTop;

import { cn } from "@/lib/utils";
import { motion } from "framer-motion";

export default function Button({
  children,
  type = "button",
  variant = "primary",
  size = "default",
  disabled = false,
  loading = false,
  onClick,
  className = "",
  ...props
}) {
  const baseStyles =
    "inline-flex items-center justify-center gap-2 font-black tracking-wide transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed cursor-pointer rounded-2xl";

  const variants = {
    primary:
      "bg-primary text-primary-foreground hover:bg-primary/90 shadow-lg shadow-primary/20",
    secondary:
      "bg-card border-2 border-border text-foreground hover:bg-muted hover:border-primary/50",
    danger:
      "bg-destructive hover:bg-destructive/90 text-destructive-foreground shadow-lg shadow-destructive/20",
    outline: "border-2 border-border text-foreground hover:bg-muted",
    ghost: "text-muted-foreground hover:text-foreground hover:bg-muted",
    gradient:
      "bg-gradient-to-r from-primary to-secondary text-primary-foreground hover:scale-105 shadow-xl shadow-primary/25",
  };

  const sizes = {
    sm: "px-4 py-2 text-sm",
    default: "px-6 py-3 text-sm",
    lg: "px-8 py-4 text-base",
    xl: "px-10 py-5 text-lg",
  };

  return (
    <motion.button
      type={type}
      disabled={disabled || loading}
      onClick={onClick}
      whileHover={disabled || loading ? {} : { scale: 1.03 }}
      whileTap={disabled || loading ? {} : { scale: 0.97 }}
      transition={{ type: "spring", stiffness: 400, damping: 20 }}
      className={cn(baseStyles, variants[variant], sizes[size], className)}
      {...props}
    >
      {loading ? (
        <>
          <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
            <circle
              className="opacity-25"
              cx="12"
              cy="12"
              r="10"
              stroke="currentColor"
              strokeWidth="4"
              fill="none"
            />
            <path
              className="opacity-75"
              fill="currentColor"
              d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
            />
          </svg>
          Loading...
        </>
      ) : (
        children
      )}
    </motion.button>
  );
}

