                          </div>
                          <h5 className="text-sm font-bold text-foreground group-hover:text-primary transition line-clamp-2 leading-snug">
                            {news.title}
                          </h5>
                          <p className="text-xs text-muted-foreground leading-relaxed line-clamp-2">{news.summary}</p>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </motion.div>
            ) : null}
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  )
}

import { useCallback, useState } from 'react'
import { useDropzone } from 'react-dropzone'
import { Upload, FileText, X, CheckCircle, AlertCircle } from 'lucide-react'
import toast from 'react-hot-toast'

export default function DropZone({
  onFileSelect,
  disabled = false,
  maxSizeMB = 5,
  multiple = false,
}) {
  const maxSizeBytes = maxSizeMB * 1024 * 1024
  const [previews, setPreviews] = useState([])
  const [uploadProgress, setUploadProgress] = useState({})

  const simulateProgress = (fileName) => {
    let progress = 0
    setUploadProgress((prev) => ({ ...prev, [fileName]: 0 }))
    const interval = setInterval(() => {
      progress += Math.floor(Math.random() * 15) + 5
      if (progress >= 100) {
        progress = 100
        clearInterval(interval)
      }
      setUploadProgress((prev) => ({ ...prev, [fileName]: progress }))
    }, 150)
  }

  const onDrop = useCallback(
    (acceptedFiles, rejectedFiles) => {
      if (rejectedFiles && rejectedFiles.length > 0) {
        rejectedFiles.forEach((file) => {
          if (file.errors?.[0]?.code === 'file-too-large') {
            const sizeMB = (file.file.size / (1024 * 1024)).toFixed(2)
            toast.error(`"${file.file.name}" (${sizeMB}MB) exceeds ${maxSizeMB}MB limit`)
          } else if (file.errors?.[0]?.code === 'file-invalid-type') {
            toast.error(`"${file.file.name}" is not a PDF file`)
          } else {
            toast.error(`"${file.file.name}" could not be added`)
          }
        })
        return
      }

      if (acceptedFiles.length === 0) return

      const newPreviews = acceptedFiles.map((file) => ({
        name: file.name,
        size: (file.size / (1024 * 1024)).toFixed(2),
        file,
      }))

      setPreviews((prev) => (multiple ? [...prev, ...newPreviews] : newPreviews))

      acceptedFiles.forEach((file) => simulateProgress(file.name))

      if (multiple) {
        acceptedFiles.forEach((file) => onFileSelect(file))
      } else {
        onFileSelect(acceptedFiles[0])
      }
    },
    [onFileSelect, maxSizeMB, maxSizeBytes, multiple]
  )

  const removeFile = (fileName) => {
    setPreviews((prev) => prev.filter((p) => p.name !== fileName))
    setUploadProgress((prev) => {
      const updated = { ...prev }
      delete updated[fileName]
      return updated
    })
  }

  const { getRootProps, getInputProps, isDragActive, isDragReject } = useDropzone({
    onDrop,
    accept: { 'application/pdf': ['.pdf'] },
    maxFiles: multiple ? 10 : 1,
    maxSize: maxSizeBytes,
    multiple,
    disabled,
  })

  return (
    <div className="w-full space-y-4">
      {/* Drop Zone */}
      <div
        {...getRootProps()}
        className={`
          relative border-2 border-dashed rounded-xl p-10 text-center cursor-pointer
          transition-all duration-300 group
          ${isDragReject
            ? 'border-red-500 bg-red-500/10'
            : isDragActive
            ? 'border-primary bg-primary/10 scale-[1.01]'
            : 'border-border hover:border-primary/50 bg-card hover:bg-muted/50'}
          ${disabled ? 'opacity-50 cursor-not-allowed pointer-events-none' : ''}
        `}
      >
        <input {...getInputProps()} />

        <div className="flex flex-col items-center gap-3">
          <div
            className={`w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300
              ${isDragReject
                ? 'bg-red-500/20'
                : isDragActive
                ? 'bg-primary/20 scale-110'
                : 'bg-muted group-hover:bg-primary/10'}
            `}
          >
            {isDragReject ? (
              <AlertCircle className="w-8 h-8 text-red-500" />
            ) : isDragActive ? (
              <FileText className="w-8 h-8 text-primary animate-bounce" />
            ) : (
              <Upload className="w-8 h-8 text-muted-foreground group-hover:text-primary transition-colors" />
            )}
          </div>

          {isDragReject ? (
            <p className="text-red-500 font-medium">Only PDF files are accepted</p>
          ) : isDragActive ? (
            <p className="text-primary font-medium text-lg">Drop {multiple ? 'files' : 'file'} here...</p>
          ) : (
            <>
              <div>
                <p className="text-foreground font-medium text-lg">
                  Drag & drop {multiple ? 'PDF files' : 'your resume PDF'} here
                </p>
                <p className="text-muted-foreground text-sm mt-1">or click to browse</p>
              </div>
              <div className="inline-flex items-center gap-2 px-4 py-2 bg-muted rounded-lg mt-1">
                <FileText className="w-4 h-4 text-muted-foreground" />
                <span className="text-xs text-muted-foreground">
                  PDF only • Max {maxSizeMB}MB{multiple ? ' • Multiple files supported' : ''}
                </span>
              </div>
            </>
          )}
        </div>
      </div>

      {/* File Previews */}
      {previews.length > 0 && (
        <div className="space-y-3">
          {previews.map((preview) => {
            const progress = uploadProgress[preview.name] ?? 0
            const isDone = progress === 100

            return (
              <div
                key={preview.name}
                className="flex items-center gap-3 p-3 rounded-xl border border-border bg-card"
              >
                {/* Icon */}
                <div className="w-10 h-10 bg-primary/10 rounded-lg flex items-center justify-center shrink-0">
                  <FileText className="w-5 h-5 text-primary" />
                </div>

                {/* Info + Progress */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center justify-between mb-1">
                    <p className="text-sm font-medium text-foreground truncate">{preview.name}</p>
                    <span className="text-xs text-muted-foreground ml-2 shrink-0">
                      {preview.size} MB
                    </span>
                  </div>
                  {/* Progress Bar */}
                  <div className="w-full h-1.5 bg-muted rounded-full overflow-hidden">
                    <div
                      className={`h-full rounded-full transition-all duration-200 ${
                        isDone ? 'bg-green-500' : 'bg-primary'
                      }`}
                      style={{ width: `${progress}%` }}
                    />
                  </div>
                  <p className="text-xs text-muted-foreground mt-1">
                    {isDone ? 'Ready to upload' : `Preparing... ${progress}%`}
                  </p>
                </div>

                {/* Status / Remove */}
                <div className="shrink-0">
                  {isDone ? (
                    <CheckCircle className="w-5 h-5 text-green-500" />
                  ) : (
                    <button
                      onClick={(e) => {
                        e.stopPropagation()
                        removeFile(preview.name)
                      }}
                      className="p-1 rounded-md hover:bg-muted transition-colors"
                    >
                      <X className="w-4 h-4 text-muted-foreground hover:text-foreground" />
                    </button>
                  )}
                </div>
              </div>
            )
          })}
        </div>
      )}
    </div>
  )
}

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Plus, FileText, Briefcase, Search, Mic } from "lucide-react";
import { useNavigate } from "react-router-dom";

export default function FAB({ scrollContainerRef }) {
  const [isOpen, setIsOpen] = useState(false);
  const [isVisible, setIsVisible] = useState(true);
  const navigate = useNavigate();

  const actions = [
    {
      label: "Create Portfolio",
      icon: <FileText size={18} />,
      onClick: () => navigate("/portfolio"),
    },
    {
      label: "Upload Resume",
      icon: <Briefcase size={18} />,
      onClick: () => navigate("/upload"),
    },
    {
      label: "Search Jobs",
      icon: <Search size={18} />,
      onClick: () => navigate("/jobs"),
    },
    {
      label: "Start Interview",
      icon: <Mic size={18} />,
      onClick: () => navigate("/interview"),
    },
  ];

  useEffect(() => {
    let lastScrollY = 0;
    const mainContainer = scrollContainerRef?.current;

    const handleScroll = () => {
      if (!mainContainer) return;

      const currentScrollY = mainContainer.scrollTop;

      setIsVisible(
        currentScrollY < lastScrollY || currentScrollY < 100
      );

      lastScrollY = currentScrollY;
    };

    mainContainer?.addEventListener("scroll", handleScroll);

    return () => {
      mainContainer?.removeEventListener("scroll", handleScroll);
    };
  }, [scrollContainerRef]);

  // Close menu when FAB becomes hidden
  useEffect(() => {
    if (!isVisible && isOpen) {
      setIsOpen(false);
    }
  }, [isVisible, isOpen]);

  // Escape key closes menu
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === "Escape" && isOpen) {
        setIsOpen(false);
      }
    };

    document.addEventListener("keydown", handleKeyDown);

    return () => {
      document.removeEventListener("keydown", handleKeyDown);
    };
  }, [isOpen]);

  return (
    <motion.div className="fixed bottom-6 right-6 z-50">
      <AnimatePresence>
        {isVisible && (
          <div className="flex flex-col-reverse items-end gap-3">
            <motion.button
              type="button"
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              exit={{ scale: 0 }}
              onClick={() => setIsOpen(!isOpen)}
              aria-label={
                isOpen ? "Close quick actions" : "Open quick actions"
              }
              aria-expanded={isOpen}
              className="p-4 bg-primary text-primary-foreground rounded-full shadow-xl hover:scale-110 transition-transform glow"
            >
              <motion.div animate={{ rotate: isOpen ? 45 : 0 }}>
                <Plus size={24} />
              </motion.div>
            </motion.button>

            {isOpen && (
              <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="flex flex-col gap-2 mb-2"
                role="menu"
                aria-label="Quick actions"
              >
                {actions.map((action, index) => (
                  <button
                    key={index}
                    type="button"
                    role="menuitem"
                    tabIndex={0}
                    aria-label={action.label}
                    onClick={() => action.onClick?.()}
                    className="flex items-center gap-3 px-4 py-2 glass border-border rounded-full shadow-lg hover:bg-primary/10 hover:text-primary transition-all-300 hover:-translate-y-1 whitespace-nowrap"
                  >
                    {action.icon}
                    <span className="text-sm font-medium">
                      {action.label}
                    </span>
                  </button>
                ))}
              </motion.div>
            )}
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Bell, MapPin, DollarSign, Briefcase, Tag } from 'lucide-react';
import toast from 'react-hot-toast';
import { jobAlertsApi } from '../services/api';

const EMPLOYMENT_TYPES = [
    { value: 'full-time', label: 'Full-time' },
    { value: 'part-time', label: 'Part-time' },
    { value: 'contract', label: 'Contract' },
    { value: 'internship', label: 'Internship' }
];

export default function JobAlertModal({ isOpen, onClose, onSuccess, editAlert = null }) {
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState({
        title: editAlert?.title || '',
        keywords: editAlert?.keywords?.join(', ') || '',
        location: editAlert?.location || '',
        remoteOnly: editAlert?.remoteOnly || false,
        salaryMin: editAlert?.salaryMin || '',
        salaryMax: editAlert?.salaryMax || '',
        employmentType: editAlert?.employmentType || ['full-time']
    });

    useEffect(() => {
        setFormData({
            title: editAlert?.title || '',
            keywords: editAlert?.keywords?.join(', ') || '',
            location: editAlert?.location || '',
            remoteOnly: editAlert?.remoteOnly || false,
            salaryMin: editAlert?.salaryMin || '',
            salaryMax: editAlert?.salaryMax || '',
            employmentType: editAlert?.employmentType || ['full-time']
        });
    }, [editAlert]);

    const parseSalary = (value) => {
        const trimmed = String(value ?? '').trim();
        if (!trimmed) return null;
        const parsed = Number(trimmed);
        return Number.isFinite(parsed) ? parsed : null;
    };

    const handleInputChange = (e) => {
        const { name, value, type, checked } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? checked : value
        }));
    };

    const handleEmploymentTypeChange = (type) => {
        setFormData(prev => {
            const current = prev.employmentType;
            if (current.includes(type)) {
                return { ...prev, employmentType: current.filter(t => t !== type) };
            }
            return { ...prev, employmentType: [...current, type] };
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!formData.title.trim()) {
            toast.error('Please enter an alert title');
            return;
        }

        setLoading(true);
        try {
            const alertData = {
                title: formData.title.trim(),
                keywords: formData.keywords.split(',').map(k => k.trim()).filter(Boolean),
                location: formData.location.trim(),
                remoteOnly: formData.remoteOnly,
                salaryMin: parseSalary(formData.salaryMin),
                salaryMax: parseSalary(formData.salaryMax),
                employmentType: formData.employmentType
            };

            if (editAlert) {
                await jobAlertsApi.update(editAlert._id, alertData);
                toast.success('Alert updated successfully!');
            } else {
                await jobAlertsApi.create(alertData);
                toast.success('Job alert created! 🎉');
            }

            onSuccess?.();
            onClose();
        } catch (error) {
            toast.error(error.message || 'Failed to save alert');
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return (
        <AnimatePresence>
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4 overflow-y-auto">
                {/* Backdrop */}
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    onClick={onClose}
                    className="fixed inset-0 bg-background/80 backdrop-blur-sm"
                />

                {/* Modal */}
                <motion.div
                    initial={{ opacity: 0, scale: 0.95, y: 20 }}
                    animate={{ opacity: 1, scale: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.95, y: 20 }}
                    className="relative w-full max-w-lg bg-card border border-border rounded-2xl shadow-2xl my-8 max-h-[90vh] flex flex-col"
                >
                    {/* Header */}
                    <div className="bg-gradient-to-r from-primary to-secondary px-6 py-5 shrink-0 rounded-t-2xl">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-primary-foreground/20 rounded-lg">
                                    <Bell className="w-5 h-5 text-primary-foreground" />
                                </div>
                                <h2 className="text-xl font-semibold text-primary-foreground">
                                    {editAlert ? 'Edit Job Alert' : 'Create Job Alert'}
                                </h2>
                            </div>
                            <button
                                onClick={onClose}
                                className="p-1 hover:bg-primary-foreground/20 rounded-lg transition-colors"
                                aria-label="Close modal"
                            >
                                <X className="w-5 h-5 text-primary-foreground" />
                            </button>
                        </div>
                        <p className="mt-2 text-primary-foreground/80 text-sm">
                            Get notified when new jobs match your preferences
                        </p>
                    </div>

                    {/* Form */}
                    <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto flex-1">
                        {/* Alert Title */}
                        <div>
                            <label className="block text-sm font-medium text-foreground mb-1.5">
                                <Briefcase className="w-4 h-4 inline mr-1.5" />
                                Job Title *
                            </label>
                            <input
                                type="text"
                                name="title"
                                value={formData.title}
                                onChange={handleInputChange}
                                placeholder="e.g., Frontend Developer"
                                className="w-full px-4 py-2.5 bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary focus:border-primary transition-colors"
                                required
                            />
                        </div>

                        {/* Keywords */}
                        <div>
                            <label className="block text-sm font-medium text-foreground mb-1.5">
                                <Tag className="w-4 h-4 inline mr-1.5" />
                                Keywords (comma separated)
                            </label>
                            <input
                                type="text"
                                name="keywords"
                                value={formData.keywords}
                                onChange={handleInputChange}
                                placeholder="e.g., React, TypeScript, Remote"
                                className="w-full px-4 py-2.5 bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary focus:border-primary transition-colors"
                            />
                        </div>

                        {/* Location + Remote */}
                        <div className="flex gap-4">
                            <div className="flex-1">
                                <label className="block text-sm font-medium text-foreground mb-1.5">
                                    <MapPin className="w-4 h-4 inline mr-1.5" />
                                    Location
                                </label>
                                <input
                                    type="text"
                                    name="location"
                                    value={formData.location}
                                    onChange={handleInputChange}
                                    placeholder="e.g., San Francisco, CA"
                                    className="w-full px-4 py-2.5 bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary focus:border-primary transition-colors disabled:opacity-50"
                                    disabled={formData.remoteOnly}
                                />
                            </div>
                            <div className="flex items-end pb-2">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input
                                        type="checkbox"
                                        name="remoteOnly"
                                        checked={formData.remoteOnly}
                                        onChange={handleInputChange}
                                        className="w-4 h-4 text-primary bg-muted border-border rounded focus:ring-primary"
                                    />
                                    <span className="text-sm text-foreground">Remote only</span>
                                </label>
                            </div>
                        </div>

                        {/* Salary Range */}
                        <div>
                            <label className="block text-sm font-medium text-foreground mb-1.5">
                                <DollarSign className="w-4 h-4 inline mr-1.5" />
                                Salary Range (USD/year)
                            </label>
                            <div className="flex gap-3 items-center">
                                <input
                                    type="number"
                                    name="salaryMin"
                                    value={formData.salaryMin}
                                    onChange={handleInputChange}
                                    placeholder="Min"
                                    className="flex-1 px-4 py-2.5 bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary focus:border-primary transition-colors"
                                />
                                <span className="text-muted-foreground">to</span>
                                <input
                                    type="number"
                                    name="salaryMax"
                                    value={formData.salaryMax}
                                    onChange={handleInputChange}
                                    placeholder="Max"
                                    className="flex-1 px-4 py-2.5 bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary focus:border-primary transition-colors"
                                />
                            </div>
                        </div>

                        {/* Employment Type */}
                        <div>
                            <label className="block text-sm font-medium text-foreground mb-2">
                                Employment Type
                            </label>
                            <div className="flex flex-wrap gap-2">
                                {EMPLOYMENT_TYPES.map(type => (
                                    <button
                                        key={type.value}
                                        type="button"
                                        onClick={() => handleEmploymentTypeChange(type.value)}
                                        className={`px-3 py-1.5 rounded-full text-sm font-medium transition-colors ${formData.employmentType.includes(type.value)
                                                ? 'bg-primary/20 text-primary border-2 border-primary/50'
                                                : 'bg-muted text-muted-foreground border-2 border-transparent hover:bg-muted/80'
                                            }`}
                                    >
                                        {type.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Actions */}
                        <div className="flex gap-3 pt-4 border-t border-border sticky bottom-0 bg-card pb-1">
                            <button
                                type="button"
                                onClick={onClose}
                                className="flex-1 px-4 py-2.5 border border-border rounded-lg text-foreground font-medium hover:bg-muted transition-colors"
                            >
                                Cancel
                            </button>
                            <button
                                type="submit"
                                disabled={loading}
                                className="flex-1 px-4 py-2.5 bg-gradient-to-r from-primary to-secondary text-primary-foreground rounded-lg font-medium hover:from-primary/90 hover:to-secondary/90 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                {loading ? 'Saving...' : (editAlert ? 'Update Alert' : 'Create Alert')}
                            </button>
                        </div>
                    </form>
                </motion.div>
            </div>
        </AnimatePresence>
    );
}

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import {
    Bell,
    BellOff,
    Plus,
    Trash2,
    Edit2,
    Play,
    MapPin,
    Clock,
    Briefcase,
    Loader2,
    AlertCircle
} from 'lucide-react';
import { SkeletonList } from './ui/Skeleton';
import toast from 'react-hot-toast';
import { jobAlertsApi } from '../services/api';
import JobAlertModal from './JobAlertModal';
import Tooltip from './ui/Tooltip';

export default function JobAlertsList() {
    const [alerts, setAlerts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
