                  aria-label="Notifications"
                >
                  <Bell className="w-5 h-5 text-foreground" />

                  {notificationCount > 0 && (
                    <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold w-5 h-5 rounded-full flex items-center justify-center">
                      {notificationCount}
                    </span>
                  )}
                </button>

                {/* User Dropdown */}
                <div className="relative">
                  <button
                    onClick={() => setShowDropdown(!showDropdown)}
                    className="flex items-center gap-2 px-3 py-2 bg-muted border border-border rounded-full hover:bg-accent transition-all"
                    aria-label="User menu"
                    aria-expanded={showDropdown}
                  >
                    <div className="w-8 h-8 rounded-full overflow-hidden bg-primary/20 flex items-center justify-center">
                      <img
                        src="/user.svg"
                        alt="User profile"
                        className="w-full h-full object-cover"
                      />
                    </div>

                    <span className="text-sm font-medium text-foreground max-w-[100px] truncate">
                      {user.displayName || user.email?.split('@')[0]}
                    </span>

                    <ChevronDown className="w-4 h-4 text-muted-foreground" />
                  </button>

                  <AnimatePresence>
                    {showDropdown && (
                      <motion.div
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: 10 }}
                        className="absolute right-0 top-14 w-52 bg-background border border-border rounded-2xl shadow-xl overflow-hidden"
                      >
                        <Link
                          to="/profile"
                          className="flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-sm"
                        >
                          <User className="w-4 h-4" />
                          Profile
                        </Link>

                        <Link
                          to="/settings"
                          className="flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-sm"
                        >
                          <Palette className="w-4 h-4" />
                          Settings
                        </Link>

                        <button
                          onClick={handleLogout}
                          className="flex items-center gap-2 w-full px-4 py-3 text-left hover:bg-destructive/10 text-destructive transition-colors text-sm"
                        >
                          <LogOut className="w-4 h-4" />
                          Logout
                        </button>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              </>
            ) : (
              <>
                <Link
                  to="/login"
                  className="px-4 py-2 text-muted-foreground hover:text-foreground text-sm font-medium transition-colors"
                >
                  Login
                </Link>

                <Link
                  to="/register"
                  className="px-5 py-2 bg-primary hover:bg-primary/90 text-primary-foreground rounded-lg text-sm font-bold transition-all-300 shadow-lg shadow-primary/20 hover:-translate-y-0.5 hover:shadow-primary/40"
                >
                  Get Started
                </Link>
              </>
            )}
          </div>

          {/* Mobile Menu */}
          <div className="flex items-center gap-2 md:hidden">

            <button
              onClick={toggleTheme}
              className="p-2 rounded-xl bg-muted border border-border"
              aria-label="Toggle theme"
            >
              {theme === 'light' ? (
                <Moon className="w-5 h-5" />
              ) : (
                <Sun className="w-5 h-5" />
              )}
            </button>

            <button
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
              className="p-2 rounded-lg hover:bg-muted transition-all"
              aria-label={mobileMenuOpen ? "Close main navigation menu" : "Open main navigation menu"}
              aria-expanded={mobileMenuOpen}
            >
              {mobileMenuOpen ? (
                <X className="w-6 h-6" />
              ) : (
                <Menu className="w-6 h-6" />
              )}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Dropdown */}
      <AnimatePresence>
        {mobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="md:hidden border-t border-border bg-background/95 backdrop-blur-xl overflow-hidden"
          >
            <div className="px-4 py-6 space-y-3">

              {/* Mobile Search */}
              <div className="flex items-center bg-muted border border-border rounded-xl px-3 py-3">
                <Search className="w-4 h-4 text-muted-foreground mr-2" />

                <input
                  type="text"
                  placeholder="Search..."
                  className="bg-transparent outline-none text-sm w-full"
                />
              </div>

              {publicLinks.map(({ path, label, icon: Icon }) => (
                <Link
                  key={path}
                  to={path}
                  onClick={() => setMobileMenuOpen(false)}
                  className={`nav-link text-base ${isActive(path) ? 'nav-link-active' : 'nav-link-inactive'}`}
                >
                  <Icon className="w-5 h-5" />
                  {label}
                </Link>
              ))}

              {user &&
                privateLinks.map(({ path, label, icon: Icon }) => (
                  <Link
                    key={path}
                    to={path}
                    onClick={() => setMobileMenuOpen(false)}
                    className={`nav-link text-base ${isActive(path) ? 'nav-link-active' : 'nav-link-inactive'}`}
                  >
                    <Icon className="w-5 h-5" />
                    {label}
                  </Link>
                ))}

               


              {user ? (
                <button
                  onClick={() => {
                    handleLogout()
                    setMobileMenuOpen(false)
                  }}
                  className="flex items-center gap-3 w-full px-4 py-4 rounded-xl text-base font-semibold text-destructive hover:bg-destructive/10 transition-all"
                >
                  <LogOut className="w-5 h-5" />
                  Logout
                </button>
              ) : (
                <div className="grid grid-cols-2 gap-4">
                  <Link
                    to="/login"
                    className="flex justify-center items-center px-4 py-3 bg-muted rounded-xl font-semibold"
                  >
                    Login
                  </Link>

                  <Link
                    to="/register"
                    className="flex justify-center items-center px-4 py-3 bg-primary text-primary-foreground rounded-xl font-semibold"
                  >
                    Get Started
                  </Link>
                </div>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  )
}

import { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Bell, BriefcaseBusiness, Mail, XCircle, CheckCheck, X } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { useSocket } from "../hooks/useSocket";
import { cn } from "../lib/utils";

function timeAgo(date) {
  const diff = (Date.now() - new Date(date)) / 1000;
  if (diff < 60) return "just now";
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  return `${Math.floor(diff / 86400)}d ago`;
}

const TYPE_CONFIG = {
  job_alert_new_jobs:    { icon: BriefcaseBusiness, color: "text-primary",    bg: "bg-primary/10",     label: "New Jobs Found",   href: "/job-alerts" },
  job_alert_email_sent:  { icon: Mail,              color: "text-green-500",   bg: "bg-green-500/10",   label: "Alert Email Sent", href: "/job-alerts" },
  job_alert_email_failed:{ icon: XCircle,           color: "text-destructive", bg: "bg-destructive/10", label: "Email Failed",     href: "/job-alerts" },
  notification:          { icon: Bell,              color: "text-primary",     bg: "bg-primary/10",     label: "Notification",     href: "/dashboard"  },
};

function getTitle(notif) {
  if (notif.type === "job_alert_new_jobs") {
    const count = Number.isFinite(notif.data?.jobCount)
      ? notif.data.jobCount
      : 0;

    const title = notif.data?.alertTitle || "your alert";

    return `${count} new job${count === 1 ? "" : "s"} for "${title}"`;
  }

  if (notif.type === "job_alert_email_sent")
    return `Email sent for "${notif.data?.alertTitle || "your alert"}"`;

  if (notif.type === "job_alert_email_failed")
    return `Email failed for "${notif.data?.alertTitle || "your alert"}"`;

  return notif.data?.message ?? TYPE_CONFIG.notification.label;
}

export default function NotificationCenter() {
  const [open, setOpen] = useState(false);
  const panelRef = useRef(null);
  const navigate = useNavigate();

  // Read ALL notification state from the single source of truth: SocketContext
  const { notifications, unreadCount, markRead, markAllRead, dismissNotification } = useSocket();

  // Close on outside click
  useEffect(() => {
    const handler = (e) => {
      if (panelRef.current && !panelRef.current.contains(e.target)) setOpen(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleClick = (notif) => {
    markRead(notif.id);
    const config = TYPE_CONFIG[notif.type] || TYPE_CONFIG.notification;
    setOpen(false);
    navigate(config.href);
  };

  const handleDismiss = (e, id) => {
    e.stopPropagation();
    dismissNotification(id);
  };

  return (
    <div className="relative" ref={panelRef}>
      {/* Bell button */}
      <button
        onClick={() => setOpen((v) => !v)}
        className="relative flex items-center justify-center w-10 h-10 rounded-xl hover:bg-muted transition-colors text-muted-foreground hover:text-foreground"
        aria-label="Notifications"
      >
        <Bell className="w-5 h-5" />
        {unreadCount > 0 && (
          <motion.span
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            className="absolute -top-0.5 -right-0.5 min-w-[18px] h-[18px] px-1 rounded-full bg-primary text-primary-foreground text-[10px] font-bold flex items-center justify-center leading-none"
          >
            {unreadCount > 99 ? "99+" : unreadCount}
          </motion.span>
        )}
      </button>

      {/* Dropdown */}
      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, y: -8, scale: 0.96 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -8, scale: 0.96 }}
            transition={{ duration: 0.15 }}
            className="absolute right-0 top-12 w-80 max-h-[480px] flex flex-col rounded-2xl bg-card border border-border shadow-2xl z-50 overflow-hidden"
          >
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 border-b border-border shrink-0">
              <span className="font-bold text-foreground text-sm">Notifications</span>
              {unreadCount > 0 && (
                <button
                  onClick={markAllRead}
                  className="flex items-center gap-1 text-xs text-primary hover:text-primary/80 font-medium transition-colors"
                >
                  <CheckCheck className="w-3.5 h-3.5" />
                  Mark all read
                </button>
              )}
            </div>

            {/* List */}
            <div className="overflow-y-auto flex-1 divide-y divide-border">
              {notifications.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-12 gap-2 text-muted-foreground">
                  <Bell className="w-8 h-8 opacity-30" />
                  <p className="text-sm font-medium">No notifications yet</p>
                  <p className="text-xs opacity-60">Job alerts will appear here in real-time</p>
                </div>
              ) : (
                notifications.map((notif) => {
                  const config = TYPE_CONFIG[notif.type] || TYPE_CONFIG.notification;
                  const Icon = config.icon;
                  return (
                    <div
                      key={notif.id}
                      onClick={() => handleClick(notif)}
                      role="button"
                      tabIndex={0}
                      onKeyDown={(e) => {
                        if (e.key === "Enter" || e.key === " ") {
                          e.preventDefault();
                          handleClick(notif);
                        }
                      }}
                      className={cn(
                        "flex items-start gap-3 px-4 py-3 cursor-pointer transition-colors hover:bg-muted/60 relative group",
                        !notif.read && "bg-primary/5"
                      )}
                    >
                      {/* Icon */}
                      <div className={cn("w-8 h-8 rounded-lg flex items-center justify-center shrink-0 mt-0.5", config.bg)}>
                        <Icon className={cn("w-4 h-4", config.color)} />
                      </div>
                      {/* Content */}
                      <div className="flex-1 min-w-0">
                        <p className={cn("text-sm leading-snug", notif.read ? "text-muted-foreground" : "text-foreground font-medium")}>
                          {getTitle(notif)}
                        </p>
                        <p className="text-xs text-muted-foreground mt-0.5">{timeAgo(notif.timestamp)}</p>
                      </div>
                      {/* Unread dot */}
                      {!notif.read && (
                        <span className="w-2 h-2 rounded-full bg-primary shrink-0 mt-1.5" />
                      )}
                      {/* Dismiss */}
                      <button
                        onClick={(e) => handleDismiss(e, notif.id)}
                        className="opacity-0 group-hover:opacity-100 absolute right-2 top-2 p-1 rounded-lg hover:bg-muted text-muted-foreground hover:text-foreground transition-all"
                        aria-label="Dismiss notification"
                      >
                        <X className="w-3 h-3" />
                      </button>
                    </div>
                  );
                })
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

import { motion } from 'framer-motion'
import { CheckCircle, Lightbulb, RefreshCw } from 'lucide-react'

const getScoreColor = (score) => {
  if (score >= 70) return { bar: 'bg-green-500', text: 'text-green-400', ring: '#22c55e' }
  if (score >= 40) return { bar: 'bg-yellow-500', text: 'text-yellow-400', ring: '#eab308' }
  return { bar: 'bg-red-500', text: 'text-red-400', ring: '#ef4444' }
}

const ScoreRing = ({ score }) => {
  const size = 140
  const strokeWidth = 10
  const radius = (size - strokeWidth) / 2
  const circumference = radius * 2 * Math.PI
  const offset = circumference - (score / 100) * circumference
  const { ring } = getScoreColor(score)

  return (
    <div className="relative shrink-0" style={{ width: size, height: size }}>
      <svg className="transform -rotate-90" width={size} height={size}>
        <circle
          strokeWidth={strokeWidth}
          stroke="currentColor"
          className="text-muted-foreground/20"
          fill="transparent"
          r={radius}
          cx={size / 2}
          cy={size / 2}
        />
        <motion.circle
          initial={{ strokeDashoffset: circumference }}
          animate={{ strokeDashoffset: offset }}
          transition={{ duration: 1.2, ease: 'easeOut' }}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          stroke={ring}
          fill="transparent"
          r={radius}
          cx={size / 2}
          cy={size / 2}
          style={{ strokeDasharray: circumference }}
        />
      </svg>
      <div className="absolute inset-0 flex flex-col items-center justify-center">
        <motion.span
          initial={{ opacity: 0, scale: 0.5 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ delay: 0.6, duration: 0.3 }}
          className="text-4xl font-bold text-foreground"
        >
          {score}
        </motion.span>
        <span className="text-xs text-muted-foreground mt-0.5">/ 100</span>
      </div>
    </div>
  )
}

const SectionBar = ({ section, score, feedback, index }) => {
  const { bar, text } = getScoreColor(score)
  return (
    <motion.div
      initial={{ opacity: 0, x: -10 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ delay: 0.1 * index }}
      className="space-y-1"
    >
      <div className="flex justify-between text-sm">
        <span className="text-foreground capitalize font-medium">{section}</span>
        <span className={`font-semibold ${text}`}>{score}</span>
      </div>
      <div className="h-2 bg-card rounded-full overflow-hidden">
        <motion.div
          initial={{ width: 0 }}
          animate={{ width: `${score}%` }}
          transition={{ duration: 0.8, delay: 0.15 * index, ease: 'easeOut' }}
          className={`h-full rounded-full ${bar}`}
        />
      </div>
      <p className="text-xs text-muted-foreground">{feedback}</p>
    </motion.div>
  )
}

export default function ResumeScore({ data, onRescore }) {
  if (!data) return null

  const { overallScore, sections, topSuggestions } = data
  const { text: scoreText } = getScoreColor(overallScore)

  const label =
    overallScore >= 80 ? 'Excellent!' :
    overallScore >= 60 ? 'Good Progress' :
    overallScore >= 40 ? 'Needs Work' :
    'Major Improvements Needed'

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="space-y-6"
    >
      {/* Overall Score */}
      <div className="bg-background/50 border border-border rounded-2xl p-6 flex flex-col sm:flex-row items-center gap-6">
        <ScoreRing score={overallScore} />
        <div className="text-center sm:text-left">
          <p className={`text-2xl font-bold ${scoreText}`}>{label}</p>
          <p className="text-muted-foreground text-sm mt-1">Overall Resume Score</p>
          {onRescore && (
            <button
              onClick={onRescore}
              className="mt-3 text-sm text-primary hover:text-primary/80 flex items-center gap-1 mx-auto sm:mx-0"
            >
              <RefreshCw className="w-4 h-4" />
              Re-score
            </button>
          )}
        </div>
      </div>

      {/* Section Breakdown */}
      {sections && (
        <div className="bg-background/50 border border-border rounded-2xl p-6 space-y-5">
          <h3 className="text-lg font-semibold text-foreground">Section Breakdown</h3>
          {Object.entries(sections).map(([section, { score, feedback }], i) => (
            <SectionBar key={section} section={section} score={score} feedback={feedback} index={i} />
          ))}
        </div>
      )}

      {/* Suggestions */}
      {topSuggestions?.length > 0 && (
        <div className="bg-background/50 border border-border rounded-2xl p-6">
          <h3 className="text-lg font-semibold text-foreground mb-4 flex items-center gap-2">
            <Lightbulb className="w-5 h-5 text-yellow-400" />
            Top Suggestions
          </h3>
          <ul className="space-y-3">
            {topSuggestions.map((tip, i) => (
              <motion.li
                key={i}
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.1 * i }}
                className="flex items-start gap-3"
              >
                <CheckCircle className="w-4 h-4 text-primary mt-0.5 shrink-0" />
                <span className="text-foreground text-sm">{tip}</span>
              </motion.li>
            ))}
          </ul>
        </div>
      )}
    </motion.div>
  )
}

import React, { useState, useEffect } from 'react'
import { FileText, Plus, CheckCircle, RotateCcw, Trash2, Edit2, GitPullRequest, Bookmark, Sparkles, Tag, X } from 'lucide-react'
import { resumeApi } from '../services/api'
import toast from 'react-hot-toast'
import VersionCompareModal from './VersionCompareModal'
import { motion, AnimatePresence } from 'framer-motion'

export default function ResumeVersions({ 
  resumeId, 
  currentOriginalText, 
  currentEnhancedText, 
  currentJobRole, 
  currentAtsScore,
  onRestore 
}) {
  const [versions, setVersions] = useState([])
  const [loading, setLoading] = useState(true)
  
  // Snapshot Form state
  const [showSnapshotForm, setShowSnapshotForm] = useState(false)
  const [snapshotTitle, setSnapshotTitle] = useState('')
  const [snapshotRole, setSnapshotRole] = useState(currentJobRole || '')
  const [snapshotTags, setSnapshotTags] = useState('')
  const [savingSnapshot, setSavingSnapshot] = useState(false)

  // Edit version metadata state
  const [editingVersion, setEditingVersion] = useState(null)
  const [editTitle, setEditTitle] = useState('')
  const [editRole, setEditRole] = useState('')
  const [editTags, setEditTags] = useState('')
  const [updatingMetadata, setUpdatingMetadata] = useState(false)

  // Comparison Modal state
  const [compareOpen, setCompareOpen] = useState(false)
  const [compareLeft, setCompareLeft] = useState(null)
  const [compareRight, setCompareRight] = useState(null)

  useEffect(() => {
    fetchVersions()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [resumeId])

  const fetchVersions = async () => {
    try {
      setLoading(true)
      const res = await resumeApi.getVersions(resumeId)
      setVersions(res.data || [])
    } catch (err) {
      toast.error('Failed to load version history')
    } finally {
      setLoading(false)
    }
  }

  const handleCreateSnapshot = async (e) => {
    e.preventDefault()
    if (!currentOriginalText) {
      toast.error('No resume content available to snapshot')
      return
    }

    try {
      setSavingSnapshot(true)
      const tagsArray = snapshotTags
        .split(',')
        .map(t => t.trim())
        .filter(t => t.length > 0)

      const payload = {
        title: snapshotTitle.trim() || undefined,
        originalText: currentOriginalText,
        enhancedText: currentEnhancedText || null,
        jobRole: snapshotRole.trim() || null,
        atsScore: currentAtsScore !== undefined && currentAtsScore !== null ? currentAtsScore : null,
        tags: tagsArray
      }

      const res = await resumeApi.createVersion(resumeId, payload)
      setVersions(prev => [res.data, ...prev])
      toast.success('Snapshot created successfully!')
      
      // Reset form
      setSnapshotTitle('')
      setSnapshotTags('')
      setShowSnapshotForm(false)
    } catch (err) {
      toast.error('Failed to save snapshot version')
    } finally {
      setSavingSnapshot(false)
    }
  }

  const handleRestore = async (version) => {
    const confirm = window.confirm(`Are you sure you want to restore the resume to Version ${version.versionNumber} ("${version.title}")? This will update your active resume.`)
    if (!confirm) return

    try {
      toast.loading('Restoring resume version...', { id: 'restore' })
      const res = await resumeApi.restoreVersion(resumeId, version.id)
      toast.success('Resume restored successfully!', { id: 'restore' })
      if (onRestore) {
        onRestore(res.data)
      }
    } catch (err) {
      toast.error('Failed to restore resume version', { id: 'restore' })
    }
  }

  const handleDelete = async (version) => {
    if (versions.length === 1) {
      toast.error('Cannot delete the only remaining version of the resume')
      return
    }
    const confirm = window.confirm(`Are you sure you want to delete Version ${version.versionNumber} ("${version.title}")? This action cannot be undone.`)
    if (!confirm) return

    try {
      await resumeApi.deleteVersion(resumeId, version.id)
      setVersions(prev => prev.filter(v => v.id !== version.id))
      toast.success('Version deleted')
    } catch (err) {
      toast.error('Failed to delete version')
    }
  }

  const startEdit = (version) => {
    setEditingVersion(version)
    setEditTitle(version.title || '')
    setEditRole(version.jobRole || '')
    setEditTags(version.tags ? version.tags.join(', ') : '')
  }

  const handleUpdateMetadata = async (e) => {
    e.preventDefault()
    try {
      setUpdatingMetadata(true)
      const tagsArray = editTags
        .split(',')
        .map(t => t.trim())
        .filter(t => t.length > 0)

      const payload = {
        title: editTitle.trim() || `Version ${editingVersion.versionNumber}`,
        jobRole: editRole.trim() || null,
        tags: tagsArray
      }

      const res = await resumeApi.updateVersion(resumeId, editingVersion.id, payload)
      setVersions(prev => prev.map(v => v.id === editingVersion.id ? res.data : v))
      toast.success('Version details updated')
      setEditingVersion(null)
    } catch (err) {
      toast.error('Failed to update version details')
    } finally {
      setUpdatingMetadata(false)
    }
  }

  const triggerCompare = (targetVersion) => {
    setCompareLeft(targetVersion)
    // Find next oldest version as fallback, or the same if single
    const index = versions.findIndex(v => v.id === targetVersion.id)
    const fallbackRight = versions[index + 1] || versions[0]
    setCompareRight(fallbackRight)
    setCompareOpen(true)
  }

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    })
  }

  return (
    <div className="space-y-6">
      {/* Header and Controls */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h3 className="text-lg font-bold text-foreground">Resume Version Manager</h3>
          <p className="text-xs text-muted-foreground">Restore snapshots or review content changes over time</p>
        </div>
        <button
          onClick={() => {
            setSnapshotRole(currentJobRole || '')
            setShowSnapshotForm(true)
          }}
          className="inline-flex items-center gap-1.5 px-4 py-2 rounded-xl bg-gradient-to-r from-primary to-secondary text-primary-foreground text-xs font-semibold hover:opacity-90 hover:scale-[1.02] transition-all shadow-md"
        >
          <Plus className="w-4 h-4" />
          Create Snapshot
        </button>
      </div>

      {/* Timeline List */}
      {loading ? (
        <div className="flex justify-center py-12">
          <div className="w-8 h-8 border-4 border-muted border-t-primary rounded-full animate-spin"></div>
        </div>
      ) : versions.length === 0 ? (
        <div className="border border-dashed border-border rounded-2xl p-10 text-center text-muted-foreground bg-card/10">
          <FileText className="w-12 h-12 mx-auto mb-3 opacity-55" />
          <p className="text-sm">No saved resume versions found.</p>
        </div>
      ) : (
        <div className="relative border-l-2 border-border/80 pl-6 ml-4 space-y-8 py-2">
          {versions.map((version, idx) => {
            const isActive = currentOriginalText === version.originalText && currentEnhancedText === version.enhancedText
            return (
              <motion.div
                key={version.id}
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: idx * 0.05 }}
                className="relative group"
              >
                {/* Timeline Dot Indicator */}
                <span className={`absolute -left-[33px] top-1.5 w-4 h-4 rounded-full border-2 ${
                  isActive ? 'bg-primary border-primary shadow-glow' : 'bg-background border-border group-hover:border-primary'
                } transition-all-300`} />

                {/* Timeline Card */}
                <div className="bg-card/40 border border-border/80 hover:border-primary/30 p-5 rounded-2xl transition-all-300 relative shadow-sm hover:shadow">
                  <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
                    <div className="space-y-1.5">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span className="text-xs font-bold px-2 py-0.5 rounded bg-primary/10 text-primary border border-primary/20">
                          v{version.versionNumber}
                        </span>
                        <h4 className="font-bold text-foreground">{version.title || `Version ${version.versionNumber}`}</h4>
                        {isActive && (
                          <span className="inline-flex items-center gap-1 text-[10px] font-bold px-1.5 py-0.5 rounded bg-green-500/10 text-green-400 border border-green-500/20">
                            <CheckCircle className="w-2.5 h-2.5" />
                            Active
                          </span>
                        )}
                      </div>
                      
                      <div className="flex items-center gap-4 text-xs text-muted-foreground flex-wrap">
                        <span>{formatDate(version.createdAt)}</span>
                        {version.jobRole && (
                          <span className="flex items-center gap-1">
                            <Bookmark className="w-3.5 h-3.5 text-muted-foreground" />
                            {version.jobRole}
                          </span>
                        )}
                        {(version.atsScore !== null && version.atsScore !== undefined) && (
                          <span className="inline-flex items-center gap-1 font-semibold text-emerald-400">
                            <Sparkles className="w-3.5 h-3.5 text-emerald-400" />
                            ATS Score: {version.atsScore}
                          </span>
                        )}
                      </div>

                      {/* Version Tags */}
                      {version.tags && version.tags.length > 0 && (
                        <div className="flex flex-wrap gap-1 mt-2">
                          {version.tags.map(tag => (
                            <span key={tag} className="text-[10px] px-2 py-0.5 bg-muted rounded-full text-muted-foreground flex items-center gap-1">
                              <Tag className="w-2.5 h-2.5" />
                              {tag}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>

                    {/* Timeline Card Action Buttons */}
                    <div className="flex items-center gap-1.5 sm:self-start">
                      <button
                        onClick={() => triggerCompare(version)}
                        title="Compare with another version"
                        className="p-2 rounded-xl bg-muted/40 hover:bg-primary/15 text-muted-foreground hover:text-primary transition-all cursor-pointer"
                      >
                        <GitPullRequest className="w-4 h-4" />
                      </button>
                      <button
                        onClick={() => startEdit(version)}
                        title="Edit label & tags"
                        className="p-2 rounded-xl bg-muted/40 hover:bg-yellow-500/15 text-muted-foreground hover:text-yellow-400 transition-all cursor-pointer"
                      >
                        <Edit2 className="w-4 h-4" />
                      </button>
                      <button
                        onClick={() => handleRestore(version)}
                        disabled={isActive}
                        title={isActive ? "Current active version" : "Restore this version"}
                        className={`p-2 rounded-xl text-xs font-semibold flex items-center gap-1.5 transition-all cursor-pointer ${
                          isActive 
                            ? 'bg-muted text-muted-foreground/40 cursor-not-allowed'
                            : 'bg-primary/10 hover:bg-primary/25 text-primary'
                        }`}
                      >
                        <RotateCcw className="w-4 h-4" />
                        <span>Restore</span>
                      </button>
                      <button
                        onClick={() => handleDelete(version)}
                        title="Delete this version"
                        className="p-2 rounded-xl bg-destructive/10 hover:bg-destructive/25 text-destructive transition-all cursor-pointer"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                </div>
              </motion.div>
            )
          })}
        </div>
      )}

      {/* Snapshot Dialog Popup */}
      <AnimatePresence>
        {showSnapshotForm && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setShowSnapshotForm(false)}
              className="absolute inset-0 bg-background/80 backdrop-filter backdrop-blur-sm"
            />
            <motion.div
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="relative bg-card border border-border w-full max-w-md rounded-3xl p-6 shadow-2xl z-10 glass"
            >
              <div className="flex justify-between items-center mb-4">
                <h4 className="text-lg font-bold text-foreground">Create Resume Snapshot</h4>
                <button onClick={() => setShowSnapshotForm(false)} className="text-muted-foreground hover:text-foreground">
                  <X className="w-5 h-5" />
                </button>
              </div>

              <form onSubmit={handleCreateSnapshot} className="space-y-4">
                <div>
                  <label className="block text-xs font-semibold text-muted-foreground mb-1">Version Title/Label</label>
                  <input
                    type="text"
                    value={snapshotTitle}
                    onChange={(e) => setSnapshotTitle(e.target.value)}
                    placeholder="e.g. Optimized for Fullstack Dev"
                    className="w-full px-3 py-2 bg-muted/40 border border-border rounded-xl text-foreground text-sm focus:ring-2 focus:ring-primary focus:border-transparent"
                  />
                </div>

                <div>
                  <label className="block text-xs font-semibold text-muted-foreground mb-1">Target Job Role</label>
                  <input
                    type="text"
                    value={snapshotRole}
                    onChange={(e) => setSnapshotRole(e.target.value)}
                    placeholder="e.g. Senior Node JS Developer"
                    className="w-full px-3 py-2 bg-muted/40 border border-border rounded-xl text-foreground text-sm focus:ring-2 focus:ring-primary focus:border-transparent"
                  />
                </div>

                <div>
                  <label className="block text-xs font-semibold text-muted-foreground mb-1">Tags (Comma-separated)</label>
                  <input
                    type="text"
                    value={snapshotTags}
                    onChange={(e) => setSnapshotTags(e.target.value)}
                    placeholder="e.g. Fullstack, Node, Backend"
                    className="w-full px-3 py-2 bg-muted/40 border border-border rounded-xl text-foreground text-sm focus:ring-2 focus:ring-primary focus:border-transparent"
                  />
                </div>

                <div className="flex gap-3 justify-end pt-2">
                  <button
                    type="button"
                    onClick={() => setShowSnapshotForm(false)}
                    className="px-4 py-2 rounded-xl bg-muted/50 hover:bg-muted text-foreground text-xs font-semibold"
                  >
                    Cancel
                  </button>
                  <button
                    type="submit"
                    disabled={savingSnapshot}
                    className="px-4 py-2 rounded-xl bg-primary text-primary-foreground text-xs font-semibold hover:opacity-90 disabled:opacity-50"
                  >
                    {savingSnapshot ? 'Saving...' : 'Save Snapshot'}
                  </button>
                </div>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* Edit Metadata Dialog Popup */}
      <AnimatePresence>
        {editingVersion && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setEditingVersion(null)}
              className="absolute inset-0 bg-background/80 backdrop-filter backdrop-blur-sm"
            />
            <motion.div
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="relative bg-card border border-border w-full max-w-md rounded-3xl p-6 shadow-2xl z-10 glass"
            >
              <div className="flex justify-between items-center mb-4">
                <h4 className="text-lg font-bold text-foreground">Edit Version Details (v{editingVersion.versionNumber})</h4>
                <button onClick={() => setEditingVersion(null)} className="text-muted-foreground hover:text-foreground">
                  <X className="w-5 h-5" />
                </button>
              </div>

              <form onSubmit={handleUpdateMetadata} className="space-y-4">
                <div>
                  <label className="block text-xs font-semibold text-muted-foreground mb-1">Version Title/Label</label>
                  <input
                    type="text"
                    value={editTitle}
                    onChange={(e) => setEditTitle(e.target.value)}
                    placeholder="e.g. Version 2 - Updated Projects"
                    className="w-full px-3 py-2 bg-muted/40 border border-border rounded-xl text-foreground text-sm focus:ring-2 focus:ring-primary focus:border-transparent"
                    required
                  />
                </div>

                <div>
                  <label className="block text-xs font-semibold text-muted-foreground mb-1">Target Job Role</label>
                  <input
                    type="text"
                    value={editRole}
                    onChange={(e) => setEditRole(e.target.value)}
                    placeholder="e.g. Backend Engineer"
                    className="w-full px-3 py-2 bg-muted/40 border border-border rounded-xl text-foreground text-sm focus:ring-2 focus:ring-primary focus:border-transparent"
                  />
                </div>

                <div>
                  <label className="block text-xs font-semibold text-muted-foreground mb-1">Tags (Comma-separated)</label>
                  <input
                    type="text"
                    value={editTags}
                    onChange={(e) => setEditTags(e.target.value)}
                    placeholder="e.g. backend, node, active"
                    className="w-full px-3 py-2 bg-muted/40 border border-border rounded-xl text-foreground text-sm focus:ring-2 focus:ring-primary focus:border-transparent"
                  />
                </div>

                <div className="flex gap-3 justify-end pt-2">
                  <button
                    type="button"
                    onClick={() => setEditingVersion(null)}
                    className="px-4 py-2 rounded-xl bg-muted/50 hover:bg-muted text-foreground text-xs font-semibold"
                  >
                    Cancel
                  </button>
                  <button
                    type="submit"
                    disabled={updatingMetadata}
                    className="px-4 py-2 rounded-xl bg-primary text-primary-foreground text-xs font-semibold hover:opacity-90 disabled:opacity-50"
                  >
                    {updatingMetadata ? 'Updating...' : 'Update Details'}
                  </button>
                </div>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* Compare Modal */}
      {compareOpen && (
        <VersionCompareModal
          isOpen={compareOpen}
          onClose={() => setCompareOpen(false)}
          versions={versions}
          initialLeftVersion={compareLeft}
          initialRightVersion={compareRight}
        />
      )}
    </div>
  )
}

import { motion } from 'framer-motion';
import { Check, ChevronLeft, ChevronRight } from 'lucide-react';
import { cn } from '@/lib/utils';

export default function StepWizard({ steps = [], currentStep = 0, onStepChange }) {
  const isFirst = currentStep === 0;
  const isLast = currentStep === steps.length - 1;

  return (
    <div className="flex flex-col gap-8">
      {/* Step Indicator */}
      <div className="flex items-start">
        {steps.map((step, index) => {
          const isCompleted = index < currentStep;
          const isCurrent = index === currentStep;

          return (
            <div key={index} className="flex items-start flex-1">
              {/* Step Node + Label */}
              <div className="flex flex-col items-center gap-2 min-w-0">
                <motion.button
                  onClick={() => onStepChange?.(index)}
                  whileHover={{ scale: 1.08 }}
                  whileTap={{ scale: 0.95 }}
                  className={cn(
                    'w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm transition-colors duration-300 border-2 cursor-pointer',
                    isCompleted && 'bg-green-500 border-green-500 text-white',
                    isCurrent && 'bg-primary border-primary text-primary-foreground shadow-lg shadow-primary/30',
                    !isCompleted && !isCurrent && 'bg-card border-border text-muted-foreground'
                  )}
                >
                  {isCompleted ? (
                    <motion.span
                      initial={{ scale: 0 }}
                      animate={{ scale: 1 }}
                      transition={{ type: 'spring', stiffness: 400, damping: 20 }}
                    >
                      <Check className="w-4 h-4" strokeWidth={3} />
                    </motion.span>
                  ) : step.icon ? (
                    <step.icon className="w-4 h-4" />
                  ) : (
                    <span>{index + 1}</span>
                  )}
                </motion.button>

                <div className="text-center px-1 max-w-[80px]">
                  <p className={cn(
                    'text-xs font-semibold leading-tight',
                    isCurrent ? 'text-foreground' : 'text-muted-foreground'
                  )}>
                    {step.title}
                  </p>
                  {step.description && (
                    <p className="text-[10px] text-muted-foreground mt-0.5 leading-tight hidden sm:block">
                      {step.description}
                    </p>
                  )}
                </div>
              </div>

              {/* Connector Line — aligned to circle center (mt-5 = 20px = half of 40px circle) */}
              {index < steps.length - 1 && (
                <div className="flex-1 h-0.5 mt-5 mx-2 bg-border overflow-hidden rounded-full">
                  <motion.div
                    className="h-full bg-green-500 rounded-full"
                    initial={{ width: '0%' }}
                    animate={{ width: isCompleted ? '100%' : '0%' }}
                    transition={{ duration: 0.4, ease: 'easeInOut' }}
                  />
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Navigation */}
      <div className="flex justify-between">
          <button
            onClick={() => onStepChange?.(currentStep - 1)}
            disabled={isFirst}
            className={cn(
              'inline-flex items-center gap-2 px-6 py-3 rounded-2xl text-sm font-black tracking-wide transition-all duration-300',
              isFirst
                ? 'opacity-40 cursor-not-allowed bg-card border-2 border-border text-muted-foreground'
                : 'bg-card border-2 border-border text-foreground hover:bg-muted hover:border-primary/50 cursor-pointer'
            )}
          >
            <ChevronLeft className="w-4 h-4" />
            Previous
          </button>

          <button
            onClick={() => onStepChange?.(currentStep + 1)}
            disabled={isLast}
            className={cn(
              'inline-flex items-center gap-2 px-6 py-3 rounded-2xl text-sm font-black tracking-wide transition-all duration-300',
              isLast
                ? 'opacity-40 cursor-not-allowed bg-primary text-primary-foreground'
                : 'bg-primary text-primary-foreground hover:bg-primary/90 shadow-lg shadow-primary/20 cursor-pointer'
            )}
          >
            Next
            <ChevronRight className="w-4 h-4" />
          </button>
      </div>
    </div>
  );
}

import { Link } from 'react-router-dom'
import { motion } from 'framer-motion'
import { ArrowRight } from 'lucide-react'

export default function ToolCard({ to, icon: Icon, title, description, color = 'primary', badge, onClick }) {
  const content = (
    <motion.div
      whileHover={{ y: -4, scale: 1.01 }}
      whileTap={{ scale: 0.98 }}
      className="group relative p-6 rounded-2xl bg-card border border-border overflow-hidden transition-all duration-300 hover:border-primary/40 hover:shadow-xl hover:shadow-primary/5 cursor-pointer h-full"
    >
      {/* Hover glow effect */}
      <div className="absolute inset-0 bg-gradient-to-br from-primary/5 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none" />

      {/* Badge */}
      {badge && (
        <div className="absolute top-4 right-4 px-2 py-0.5 bg-primary/15 rounded-full text-[10px] text-primary font-black uppercase tracking-wider border border-primary/20">
          {badge}
        </div>
      )}

      {/* Icon */}
      <div className={`relative w-14 h-14 rounded-xl bg-${color}/10 border border-${color}/20 flex items-center justify-center mb-4 group-hover:scale-110 group-hover:bg-${color}/15 transition-all duration-300`}>
        <Icon className={`w-7 h-7 text-${color} transition-colors`} />
      </div>

      {/* Text */}
      <h3 className="relative text-lg font-bold text-foreground mb-1.5 group-hover:text-primary transition-colors">
        {title}
      </h3>
      <p className="relative text-sm text-muted-foreground font-medium leading-relaxed">
        {description}
      </p>

      {/* Arrow indicator */}
      <div className="relative flex items-center gap-1.5 mt-4 text-xs font-semibold text-muted-foreground group-hover:text-primary transition-colors">
        <span>Open</span>
        <ArrowRight className="w-3.5 h-3.5 group-hover:translate-x-1 transition-transform" />
      </div>
    </motion.div>
  )

  if (onClick) {
    return <div onClick={onClick}>{content}</div>
  }

  return (
    <Link to={to} className="block">
      {content}
    </Link>
  )
}

import React, { useState, useEffect } from 'react'
import { X, GitCommit, ArrowRight, BookOpen } from 'lucide-react'
import { diffLines } from '../utils/diff'
import { motion, AnimatePresence } from 'framer-motion'

export default function VersionCompareModal({ isOpen, onClose, versions, initialLeftVersion, initialRightVersion }) {
  const [leftVersionId, setLeftVersionId] = useState('')
  const [rightVersionId, setRightVersionId] = useState('')
  const [diffResult, setDiffResult] = useState([])
  const [viewMode, setViewMode] = useState('split') // 'split' or 'unified'

  useEffect(() => {
    if (initialLeftVersion) setLeftVersionId(initialLeftVersion.id)
    if (initialRightVersion) setRightVersionId(initialRightVersion.id)
  }, [initialLeftVersion, initialRightVersion])

  const leftVersion = versions.find(v => v.id === leftVersionId)
  const rightVersion = versions.find(v => v.id === rightVersionId)

  useEffect(() => {
    const leftText = leftVersion ? (leftVersion.enhancedText || leftVersion.originalText) : ''
    const rightText = rightVersion ? (rightVersion.enhancedText || rightVersion.originalText) : ''
    
    if (leftText || rightText) {
      const diffs = diffLines(leftText, rightText)
      setDiffResult(diffs)
    } else {
      setDiffResult([])
    }
  }, [leftVersion, rightVersion])

  if (!isOpen) return null

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6 md:p-10">
      {/* Backdrop */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="fixed inset-0 bg-background/80 backdrop-filter backdrop-blur-md"
      />

      {/* Modal Content */}
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="relative w-full max-w-6xl h-[85vh] bg-card border border-border rounded-3xl shadow-2xl flex flex-col overflow-hidden glass"
      >
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-border">
          <div className="flex items-center gap-3">
            <div className="p-2 rounded-xl bg-primary/10 text-primary">
              <BookOpen className="w-5 h-5" />
            </div>
            <div>
              <h2 className="text-xl font-bold text-foreground">Compare Resume Versions</h2>
              <p className="text-xs text-muted-foreground">Select two versions to inspect exact modifications</p>
            </div>
          </div>
          <button 
            onClick={onClose}
            className="p-1.5 rounded-lg hover:bg-muted text-muted-foreground hover:text-foreground transition-all"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Dropdowns Selector */}
        <div className="p-4 bg-muted/30 border-b border-border flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex flex-wrap items-center gap-3 w-full md:w-auto">
            <div className="flex items-center gap-2">
              <span className="text-xs font-semibold text-muted-foreground">Base:</span>
              <select
                value={leftVersionId}
                onChange={(e) => setLeftVersionId(e.target.value)}
                className="px-3 py-1.5 bg-card border border-border rounded-xl text-sm text-foreground focus:ring-2 focus:ring-primary focus:border-transparent"
              >
                {versions.map(v => (
                  <option key={v.id} value={v.id}>
                    v{v.versionNumber} - {v.title || `Version ${v.versionNumber}`}
                  </option>
                ))}
              </select>
            </div>
            <ArrowRight className="w-4 h-4 text-muted-foreground hidden sm:block" />
            <div className="flex items-center gap-2">
              <span className="text-xs font-semibold text-muted-foreground">Compare:</span>
              <select
                value={rightVersionId}
                onChange={(e) => setRightVersionId(e.target.value)}
                className="px-3 py-1.5 bg-card border border-border rounded-xl text-sm text-foreground focus:ring-2 focus:ring-primary focus:border-transparent"
              >
                {versions.map(v => (
                  <option key={v.id} value={v.id}>
                    v{v.versionNumber} - {v.title || `Version ${v.versionNumber}`}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <div className="flex items-center bg-card border border-border rounded-xl p-0.5">
            <button
              onClick={() => setViewMode('split')}
              className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all ${
                viewMode === 'split' ? 'bg-primary text-primary-foreground shadow-sm' : 'text-muted-foreground hover:text-foreground'
              }`}
            >
              Split View
            </button>
            <button
              onClick={() => setViewMode('unified')}
              className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all ${
                viewMode === 'unified' ? 'bg-primary text-primary-foreground shadow-sm' : 'text-muted-foreground hover:text-foreground'
              }`}
            >
              Unified View
            </button>
          </div>
        </div>

        {/* Comparison Viewer Body */}
        <div className="flex-1 overflow-auto p-6 font-mono text-xs leading-relaxed bg-card/45">
          {viewMode === 'unified' ? (
            <div className="space-y-0.5 select-text">
              {diffResult.map((line, idx) => {
                let bgClass = 'text-foreground'
                let sign = ' '
                if (line.type === 'added') {
                  bgClass = 'bg-green-500/10 text-green-400 border-l-2 border-green-500 pl-1'
                  sign = '+'
                } else if (line.type === 'removed') {
                  bgClass = 'bg-red-500/10 text-red-400 border-l-2 border-red-500 pl-1 line-through'
                  sign = '-'
                }
                return (
                  <div key={idx} className={`flex py-0.5 px-2 rounded ${bgClass}`}>
                    <span className="w-8 text-right pr-3 select-none text-muted-foreground/60">{idx + 1}</span>
                    <span className="w-4 select-none font-bold text-center mr-2">{sign}</span>
                    <span className="whitespace-pre-wrap">{line.value || ' '}</span>
                  </div>
                )
              })}
              {diffResult.length === 0 && (
                <div className="flex flex-col items-center justify-center py-20 text-muted-foreground">
                  <GitCommit className="w-12 h-12 mb-3 opacity-50 animate-bounce" />
                  <p>No content differences detected between selected versions.</p>
                </div>
              )}
            </div>
          ) : (
            /* Split View Side-by-side */
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 h-full">
              {/* Left Column (Base) */}
              <div className="flex flex-col border border-border rounded-2xl bg-muted/20 overflow-hidden h-full">
                <div className="px-4 py-2 border-b border-border bg-muted/40 font-sans font-bold text-muted-foreground flex justify-between">
                  <span>Base (v{leftVersion?.versionNumber})</span>
                  {leftVersion?.atsScore && <span className="text-xs text-primary">ATS: {leftVersion.atsScore}</span>}
                </div>
                <div className="flex-1 overflow-auto p-4 space-y-0.5">
                  {diffResult
                    .filter(line => line.type !== 'added')
                    .map((line, idx) => {
                      const bgClass = line.type === 'removed' ? 'bg-red-500/15 text-red-400 pl-1 border-l-2 border-red-500' : 'text-foreground/80'
                      return (
                        <div key={idx} className={`flex py-0.5 px-2 rounded ${bgClass}`}>
                          <span className="w-6 text-right pr-2 select-none text-muted-foreground/50">{idx + 1}</span>
                          <span className="whitespace-pre-wrap">{line.value || ' '}</span>
                        </div>
                      )
                    })}
                </div>
              </div>

              {/* Right Column (Compare) */}
              <div className="flex flex-col border border-border rounded-2xl bg-muted/20 overflow-hidden h-full">
                <div className="px-4 py-2 border-b border-border bg-muted/40 font-sans font-bold text-muted-foreground flex justify-between">
                  <span>Compare (v{rightVersion?.versionNumber})</span>
                  {rightVersion?.atsScore && <span className="text-xs text-green-400 font-semibold">ATS: {rightVersion.atsScore}</span>}
                </div>
                <div className="flex-1 overflow-auto p-4 space-y-0.5">
                  {diffResult
                    .filter(line => line.type !== 'removed')
                    .map((line, idx) => {
                      const bgClass = line.type === 'added' ? 'bg-green-500/15 text-green-400 pl-1 border-l-2 border-green-500' : 'text-foreground/80'
                      return (
                        <div key={idx} className={`flex py-0.5 px-2 rounded ${bgClass}`}>
                          <span className="w-6 text-right pr-2 select-none text-muted-foreground/50">{idx + 1}</span>
                          <span className="whitespace-pre-wrap">{line.value || ' '}</span>
                        </div>
                      )
                    })}
                </div>
              </div>
            </div>
          )}
        </div>
      </motion.div>
    </div>
  )
}

/**
 * VoiceToTextButton — Reusable microphone toggle button with live transcript display.
 *
 * Implements issue #28: Voice-to-Text for Mock Interviews
 *
 * Props:
 *  onTranscriptChange  (string) => void   Called whenever transcript updates
 *  lang                string             BCP-47 language tag (default 'en-US')
 *  placeholder         string             Hint text shown in empty textarea
 *  disabled            boolean            Disable the button externally
 *  className           string             Extra Tailwind classes for the wrapper
 *  showTranscript      boolean            Whether to render the transcript textarea (default true)
 *  size                'sm'|'md'|'lg'     Button size preset (default 'md')
 */
import { useCallback } from 'react';
import { Mic, MicOff, AlertCircle, Loader2 } from 'lucide-react';
import { useVoiceToText, isSpeechRecognitionSupported } from '../hooks/useVoiceToText';

const SIZE = {
    sm: { btn: 'p-2', icon: 'w-4 h-4', pulse: 'w-8 h-8' },
    md: { btn: 'p-3', icon: 'w-5 h-5', pulse: 'w-10 h-10' },
    lg: { btn: 'p-4', icon: 'w-6 h-6', pulse: 'w-12 h-12' },
};

export default function VoiceToTextButton({
    onTranscriptChange,
    lang = 'en-US',
    placeholder = 'Your spoken answer will appear here…',
    disabled = false,
    className = '',
    showTranscript = true,
    size = 'md',
}) {
    const s = SIZE[size] || SIZE.md;

    const handleFinal = useCallback(
        (text) => onTranscriptChange?.(text),
        [onTranscriptChange]
    );

    const {
        isListening,
        transcript,
        interimTranscript,
        error,
        isSupported,
        startListening,
        stopListening,
        resetTranscript,
    } = useVoiceToText({ lang, onFinalTranscript: handleFinal });

    const toggle = () => {
        if (disabled) return;
        if (isListening) {
            stopListening();
        } else {
            resetTranscript();
            startListening();
        }
    };

    const displayText = transcript + interimTranscript;

    // Not supported — show a static badge
    if (!isSpeechRecognitionSupported()) {
        return (
            <div className={`flex items-center gap-2 text-sm text-amber-400 ${className}`}>
                <AlertCircle className="w-4 h-4 flex-shrink-0" />
                <span>Voice input requires Chrome or Edge on desktop.</span>
            </div>
        );
    }

    return (
        <div className={`flex flex-col gap-3 ${className}`}>
            {/* Button row */}
            <div className="flex items-center gap-3">
                {/* Outer pulse ring when listening */}
                <div className="relative flex-shrink-0">
                    {isListening && (
                        <span
                            className={`absolute inset-0 rounded-full bg-red-500/30 animate-ping ${s.pulse}`}
                            aria-hidden="true"
                        />
                    )}
                    <button
                        type="button"
                        onClick={toggle}
                        disabled={disabled}
                        aria-label={isListening ? 'Stop voice input' : 'Start voice input'}
                        aria-pressed={isListening}
                        className={[
                            s.btn,
                            'relative rounded-full transition-all duration-200 focus:outline-none focus-visible:ring-2 focus-visible:ring-primary',
                            disabled
                                ? 'opacity-40 cursor-not-allowed bg-muted'
                                : isListening
                                    ? 'bg-red-500 text-white shadow-lg shadow-red-500/30 hover:bg-red-600'
                                    : 'bg-primary/10 text-primary border border-primary/30 hover:bg-primary/20',
                        ].join(' ')}
                    >
                        {isListening
                            ? <MicOff className={s.icon} />
                            : <Mic className={s.icon} />
                        }
                    </button>
                </div>

                {/* Status label */}
                <span className={`text-sm font-medium ${isListening ? 'text-red-400' : 'text-muted-foreground'}`}>
                    {isListening ? (
                        <span className="flex items-center gap-1.5">
                            <Loader2 className="w-3.5 h-3.5 animate-spin" />
                            Listening…
                        </span>
                    ) : transcript
                        ? 'Click mic to re-record'
                        : 'Click mic to speak your answer'
                    }
                </span>

                {/* Clear button */}
                {transcript && !isListening && (
                    <button
                        type="button"
                        onClick={() => { resetTranscript(); onTranscriptChange?.(''); }}
                        className="ml-auto text-xs text-muted-foreground hover:text-foreground transition-colors underline underline-offset-2"
                        aria-label="Clear transcript"
                    >
                        Clear
                    </button>
                )}
            </div>

            {/* Transcript area */}
            {showTranscript && (
                <div
                    role="status"
                    aria-live="polite"
                    aria-atomic="false"
                    className={[
                        'min-h-[80px] rounded-xl border p-4 text-sm leading-relaxed transition-colors',
                        isListening
                            ? 'border-red-500/40 bg-red-500/5'
                            : displayText
                                ? 'border-border bg-muted/40'
                                : 'border-dashed border-border/60 bg-transparent',
                    ].join(' ')}
                >
                    {displayText ? (
                        <>
                            <span className="text-foreground">{transcript}</span>
                            {interimTranscript && (
                                <span className="text-muted-foreground italic">{interimTranscript}</span>
                            )}
                        </>
                    ) : (
                        <span className="text-muted-foreground/60">{placeholder}</span>
                    )}
                </div>
            )}

            {/* Error message */}
            {error && (
                <div
                    role="alert"
                    className="flex items-start gap-2 rounded-lg bg-destructive/10 border border-destructive/20 p-3 text-sm text-destructive"
                >
                    <AlertCircle className="w-4 h-4 flex-shrink-0 mt-0.5" />
                    <span>{error}</span>
                </div>
            )}
        </div>
    );
}

import { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Loader2, ShieldAlert } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { useAnalyzerStore } from '../../stores/useAnalyzerStore';
import { auth } from '../../config/firebase';

const API_BASE = import.meta.env.VITE_API_BASE || '/api';

export default function ChatPanel() {
  const [input, setInput] = useState('');
  const messagesEndRef = useRef(null);
  
  const { 
    messages, 
    addMessage, 
    sessionId, 
    isInterviewMode, 
    isStreaming,
    setIsStreaming,
    setMessages
  } = useAnalyzerStore();

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isStreaming]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim() || !sessionId || isStreaming) return;

    const userMessage = { role: 'user', content: input };
    addMessage(userMessage);
    setInput('');
    setIsStreaming(true);

    addMessage({ role: 'assistant', content: '' });

    try {
      const user = auth.currentUser;
      const token = await user.getIdToken();

      const response = await fetch(`${API_BASE}/analyzer/chat`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          sessionId,
          messages: [...messages, userMessage],
          isInterviewMode
        })
      });

      if (!response.ok) throw new Error('Chat failed');

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let streamContent = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });
        const lines = chunk.split('\n');
        
        for (const line of lines) {
          if (line.startsWith('data: ')) {
            const dataStr = line.slice(6);
            if (dataStr === '[DONE]') continue;
            
            try {
              const data = JSON.parse(dataStr);
              if (data.text) {
                streamContent += data.text;
                setMessages(prev => {
                  const newMsgs = [...prev];
                  newMsgs[newMsgs.length - 1] = { role: 'assistant', content: streamContent };
                  return newMsgs;
                });
              } else if (data.error) {
                console.error('Chat error:', data.error);
              }
            } catch (e) {
              // Ignore incomplete JSON
            }
          }
        }
      }
    } catch (error) {
      console.error('Chat stream error:', error);
      setMessages(prev => {
        const newMsgs = [...prev];
        newMsgs[newMsgs.length - 1] = { role: 'assistant', content: 'Error: Failed to connect to AI engine.' };
        return newMsgs;
      });
    } finally {
      setIsStreaming(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-[#050816] relative">
      {/* Header */}
      <div className="flex items-center justify-between p-4 border-b border-white/10 bg-[#0f172a]">
        <div className="flex items-center gap-2">
          {isInterviewMode ? (
            <ShieldAlert className="w-5 h-5 text-red-500" />
          ) : (
            <Bot className="w-5 h-5 text-blue-500" />
          )}
          <span className="font-semibold text-slate-200">
            {isInterviewMode ? 'Principal Interview Mode' : 'QA Engine Mode'}
          </span>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center text-slate-500 space-y-4">
            <Bot className="w-12 h-12 text-slate-700" />
            <p className="max-w-[250px]">
              {isInterviewMode 
                ? "I am ready to grill you on this architecture. Send a message to begin."
                : "Ask me anything about this repository's structure, patterns, or architecture."}
            </p>
          </div>
        )}
        
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${
              msg.role === 'user' ? 'bg-blue-600' : isInterviewMode ? 'bg-red-900/50 text-red-500' : 'bg-slate-800 text-blue-400'
            }`}>
              {msg.role === 'user' ? <User className="w-4 h-4 text-white" /> : <Bot className="w-4 h-4" />}
            </div>
            
            <div className={`max-w-[85%] rounded-2xl p-4 ${
              msg.role === 'user' 
                ? 'bg-blue-600 text-white rounded-tr-none' 
                : 'bg-slate-800/50 text-slate-200 rounded-tl-none border border-slate-700'
            }`}>
              {msg.role === 'assistant' ? (
                <div className="prose prose-invert prose-sm max-w-none">
                  <ReactMarkdown>{msg.content}</ReactMarkdown>
                </div>
              ) : (
                <div className="whitespace-pre-wrap text-sm">{msg.content}</div>
              )}
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Form */}
      <form onSubmit={handleSubmit} className="p-4 border-t border-white/10 bg-[#0b1120]">
        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={!sessionId || isStreaming}
            placeholder={!sessionId ? "Ingest a repository first..." : "Ask about the codebase..."}
            className="w-full bg-[#1e293b] border border-slate-700 rounded-full py-3 pl-4 pr-12 text-slate-200 placeholder:text-slate-500 focus:outline-none focus:border-blue-500 disabled:opacity-50"
          />
          <button
            type="submit"
            disabled={!input.trim() || !sessionId || isStreaming}
            className="absolute right-2 p-2 rounded-full bg-blue-600 text-white hover:bg-blue-500 disabled:opacity-50 disabled:hover:bg-blue-600 transition-colors"
          >
            {isStreaming ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
          </button>
        </div>
      </form>
    </div>
  );
}

import { useCallback, useEffect } from 'react';
import { ReactFlow, MiniMap, Controls, Background, useNodesState, useEdgesState, addEdge } from '@xyflow/react';
import '@xyflow/react/dist/style.css';
import dagre from 'dagre';
import { useAnalyzerStore } from '../../stores/useAnalyzerStore';
import AnalyzerNode from './AnalyzerNode';
import { analyzerApi } from '../../services/api';
import toast from 'react-hot-toast';

const nodeTypes = {
  analyzerNode: AnalyzerNode,
};

const getLayoutedElements = (nodes, edges, direction = 'TB') => {
  const dagreGraph = new dagre.graphlib.Graph();
  dagreGraph.setDefaultEdgeLabel(() => ({}));

  const nodeWidth = 200;
  const nodeHeight = 80;

  dagreGraph.setGraph({ rankdir: direction });

  nodes.forEach((node) => {
    dagreGraph.setNode(node.id, { width: nodeWidth, height: nodeHeight });
  });

  edges.forEach((edge) => {
    dagreGraph.setEdge(edge.source, edge.target);
  });

  dagre.layout(dagreGraph);

  const newNodes = nodes.map((node) => {
    const nodeWithPosition = dagreGraph.node(node.id);
    return {
      ...node,
      position: {
        x: nodeWithPosition.x - nodeWidth / 2,
        y: nodeWithPosition.y - nodeHeight / 2,
      },
    };
  });

  return { nodes: newNodes, edges };
};

export default function GraphCanvas() {
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  
  const storeNodes = useAnalyzerStore(state => state.nodes);
  const storeEdges = useAnalyzerStore(state => state.edges);
  const sessionId = useAnalyzerStore(state => state.sessionId);
  const setSelectedFile = useAnalyzerStore(state => state.setSelectedFile);
  const setFileContent = useAnalyzerStore(state => state.setFileContent);

  useEffect(() => {
    if (storeNodes.length > 0) {
      const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(
        storeNodes,
        storeEdges
      );
      setNodes(layoutedNodes);
      setEdges(layoutedEdges);
    } else {
      setNodes([]);
      setEdges([]);
    }
  }, [storeNodes, storeEdges, setNodes, setEdges]);

  const onConnect = useCallback(
    (params) => setEdges((eds) => addEdge(params, eds)),
    [setEdges]
  );

  const onNodeClick = async (_, node) => {
    if (!sessionId) return;
    
    setSelectedFile(node.data);
    setFileContent('');
    
    try {
      const content = await analyzerApi.getFileContent(sessionId, node.data.relativePath);
      setFileContent(content);
    } catch (error) {
      toast.error('Failed to load file content');
      setFileContent('// Error loading file content');
    }
  };

  return (
    <div className="absolute inset-0 w-full h-full bg-[#050816]">
      <ReactFlow
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={onConnect}
        onNodeClick={onNodeClick}
        nodeTypes={nodeTypes}
        colorMode="dark"
        fitView
        minZoom={0.1}
        className="[&_.react-flow__pane]:bg-[#050816]"
      >
        <Background color="#1e293b" gap={16} />
        <Controls className="!bg-[#0f172a] !border-slate-700 !fill-slate-300" />
        <MiniMap 
          className="!bg-[#0f172a] !border-slate-700" 
          nodeColor="#3b82f6" 
          maskColor="rgba(5, 8, 22, 0.7)"
        />
      </ReactFlow>
    </div>
  );
}

import { Hash, Lock, Plus, ChevronDown, ChevronRight } from 'lucide-react';
import { useState } from 'react';
import { motion } from 'framer-motion';
import { Skeleton } from '../ui/Skeleton';

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.05,
      delayChildren: 0.05,
    },
  },
};

const itemVariants = {
  hidden: { opacity: 0, x: -6 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { type: 'spring', stiffness: 300, damping: 24 },
  },
};

export default function ChannelList({ 
  channels, 
  activeChannel, 
  onSelectChannel, 
  onCreateChannel,
  loading 
}) {
  const [expandedCategories, setExpandedCategories] = useState({
    general: true,
    'job-hunting': true,
    'interview-prep': true,
    'resume-tips': true,
    networking: true,
    announcements: true,
    other: true
  });

  // Group channels by category
  const groupedChannels = channels.reduce((acc, channel) => {
    const category = channel.category || 'general';
    if (!acc[category]) acc[category] = [];
    acc[category].push(channel);
    return acc;
  }, {});

  const categoryLabels = {
    general: 'General',
    'job-hunting': 'Job Hunting',
    'interview-prep': 'Interview Prep',
    'resume-tips': 'Resume Tips',
    networking: 'Networking',
    announcements: 'Announcements',
    other: 'Other'
  };

  const toggleCategory = (category) => {
    setExpandedCategories(prev => ({
      ...prev,
      [category]: !prev[category]
    }));
  };

  if (loading) {
    return (
      <div className="p-4 space-y-4">
        <div className="space-y-2">
          <Skeleton className="h-4 w-24 mb-4" />
          {[...Array(6)].map((_, i) => (
            <div key={i} className="flex items-center gap-3">
              <Skeleton className="h-8 w-8 rounded-lg" />
              <div className="flex-1 space-y-2">
                <Skeleton className="h-3 w-full" />
                <Skeleton className="h-2 w-2/3" />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="py-2">
      {/* Create Channel Button */}
      <div className="px-3 mb-2">
        <button
          onClick={onCreateChannel}
          className="w-full flex items-center gap-2 px-3 py-2 text-sm text-muted-foreground hover:bg-muted rounded-lg transition-colors"
        >
          <Plus className="w-4 h-4" />
          Create Channel
        </button>
      </div>

      {/* Channel Categories */}
      {Object.entries(groupedChannels).map(([category, categoryChannels]) => (
        <div key={category} className="mb-1">
          {/* Category Header */}
          <button
            onClick={() => toggleCategory(category)}
            className="w-full flex items-center gap-1 px-3 py-1.5 text-xs font-semibold text-muted-foreground uppercase tracking-wider hover:text-foreground"
          >
            {expandedCategories[category] ? (
              <ChevronDown className="w-3 h-3" />
            ) : (
              <ChevronRight className="w-3 h-3" />
            )}
            {categoryLabels[category] || category}
            <span className="ml-auto text-muted-foreground/50 font-normal">
              {categoryChannels.length}
            </span>
          </button>

          {/* Channels in Category */}
          {expandedCategories[category] && (
            <motion.div
              variants={containerVariants}
              initial="hidden"
              animate="visible"
              className="space-y-0.5 px-2"
            >
              {categoryChannels.map(channel => {
                const channelId = channel.id || channel._id;
                const activeId = activeChannel?.id || activeChannel?._id;
                return (
                  <motion.button
                    key={channelId}
                    variants={itemVariants}
                    onClick={() => onSelectChannel(channel)}
                    className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-left transition-colors ${
                      activeId === channelId
                        ? 'bg-primary/20 text-primary'
                        : 'text-foreground hover:bg-muted'
                    }`}
                  >
                    {channel.type === 'private' ? (
                      <Lock className="w-4 h-4 text-muted-foreground shrink-0" />
                    ) : (
                      <Hash className="w-4 h-4 text-muted-foreground shrink-0" />
                    )}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1">
                        <span className="font-medium truncate text-sm">{channel.name}</span>
                      </div>
                      {channel.lastMessage && (
                        <p className="text-xs text-muted-foreground truncate">
                          {channel.lastMessage.senderName}: {channel.lastMessage.content}
                        </p>
                      )}
                    </div>
                    {channel.memberCount > 0 && (
                      <span className="text-xs text-muted-foreground shrink-0">
                        {channel.memberCount}
                      </span>
                    )}
                  </motion.button>
                );
              })}
            </motion.div>
          )}
        </div>
      ))}

      {channels.length === 0 && !loading && (
        <div className="px-4 py-8 text-center text-muted-foreground">
          <p className="text-sm">No channels yet</p>
          <button
            onClick={onCreateChannel}
            className="mt-2 text-primary hover:text-primary/80 text-sm font-medium"
          >
            Create the first channel
          </button>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { formatDistanceToNow } from 'date-fns';
import { communityApi } from '../../services/api';
import { 
  Heart, 
  MessageCircle, 
  Send, 
  MoreHorizontal,
  ChevronDown,
  ChevronUp,
  Loader2
} from 'lucide-react';
import toast from 'react-hot-toast';
import { SkeletonListItems } from '../ui/Skeleton';

function CommentItem({ comment, currentUser, onReply, onLike, depth = 0 }) {
  const [showReplies, setShowReplies] = useState(depth === 0);
  const [isReplying, setIsReplying] = useState(false);
  const [replyContent, setReplyContent] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const isLiked = comment.likes?.some(l => l.uid === currentUser?.uid);
  const isOwn = comment.author?.uid === currentUser?.uid;
  const likeCount = comment.likes?.length || comment.likeCount || 0;

  const getInitials = (name) => {
    return name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '??';
  };

  const handleSubmitReply = async (e) => {
    e.preventDefault();
    if (!replyContent.trim() || isSubmitting) return;

    setIsSubmitting(true);
    try {
      await onReply(comment.id, replyContent.trim());
      setReplyContent('');
      setIsReplying(false);
    } catch (error) {
      toast.error('Failed to post reply');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className={`${depth > 0 ? 'ml-8 border-l-2 border-border pl-4' : ''}`}>
      <div className="flex gap-3 py-3">
        {/* Avatar */}
        <div className="shrink-0">
          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-xs font-medium">
            {comment.author?.avatar ? (
              <img 
                src={comment.author.avatar} 
                alt={comment.author.name}
                className="w-full h-full rounded-full object-cover"
              />
            ) : (
              getInitials(comment.author?.name)
            )}
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="font-medium text-sm text-foreground">
              {comment.author?.name || 'Anonymous'}
            </span>
            {isOwn && (
              <span className="text-xs bg-primary/20 text-primary px-1.5 py-0.5 rounded">
                You
              </span>
            )}
            <span className="text-xs text-muted-foreground">
              {comment.createdAt ? formatDistanceToNow(new Date(comment.createdAt), { addSuffix: true }) : ''}
            </span>
            {comment.isEdited && (
              <span className="text-xs text-muted-foreground">(edited)</span>
            )}
          </div>

          <p className="text-sm text-foreground mt-1 whitespace-pre-wrap">
            {comment.content}
          </p>

          {/* Actions */}
          <div className="flex items-center gap-4 mt-2">
            <button
              onClick={() => onLike(comment.id)}
              className={`flex items-center gap-1 text-xs transition-colors ${
                isLiked ? 'text-destructive' : 'text-muted-foreground hover:text-destructive'
              }`}
            >
              <Heart className={`w-4 h-4 ${isLiked ? 'fill-current' : ''}`} />
              <span>{likeCount > 0 ? likeCount : ''}</span>
            </button>

            {depth === 0 && (
              <button
                onClick={() => setIsReplying(!isReplying)}
                className="flex items-center gap-1 text-xs text-muted-foreground hover:text-primary"
              >
                <MessageCircle className="w-4 h-4" />
                <span>Reply</span>
              </button>
            )}
          </div>

          {/* Reply Input */}
          {isReplying && (
            <form onSubmit={handleSubmitReply} className="mt-3 flex gap-2">
              <input
                type="text"
                value={replyContent}
                onChange={(e) => setReplyContent(e.target.value)}
                placeholder="Write a reply..."
                className="flex-1 px-3 py-2 text-sm bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary"
                autoFocus
              />
              <button
                type="submit"
                disabled={!replyContent.trim() || isSubmitting}
                className="px-3 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isSubmitting ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : (
                   <>
        <Send className="w-4 h-4" />
        <span className="sr-only">Post Reply</span>
    </>
                )}
              </button>
            </form>
          )}
        </div>
      </div>

      {/* Replies */}
      {comment.replies?.length > 0 && (
        <div className="mt-1">
          <button
            onClick={() => setShowReplies(!showReplies)}
            className="flex items-center gap-1 text-xs text-primary hover:text-primary/80 mb-2 ml-11"
          >
            {showReplies ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
            {showReplies ? 'Hide' : 'Show'} {comment.replies.length} {comment.replies.length === 1 ? 'reply' : 'replies'}
          </button>
          
          {showReplies && (
            <div className="space-y-1">
              {comment.replies.map(reply => (
                <CommentItem
                  key={reply.id || reply._id}
                  comment={reply}
                  currentUser={currentUser}
                  onReply={onReply}
                  onLike={onLike}
                  depth={depth + 1}
                />
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default function CommentSection({ postId, currentUser, onCommentAdded }) {
  const [comments, setComments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [newComment, setNewComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(false);
  const [total, setTotal] = useState(0);

  useEffect(() => {
    fetchComments();
  }, [postId]);

  const fetchComments = async (loadMore = false) => {
    try {
      if (!loadMore) setLoading(true);
      
      const pageToFetch = loadMore ? page + 1 : 1;
      const data = await communityApi.getComments(postId, pageToFetch);
      
      if (loadMore) {
        setComments(prev => [...prev, ...data.comments]);
        setPage(pageToFetch);
      } else {
        setComments(data.comments);
        setPage(1);
      }
      
      setTotal(data.pagination.total);
      setHasMore(data.comments.length === 20 && data.pagination.total > pageToFetch * 20);
    } catch (error) {
      toast.error('Failed to load comments', { id: `community-comments-load-error-${postId}` });
    } finally {
      setLoading(false);
    }
  };

  const handleSubmitComment = async (e) => {
    e.preventDefault();
    if (!newComment.trim() || isSubmitting) return;

    setIsSubmitting(true);
    try {
      const data = await communityApi.createComment(postId, { content: newComment.trim() });
      setComments(prev => [data.comment, ...prev]);
      setNewComment('');
      setTotal(prev => prev + 1);
      onCommentAdded?.();
      toast.success('Comment posted!');
    } catch (error) {
      toast.error('Failed to post comment', { id: `community-post-comment-error-${postId}` });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleReply = async (parentCommentId, content) => {
    const data = await communityApi.createComment(postId, { 
      content, 
      parentCommentId 
    });
    
    // Add reply to the parent comment
    setComments(prev => prev.map(comment => {
      if ((comment.id || comment._id) === parentCommentId) {
        return {
          ...comment,
          replies: [...(comment.replies || []), data.comment],
          replyCount: (comment.replyCount || 0) + 1
        };
      }
      return comment;
    }));
    
    onCommentAdded?.();
  };

  const handleLikeComment = async (commentId) => {
    try {
      const data = await communityApi.toggleLikeComment(commentId);
      
      // Update the comment in state
      const updateCommentLike = (comments) => {
        return comments.map(comment => {
          if ((comment.id || comment._id) === commentId) {
            const newLikes = data.liked
              ? [...(comment.likes || []), { uid: currentUser.uid, name: currentUser.displayName }]
              : (comment.likes || []).filter(l => l.uid !== currentUser.uid);
            return { ...comment, likes: newLikes, likeCount: data.likeCount };
          }
          // Check replies
          if (comment.replies) {
            return { ...comment, replies: updateCommentLike(comment.replies) };
          }
          return comment;
        });
      };
      
      setComments(updateCommentLike);
    } catch (error) {
      toast.error('Failed to like comment', { id: `community-like-comment-error-${commentId}` });
    }
  };

  return (
    <div className="border-t border-border bg-card">
      {/* Comment Input */}
      <div className="p-4 border-b border-border bg-muted/50">
        <form onSubmit={handleSubmitComment} className="flex gap-2">
          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-xs font-medium shrink-0">
            {currentUser?.photoURL ? (
              <img 
                src={currentUser.photoURL} 
                alt={currentUser.displayName}
                className="w-full h-full rounded-full object-cover"
              />
            ) : (
              currentUser?.displayName?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '??'
            )}
          </div>
          <input
            type="text"
            value={newComment}
            onChange={(e) => setNewComment(e.target.value)}
            placeholder="Write a comment..."
            className="flex-1 px-4 py-2 bg-muted border border-border rounded-full text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary"
          />
          <button
            type="submit"
            disabled={!newComment.trim() || isSubmitting}
            className="px-4 py-2 bg-primary text-primary-foreground rounded-full hover:bg-primary/90 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
          >
            {isSubmitting ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <>
                <Send className="w-4 h-4" />
                <span className="hidden sm:inline">Post Comment </span>
              </>
            )}
          </button>
        </form>
      </div>

      {/* Comments List */}
      <div className="max-h-96 overflow-y-auto">
        {loading ? (
          <div className="px-4 py-4">
            <SkeletonListItems count={3} />
          </div>
        ) : comments.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            <MessageCircle className="w-12 h-12 mx-auto mb-2 text-muted-foreground/60" />
            <p>No comments yet. Be the first to comment!</p>
          </div>
        ) : (
          <div className="px-4 divide-y divide-border">
            {comments.map(comment => (
              <CommentItem
                key={comment.id || comment._id}
                comment={comment}
                currentUser={currentUser}
                onReply={handleReply}
                onLike={handleLikeComment}
              />
            ))}
          </div>
        )}

        {/* Load More */}
        {hasMore && !loading && (
          <div className="p-4 text-center">
            <button
              onClick={() => fetchComments(true)}
              className="text-sm text-primary hover:text-primary/80 font-medium"
            >
              Load more comments ({total - comments.length} remaining)
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { useSocket } from '../../hooks/useSocket';
import { communityApi } from '../../services/api';
import { formatDistanceToNow } from 'date-fns';
import { Search, Plus, Circle, X } from 'lucide-react';

export default function DirectMessages() {
  const { user } = useAuth();
  const { subscribe, onlineUsers, startConversation } = useSocket();
  
  const [conversations, setConversations] = useState([]);
  const [selectedConversation, setSelectedConversation] = useState(null);
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showNewDM, setShowNewDM] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Fetch conversations on mount
  const fetchConversations = useCallback(async () => {
    try {
      setLoading(true);
      const data = await communityApi.getConversations();
      setConversations(data.conversations);
    } catch (error) {
      console.error('Failed to fetch conversations:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchConversations();
  }, [fetchConversations]);

  // Subscribe to new DMs
  useEffect(() => {
    const unsubNewDM = subscribe('new_direct_message', ({ message, conversation }) => {
      const convId = conversation.id || conversation._id;
      // Update conversations list
      setConversations(prev => {
        const exists = prev.find(c => (c.id || c._id) === convId);
        if (exists) {
          return prev.map(c => (c.id || c._id) === convId ? conversation : c);
        }
        return [conversation, ...prev];
      });

      // Update messages if viewing this conversation
      const selectedId = selectedConversation?.id || selectedConversation?._id;
      if (selectedId === convId) {
        setMessages(prev => [...prev, message]);
      }
    });

    return () => unsubNewDM();
  }, [subscribe, selectedConversation]);

  const fetchMessages = async (conversationId) => {
    try {
      const data = await communityApi.getConversationMessages(conversationId);
      setMessages(data.messages);
    } catch (error) {
      console.error('Failed to fetch messages:', error);
    }
  };

  const handleSelectConversation = (conv) => {
    const convId = conv.id || conv._id;
    setSelectedConversation(conv);
    fetchMessages(convId);
  };

  const handleStartConversation = (targetUser) => {
    startConversation({
      receiverId: targetUser.uid,
      receiverName: targetUser.name,
      receiverEmail: targetUser.email
    });
    setShowNewDM(false);
  };

  const getInitials = (name) => {
    return name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '??';
  };

  // Filter online users for new DM
  const filteredUsers = onlineUsers.filter(u => 
    u.uid !== user?.uid &&
    (searchQuery === '' || (u.name || '').toLowerCase().includes(searchQuery.toLowerCase()))
  );

  return (
    <div className="h-full flex flex-col">
      {/* Header */}
      <div className="p-4 border-b border-border flex items-center justify-between">
        <h3 className="font-semibold text-foreground">Direct Messages</h3>
        <button
          onClick={() => setShowNewDM(true)}
          className="p-1.5 text-primary hover:bg-primary/20 rounded-lg"
        >
          <Plus className="w-5 h-5" />
        </button>
      </div>

      {/* Conversations List */}
      <div className="flex-1 overflow-y-auto">
        {loading ? (
          <div className="p-4 space-y-3">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="animate-pulse flex gap-3">
                <div className="w-10 h-10 bg-muted rounded-full" />
                <div className="flex-1 space-y-2">
                  <div className="w-24 h-4 bg-muted rounded" />
                  <div className="w-32 h-3 bg-muted rounded" />
                </div>
              </div>
            ))}
          </div>
        ) : conversations.length > 0 ? (
          <div className="py-2">
            {conversations.map(conv => {
              const convId = conv.id || conv._id;
              const selectedId = selectedConversation?.id || selectedConversation?._id;
              const otherUser = conv.otherParticipant;
              const isOnline = conv.isOnline;
              const unreadCount = conv.unreadCount || 0;

              return (
                <button
                  key={convId}
                  onClick={() => handleSelectConversation(conv)}
                  className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors ${
                    selectedId === convId ? 'bg-primary/20' : ''
                  }`}
                >
                  {/* Avatar with online status */}
                  <div className="relative">
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-sm font-medium">
                      {otherUser?.avatar ? (
                        <img 
                          src={otherUser.avatar} 
                          alt={otherUser.name}
                          className="w-full h-full rounded-full object-cover"
                        />
                      ) : (
                        getInitials(otherUser?.name)
                      )}
                    </div>
                    <span 
                      className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-background ${
                        isOnline ? 'bg-green-500' : 'bg-muted-foreground/50'
                      }`}
                    />
                  </div>

                  <div className="flex-1 min-w-0 text-left">
                    <div className="flex items-center justify-between">
                      <span className="font-medium text-foreground truncate">
                        {otherUser?.name}
                      </span>
                      {conv.lastMessage?.timestamp && (
                        <span className="text-xs text-muted-foreground">
                          {formatDistanceToNow(new Date(conv.lastMessage.timestamp), { addSuffix: false })}
                        </span>
                      )}
                    </div>
                    <p className="text-sm text-muted-foreground truncate">
                      {conv.lastMessage?.senderId === user?.uid && 'You: '}
                      {conv.lastMessage?.content || 'No messages yet'}
                    </p>
                  </div>

                  {/* Unread badge */}
                  {unreadCount > 0 && (
                    <span className="w-5 h-5 bg-primary text-primary-foreground text-xs rounded-full flex items-center justify-center">
                      {unreadCount > 9 ? '9+' : unreadCount}
                    </span>
                  )}
                </button>
              );
            })}
          </div>
        ) : (
          <div className="p-6 text-center text-muted-foreground">
            <p className="text-sm">No conversations yet</p>
            <button
              onClick={() => setShowNewDM(true)}
              className="mt-2 text-primary hover:text-primary/80 text-sm font-medium"
            >
              Start a conversation
            </button>
          </div>
        )}
      </div>

      {/* New DM Modal */}
      {showNewDM && (
        <div className="fixed inset-0 bg-background/80 flex items-center justify-center z-50 p-4">
          <div className="bg-card border border-border rounded-xl shadow-xl max-w-md w-full">
            <div className="flex items-center justify-between p-4 border-b border-border">
              <h3 className="font-semibold text-foreground">New Message</h3>
              <button
                onClick={() => setShowNewDM(false)}
                className="p-1 text-muted-foreground hover:text-foreground"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="p-4">
              {/* Search */}
              <div className="relative mb-4">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Search users..."
                  className="w-full pl-10 pr-4 py-2 bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary"
                />
              </div>

              {/* Online Users */}
              <div className="max-h-64 overflow-y-auto">
                <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider mb-2">
                  Online Users
                </p>
                {filteredUsers.length > 0 ? (
                  <div className="space-y-1">
                    {filteredUsers.map(u => (
                      <button
                        key={u.uid}
                        onClick={() => handleStartConversation(u)}
                        className="w-full flex items-center gap-3 px-3 py-2 hover:bg-muted rounded-lg"
                      >
                        <div className="relative">
                          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-xs font-medium">
                            {getInitials(u.name)}
                          </div>
                          <Circle className="absolute -bottom-0.5 -right-0.5 w-3 h-3 text-green-500 fill-green-500" />
                        </div>
                        <span className="font-medium text-foreground">{u.name}</span>
                      </button>
                    ))}
                  </div>
                ) : (
                  <p className="text-sm text-muted-foreground text-center py-4">
                    No users found
                  </p>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { Circle, Crown, Shield } from 'lucide-react';
import { motion } from 'framer-motion';

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.06,
      delayChildren: 0.05,
    },
  },
};

const itemVariants = {
  hidden: { opacity: 0, x: -8 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { type: 'spring', stiffness: 300, damping: 24 },
  },
};

export default function MembersList({ channel, onlineUsers }) {
  const safeOnlineUsers = onlineUsers || [];
  // Get channel members with online status
  const membersWithStatus = channel?.members?.map(member => ({
    ...member,
    isOnline: safeOnlineUsers.some(u => u.uid === member.uid)
  })) || [];

  // Sort: online first, then by role
  const sortedMembers = [...membersWithStatus].sort((a, b) => {
    // Online status first
    if (a.isOnline && !b.isOnline) return -1;
    if (!a.isOnline && b.isOnline) return 1;
    
    // Then by role
    const roleOrder = { admin: 0, moderator: 1, member: 2 };
    return (roleOrder[a.role] || 2) - (roleOrder[b.role] || 2);
  });

  const onlineMembers = sortedMembers.filter(m => m.isOnline);
  const offlineMembers = sortedMembers.filter(m => !m.isOnline);

  const getInitials = (name) => {
    return name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '??';
  };

  const getRoleBadge = (role) => {
    if (role === 'admin') {
      return <Crown className="w-3 h-3 text-yellow-500" />;
    }
    if (role === 'moderator') {
      return <Shield className="w-3 h-3 text-primary" />;
    }
    return null;
  };

  const MemberItem = ({ member }) => (
    <motion.div variants={itemVariants} className="flex items-center gap-3 px-3 py-2 hover:bg-muted rounded-lg cursor-pointer">
      <div className="relative">
        <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-xs font-medium">
          {member.avatar ? (
            <img
              src={member.avatar}
              alt={member.name}
              className="w-full h-full rounded-full object-cover"
            />
          ) : (
            getInitials(member.name)
          )}
        </div>
        {/* Online Indicator */}
        <span
          className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-background ${
            member.isOnline ? 'bg-green-500' : 'bg-muted-foreground/50'
          }`}
        />
      </div>

      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-1.5">
          <span className={`text-sm font-medium truncate ${
            member.isOnline ? 'text-foreground' : 'text-muted-foreground'
          }`}>
            {member.name}
          </span>
          {getRoleBadge(member.role)}
        </div>
        {member.email && (
          <p className="text-xs text-muted-foreground truncate">{member.email}</p>
        )}
      </div>
    </motion.div>
  );

  if (!channel) {
    return (
      <div className="p-4 text-center text-muted-foreground text-sm">
        Select a channel to see members
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col">
      {/* Header */}
      <div className="p-4 border-b border-border">
        <h3 className="font-semibold text-foreground">Members</h3>
        <p className="text-xs text-muted-foreground mt-0.5">
          {onlineMembers.length} online · {channel.memberCount || membersWithStatus.length} total
        </p>
      </div>

      {/* Members List */}
      <div className="flex-1 overflow-y-auto py-2">
        {/* Online Members */}
        {onlineMembers.length > 0 && (
          <div className="mb-4">
            <div className="px-4 py-1.5 text-xs font-semibold text-muted-foreground uppercase tracking-wider flex items-center gap-2">
              <Circle className="w-2 h-2 fill-green-500 text-green-500" />
              Online — {onlineMembers.length}
            </div>
            <motion.div
              variants={containerVariants}
              initial="hidden"
              animate="visible"
              className="px-1"
            >
              {onlineMembers.map(member => (
                <MemberItem key={member.uid} member={member} />
              ))}
            </motion.div>
          </div>
        )}

        {/* Offline Members */}
        {offlineMembers.length > 0 && (
          <div>
            <div className="px-4 py-1.5 text-xs font-semibold text-muted-foreground uppercase tracking-wider flex items-center gap-2">
              <Circle className="w-2 h-2 fill-muted-foreground/50 text-muted-foreground/50" />
              Offline — {offlineMembers.length}
            </div>
            <motion.div
              variants={containerVariants}
              initial="hidden"
              animate="visible"
              className="px-1"
            >
              {offlineMembers.map(member => (
                <MemberItem key={member.uid} member={member} />
              ))}
            </motion.div>
          </div>
        )}

        {membersWithStatus.length === 0 && (
          <div className="px-4 py-8 text-center text-muted-foreground text-sm">
            No members in this channel
          </div>
        )}
      </div>

      {/* Global Online Users */}
      {safeOnlineUsers.length > 0 && (
        <div className="border-t border-border p-4">
          <h4 className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-2">
            All Online Users
          </h4>
          <div className="flex flex-wrap gap-1">
            {safeOnlineUsers.slice(0, 10).map(user => (
              <div
                key={user.uid}
                className="w-7 h-7 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-xs font-medium ring-2 ring-background"
                title={user.name}
              >
                {getInitials(user.name)}
              </div>
            ))}
            {safeOnlineUsers.length > 10 && (
              <div className="w-7 h-7 rounded-full bg-muted flex items-center justify-center text-muted-foreground text-xs font-medium ring-2 ring-background">
                +{safeOnlineUsers.length - 10}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { useState } from 'react';
import { useSocket } from '../../hooks/useSocket';
import { useAuth } from '../../hooks/useAuth';
import { 
  MoreHorizontal, 
  Reply, 
  Smile, 
  Edit2, 
  Trash2, 
  Pin,
  Copy,
  Check
} from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';

const QUICK_REACTIONS = ['👍', '❤️', '😂', '🎉', '🔥', '👏'];

export default function MessageBubble({ message, isOwn, showAvatar, channelId, onOptimisticReaction, onOptimisticEdit, onOptimisticDelete }) {
  const { addReaction, removeReaction, editMessage, deleteMessage } = useSocket();
  const { user } = useAuth();
  const [showActions, setShowActions] = useState(false);
  const [showReactions, setShowReactions] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editContent, setEditContent] = useState(message.content);
  const [copied, setCopied] = useState(false);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);

  const handleReaction = (emoji) => {
    const messageId = message.id || message._id;
    const hasReacted = message.reactions?.some(
      r => r.emoji === emoji && r.users.some(u => u.uid === user?.uid)
    );

    if (hasReacted) {
      // Optimistic update - immediately show removal
      onOptimisticReaction?.({ messageId, emoji, action: 'remove' });
      removeReaction(messageId, emoji);
    } else {
      // Optimistic update - immediately show addition
      onOptimisticReaction?.({ messageId, emoji, action: 'add' });
      addReaction(messageId, emoji);
    }
    setShowReactions(false);
  };

  const handleEdit = () => {
    const messageId = message.id || message._id;
    if (editContent.trim() && editContent !== message.content) {
      // Optimistic update - immediately show edited content
      onOptimisticEdit?.({ messageId, content: editContent.trim() });
      editMessage(messageId, editContent.trim());
    }
    setIsEditing(false);
  };

  const confirmDelete = () => {
    const messageId = message.id || message._id;
    // Optimistic update - immediately show as deleted
    onOptimisticDelete?.({ messageId });
    deleteMessage(messageId);
    setShowConfirmDelete(false);
  };

  const handleCopy = async () => {
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(message.content);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      } else {
        // Fallback for older browsers or insecure contexts
        const textarea = document.createElement('textarea');
        textarea.value = message.content;
        textarea.style.position = 'fixed';
        textarea.style.left = '-999999px';
        textarea.setAttribute('readonly', '');
        document.body.appendChild(textarea);
        textarea.select();
        const success = document.execCommand('copy');
        document.body.removeChild(textarea);
        if (success) {
          setCopied(true);
          setTimeout(() => setCopied(false), 2000);
        } else {
          throw new Error('Fallback copy command failed');
        }
      }
    } catch (error) {
      console.error('Failed to copy message:', error);
    }
  };

  const getInitials = (name) => {
    return name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '??';
  };

  const formattedTime = message.createdAt 
    ? formatDistanceToNow(new Date(message.createdAt), { addSuffix: true }) 
    : '';

  if (message.isDeleted) {
    return (
      <div className={`flex gap-3 ${isOwn ? 'flex-row-reverse' : ''}`}>
        <div className="w-8" />
        <div className="bg-muted rounded-lg px-4 py-2 text-muted-foreground italic text-sm">
          This message was deleted
        </div>
      </div>
    );
  }

  return (
    <div 
      className={`group flex gap-3 hover:bg-muted/50 -mx-2 px-2 py-1 rounded-lg ${
        isOwn ? 'flex-row-reverse' : ''
      }`}
      onMouseEnter={() => setShowActions(true)}
      onMouseLeave={() => {
        setShowActions(false);
        setShowReactions(false);
      }}
    >
      {/* Avatar */}
      {showAvatar ? (
        <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-xs font-medium shrink-0">
          {message.sender.avatar ? (
            <img 
              src={message.sender.avatar} 
              alt={message.sender.name}
              className="w-full h-full rounded-full object-cover"
            />
          ) : (
            getInitials(message.sender.name)
          )}
        </div>
      ) : (
        <div className="w-8 shrink-0" />
      )}

      {/* Message Content */}
      <div className={`flex-1 min-w-0 ${isOwn ? 'text-right' : ''}`}>
        {showAvatar && (
          <div className={`flex items-baseline gap-2 mb-0.5 ${isOwn ? 'flex-row-reverse' : ''}`}>
            <span className="font-medium text-sm text-foreground">
              {message.sender.name}
            </span>
            <span className="text-xs text-muted-foreground">{formattedTime}</span>
          </div>
        )}

        {/* Reply Preview */}
        {message.replyToPreview && (
          <div className={`mb-1 ${isOwn ? 'ml-auto' : 'mr-auto'} max-w-sm`}>
            <div className="text-xs text-muted-foreground bg-muted rounded px-2 py-1 border-l-2 border-primary">
              <span className="font-medium">{message.replyToPreview.senderName}</span>
              <p className="truncate">{message.replyToPreview.content}</p>
            </div>
          </div>
        )}

        {/* Message Bubble */}
        <div className={`relative inline-block ${isOwn ? 'text-left' : ''}`}>
          {isEditing ? (
            <div className="flex gap-2">
              <input
                type="text"
                value={editContent}
                onChange={(e) => setEditContent(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleEdit()}
                className="flex-1 px-3 py-1.5 bg-muted border border-border rounded-lg text-sm text-foreground focus:ring-2 focus:ring-primary"
                autoFocus
              />
              <button
                onClick={handleEdit}
                className="px-3 py-1 bg-primary text-primary-foreground rounded-lg text-sm"
              >
                Save
              </button>
              <button
                onClick={() => setIsEditing(false)}
                className="px-3 py-1 bg-muted-foreground/20 text-foreground rounded-lg text-sm"
              >
                Cancel
              </button>
            </div>
          ) : (
            <div
              className={`rounded-2xl px-4 py-2 max-w-lg ${
                isOwn 
                  ? 'bg-primary text-primary-foreground rounded-br-md' 
                  : 'bg-card border border-border text-foreground rounded-bl-md'
              }`}
            >
           <ReactMarkdown
  remarkPlugins={[remarkGfm]}
  disallowedElements={['img']}
  components={{
