                </span>

                {post.isEdited && (
                  <span>• edited</span>
                )}

                <span className="flex items-center gap-1">
                  <Eye className="w-3 h-3" />
                  {post.views || 0}
                </span>
              </div>
            </div>
          </div>
        </div>

        {/* Category */}
        <div className="mt-3 flex items-center gap-2 flex-wrap">
          <span
            className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${getCategoryStyle(
              post.category
            )}`}
          >
            {getCategoryIcon(post.category)}
            {post.category?.replace('-', ' ')}
          </span>

          {post.isPinned && (
            <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-amber-500/20 text-amber-400">
              📌 Pinned
            </span>
          )}

          {post.status === 'scheduled' &&
            post.scheduledAt && (
              <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-sky-500/20 text-sky-400">
                <Clock className="w-3 h-3" />
                Scheduled ·{' '}
                {format(
                  new Date(post.scheduledAt),
                  'MMM d, h:mm a'
                )}
              </span>
            )}

          {post.status === 'draft' && (
            <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-neutral-600/40 text-neutral-400">
              Draft
            </span>
          )}
        </div>

        {/* Scheduled Banner */}
        {post.status === 'scheduled' &&
          post.scheduledAt &&
          isOwn &&
          onCancelSchedule && (
            <div className="mt-2 flex items-center justify-between px-3 py-2 bg-sky-500/10 border border-sky-500/20 rounded-lg">
              <p className="text-xs text-sky-400">
                This post will publish automatically on{' '}
                <span className="font-medium">
                  {format(
                    new Date(post.scheduledAt),
                    "MMM d, yyyy 'at' h:mm a"
                  )}
                </span>
              </p>

              <button
                onClick={() =>
                  onCancelSchedule(
                    post.id || post._id
                  )
                }
                className="flex items-center gap-1 text-xs text-neutral-400 hover:text-red-400 ml-3 flex-shrink-0 transition-colors"
              >
                <X className="w-3.5 h-3.5" />
                Cancel
              </button>
            </div>
          )}
      </div>

      {/* Content */}
      <div className="p-4 py-3">
        <h3 className="text-lg font-semibold text-foreground mb-2 line-clamp-2">
          {post.title}
        </h3>

        <div className="prose prose-sm max-w-none text-muted-foreground dark:prose-invert">
          {shouldTruncate &&
          !showFullContent ? (
            <>
              <ReactMarkdown
                remarkPlugins={[remarkGfm]}
                disallowedElements={['script', 'iframe', 'style']}
                components={{
                  a: ({ node, ...props }) => (
                    <a {...props} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline" />
                  ),
                }}
              >
                {previewText + '...'}
              </ReactMarkdown>

              <button
                onClick={() =>
                  setShowFullContent(true)
                }
                className="text-primary hover:text-primary/80 font-medium text-sm"
              >
                Read more
              </button>
            </>
          ) : (
            <>
              <ReactMarkdown
                remarkPlugins={[remarkGfm]}
                disallowedElements={['script', 'iframe', 'style']}
                components={{
                  a: ({ node, ...props }) => (
                    <a {...props} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline" />
                  ),
                }}
              >
                {post.content}
              </ReactMarkdown>
              {shouldTruncate && (
                <button
                  onClick={() => setShowFullContent(false)}
                  className="text-primary hover:text-primary/80 font-medium text-sm mt-2 block"
                >
                  Show less
                </button>
              )}
            </>
          )}
        </div>
      </div>

      {/* Attachments */}
      {post.attachments?.length > 0 && (
        <div className="px-4 pb-3">
          <div className="flex flex-wrap gap-3">
            {post.attachments.map((att, index) => {
              const ext = att.name
                ?.split('.')
                .pop()
                ?.toLowerCase();

              const icon = {
                pdf: '📄',
                doc: '📝',
                docx: '📝',
                ppt: '📊',
                pptx: '📊',
                txt: '📃',
                png: '🖼️',
                jpg: '🖼️',
                jpeg: '🖼️',
                gif: '🖼️',
                webp: '🖼️'
              }[ext] || '📎';

              // Image preview
              if (
                att.type?.startsWith('image/') &&
                att.url
              ) {
                return (
                  <div
                    key={index}
                    className="flex-shrink-0"
                  >
                    <img
                      src={att.url}
                      alt={att.name}
                      className="max-h-64 rounded-xl border border-border object-cover"
                    />
                  </div>
                );
              }

              // Clickable document card
              if (att.url) {
                return (
                  <a
                    key={index}
                    href={att.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="block"
                  >
                    <div className="flex items-center gap-3 px-4 py-3 bg-muted border border-border rounded-xl text-sm text-foreground hover:border-primary/40 hover:bg-muted/80 transition-colors cursor-pointer">
                      <span className="text-2xl flex-shrink-0">
                        {icon}
                      </span>

                      <div className="min-w-0">
                        <p className="font-medium truncate max-w-[200px]">
                          {att.name}
                        </p>

                        <p className="text-xs text-muted-foreground uppercase">
                          {ext} file
                        </p>
                      </div>
                    </div>
                  </a>
                );
              }

              // Fallback card
              return (
                <div
                  key={index}
                  className="flex items-center gap-3 px-4 py-3 bg-muted border border-border rounded-xl text-sm text-foreground"
                >
                  <span className="text-2xl flex-shrink-0">
                    {icon}
                  </span>

                  <div className="min-w-0">
                    <p className="font-medium truncate max-w-[200px]">
                      {att.name}
                    </p>

                    <p className="text-xs text-muted-foreground uppercase">
                      {ext} file
                    </p>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Actions */}
      <div className="px-4 py-3 border-t border-border flex items-center justify-between">
        <div className="flex items-center gap-4">
          <button
            onClick={() =>
              onLike(post.id || post._id)
            }
            className={`flex items-center gap-1.5 text-sm transition-colors ${
              isLiked
                ? 'text-red-500'
                : 'text-muted-foreground hover:text-red-500'
            }`}
          >
            <Heart
              className={`w-5 h-5 ${
                isLiked ? 'fill-current' : ''
              }`}
            />

            <span>
              {Math.max(
                0,
                post.likes?.length ||
                  post.likeCount ||
                  0
              )}
            </span>
          </button>

          {/* Comments */}
          <button
            onClick={() =>
              setShowComments(!showComments)
            }
            className={`flex items-center gap-1.5 text-sm transition-colors ${
              showComments
                ? 'text-primary'
                : 'text-muted-foreground hover:text-primary'
            }`}
          >
            <MessageCircle
              className={`w-5 h-5 ${
                showComments
                  ? 'fill-primary/20'
                  : ''
              }`}
            />

            <span>{commentCount}</span>

            {showComments ? (
              <ChevronUp className="w-4 h-4" />
            ) : (
              <ChevronDown className="w-4 h-4" />
            )}
          </button>

          {/* Share */}
          <button
            onClick={handleShare}
            className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-primary"
          >
            <Share2 className="w-5 h-5" />
          </button>
        </div>

        <button
          onClick={handleShare}
          className="p-1.5 rounded-lg hover:bg-muted text-muted-foreground hover:text-foreground transition-colors"
          title="Share Post"
        >
          <Share2 className="w-4 h-4" />
        </button>
      </div>

      {/* Comments Section */}
      {showComments && (
        <CommentSection
          postId={post.id || post._id}
          currentUser={currentUser}
          onCommentAdded={
            handleCommentAdded
          }
        />
      )}
    </article>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { motion } from 'framer-motion';
import { useAuth } from '../../hooks/useAuth';
import { useSocket } from '../../hooks/useSocket';
import { communityApi } from '../../services/api';
import PostCard from './PostCard';
import PostEditor from './PostEditor';
import {
  Plus,
  TrendingUp,
  Clock,
  Heart,
  Filter,
  Search,
  X,
  ChevronDown,
  ChevronUp
} from 'lucide-react';
import toast from 'react-hot-toast';

const CATEGORIES = [
  { value: 'all', label: 'All Posts', icon: '📋' },
  { value: 'experience', label: 'Experience', icon: '💼' },
  { value: 'interview', label: 'Interview', icon: '🎤' },
  { value: 'tips', label: 'Tips & Tricks', icon: '💡' },
  { value: 'question', label: 'Questions', icon: '❓' },
  { value: 'success-story', label: 'Success Stories', icon: '🎉' },
  { value: 'resource', label: 'Resources', icon: '📚' },
  { value: 'discussion', label: 'Discussion', icon: '💬' },
];

export default function PostsFeed() {
  const { user } = useAuth();
  const { subscribe, subscribePosts, unsubscribePosts, isConnected } = useSocket();
  
  const [posts, setPosts] = useState([]);
  const [scheduledPosts, setScheduledPosts] = useState([]);
  const [showScheduled, setShowScheduled] = useState(true);
  const [loading, setLoading] = useState(true);
  const [showEditor, setShowEditor] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [sortBy, setSortBy] = useState('latest');
  const [searchQuery, setSearchQuery] = useState('');
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Fetch scheduled posts helper
  const fetchScheduledPosts = useCallback(async () => {
    try {
      const data = await communityApi.getScheduledPosts();
      setScheduledPosts(data.posts || []);
    } catch {
      // Silently ignore — not critical
    }
  }, []);

  // Fetch posts helper
  const fetchPosts = useCallback(async (pageToFetch, isLoadMore) => {
    try {
      if (!isLoadMore) {
        setLoading(true);
      }

      const params = {
        page: pageToFetch,
        limit: 20,
        sortBy,
        ...(selectedCategory !== 'all' && { category: selectedCategory })
      };

      const data = await communityApi.getPosts(params);
      
      if (isLoadMore) {
        setPosts(prev => [...prev, ...data.posts]);
      } else {
        setPosts(data.posts);
      }
      
      setHasMore(data.pagination.hasMore);
    } catch (error) {
      toast.error('Failed to load posts');
    } finally {
      setLoading(false);
    }
  }, [sortBy, selectedCategory]);

  const handleLoadMore = () => {
    const nextPage = page + 1;
    setPage(nextPage);
    fetchPosts(nextPage, true);
  };

  // Fetch posts on mount and when filters change
  useEffect(() => {
    setPage(1);
    fetchPosts(1, false);
  }, [selectedCategory, sortBy, fetchPosts]);

  // Refetch scheduled posts whenever the logged-in user changes
  useEffect(() => {
    if (user) {
      fetchScheduledPosts();
    } else {
      setScheduledPosts([]);
    }
  }, [user, fetchScheduledPosts]);

  // Subscribe to real-time updates
  useEffect(() => {
    subscribePosts();

    const unsubNewPost = subscribe('new_post', ({ post }) => {
      setPosts(prev => {
        const postId = post.id || post._id;
        if (prev.some(p => (p.id || p._id) === postId)) {
          return prev;
        }
        return [post, ...prev];
      });
    });

    const unsubLikeUpdated = subscribe('post_like_updated', ({ postId, likeCount, likes }) => {
      // Only update if it's from another user's action (prevents duplicate updates from our own likes)
      setPosts(prev => prev.map(post => {
        const pId = post.id || post._id;
        if (pId === postId) {
          // Check if the like count is different to avoid unnecessary re-renders
          if (post.likeCount !== likeCount) {
            return { ...post, likeCount, likes };
          }
        }
        return post;
      }));
    });

    const unsubCommentAdded = subscribe('comment_added', ({ postId, commentCount }) => {
      setPosts(prev => prev.map(post => {
        const pId = post.id || post._id;
        return pId === postId ? { ...post, commentCount } : post;
      }));
    });

    return () => {
      unsubscribePosts();
      unsubNewPost();
      unsubLikeUpdated();
      unsubCommentAdded();
    };
  }, [subscribe, subscribePosts, unsubscribePosts]);


const handleCreatePost = async (postData) => {
  if (isSubmitting) return; // Prevent double-click submissions

  setIsSubmitting(true);

  try {
    const data = await communityApi.createPost(postData);

    if (data.post.status === 'scheduled') {
      setScheduledPosts(prev => {
        const postId = data.post.id || data.post._id;

        if (prev.some(p => (p.id || p._id) === postId)) {
          return prev;
        }

        return [data.post, ...prev].sort(
          (a, b) =>
            new Date(a.scheduledAt) -
            new Date(b.scheduledAt)
        );
      });

      setShowEditor(false);

      toast.success('Post scheduled successfully!');
    } else {
      // Insert immediately for responsive UX.
      // Socket listener already has duplicate protection.
      setPosts(prev => {
        const postId =
          data.post.id || data.post._id;

        if (
          prev.some(
            p => (p.id || p._id) === postId
          )
        ) {
          return prev;
        }

        return [data.post, ...prev];
      });

      setShowEditor(false);

      toast.success(
        'Post created successfully!'
      );
    }
  } catch (error) {
    toast.error(error.message);
  } finally {
    setIsSubmitting(false);
  }
};

  const handleCancelScheduled = async (postId) => {
    try {
      await communityApi.cancelScheduledPost(postId);
      setScheduledPosts(prev => prev.filter(p => (p.id || p._id) !== postId));
      toast.success('Scheduled post cancelled');
    } catch (error) {
      toast.error(error.message || 'Failed to cancel scheduled post');
    }
  };

  const handleLikePost = async (postId) => {
    // Optimistic update - immediately show the change
    setPosts(prev => prev.map(post => {
      const pId = post.id || post._id;
      if (pId === postId) {
        const currentLikes = post.likes || [];
        const isCurrentlyLiked = currentLikes.some(l => l.uid === user?.uid);
        
        if (isCurrentlyLiked) {
          // Unlike - remove user from likes
          return {
            ...post,
            likes: currentLikes.filter(l => l.uid !== user?.uid),
            likeCount: Math.max(0, (post.likeCount || currentLikes.length) - 1)
          };
        } else {
          // Like - add user to likes
          return {
            ...post,
            likes: [...currentLikes, { uid: user?.uid, name: user?.displayName || user?.name }],
            likeCount: (post.likeCount || currentLikes.length) + 1
          };
        }
      }
      return post;
    }));

    try {
      // Call API in background - socket will confirm the update
      await communityApi.toggleLikePost(postId);
    } catch (error) {
      // Revert on error - toggle back
      setPosts(prev => prev.map(post => {
        const pId = post.id || post._id;
        if (pId === postId) {
          const currentLikes = post.likes || [];
          const isCurrentlyLiked = currentLikes.some(l => l.uid === user?.uid);
          
          if (isCurrentlyLiked) {
            return {
              ...post,
              likes: currentLikes.filter(l => l.uid !== user?.uid),
              likeCount: Math.max(0, (post.likeCount || currentLikes.length) - 1)
            };
          } else {
            return {
              ...post,
              likes: [...currentLikes, { uid: user?.uid, name: user?.displayName || user?.name }],
              likeCount: (post.likeCount || currentLikes.length) + 1
            };
          }
        }
        return post;
      }));
      toast.error('Failed to like post');
    }
  };

  const handleDeletePost = async (postId) => {
    try {
      await communityApi.deletePost(postId);
      setPosts(prev => prev.filter(post => {
        const pId = post.id || post._id;
        return pId !== postId;
      }));
      toast.success('Post deleted');
    } catch (error) {
      toast.error(error.message);
    }
  };

  // Filter posts by search
  const filteredPosts = searchQuery
    ? posts.filter(post => 
        post.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        post.content.toLowerCase().includes(searchQuery.toLowerCase()) ||
        post.tags?.some(tag => tag.toLowerCase().includes(searchQuery.toLowerCase()))
      )
    : posts;

  return (
    <div className="h-full flex flex-col bg-background">
      {/* Header */}
      <div className="bg-background border-b border-border px-6 py-4">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-bold text-foreground">Community Discussions</h2>
          <button
            onClick={() => setShowEditor(true)}
            className="flex items-center gap-2 px-4 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors"
          >
            <Plus className="w-4 h-4" />
            New Post
          </button>
        </div>

        {/* Filters */}
        <div className="flex flex-wrap gap-3 items-center">
          {/* Sort Options */}
          <div className="flex gap-1 bg-muted p-1 rounded-lg">
            <button
              onClick={() => setSortBy('latest')}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition-colors ${
                sortBy === 'latest' ? 'bg-card shadow-sm text-primary' : 'text-muted-foreground hover:text-foreground'
              }`}
            >
              <Clock className="w-4 h-4" />
              Latest
            </button>
            <button
              onClick={() => setSortBy('popular')}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition-colors ${
                sortBy === 'popular' ? 'bg-card shadow-sm text-primary' : 'text-muted-foreground hover:text-foreground'
              }`}
            >
              <Heart className="w-4 h-4" />
              Popular
            </button>
            <button
              onClick={() => setSortBy('trending')}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition-colors ${
                sortBy === 'trending' ? 'bg-card shadow-sm text-primary' : 'text-muted-foreground hover:text-foreground'
              }`}
            >
              <TrendingUp className="w-4 h-4" />
              Trending
            </button>
          </div>

          {/* Search */}
          <div className="relative flex-1 min-w-[200px] max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search posts..."
              className="w-full pl-10 pr-4 py-2 bg-muted border border-border rounded-lg text-sm text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary focus:border-primary"
            />
            {searchQuery && (
              <button
                onClick={() => setSearchQuery('')}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
              >
                <X className="w-4 h-4" />
              </button>
            )}
          </div>
        </div>

        {/* Category Tabs */}
        <div className="flex gap-2 mt-4 overflow-x-auto pb-2">
          {CATEGORIES.map(cat => (
            <button
              key={cat.value}
              onClick={() => setSelectedCategory(cat.value)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm whitespace-nowrap transition-colors ${
                selectedCategory === cat.value
                  ? 'bg-primary/20 text-primary font-medium'
                  : 'bg-muted text-muted-foreground hover:bg-muted/80'
              }`}
            >
              <span>{cat.icon}</span>
              {cat.label}
            </button>
          ))}
        </div>
      </div>

      {/* Posts List */}
      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-3xl mx-auto space-y-4">
          {/* Scheduled posts section — only shown to the post author */}
          {scheduledPosts.length > 0 && (
            <div className="border border-sky-500/20 rounded-xl overflow-hidden">
              <button
                onClick={() => setShowScheduled(prev => !prev)}
                className="w-full flex items-center justify-between px-4 py-3 bg-sky-500/10 hover:bg-sky-500/15 transition-colors"
              >
                <div className="flex items-center gap-2 text-sky-400 text-sm font-medium">
                  <Clock className="w-4 h-4" />
                  Scheduled Posts ({scheduledPosts.length})
                </div>
                {showScheduled
                  ? <ChevronUp className="w-4 h-4 text-sky-400" />
                  : <ChevronDown className="w-4 h-4 text-sky-400" />
                }
              </button>
              {showScheduled && (
                <div className="divide-y divide-neutral-800/50 bg-neutral-900/50">
                  {scheduledPosts.map(post => {
                    const postId = post.id || post._id;
                    return (
                      <PostCard
                        key={postId}
                        post={post}
                        currentUser={user}
                        onLike={() => {}}
                        onCancelSchedule={handleCancelScheduled}
                      />
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {loading ? (
            [...Array(3)].map((_, i) => (
              <div key={i} className="bg-muted border border-border rounded-xl p-6 animate-pulse">
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-10 h-10 bg-muted-foreground/20 rounded-full" />
                  <div className="space-y-2">
                    <div className="w-32 h-4 bg-muted-foreground/20 rounded" />
                    <div className="w-24 h-3 bg-muted-foreground/20 rounded" />
                  </div>
                </div>
                <div className="space-y-2">
                  <div className="w-3/4 h-5 bg-muted-foreground/20 rounded" />
                  <div className="w-full h-4 bg-muted-foreground/20 rounded" />
                  <div className="w-2/3 h-4 bg-muted-foreground/20 rounded" />
                </div>
              </div>
            ))
          ) : filteredPosts.length > 0 ? (
            <>
              {filteredPosts.map(post => {
                const postId = post.id || post._id;
                return (
                  <PostCard
                    key={postId}
                    post={post}
                    currentUser={user}
                    onLike={handleLikePost}
                    onDelete={handleDeletePost}
                    onCancelSchedule={handleCancelScheduled}
                    onCommentAdded={() => {
                      // Update comment count in local state
                      setPosts(prev => prev.map(p => {
                        const pId = p.id || p._id;
                        return pId === postId 
                          ? { ...p, commentCount: (p.commentCount || 0) + 1 }
                          : p;
                      }));
                    }}
                  />
                );
              })}

              {hasMore && (
                <motion.button
                  onClick={handleLoadMore}
                  className="w-full py-3 text-primary hover:text-primary/80 font-medium cursor-pointer"
                >
                  Load more posts
                </motion.button>
              )}
            </>
          ) : (
            <div className="text-center py-12">
              <p className="text-4xl mb-3">📝</p>
              <h3 className="text-lg font-medium text-foreground">No posts yet</h3>
              <p className="text-muted-foreground mt-1">Be the first to share your thoughts!</p>
              <button
                onClick={() => setShowEditor(true)}
                className="mt-4 px-4 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90"
              >
                Create Post
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Post Editor Modal */}
      {showEditor && (
        <PostEditor
          onClose={() => setShowEditor(false)}
          onSubmit={handleCreatePost}
        />
      )}
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Globe, Copy, Check, ExternalLink, Loader2, Sparkles, AlertCircle, Terminal } from 'lucide-react';
import toast from 'react-hot-toast';
import confetti from 'canvas-confetti';
import { auth } from '../../config/firebase';
import { portfolioApi } from '../../services/api';

// Hey there, code reviewer or fellow builder!
// We defined some custom metadata here for each hosting platform.
// Adding a "tag" adds that handcrafted touch that makes standard cards feel alive.
const PROVIDERS = [
  { id: 'github', name: 'GitHub Pages', desc: 'Deploy to your GitHub account repository free.', icon: '⚡', tag: 'EASY & FREE', needsToken: true },
  { id: 'cloudflare', name: 'Cloudflare Pages', desc: 'Fast, secure hosting with global CDN.', icon: '☁️', tag: 'RECOMMENDED', needsToken: false },
  { id: 'netlify', name: 'Netlify', desc: 'Instant serverless deploys and form handling.', icon: '◈', tag: 'STABLE', needsToken: true },
];

// High fidelity build console log stream.
// Standard boring spinning circles look too AI-generated. A developer terminal
// streaming realistic telemetry lines makes this flow look incredibly bespoke.
const BUILD_LOGS = [
  { text: "⚡ npm run build:portfolio --minify=esbuild", type: "command" },
  { text: "vite v7.3.3 building client environment for production...", type: "info" },
  { text: "(node:8240) [DEP0040] DeprecationWarning: The punycode module is deprecated.", type: "warn" },
  { text: "✓ 284 modules transformed and tree-shaken.", type: "success" },
  { text: "rendering chunks & compiling routes...", type: "info" },
  { text: "dist/index.html                     1.32 kB │ gzip:   0.66 kB", type: "log" },
  { text: "dist/assets/index-CJMNWdNk.css    143.95 kB │ gzip:  19.09 kB", type: "log" },
  { text: "dist/assets/index-B55MMtHS.js   1868.60 kB │ gzip: 571.47 kB", type: "log" },
  { text: "✓ production bundle successfully built in 1.84s", type: "success" },
  { text: "🚀 initializing handshake with deployment edge gateway...", type: "info" },
  { text: "✓ secure token handshake with edge: 100% verified", type: "success" },
  { text: "uploading static assets to globally distributed CDN...", type: "info" },
  { text: "caching files across 280+ POPs worldwide...", type: "info" },
  { text: "configuring DNS subdomains and securing SSL/TLS...", type: "info" },
  { text: "✓ pipeline deployment successfully finalized!", type: "success" }
];

function TokenStatusChip({ status }) {
  if (!status) return null;
  if (status === 'checking') {
    return (
      <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-mono font-bold bg-zinc-800 text-zinc-400">
        <Loader2 className="w-2.5 h-2.5 animate-spin" /> checking…
      </span>
    );
  }
  if (status.valid) {
    return (
      <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-mono font-bold bg-emerald-500/10 text-emerald-400 border border-emerald-500/30">
        ✓ connected
      </span>
    );
  }
  return (
    <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-mono font-bold bg-rose-500/10 text-rose-400 border border-rose-500/30" title={status.reason}>
      <AlertCircle className="w-2.5 h-2.5" /> failed
    </span>
  );
}

export default function DeployModal({ isOpen, onClose, portfolioTitle = "My Portfolio", aiDraft, onDeploySuccess }) {
  // Step workflow: select -> loading -> success -> error
  const [step, setStep] = useState('select');
  const [selectedProvider, setSelectedProvider] = useState('cloudflare'); // default to recommended Cloudflare
  const [visibleLogs, setVisibleLogs] = useState([]);
  const [deployedUrl, setDeployedUrl] = useState('');
  const [copied, setCopied] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');

  // Token validation state — one entry per provider that needs a user-supplied token
  const [tokenInputs, setTokenInputs] = useState({ github: '', netlify: '' });
  const [tokenStatuses, setTokenStatuses] = useState({});

  // Refs for tracking async operations.
  // Crucial UX fix: If a user closes the modal before the deployment simulator finishes,
  // we MUST cancel all timeouts to avoid state updates on unmounted components (memory leaks).
  const logTimerRef = useRef(null);
  const confettiIntervalRef = useRef(null);
  const deployTimeoutRef = useRef(null);
  const terminalEndRef = useRef(null);

  // Clear timers/confetti on unmount to keep everything clean and prevent leakages
  useEffect(() => {
    return () => {
      if (logTimerRef.current) clearTimeout(logTimerRef.current);
      if (confettiIntervalRef.current) clearInterval(confettiIntervalRef.current);
      if (deployTimeoutRef.current) clearTimeout(deployTimeoutRef.current);
      confetti.reset();
    };
  }, []);

  // Handle auto-scrolling to the bottom of our retro build terminal
  useEffect(() => {
    if (terminalEndRef.current) {
      terminalEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [visibleLogs]);

  // Telemetry stream generator for the build terminal
  useEffect(() => {
    if (step === 'loading') {
      setVisibleLogs([]);
      let logIndex = 0;

      const streamLogs = () => {
        if (logIndex < BUILD_LOGS.length) {
          const timestamp = new Date().toTimeString().split(' ')[0];
          const nextLog = {
            ...BUILD_LOGS[logIndex],
            timestamp
          };
          setVisibleLogs(prev => [...prev, nextLog]);
          logIndex++;
          // Stagger each log by roughly 220ms so it completes within the 3.5s simulation window
          logTimerRef.current = setTimeout(streamLogs, 220);
        }
      };

      streamLogs();
    } else {
      if (logTimerRef.current) {
        clearTimeout(logTimerRef.current);
        logTimerRef.current = null;
      }
    }
  }, [step]);

  /**
   * Confetti Burst Celebration!
   * We set the origin coordinate to (0.2, 0.8) so the confetti bursts frame the modal
   * beautifully on the sides, instead of bursting directly over the main actions
   * (which blocks the user's cursor from clicking "View Portfolio"). UX gotcha solved!
   */
  const triggerConfetti = () => {
    const duration = 3000;
    const animationEnd = Date.now() + duration;
    const defaults = { startVelocity: 30, spread: 360, ticks: 60, zIndex: 9999 };

    const randomInRange = (min, max) => Math.random() * (max - min) + min;

    confettiIntervalRef.current = setInterval(() => {
      const timeLeft = animationEnd - Date.now();

      if (timeLeft <= 0) {
        clearInterval(confettiIntervalRef.current);
        confettiIntervalRef.current = null;
        return;
      }

      const particleCount = 50 * (timeLeft / duration);

      confetti({
        ...defaults,
        particleCount,
        origin: { x: randomInRange(0.1, 0.3), y: Math.random() - 0.2 }
      });
      confetti({
        ...defaults,
        particleCount,
        origin: { x: randomInRange(0.7, 0.9), y: Math.random() - 0.2 }
      });
    }, 250);
  };

  /**
   * Validates a provider token against the backend before allowing deployment.
   * Never caches the result — each call makes a fresh API request.
   */
  const handleCheckToken = async (providerId) => {
    setTokenStatuses((prev) => ({ ...prev, [providerId]: 'checking' }));
    try {
      const user = auth.currentUser;
      if (!user) throw new Error('Not authenticated');
      const idToken = await user.getIdToken();

      const provider = PROVIDERS.find((p) => p.id === providerId);
      const res = await fetch('/api/portfolio/validate-token', {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${idToken}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          provider: providerId,
          token: provider?.needsToken ? tokenInputs[providerId] : undefined,
        }),
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Request failed');
      setTokenStatuses((prev) => ({ ...prev, [providerId]: data }));

      if (data.valid) {
        toast.success(`${PROVIDERS.find((p) => p.id === providerId)?.name} token verified!`);
      } else {
        toast.error(data.reason || 'Token is invalid.');
      }
    } catch (err) {
      setTokenStatuses((prev) => ({ ...prev, [providerId]: { valid: false, reason: err.message } }));
      toast.error(err.message || 'Token check failed.');
    }
  };

  /**
   * Simulates the build & publish loop.
   * 3.5 seconds gives the user just enough time to watch the build terminal telemetry.
   * A 92% success rate keeps simulation organic and realistic.
   */
  const handleDeploy = () => {
    setStep('loading');

    // Start the terminal animation, then fire the real deploy in parallel
    const doRealDeploy = async () => {
      const slug = portfolioTitle
        .toLowerCase()
        .replace(/[^a-z0-9]/g, '-')
        .replace(/-+/g, '-')
        .replace(/^-|-$/g, '') || 'portfolio';

      try {
        // Call the real backend deploy endpoint
        const result = await portfolioApi.deploy({
          slug,
          sections: aiDraft || {},
          templateId: 'default',
          title: portfolioTitle,
        });

        // Wait for the terminal animation to finish (at least 3.6s total)
        deployTimeoutRef.current = setTimeout(() => {
          const liveUrl = result.data?.url || `https://cp-${slug}.pages.dev`;
          setDeployedUrl(liveUrl);
          setStep('success');
          triggerConfetti();
          toast.success('Your portfolio is live! 🚀');
          if (onDeploySuccess) onDeploySuccess();
        }, 3600);

      } catch (err) {
        console.error('Deploy error:', err);
        // Wait for animation before showing error
        deployTimeoutRef.current = setTimeout(() => {
          setErrorMessage(err.message || 'Deployment failed. Please try again.');
          setStep('error');
          toast.error('Deployment failed.');
        }, 3600);
      }
    };

    doRealDeploy();
  };

  const handleCopyLink = async () => {
    if (!deployedUrl) return;
    try {
      await navigator.clipboard.writeText(deployedUrl);
      setCopied(true);
      toast.success('Link copied! Go share your craft. 📋');
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy: ', err);
      toast.error('Failed to copy to clipboard.');
    }
  };

  const handleClose = () => {
    setStep('select');
    setDeployedUrl('');
    setErrorMessage('');
    if (confettiIntervalRef.current) {
      clearInterval(confettiIntervalRef.current);
      confettiIntervalRef.current = null;
    }
    if (deployTimeoutRef.current) {
      clearTimeout(deployTimeoutRef.current);
      deployTimeoutRef.current = null;
    }
    confetti.reset();
    onClose();
  };

  // Deploy button is enabled only when the selected provider's token is validated
  const selectedProviderMeta = PROVIDERS.find((p) => p.id === selectedProvider);
  const isTokenValidated = !selectedProviderMeta?.needsToken || tokenStatuses[selectedProvider]?.valid === true;

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 overflow-y-auto">
        {/* Modern Backdrop */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={handleClose}
          className="fixed inset-0 bg-zinc-950/80 backdrop-blur-md"
        />

        {/*
          Modal Window Container
          Added a gorgeous asymmetrical floating developer pipeline badge,
          custom premium box shadow, and sleek dark borders.
        */}
        <motion.div
          initial={{ opacity: 0, scale: 0.96, y: 15 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.96, y: 15 }}
          transition={{ type: "spring", duration: 0.5, bounce: 0.2 }}
          className="relative w-full max-w-md bg-zinc-900 border border-zinc-800 rounded-3xl shadow-2xl overflow-hidden flex flex-col z-10"
        >
          {/* Tilted Asymmetrical Hand-crafted Ribbon Stamp */}
          <div className="absolute -top-1 -right-1 bg-amber-500 text-zinc-950 text-[9px] font-bold font-mono px-3 py-1 rounded-bl-xl shadow-md uppercase tracking-wider select-none rotate-1 border-b border-l border-amber-600">
            Engine v2.1
          </div>

          {/* Header */}
          <div className="p-6 pb-4 border-b border-zinc-800/60 flex items-center justify-between shrink-0">
            <div className="flex items-center gap-3.5">
              <div className="w-10 h-10 bg-primary/10 border border-primary/20 rounded-xl flex items-center justify-center text-primary shadow-inner">
                <Globe className="w-5 h-5 text-indigo-400" />
              </div>
              <div className="text-left">
                <h3 className="font-bold text-lg text-zinc-100 font-sans tracking-tight">Deploy Portfolio</h3>
                <p className="text-xs text-zinc-400 mt-0.5 max-w-[220px] truncate">
                  Configuring: <span className="font-mono text-indigo-400">{portfolioTitle}</span>
                </p>
              </div>
            </div>
            <button
              onClick={handleClose}
              aria-label="Close Deploy Dialog"
              className="p-2 hover:bg-zinc-800/80 rounded-xl transition-colors cursor-pointer text-zinc-400 hover:text-zinc-200"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          {/* Modal Body */}
          <div className="p-6">
            <AnimatePresence mode="wait">
              {/* State 1: Provider Selection */}
              {step === 'select' && (
                <motion.div
                  key="select"
                  initial={{ opacity: 0, y: 5 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -5 }}
                  className="space-y-5"
                >
                  <p className="text-xs text-zinc-400 text-left leading-relaxed">
                    Choose your cloud deployment target. We will compile your clean production assets, bundle stylesheets, and provision a live SSL subdomain.
                  </p>

                  {/* Provider Cards */}
                  <div className="space-y-2.5">
                    {PROVIDERS.map((provider) => {
                      const isSelected = selectedProvider === provider.id;
                      const tokenStatus = tokenStatuses[provider.id];
                      return (
                        <div
                          key={provider.id}
                          className={`group w-full text-left rounded-2xl border transition-all duration-300 select-none ${
                            isSelected
                              ? 'bg-indigo-950/20 border-indigo-500 shadow-lg shadow-indigo-950/20'
                              : 'bg-zinc-900/40 border-zinc-800 hover:border-zinc-700 hover:bg-zinc-800/40'
                          }`}
                        >
                          {/* Clickable header row */}
                          <button
                            type="button"
                            onClick={() => setSelectedProvider(provider.id)}
                            className="w-full flex items-start gap-4 p-4 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500/40 cursor-pointer"
                          >
                            <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xl font-bold shrink-0 transition-transform group-hover:scale-105 ${
                              isSelected ? 'bg-indigo-500/20 text-indigo-400' : 'bg-zinc-800 text-zinc-400'
                            }`}>
                              {provider.icon}
                            </div>

                            <div className="flex-1 min-w-0 text-left">
                              <div className="flex items-center gap-2 flex-wrap">
                                <h4 className="font-semibold text-sm text-zinc-100">{provider.name}</h4>
                                {provider.tag && (
                                  <span className={`text-[8px] font-bold font-mono px-2 py-0.5 rounded-full uppercase tracking-wider ${
                                    isSelected
                                      ? 'bg-indigo-500/20 text-indigo-400 border border-indigo-500/30'
                                      : 'bg-zinc-800 text-zinc-500 group-hover:text-zinc-400'
                                  }`}>
                                    {provider.tag}
                                  </span>
                                )}
                                <TokenStatusChip status={tokenStatus} />
                              </div>
                              <p className="text-xs text-zinc-400 mt-1 leading-normal group-hover:text-zinc-300 transition-colors">{provider.desc}</p>
                            </div>
                          </button>

                          {/* Token input + check button — shown only when this provider is selected and needs a token */}
                          {isSelected && provider.needsToken && (
                            <div className="px-4 pb-4 flex gap-2" onClick={(e) => e.stopPropagation()}>
                              <input
                                type="password"
                                placeholder={`Paste your ${provider.name} token…`}
                                value={tokenInputs[provider.id] ?? ''}
                                onChange={(e) =>
                                  setTokenInputs((prev) => ({ ...prev, [provider.id]: e.target.value }))
                                }
                                className="flex-1 text-xs rounded-xl border border-zinc-700 bg-zinc-800 text-zinc-100 placeholder-zinc-500 px-3 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500/40"
                              />
                              <button
                                type="button"
                                disabled={!tokenInputs[provider.id] || tokenStatus === 'checking'}
                                onClick={() => handleCheckToken(provider.id)}
                                className="text-[10px] font-bold font-mono px-3 py-2 rounded-xl bg-indigo-600/20 border border-indigo-500/30 text-indigo-400 hover:bg-indigo-600/30 disabled:opacity-40 disabled:cursor-not-allowed transition-colors whitespace-nowrap"
                              >
                                Check
                              </button>
                            </div>
                          )}

                          {/* Cloudflare: server-side token — show check button with no input */}
                          {isSelected && !provider.needsToken && (
                            <div className="px-4 pb-4 flex justify-end" onClick={(e) => e.stopPropagation()}>
                              <button
                                type="button"
                                disabled={tokenStatus === 'checking'}
                                onClick={() => handleCheckToken(provider.id)}
                                className="text-[10px] font-bold font-mono px-3 py-2 rounded-xl bg-indigo-600/20 border border-indigo-500/30 text-indigo-400 hover:bg-indigo-600/30 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                              >
                                {tokenStatus === 'checking' ? 'Checking…' : 'Check connection'}
