          </section>

          {/* ================= TESTIMONIALS ================= */}
          <section>
            <h3 className="text-3xl font-bold text-zinc-100 mb-10 text-center">Word on the Street</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {testimonials.map((testimonial, index) => (
                <motion.div 
                  key={index}
                  initial={{ opacity: 0, scale: 0.95 }}
                  whileInView={{ opacity: 1, scale: 1 }}
                  viewport={{ once: true }}
                  className="sketch-box p-8 relative"
                >
                  {/* Huge sketched quote mark */}
                  <div className="text-zinc-500 text-6xl absolute -top-4 -left-2 opacity-50 font-serif">"</div>
                  
                  <p className="text-zinc-300 italic mb-6 relative z-10 leading-relaxed">
                    {testimonial.text}
                  </p>
                  
                  <div className="flex items-center gap-4">
                      <img 
                      src={testimonial.avatar} 
                      alt={testimonial.name} 
                      onError={(e) => { 
                        e.currentTarget.src = `https://ui-avatars.com/api/?name=${encodeURIComponent(testimonial.name)}&background=27272a&color=a1a1aa`; 
                      }}
                      className="w-12 h-12 rounded-full sketch-box grayscale"
                    />
                    <div>
                      <h4 className="font-bold text-zinc-100">{testimonial.name}</h4>
                      <span className="text-sm text-zinc-500">{testimonial.role}</span>
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          </section>

          {/* ================= FOOTER / CONTACT ================= */}
          <footer className="border-t-2 border-zinc-800 border-dashed pt-12 pb-24 text-center">
            <h3 className="text-3xl font-bold text-zinc-100 mb-6">Let's create something.</h3>
            <p className="text-zinc-400 mb-8 max-w-lg mx-auto">
              My inbox is always open. Whether you have a question or just want to say hi, I'll try my best to get back to you!
            </p>
            <a 
              href={`mailto:${socials.email}`} 
              className="inline-block sketch-box px-8 py-4 text-zinc-100 font-bold hover:bg-zinc-800 hover:text-white transition-colors"
            >
              Say Hello
            </a>
          </footer>

        </div>
      </div>
    </div>
  );
}

import React, { useState, useRef, useEffect } from "react";
import data from "../../../../data/dummy_data.json";
import { Send, Sparkles } from "lucide-react";

export default function ChatbotPortfolio() {
  const [messages, setMessages] = useState([
    {
      type: "bot",
      content: {
        type: "intro",
        text: `Hey 👋 I'm the portfolio assistant for ${data.personal.name}. Ask me about About, Skills, Projects, Experience, Testimonials, or Contact.`,
      },
    },
  ]);

  const [input, setInput] = useState("");
  const chatEndRef = useRef(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const pushMessage = (msg) => {
    setMessages((prev) => [...prev, msg]);
  };

  const generateResponse = (text) => {
    const msg = text.toLowerCase();

    // ABOUT
    if (msg.includes("about")) {
      return {
        type: "bot",
        content: {
          type: "about",
          name: data.personal.name,
          title: data.personal.title,
          bio: data.personal.bio,
          location: data.personal.location,
          avatar: data.personal.avatar,
        },
      };
    }

    // SKILLS
    if (msg.includes("skill")) {
      return {
        type: "bot",
        content: {
          type: "skills",
          skills: data.skills,
        },
      };
    }

    // PROJECTS
    if (msg.includes("project")) {
      return {
        type: "bot",
        content: {
          type: "projects",
          projects: data.projects,
        },
      };
    }

    // EXPERIENCE
    if (msg.includes("experience")) {
      return {
        type: "bot",
        content: {
          type: "experience",
          experience: data.experience,
        },
      };
    }

    // TESTIMONIALS
    if (msg.includes("testimonial")) {
      return {
        type: "bot",
        content: {
          type: "testimonials",
          testimonials: data.testimonials,
        },
      };
    }

    // CONTACT
    if (msg.includes("contact")) {
      return {
        type: "bot",
        content: {
          type: "contact",
          socials: data.socials,
        },
      };
    }

    return {
      type: "bot",
      content: {
        type: "help",
        text: "Try asking: about, skills, projects, experience, testimonials, contact 👀",
      },
    };
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMsg = {
      type: "user",
      content: { type: "text", text: input },
    };

    const botMsg = generateResponse(input);

    setMessages((prev) => [...prev, userMsg, botMsg]);
    setInput("");
  };

  // ---------------- UI RENDERERS ----------------

  const renderBotMessage = (content) => {
    switch (content.type) {
      case "about":
        return (
          <div className="space-y-2">
            <p className="font-semibold text-cyan-400">{content.name}</p>
            <p className="text-sm text-gray-300">{content.title}</p>
            <p className="text-gray-400">{content.bio}</p>
            <p className="text-xs text-gray-500">📍 {content.location}</p>
          </div>
        );

      case "skills":
        return (
          <div className="space-y-2">
            <p className="font-semibold text-cyan-400 mb-2">Skills</p>
            {content.skills.map((s, i) => (
              <div key={i}>
                <div className="flex justify-between text-xs text-gray-300">
                  <span>{s.name}</span>
                  <span>{s.level}%</span>
                </div>
                <div className="w-full h-2 bg-gray-800 rounded">
                  <div
                    className="h-2 bg-cyan-500 rounded"
                    style={{ width: `${s.level}%` }}
                  />
                </div>
              </div>
            ))}
          </div>
        );

      case "projects":
        return (
          <div className="space-y-3">
            <p className="font-semibold text-cyan-400">Projects</p>
            {content.projects.map((p, i) => (
              <div key={i} className="p-3 bg-gray-900 rounded-xl border border-gray-800">
                <p className="font-semibold">{p.title}</p>
                <p className="text-xs text-gray-400">{p.description}</p>
                <p className="text-[10px] text-gray-500 mt-1">
                  {p.techStack?.join(", ")}
                </p>
              </div>
            ))}
          </div>
        );

      case "experience":
        return (
          <div className="space-y-3">
            <p className="font-semibold text-cyan-400">Experience</p>
            {content.experience.map((e, i) => (
              <div key={i} className="border-l-2 border-cyan-600 pl-3">
                <p className="font-semibold">{e.role}</p>
                <p className="text-xs text-gray-400">
                  {e.company} • {e.period}
                </p>
                <p className="text-sm text-gray-300">{e.description}</p>
              </div>
            ))}
          </div>
        );

      case "testimonials":
        return (
          <div className="space-y-3">
            <p className="font-semibold text-cyan-400">Testimonials</p>
            {content.testimonials.map((t, i) => (
              <div key={i} className="bg-gray-900 p-3 rounded-xl">
                <p className="text-gray-300 italic">"{t.text}"</p>
                <p className="text-xs text-gray-500 mt-1">
                  — {t.name}, {t.role}
                </p>
              </div>
            ))}
          </div>
        );

      case "contact":
        return (
          <div className="space-y-2">
            <p className="font-semibold text-cyan-400">Contact</p>
            <p className="text-sm text-gray-300">Let’s connect 👇</p>
            <p className="text-xs text-gray-400">Email: {content.socials.email}</p>
            <p className="text-xs text-gray-400">GitHub: {content.socials.github}</p>
            <p className="text-xs text-gray-400">LinkedIn: {content.socials.linkedin}</p>
          </div>
        );

      default:
        return <p className="text-gray-400">{content.text}</p>;
    }
  };

  const suggestions = ["About", "Skills", "Projects", "Experience", "Testimonials", "Contact"];

  return (
    <div className="h-screen flex flex-col bg-gray-950 text-white">
      {/* HEADER */}
      <div className="p-4 border-b border-gray-800 text-center">
        <h1 className="text-xl font-bold text-cyan-400 flex items-center justify-center gap-2">
          <Sparkles size={18} /> {data.personal.name}
        </h1>
        <p className="text-sm text-gray-400">{data.personal.title}</p>
      </div>

      {/* CHAT */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg, i) => (
          <div
            key={i}
            className={`flex ${msg.type === "user" ? "justify-end" : "justify-start"}`}
          >
            <div
              className={`max-w-[80%] p-3 rounded-2xl text-sm whitespace-pre-line ${msg.type === "user"
                  ? "bg-cyan-600"
                  : "bg-gray-800 border border-gray-700"
                }`}
            >
              {msg.type === "user"
                ? msg.content.text
                : renderBotMessage(msg.content)}
            </div>
          </div>
        ))}
        <div ref={chatEndRef} />
      </div>

      {/* FIX: SUGGESTIONS (added spacing + visual separation) */}
      <div className="px-4 py-3 border-t border-gray-800 bg-gray-950/60 backdrop-blur flex flex-wrap gap-2">
        {suggestions.map((s, i) => (
          <button
            key={i}
            onClick={() => setInput(s)}
            className="text-xs px-3 py-1 bg-gray-800 rounded-full hover:bg-gray-700 transition"
          >
            {s}
          </button>
        ))}
      </div>

      {/* INPUT (fixed spacing + better separation) */}
      <div className="p-4 border-t border-gray-800 flex gap-2 bg-gray-950">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && handleSend()}
          placeholder="Ask about me..."
          className="flex-1 px-4 py-2 rounded-xl bg-gray-900 border border-gray-700"
        />
        <button
          onClick={handleSend}
          className="bg-cyan-600 px-4 py-2 rounded-xl hover:bg-cyan-700"
        >
          <Send size={18} />
        </button>
      </div>
    </div>
  );
}

import React from "react";
import { motion } from "framer-motion";

export default function About({ data }) {
  const { personal, stats } = data;
  return (
    <section className="relative z-10 px-6 py-20">
      <div className="max-w-6xl mx-auto text-left">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          viewport={{ once: true }}
          className="bg-white/70 backdrop-blur-lg rounded-3xl shadow-xl p-10"
        >
          <h2 className="text-4xl font-bold text-rose-800 mb-8 text-center">
            About Me
          </h2>

          <div className="grid md:grid-cols-2 gap-10 items-center">
            <div className="flex justify-center">
              <img
                src={personal.avatar}
                alt={personal.name}
                className="w-64 h-64 object-cover rounded-3xl shadow-xl"
              />
            </div>

            <div>
              <p className="text-gray-600 leading-relaxed text-lg">
                {personal.bio}
              </p>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mt-10">
                {Object.entries(stats).map(([key, value]) => (
                  <div
                    key={key}
                    className="bg-pink-50 rounded-2xl p-5 text-center"
                  >
                    <h3 className="text-3xl font-bold text-rose-500">
                      {value}+
                    </h3>

                    <p className="text-sm text-gray-600 mt-2 capitalize">
                      {key.replace(/([A-Z])/g, " $1")}
                    </p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </motion.div>
      </div>
    </section>
  );
