    e.preventDefault();
    if (!emailText.trim()) return;
    if (inquiryTimeoutRef.current) clearTimeout(inquiryTimeoutRef.current);
    setInquirySubmitted(true);
    inquiryTimeoutRef.current = setTimeout(() => {
