                    <polygon points="95,28 50,30 73,50" />
                    <polygon points="95,28 73,50 95,72" />
                    <polygon points="95,72 73,50 50,75" />
                    <polygon points="95,72 50,75 50,98" />
                    <polygon points="50,98 50,75 5,72" />
                    <polygon points="5,72 27,50 50,75" />
