                          />
                          <span className="text-xs font-semibold uppercase tracking-wider text-[#999]">
                            {category}
                          </span>
                        </div>
                        <div className="space-y-3">
                          {skills.map((skill) => (
                            <SkillBar
                              key={skill.name}
