              style={{
                background: "linear-gradient(135deg, rgba(34,211,238,0.18), rgba(52,211,153,0.08))",
                border: "1px solid rgba(34,211,238,0.3)",
                boxShadow: "0 0 14px rgba(34,211,238,0.2)",
              }}
            >
