              />
            );
          })}
        </div>

        {/* Footer */}
        <div style={{ marginTop: '5rem', display: 'flex', alignItems: 'center', gap: '1.5rem' }}>
          <div style={{ flex: 1, height: '1px', background: T.footerRule, opacity: 0.2 }} />
