import React, { useRef } from 'react';
import { motion, useReducedMotion } from 'framer-motion';

/* ─── "placed on table" easing: fast approach, gentle settle ─── */
const TABLE_EASE = [0.16, 1.2, 0.3, 1];

/* vary spring character so nothing feels copy-pasted */
const SPRING_VARIANTS = [
  { duration: 0.55, ease: TABLE_EASE },
  { duration: 0.65, ease: [0.12, 0.9, 0.28, 1.04] },
  { duration: 0.5, ease: [0.22, 1.3, 0.36, 1] },
];

export const ScatterItem = ({ children, delay = 0, className = '' }) => {
  const shouldReduce = useReducedMotion();

  /* stable seed per component instance */
  const seed = useRef({
    x: (Math.random() - 0.5) * 80,
    y: 20 + Math.random() * 60,
    rot: (Math.random() - 0.5) * 8,
    spring: SPRING_VARIANTS[Math.floor(Math.random() * SPRING_VARIANTS.length)],
    intermediateRot: (Math.random() - 0.5) * 3,
  });

  if (shouldReduce) {
    return <div className={className}>{children}</div>;
  }

  return (
    <motion.div
      initial={{ opacity: 0, x: seed.current.x, y: seed.current.y, rotate: seed.current.rot }}
      whileInView={{ opacity: 1, x: 0, y: 0, rotate: 0 }}
      viewport={{ once: true, amount: 0.25 }}
      transition={{ ...seed.current.spring, delay }}
      className={className}
    >
      {children}
    </motion.div>
  );
};

import React, { useEffect, useMemo, useState } from 'react';
import { motion } from 'framer-motion';
import TileSnappingText from './TileSnappingText';

const Skills = ({ skills = [] }) => {
  const [viewportWidth, setViewportWidth] = useState(
    typeof window !== 'undefined' ? window.innerWidth : 1200,
  );

  useEffect(() => {
    const onResize = () => setViewportWidth(window.innerWidth);
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);

  const headingWidth = useMemo(() => {
    const available = Math.max(0, viewportWidth - 48);
    return Math.min(700, available);
  }, [viewportWidth]);

  return (
    <section className="py-32 px-6 max-w-7xl mx-auto relative z-20 border-t border-slate-950">
      <div className="flex flex-col items-center mb-20 text-center">
        <div className="flex items-center gap-3 mb-3">
          <TileSnappingText 
            text="// Core capabilities" 
            className="text-xs font-mono uppercase tracking-[0.5em] text-violet-400"
            baseDelay={0.1}
          />
        </div>
        <h2 className="text-4xl md:text-6xl font-black text-center text-white tracking-tight" style={{ width: `${headingWidth}px` }}>
          <TileSnappingText text="Technical Arsenal" baseDelay={0.2} />
        </h2>
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
        {skills.map((skill, i) => {
          const name = skill?.name || '';
          return (
            <motion.div
              key={`${skill?.id || skill?.name}-${i}`}
              className="relative p-5 bg-[#0b0f19]/40 border border-slate-900 rounded-xl overflow-hidden group backdrop-blur-sm"
              initial={{ opacity: 0, y: 15 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.4, delay: i * 0.03 }}
              whileHover={{ 
                y: -5,
                borderColor: 'rgba(34,211,238,0.3)',
                boxShadow: '0 10px 30px -15px rgba(6,182,212,0.15)'
              }}
            >
              <div className="absolute top-0 left-0 w-full h-[2px] bg-gradient-to-r from-transparent via-cyan-500/50 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
              
              <div className="flex flex-col h-full justify-between gap-4">
                <span className="text-xs font-mono text-slate-600 group-hover:text-cyan-400 transition-colors duration-300">
                  {String(i + 1).padStart(2, '0')}
                </span>
                <span className="text-base font-semibold text-slate-300 group-hover:text-white transition-colors duration-300 tracking-tight">
                  <TileSnappingText text={name} baseDelay={0.1 + (i * 0.02)} trigger={true} />
                </span>
              </div>
            </motion.div>
          );
        })}
      </div>
    </section>
  );
};

export default Skills;

import React, { useEffect, useMemo, useState } from 'react';
import { motion } from 'framer-motion';
import TileSnappingText from './TileSnappingText';

const Testimonials = ({ testimonials = [] }) => {
  const [viewportWidth, setViewportWidth] = useState(typeof window !== 'undefined' ? window.innerWidth : 1200);

  useEffect(() => {
    const onResize = () => setViewportWidth(window.innerWidth);
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);

  const headingWidth = useMemo(() => {
    const available = Math.max(0, viewportWidth - 56);
    return Math.max(Math.min(available, 620), Math.min(300, available));
  }, [viewportWidth]);

  return (
    <section className="py-32 px-6 max-w-7xl mx-auto relative z-20 border-t border-slate-950">
      <div className="mb-20 flex flex-col items-center text-center">
        <TileSnappingText text="// Endorsements" className="text-xs font-mono uppercase tracking-[0.4em] text-violet-400 mb-3" baseDelay={0.1} />
        <h2 className="text-4xl md:text-5xl font-black text-center text-white tracking-tight" style={{ width: `${headingWidth}px` }}>
          <TileSnappingText text="Words from Others" baseDelay={0.2} />
        </h2>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {testimonials.map((t, i) => (
          <motion.div
            key={i}
            initial={{ opacity: 0, y: 25 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, amount: 0.2 }}
            transition={{ duration: 0.5, delay: i * 0.1 }}
            whileHover={{ y: -4, borderColor: 'rgba(255,255,255,0.1)' }}
            className="p-8 bg-gradient-to-br from-[#080c14] to-[#04070d] border border-slate-900 rounded-xl h-full flex flex-col justify-between relative shadow-xl"
          >
            <div className="absolute top-4 right-6 text-5xl font-serif text-slate-800/40 select-none pointer-events-none">”</div>
            
            <div className="text-slate-300 font-normal leading-relaxed text-base mb-8 relative z-10 italic">
              <TileSnappingText text={`"${t.text}"`} variant="subtle" stagger={0.004} baseDelay={0.15} />
            </div>

            <div className="flex items-center gap-4 border-t border-slate-900/60 pt-6">
              {t.avatar ? (
                <img src={t.avatar} alt={t.name} className="w-10 h-10 rounded-full object-cover border border-slate-800" />
              ) : (
                <div className="w-10 h-10 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center text-cyan-400 text-sm font-bold">
                  {t.name?.charAt(0) || '?'}
                </div>
              )}
              <div>
                <p className="text-white font-bold text-sm tracking-tight">
                  <TileSnappingText text={t.name} baseDelay={0.2} />
                </p>
                <p className="text-slate-500 text-xs font-mono">{t.role}</p>
              </div>
            </div>
          </motion.div>
        ))}
      </div>
    </section>
  );
};

export default Testimonials;

import React from 'react';
import { motion } from 'framer-motion';

const getTileScatter = (index, variant = 'default') => {
  const xDrift = ((index * 29) % 40) - 20; // Slightly reduced distance for small containers
  const yDrift = variant === 'subtle' 
    ? -15 - ((index * 19) % 25)
    : -30 - ((index * 31) % 35); 
  const rotateDrift = ((index * 13) % 20) - 10;
  return { xDrift, yDrift, rotateDrift };
};

const TileSnappingText = ({ 
  text = "", 
  className = "", 
  variant = 'default', 
  baseDelay = 0.1, 
  stagger = 0.02,
  trigger = true 
}) => {
  const words = text.split(" ");
  let charCounter = 0;

  if (!trigger) return <span className={className}>{text}</span>;

  return (
    <span className="relative inline-block max-w-full overflow-visible">
      {/* 1. THE ANIMATION LAYER: Letters are explicitly grouped into non-breaking word parents 
           so they never collapse or warp inside tight CSS flex/grid cards.
      */}
      <span className="flex flex-wrap items-center justify-center lg:justify-start gap-x-[0.25em] row-gap-0 select-none overflow-visible">
        {words.map((word, wordIdx) => (
          <span key={`${word}-${wordIdx}`} className="inline-flex whitespace-nowrap overflow-visible">
            {word.split("").map((char) => {
              const currentIdx = charCounter++;
              const { xDrift, yDrift, rotateDrift } = getTileScatter(currentIdx, variant);

              return (
                <motion.span
                  key={`${char}-${currentIdx}`}
                  initial={{ opacity: 0, x: xDrift, y: yDrift, rotate: rotateDrift }}
                  whileInView={{ opacity: 1, x: 0, y: 0, rotate: 0 }}
                  viewport={{ once: true, amount: 0.01 }}
                  transition={{
                    type: 'tween',
                    ease: [0.25, 1.4, 0.5, 1], // Magnetic click snap physics
                    duration: 0.65,
                    delay: baseDelay + currentIdx * stagger,
                  }}
                  className={`inline-block will-change-transform origin-bottom ${className}`}
                >
                  {char}
                </motion.span>
              );
            })}
          </span>
        ))}
      </span>

      {/* 2. THE BOUNDING LAYOUT GHOST: Invisible structural text ensuring the parent chip 
           always calculates perfect bounding dimensions natively from day one.
      */}
      <span className={`absolute inset-0 opacity-0 pointer-events-none select-none invisible whitespace-nowrap ${className}`}>
        {text}
      </span>
    </span>
  );
};

export default TileSnappingText;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import {
  MapPin, Mail, Github, Linkedin, Twitter, ExternalLink,
  Mountain, Wind, Star, ChevronDown, Award, Briefcase, User
} from 'lucide-react';
import data from '../../../../data/dummy_data.json';

const fadeUp = {
  hidden: { opacity: 0, y: 40 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.6 } }
};

const stagger = {
  visible: { transition: { staggerChildren: 0.15 } }
};

// Mountain SVG Divider
const MountainDivider = ({ flip = false }) => (
  <div className={`w-full overflow-hidden leading-none ${flip ? 'rotate-180' : ''}`}>
    <svg viewBox="0 0 1440 80" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="none" className="w-full h-16">
      <path d="M0,80 L0,40 L180,10 L360,50 L540,5 L720,45 L900,8 L1080,48 L1260,12 L1440,40 L1440,80 Z" fill="currentColor" />
    </svg>
  </div>
);

// Elevation Progress Bar
const ElevationBar = ({ progress }) => (
  <div className="fixed top-0 left-0 right-0 z-50 h-1.5 bg-stone-200">
    <motion.div
      className="h-full bg-gradient-to-r from-amber-700 via-amber-500 to-sky-400"
      style={{ width: `${progress}%` }}
      transition={{ duration: 0.1 }}
    />
    <div
      className="absolute top-0 text-lg transition-all duration-100"
      style={{ left: `calc(${progress}% - 10px)` }}
    >⛰️</div>
  </div>
);

// Hero Section
const Hero = ({ data }) => (
  <section id="hero" className="relative min-h-screen flex flex-col items-center justify-center overflow-hidden"
    style={{ background: 'linear-gradient(180deg, #0c1a2e 0%, #1a3a5c 40%, #4a7c59 80%, #6b5a3e 100%)' }}>
    {/* Stars */}
    {[...Array(30)].map((_, i) => (
      <div key={i} className="absolute rounded-full bg-white opacity-70"
        style={{
          width: Math.random() * 3 + 1,
          height: Math.random() * 3 + 1,
          top: `${Math.random() * 50}%`,
          left: `${Math.random() * 100}%`,
          animation: `pulse ${2 + Math.random() * 3}s infinite`
        }} />
    ))}
    {/* Mountain silhouette */}
    <div className="absolute bottom-0 w-full">
      <svg viewBox="0 0 1440 300" xmlns="http://www.w3.org/2000/svg" className="w-full">
        <path d="M0,300 L0,200 L200,80 L400,180 L600,40 L800,160 L1000,60 L1200,170 L1440,90 L1440,300 Z"
          fill="#2d1f0e" opacity="0.9" />
        <path d="M0,300 L0,240 L300,140 L500,220 L700,100 L900,200 L1100,120 L1300,210 L1440,150 L1440,300 Z"
          fill="#1a1208" opacity="0.8" />
        {/* Snow caps */}
        <path d="M600,40 L570,90 L630,90 Z" fill="white" opacity="0.9" />
        <path d="M1000,60 L975,105 L1025,105 Z" fill="white" opacity="0.9" />
        <path d="M200,80 L182,115 L218,115 Z" fill="white" opacity="0.8" />
      </svg>
    </div>

    <motion.div className="relative z-10 text-center px-6" initial="hidden" animate="visible" variants={stagger}>
      <motion.div variants={fadeUp} className="mb-4">
        <span className="inline-flex items-center gap-2 px-4 py-1.5 bg-amber-700/40 border border-amber-500/50 rounded-full text-amber-300 text-sm font-medium">
          <Mountain size={14} /> Summit Seeker
        </span>
      </motion.div>
      <motion.h1 variants={fadeUp} className="text-5xl md:text-7xl font-bold text-white mb-4" style={{ textShadow: '0 2px 20px rgba(0,0,0,0.5)' }}>
        {data.personal.name}
      </motion.h1>
      <motion.p variants={fadeUp} className="text-xl md:text-2xl text-sky-300 mb-3 font-medium">
        {data.personal.title}
      </motion.p>
      <motion.p variants={fadeUp} className="text-stone-300 flex items-center justify-center gap-2 mb-8">
        <MapPin size={16} /> {data.personal.location}
      </motion.p>
      <motion.div variants={fadeUp} className="flex justify-center gap-4 flex-wrap">
        <a href="#about" className="px-6 py-3 bg-amber-700 hover:bg-amber-600 text-white rounded-full font-semibold transition-all shadow-lg hover:shadow-amber-700/30">
          Begin the Ascent
        </a>
        <a href="#contact" className="px-6 py-3 border border-sky-400/60 hover:border-sky-400 text-sky-300 rounded-full font-semibold transition-all">
          Make Contact
        </a>
      </motion.div>
    </motion.div>

    <motion.div className="absolute bottom-8 text-white/60 z-10" animate={{ y: [0, 10, 0] }} transition={{ repeat: Infinity, duration: 2 }}>
      <ChevronDown size={28} />
    </motion.div>
  </section>
);

// About Section
const About = ({ data }) => (
  <section id="about" className="py-24 bg-stone-50">
    <div className="max-w-5xl mx-auto px-6">
      <motion.div initial="hidden" whileInView="visible" viewport={{ once: true }} variants={stagger}
        className="grid md:grid-cols-2 gap-12 items-center">
        <motion.div variants={fadeUp}>
          <img src={data.personal.avatar} alt={data.personal.name}
            className="w-72 h-72 rounded-2xl object-cover mx-auto shadow-2xl border-4 border-amber-700/30" />
        </motion.div>
        <motion.div variants={fadeUp}>
          <span className="text-amber-700 font-semibold text-sm uppercase tracking-widest flex items-center gap-2 mb-3">
            <User size={16} /> Base Camp
          </span>
          <h2 className="text-4xl font-bold text-stone-800 mb-4">About Me</h2>
          <p className="text-stone-600 leading-relaxed mb-6">{data.personal.bio}</p>
          <div className="grid grid-cols-3 gap-4">
            {[
              { label: 'Years Experience', value: data.stats.yearsExperience + '+' },
              { label: 'Projects', value: data.stats.projectsCompleted + '+' },
              { label: 'Happy Clients', value: data.stats.happyClients + '+' }
            ].map((s, i) => (
              <div key={i} className="text-center p-3 bg-white rounded-xl shadow-sm border border-stone-100">
                <div className="text-2xl font-bold text-amber-700">{s.value}</div>
                <div className="text-xs text-stone-500 mt-1">{s.label}</div>
              </div>
            ))}
          </div>
        </motion.div>
      </motion.div>
    </div>
  </section>
);

// Skills Section
const Skills = ({ data }) => {
  const categories = [...new Set(data.skills.map(s => s.category))];
  return (
    <section id="skills" className="py-24 bg-amber-50 text-stone-800 relative">
      <div className="text-amber-100"><MountainDivider flip /></div>
      <div className="max-w-5xl mx-auto px-6">
        <motion.div initial="hidden" whileInView="visible" viewport={{ once: true }} variants={stagger}>
          <motion.div variants={fadeUp} className="text-center mb-12">
            <span className="text-amber-700 font-semibold text-sm uppercase tracking-widest flex items-center justify-center gap-2 mb-3">
              <Wind size={16} /> Elevation Map
            </span>
            <h2 className="text-4xl font-bold text-stone-800">Skills & Expertise</h2>
          </motion.div>
          {categories.map(cat => (
            <motion.div key={cat} variants={fadeUp} className="mb-8">
              <h3 className="text-sm font-bold uppercase tracking-widest text-amber-700 mb-4">{cat}</h3>
              <div className="grid md:grid-cols-2 gap-4">
                {data.skills.filter(s => s.category === cat).map((skill, i) => (
                  <div key={i} className="bg-white rounded-xl p-4 shadow-sm border border-stone-100">
                    <div className="flex justify-between mb-2">
                      <span className="font-semibold text-stone-700">{skill.name}</span>
                      <span className="text-amber-700 font-bold text-sm">{skill.level}%</span>
                    </div>
                    <div className="h-2.5 bg-stone-100 rounded-full overflow-hidden">
                      <motion.div className="h-full rounded-full bg-gradient-to-r from-amber-700 to-sky-500"
                        initial={{ width: 0 }}
                        whileInView={{ width: `${skill.level}%` }}
                        transition={{ duration: 1, delay: i * 0.1 }}
                        viewport={{ once: true }} />
                    </div>
                  </div>
                ))}
              </div>
            </motion.div>
          ))}
        </motion.div>
      </div>
    </section>
  );
};

// Projects Section
const Projects = ({ data }) => (
  <section id="projects" className="py-24 bg-stone-800 text-white relative">
    <div className="text-stone-800"><MountainDivider /></div>
    <div className="max-w-6xl mx-auto px-6">
      <motion.div initial="hidden" whileInView="visible" viewport={{ once: true }} variants={stagger}>
        <motion.div variants={fadeUp} className="text-center mb-12">
          <span className="text-amber-400 font-semibold text-sm uppercase tracking-widest flex items-center justify-center gap-2 mb-3">
            <Mountain size={16} /> Peak Achievements
          </span>
          <h2 className="text-4xl font-bold text-white">Projects</h2>
        </motion.div>
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {data.projects.map((project, i) => (
            <motion.div key={i} variants={fadeUp}
              className="bg-stone-700/60 border border-stone-600/40 rounded-2xl overflow-hidden hover:border-amber-500/50 transition-all group hover:-translate-y-1">
              {project.image && (
                <div className="h-44 overflow-hidden">
                  <img src={project.image} alt={project.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
