                  {category}
                </span>
              </div>

              {/* Skill bars */}
              <div className="space-y-3">
                {items.map((skill, i) => (
                  <motion.div
                    key={skill.name}
                    initial={{ opacity: 0, x: -20 }}
                    whileInView={{ opacity: 1, x: 0 }}
                    transition={{ delay: ci * 0.1 + i * 0.06, duration: 0.4 }}
