        </motion.div>

        <motion.div initial={{ rotateY: 90 }} whileInView={{ rotateY: 0 }} transition={{ delay: 0.2 }} className="bg-white rounded-2xl shadow-2xl p-8">
          <h3 className="text-2xl font-bold text-gray-900 mb-6">Connect With Me</h3>
