import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Github, ExternalLink } from 'lucide-react';

const Projects = ({ data }) => {
  const { projects } = data;
  const [flipped, setFlipped] = useState(null);
  const [shuffling, setShuffling] = useState(false);
  const [shuffledProjects, setShuffledProjects] = useState([...projects]);

  const handleShuffle = () => {
    setShuffling(true);
    setTimeout(() => {
      setShuffledProjects([...projects].sort(() => Math.random() - 0.5));
      setShuffling(false);
    }, 500);
  };

  const suits = ['♠️', '♥️', '♣️', '♦️'];
  const ranks = ['ACE', 'KING', 'QUEEN', 'JACK', '10', '9', '8', '7'];

  return (
    <div className="mb-20">
      <div className="text-center mb-12">
        <div className="inline-block px-6 py-2 bg-purple-500/20 rounded-full mb-4">
          <span className="text-purple-300 font-semibold">🃟 PROJECT DECK 🃟</span>
        </div>
        <h2 className="text-4xl md:text-5xl font-bold text-white mb-4">My Project Cards</h2>
        <button onClick={handleShuffle} disabled={shuffling}
          className="mt-4 px-6 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-500 transition-all">
          {shuffling ? 'Shuffling...' : '🔀 Shuffle Deck'}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {shuffledProjects.map((project, idx) => (
          <motion.div key={idx} layout className="relative h-[400px] perspective-1000 cursor-pointer"
            onClick={() => setFlipped(flipped === idx ? null : idx)}>
            <motion.div className="relative w-full h-full" animate={{ rotateY: flipped === idx ? 180 : 0 }} transition={{ duration: 0.6 }}>
              
              {/* Front */}
              <div className={`absolute w-full h-full backface-hidden ${flipped === idx ? 'invisible' : 'visible'}`}>
                <div className="bg-white rounded-2xl shadow-xl p-6 h-full border-2 border-purple-200">
                  <div className="absolute top-2 left-2 text-4xl opacity-20 text-purple-600">{suits[idx % 4]}</div>
                  <div className="text-2xl font-bold text-purple-700 mb-2">{ranks[idx % ranks.length]} OF {project.techStack?.[0]?.toUpperCase() || 'CODE'}</div>
                  {project.image && <img src={project.image} alt={project.title} className="w-full h-32 object-cover rounded-lg mb-4" />}
                  <h3 className="text-xl font-bold text-gray-900 mb-2">{project.title}</h3>
                  <p className="text-gray-600 text-sm line-clamp-3">{project.description}</p>
                  <div className="flex flex-wrap gap-2 mt-3">
                    {project.techStack?.slice(0, 3).map((tech, i) => <span key={i} className="px-2 py-1 bg-purple-100 text-purple-700 text-xs rounded-full">{tech}</span>)}
                  </div>
                  <div className="text-center text-purple-400 text-sm mt-4">Click to flip 🔄</div>
                </div>
              </div>

              {/* Back */}
              <div className={`absolute w-full h-full backface-hidden rotate-y-180 ${flipped === idx ? 'visible' : 'invisible'}`}>
                <div className="bg-gradient-to-br from-purple-700 to-indigo-800 rounded-2xl shadow-2xl p-6 h-full border-2 border-purple-400 flex flex-col">
                  <h3 className="text-2xl font-bold text-white mb-4">{project.title}</h3>
                  <p className="text-purple-200 mb-6 flex-grow">{project.description}</p>
                  <div className="mb-4"><h4 className="text-purple-300 font-semibold mb-2">Tech Stack:</h4>
                    <div className="flex flex-wrap gap-2">{project.techStack?.map((tech, i) => <span key={i} className="px-2 py-1 bg-purple-600 text-white text-xs rounded-full">{tech}</span>)}</div>
                  </div>
                  <div className="flex gap-4">
                    {project.liveUrl && <a href={project.liveUrl} target="_blank" rel="noopener noreferrer" onClick={(e) => e.stopPropagation()} className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg"><ExternalLink className="w-4 h-4" />Live</a>}
                    {project.githubUrl && <a href={project.githubUrl} target="_blank" rel="noopener noreferrer" onClick={(e) => e.stopPropagation()} className="flex items-center gap-2 px-4 py-2 bg-gray-700 text-white rounded-lg"><Github className="w-4 h-4" />Code</a>}
                  </div>
                  <div className="text-center text-purple-300 text-sm mt-4">Click to flip back 🔄</div>
                </div>
              </div>
            </motion.div>
          </motion.div>
        ))}
      </div>

      <style>{`
        .perspective-1000 { perspective: 1000px; }
        .backface-hidden { backface-visibility: hidden; -webkit-backface-visibility: hidden; }
        .rotate-y-180 { transform: rotateY(180deg); }
      `}</style>
    </div>
  );
};

export default Projects;

import React from 'react';
import { motion } from 'framer-motion';
import { Code, Database, Layout } from 'lucide-react';

const Skills = ({ data }) => {
  const { skills } = data;

  const getIcon = (category) => {
    if (category?.toLowerCase().includes('front')) return <Layout className="w-5 h-5 text-purple-600" />;
    if (category?.toLowerCase().includes('back')) return <Database className="w-5 h-5 text-purple-600" />;
    return <Code className="w-5 h-5 text-purple-600" />;
  };

  return (
    <div className="mb-20">
      <div className="text-center mb-12">
        <div className="inline-block px-6 py-2 bg-purple-500/20 rounded-full mb-4">
          <span className="text-purple-300 font-semibold">♣️ SKILLS DECK ♣️</span>
        </div>
        <h2 className="text-4xl md:text-5xl font-bold text-white mb-4">My Card Suits</h2>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {skills.map((skill, idx) => (
          <motion.div key={idx} initial={{ opacity: 0, x: idx % 2 === 0 ? -50 : 50 }} whileInView={{ opacity: 1, x: 0 }}
            className="bg-white rounded-xl p-6 shadow-lg hover:shadow-xl transition-shadow">
            <div className="flex items-center justify-between mb-3">
              <div className="flex items-center gap-3">{getIcon(skill.category)}<h3 className="text-lg font-semibold text-gray-900">{skill.name}</h3></div>
              <span className="text-sm font-medium text-purple-600">{skill.level}%</span>
            </div>
            <div className="relative h-3 bg-gray-200 rounded-full overflow-hidden">
              <motion.div initial={{ width: 0 }} whileInView={{ width: `${skill.level}%` }} transition={{ duration: 1 }}
                className="absolute h-full bg-gradient-to-r from-purple-600 to-indigo-600 rounded-full" style={{ width: `${skill.level}%` }} />
            </div>
            {skill.category && <div className="mt-2 text-xs text-gray-500">{skill.category}</div>}
          </motion.div>
        ))}
      </div>
    </div>
  );
};

export default Skills;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, ChevronRight, Star, Quote } from 'lucide-react';

const Testimonials = ({ data }) => {
  const { testimonials } = data;
  const [current, setCurrent] = useState(0);

  if (!testimonials?.length) return null;

  return (
    <div className="mb-20">
      <div className="text-center mb-12">
        <div className="inline-block px-6 py-2 bg-purple-500/20 rounded-full mb-4">
          <span className="text-purple-300 font-semibold">🃟 TESTIMONIALS 🃟</span>
        </div>
        <h2 className="text-4xl md:text-5xl font-bold text-white mb-4">What People Say</h2>
      </div>

      <div className="relative max-w-4xl mx-auto">
        <button onClick={() => setCurrent((p) => (p - 1 + testimonials.length) % testimonials.length)}
          className="absolute left-0 top-1/2 -translate-y-1/2 -translate-x-4 md:-translate-x-12 z-20 p-2 bg-purple-600 text-white rounded-full hover:bg-purple-500"><ChevronLeft className="w-6 h-6" /></button>
        <button onClick={() => setCurrent((p) => (p + 1) % testimonials.length)}
          className="absolute right-0 top-1/2 -translate-y-1/2 translate-x-4 md:translate-x-12 z-20 p-2 bg-purple-600 text-white rounded-full hover:bg-purple-500"><ChevronRight className="w-6 h-6" /></button>

        <AnimatePresence mode="wait">
          <motion.div key={current} initial={{ opacity: 0, rotateY: 90 }} animate={{ opacity: 1, rotateY: 0 }} exit={{ opacity: 0, rotateY: -90 }}
            className="bg-white rounded-2xl shadow-2xl p-8 md:p-12 text-center">
            <Quote className="w-12 h-12 text-purple-600 mb-6 mx-auto" />
            <p className="text-xl md:text-2xl text-gray-700 italic mb-8">"{testimonials[current].text}"</p>
            <div className="flex items-center justify-center gap-4">
              {testimonials[current].avatar && <img src={testimonials[current].avatar} className="w-16 h-16 rounded-full border-2 border-purple-600" alt={testimonials[current].name} />}
              <div><h4 className="text-lg font-bold text-gray-900">{testimonials[current].name}</h4><p className="text-purple-600">{testimonials[current].role}</p></div>
            </div>
            <div className="flex justify-center gap-1 mt-6">{[...Array(5)].map((_, i) => <Star key={i} className="w-5 h-5 fill-yellow-500 text-yellow-500" />)}</div>
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  );
};

export default Testimonials;

