const ease = [0.25, 0.1, 0.25, 1];

function getLevelPercent(level) {
  if (typeof level === 'number') {
    return Math.max(0, Math.min(100, level));
  }

  const normalized = String(level || '').toLowerCase();
  const levelMap = {
    expert: 90,
    advanced: 80,
    intermediate: 65,
    beginner: 40,
  };

  return levelMap[normalized] || 60;
}

