import React from 'react';
import { motion } from 'framer-motion';
import { Zap } from 'lucide-react';

const ease = [0.22, 1, 0.36, 1];

function getPercent(level) {
  if (typeof level === 'number') {
    return Math.max(0, Math.min(100, level));
  }

  const normalized = String(level || '').toLowerCase();
  const map = {
    expert: 92,
    advanced: 80,
    intermediate: 65,
    beginner: 40,
  };

  return map[normalized] || 60;
}

function levelDot(level) {
  const percent = getPercent(level);
  if (percent >= 80) {
    return 'bg-[#10B981]';
  }
  if (percent >= 60) {
    return 'bg-[#6366F1]';
  }
  return 'bg-[#4B4870]';
}

export default function Skills({ data }) {
  const groupedSkills = (data.skills || []).reduce((groups, skill) => {
    const category = skill?.category || 'General';
    return {
      ...groups,
      [category]: [...(groups[category] || []), skill],
    };
  }, {});

  const topSkills = [...(data.skills || [])]
    .sort((a, b) => getPercent(b?.level) - getPercent(a?.level))
    .slice(0, 6);

  return (
    <section className="bg-[#0D0D12] px-5 py-24 md:py-32">
      <motion.div
        initial={{ opacity: 0, y: 40 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true, margin: '-80px' }}
        transition={{ duration: 0.65, ease }}
        className="mx-auto max-w-7xl"
      >
        <div className="mb-12">
          <div className="mb-5 inline-flex items-center gap-2 rounded-full border border-[#6366F1]/30 bg-[#6366F1]/10 px-3 py-1.5 text-sm text-indigo-300">
            <Zap size={15} strokeWidth={1.8} />
            Tech Stack
          </div>
          <h2 className="text-3xl font-bold tracking-tight md:text-4xl">Tools & Technologies</h2>
        </div>

        <div className="grid gap-6 lg:grid-cols-[1.05fr_0.95fr]">
          <div className="grid gap-5 md:grid-cols-2">
            {Object.entries(groupedSkills).map(([category, skills]) => (
              <motion.div
                key={category}
                whileHover={{ y: -6, transition: { duration: 0.2 } }}
                className="rounded-2xl border border-white/8 bg-[#13131A] p-6 transition-colors hover:border-[#2E2E42]"
              >
                <p className="mb-4 text-xs uppercase tracking-[0.25em] text-[#4B4870]">{category}</p>
                <div className="flex flex-wrap gap-2">
                  {(skills || []).map((skill) => (
                    <span
                      key={skill?.name}
                      className="inline-flex items-center gap-2 rounded-md border border-white/8 bg-[#0D0D12] px-3 py-1.5 font-mono text-sm text-[#8884A8]"
                      style={{ fontFamily: 'JetBrains Mono, monospace' }}
                    >
                      <span className={`h-2 w-2 rounded-full ${levelDot(skill?.level)}`} />
                      {skill?.name}
                    </span>
                  ))}
                </div>
              </motion.div>
            ))}
          </div>

          <div className="rounded-2xl border border-white/8 bg-[#13131A] p-6">
            <p className="mb-6 text-xs uppercase tracking-[0.25em] text-[#4B4870]">Proficiency</p>
            <div className="space-y-6">
              {topSkills.map((skill) => {
                const percent = getPercent(skill?.level);

                return (
                  <div key={skill?.name}>
                    <div className="mb-2 flex items-center justify-between text-sm">
                      <span className="font-medium text-[#F1F0FF]">{skill?.name}</span>
                      <span className="font-mono text-[#8884A8]" style={{ fontFamily: 'JetBrains Mono, monospace' }}>
                        {percent}%
                      </span>
                    </div>
                    <div className="h-2 overflow-hidden rounded-full bg-[#1A1A24]">
                      <motion.div
                        initial={{ width: 0 }}
                        whileInView={{ width: `${percent}%` }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.9, ease }}
                        className="h-full rounded-full bg-gradient-to-r from-[#6366F1] to-[#8B5CF6]"
                      />
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </motion.div>
    </section>
  );
}

import React, { useEffect, useRef, useState } from 'react';
import { motion } from 'framer-motion';

const ease = [0.22, 1, 0.36, 1];

function CountUp({ value, active }) {
  const [count, setCount] = useState(0);

  useEffect(() => {
    if (!active) {
      return undefined;
    }

    const target = Number(value) || 0;
    const steps = 50;
    const duration = 1500;
    let step = 0;

    const interval = window.setInterval(() => {
      step += 1;
      setCount(Math.min(Math.round((target / steps) * step), target));

      if (step >= steps) {
        window.clearInterval(interval);
      }
    }, duration / steps);

    return () => window.clearInterval(interval);
  }, [active, value]);

  return <>{count}</>;
}

export default function StatsBar({ data }) {
  const sectionRef = useRef(null);
  const [active, setActive] = useState(false);

  useEffect(() => {
    const node = sectionRef.current;
    if (!node) {
      return undefined;
    }

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setActive(true);
          observer.disconnect();
        }
      },
      { threshold: 0.35 },
    );

    observer.observe(node);
    return () => observer.disconnect();
  }, []);

  const stats = [
    { value: data.stats?.yearsExperience, label: 'Years Experience' },
    { value: data.stats?.projectsCompleted, label: 'Projects Shipped' },
    { value: data.stats?.happyClients, label: 'Happy Clients' },
  ];

  return (
    <motion.section
      ref={sectionRef}
      initial={{ opacity: 0, y: 40 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: '-80px' }}
      transition={{ duration: 0.65, ease }}
      className="border-y border-[#222232] bg-[#13131A] px-5 py-10"
    >
      <div className="mx-auto grid max-w-7xl gap-8 divide-y divide-[#222232] md:grid-cols-3 md:divide-x md:divide-y-0">
        {stats.map((stat) => (
          <div key={stat.label} className="pt-8 text-center first:pt-0 md:pt-0">
            <p className="saas-gradient-text text-4xl font-bold md:text-5xl">
              <CountUp value={stat.value} active={active} />+
            </p>
            <p className="mt-3 text-xs uppercase tracking-[0.25em] text-[#4B4870]">{stat.label}</p>
          </div>
        ))}
      </div>
    </motion.section>
  );
}

import React, { useEffect, useState } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { ChevronLeft, ChevronRight, Star } from 'lucide-react';

const ease = [0.22, 1, 0.36, 1];

export default function Testimonials({ data }) {
  const testimonials = data.testimonials || [];
  const [activeIndex, setActiveIndex] = useState(0);
  const [direction, setDirection] = useState(1);

  useEffect(() => {
    if (testimonials.length <= 1) {
      return undefined;
    }

    const timer = window.setInterval(() => {
      setDirection(1);
      setActiveIndex((current) => (current + 1) % testimonials.length);
    }, 4500);

    return () => window.clearInterval(timer);
  }, [testimonials.length]);

  const goTo = (nextDirection) => {
    setDirection(nextDirection);
    setActiveIndex((current) => {
      if (nextDirection > 0) {
        return (current + 1) % testimonials.length;
      }
      return (current - 1 + testimonials.length) % testimonials.length;
    });
  };

  const visibleCards = [0, 1, 2]
    .map((offset) => testimonials[(activeIndex + offset) % testimonials.length])
    .filter(Boolean);

  return (
    <section className="bg-[#0D0D12] px-5 py-24 md:py-32">
      <motion.div
        initial={{ opacity: 0, y: 40 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true, margin: '-80px' }}
        transition={{ duration: 0.65, ease }}
        className="mx-auto max-w-7xl"
      >
        <div className="mb-12 flex flex-col justify-between gap-6 md:flex-row md:items-end">
          <div>
            <div className="mb-5 inline-flex items-center gap-2 rounded-full border border-[#6366F1]/30 bg-[#6366F1]/10 px-3 py-1.5 text-sm text-indigo-300">
              <Star size={15} strokeWidth={1.8} />
              Testimonials
            </div>
            <h2 className="text-3xl font-bold tracking-tight md:text-5xl">What People Say</h2>
          </div>

          <div className="flex gap-3">
            <button
              type="button"
              onClick={() => goTo(-1)}
              className="flex h-11 w-11 items-center justify-center rounded-full border border-white/10 text-[#8884A8] transition hover:border-[#6366F1]/40 hover:bg-[#6366F1]/10 hover:text-white"
              aria-label="Previous testimonial"
            >
              <ChevronLeft size={20} />
            </button>
            <button
              type="button"
              onClick={() => goTo(1)}
              className="flex h-11 w-11 items-center justify-center rounded-full border border-white/10 text-[#8884A8] transition hover:border-[#6366F1]/40 hover:bg-[#6366F1]/10 hover:text-white"
              aria-label="Next testimonial"
            >
              <ChevronRight size={20} />
            </button>
          </div>
        </div>

        <AnimatePresence mode="wait" custom={direction}>
          <motion.div
            key={activeIndex}
            custom={direction}
            initial={{ opacity: 0, x: direction > 0 ? 40 : -40 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: direction > 0 ? -40 : 40 }}
            transition={{ duration: 0.35, ease }}
            className="grid gap-6 md:grid-cols-3"
          >
            {visibleCards.map((testimonial, index) => (
              <article
                key={`${testimonial?.name}-${index}`}
                className={`relative overflow-hidden rounded-2xl border bg-[#13131A] p-8 ${
                  index === 0 ? 'border-[#6366F1]/40 shadow-lg shadow-indigo-500/10' : 'border-white/8'
                }`}
              >
                <span className="absolute right-6 top-3 text-6xl font-bold text-[#6366F1]/20">&quot;</span>
                <div className="mb-6 flex gap-1">
                  {[0, 1, 2, 3, 4].map((star) => (
                    <Star key={star} size={16} className="fill-[#F59E0B] text-[#F59E0B]" />
                  ))}
                </div>
                <p className="relative text-lg italic leading-relaxed text-[#F1F0FF]">{testimonial?.text}</p>
                <div className="mt-8 flex items-center gap-3">
                  {testimonial?.avatar ? (
                    <img
                      src={testimonial.avatar}
                      alt={testimonial?.name || 'Testimonial avatar'}
                      className="h-10 w-10 rounded-full object-cover ring-2 ring-[#6366F1]/30"
                    />
                  ) : null}
                  <div>
                    <p className="text-sm font-semibold text-[#F1F0FF]">{testimonial?.name}</p>
                    <p className="text-xs text-[#8884A8]">{testimonial?.role}</p>
                  </div>
                </div>
              </article>
            ))}
          </motion.div>
        </AnimatePresence>

        <div className="mt-8 flex justify-center gap-2">
          {testimonials.map((testimonial, index) => (
            <button
              key={testimonial?.name}
              type="button"
              onClick={() => {
                setDirection(index > activeIndex ? 1 : -1);
                setActiveIndex(index);
              }}
              className={`h-2 rounded-full transition-all ${
                index === activeIndex ? 'w-8 bg-[#6366F1]' : 'w-2 bg-[#4B4870]'
              }`}
              aria-label={`Go to testimonial ${index + 1}`}
            />
          ))}
        </div>
      </motion.div>
    </section>
  );
}

