              whileTap={{ scale: 0.95 }}
              className="w-11 h-11 rounded-full bg-gray-800 hover:bg-gray-700 border border-gray-700 hover:border-orange-500/40 flex items-center justify-center text-gray-400 hover:text-orange-400 transition-colors"
