              {personal.name?.split(' ')[0] || 'ALEX'}
              <span className={isDark ? 'text-cyan-400 drop-shadow-[0_0_8px_#22d3ee]' : 'text-indigo-600'}>.</span>
            </span>
            <div className="flex items-center gap-3">
              {Object.entries(socials).map(([platform, url]) => {
