                />
              </div>
              <div>
                <h2 className="text-2xl font-black leading-tight" style={{ color: c.text }}>
                  {personal.name}
                </h2>
                <p className="text-sm mt-1 font-semibold tracking-wide" style={{ color: c.muted }}>
                  {personal.title}
