import React, { useMemo } from 'react';
import { motion } from 'framer-motion';

const PARTICLE_BRIGHTNESS = 2.0;
const PARTICLE_SPEED = 1.8;

export default function GlobalBackground() {
  const emberConfigs = useMemo(() => (
    Array.from({ length: 40 }, (_, index) => {
      const size = Math.random() * 4 + 1;
      const duration = (Math.random() * 10 + 10) / Math.max(PARTICLE_SPEED, 0.1);
      const delay = Math.random() * 10;
      const startX = Math.random() * 100;
      const driftX = (Math.random() - 0.5) * 200;
      const opacityPeak = Math.random() * 0.8 + 0.2;
      const blur = Math.min(PARTICLE_BRIGHTNESS, 3);
      const glowSpread = 10 * PARTICLE_BRIGHTNESS;
      const glowBlur = 2 * PARTICLE_BRIGHTNESS;

      return {
        key: `ember-${index}`,
        size,
        duration,
        delay,
        startX,
        driftX,
        opacityPeak,
        blur,
        glowSpread,
        glowBlur,
      };
    })
  ), []);
  
  return (
    <>
      {/* 
        ZIGZAG CRACKED EARTH OVERLAY
        Increased opacity from [0.04] to [0.15] to make the lines brighter 
      */}
      <div
        className="fixed inset-0 pointer-events-none z-0 opacity-[0.11] mix-blend-screen"
        style={{
          backgroundImage: `url("data:image/svg+xml,%3Csvg width='200' height='200' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M20 0 L40 50 L10 80 L60 120 L30 180 M150 0 L130 60 L180 90 L120 150 L160 200 M80 50 L120 80 L90 140' fill='none' stroke='%23f97316' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round' /%3E%3C/svg%3E")`,
          backgroundSize: '300px 300px',
        }}
      />
      
      {/* FLOATING EMBERS */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden z-0">
        {emberConfigs.map((config) => {
          return (
            <motion.div
              key={config.key}
              className="absolute bottom-0 rounded-full bg-orange-500"
              style={{
                width: config.size,
                height: config.size,
                left: `${config.startX}vw`,
                filter: `blur(${config.blur}px) brightness(${PARTICLE_BRIGHTNESS})`,
                boxShadow: `0 0 ${config.glowSpread}px ${config.glowBlur}px rgba(249, 115, 22, ${0.5 * Math.min(PARTICLE_BRIGHTNESS, 2)})`
              }}
              animate={{ y: ['10vh', '-110vh'], x: [0, config.driftX], opacity: [0, config.opacityPeak, 0] }}
              transition={{ duration: config.duration, repeat: Infinity, delay: config.delay, ease: 'linear' }}
            />
          );
        })}
      </div>
    </>
  );
}

"use client";

import React, { useEffect, useMemo, useRef, useState } from "react";
import { motion, AnimatePresence, useInView } from "framer-motion";

function random(min, max) {
  return Math.random() * (max - min) + min;
}

export default function LavaAnimate({
  children,
  duration = 3.5,
  formedDelay = 2800,
  particleCount = 120,
  particleColor = "#ff6a00",
  particleSize = [15, 38],
  sourceX = "50%",
  sourceY = "55%",
  particles = true,
  textMelt = true,
  meltAmount = 10,
  className = "",
}) {
  const [formed, setFormed] = useState(false);
  const rootRef = useRef(null);
  
  const inView = useInView(rootRef, {
    once: true,
    amount: 0.05,
  });

  useEffect(() => {
    if (!inView) return;
    const t = setTimeout(() => setFormed(true), formedDelay);
    return () => clearTimeout(t);
  }, [inView, formedDelay]);

  const droplets = useMemo(() => {
    return Array.from({ length: particleCount }).map((_, i) => ({
      id: i,
      tx: random(-400, 400),
      ty: random(-300, 60),
      delay: i * 0.015,
      duration: random(duration * 0.6, duration),
      size: random(particleSize[0], particleSize[1]),
    }));
  }, [particleCount, duration, particleSize]);

  const isTextElement = React.isValidElement(children) && typeof children.props.children === "string";

  return (
    <div ref={rootRef} className={`relative overflow-visible ${className}`}>
      <AnimatePresence>
        {!formed && inView && particles &&
          droplets.map((drop) => (
            <motion.div
              key={drop.id}
              initial={{ x: 0, y: 0, opacity: 0, scale: 0.2 }}
              animate={{ x: drop.tx, y: drop.ty, opacity: [0, 1, 1, 0], scale: [0.2, 1, 0.3] }}
              exit={{ opacity: 0 }}
              // Smooth bezier curve for droplet flow
              transition={{ duration: drop.duration, delay: drop.delay, ease: [0.16, 1, 0.3, 1] }}
              className="absolute pointer-events-none z-50"
              style={{ left: sourceX, top: sourceY }}
            >
              <div
                className="rounded-full"
                style={{
                  width: drop.size, height: drop.size,
                  background: `radial-gradient(circle, #ffd27a 0%, ${particleColor} 45%, #ff3d00 75%, #551000 100%)`,
                  boxShadow: `0 0 12px ${particleColor}`,
                }}
              />
            </motion.div>
          ))}
      </AnimatePresence>

      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 20, filter: "blur(10px)" }}
        animate={{
          opacity: formed ? 1 : 0,
          scale: formed ? 1 : 0.95,
          y: formed ? 0 : 20,
          filter: formed ? "blur(0px)" : "blur(10px)",
        }}
        // SMOOTH REVEAL: Longer duration with a buttery-soft easing profile
        transition={{ duration: 0.7, ease: [0.16, 1, 0.3, 1] }}
        // CENTERING FIX: w-full and flex justify-center forces child mx-auto to work
        className="relative w-full flex justify-center"
      >
        {isTextElement && formed && textMelt ? (
          <motion.div animate={{ y: [0, meltAmount, 0] }} transition={{ duration: 4.5, repeat: Infinity, ease: "easeInOut" }} className="relative">
            <div className="relative z-10">{children}</div>
            <motion.div
              animate={{ scaleY: [1, 1.08, 1], opacity: [0.18, 0.28, 0.18] }}
              transition={{ duration: 4.5, repeat: Infinity, ease: "easeInOut" }}
              className="absolute inset-0 pointer-events-none blur-[2px]"
              style={{ background: "linear-gradient(180deg, rgba(255,120,0,0.15), rgba(255,40,0,0.25))", WebkitBackgroundClip: "text" }}
            />
          </motion.div>
        ) : (
          children
        )}
      </motion.div>
    </div>
  );
}

import React from 'react';
import { motion } from 'framer-motion';
import { Mail, ChevronRight } from 'lucide-react';
import LavaAnimate from '../LavaAnimate';

export default function Contact({ email, location }) {
  return (
    <section className="py-24 w-full relative z-10 border-t border-stone-800/50 mt-12 flex justify-center">
      <LavaAnimate className="flex! w-full justify-center" particleCount={70} formedDelay={1700} meltAmount={3}>
        <div className="max-w-3xl mx-auto text-center w-full">
          <motion.div initial={{ opacity: 0, y: 20 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true, margin: '0px' }} transition={{ duration: 0.6, delay: 0 }} className="mb-8 inline-block p-4 bg-stone-900/50 rounded-full text-orange-500">
            <Mail size={32} />
          </motion.div>
          <motion.h2 initial={{ opacity: 0, y: 20 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true, margin: '0px' }} transition={{ duration: 0.6, delay: 0.1 }} className="text-4xl md:text-6xl font-black text-white mb-6">
            Ready to <span className="text-transparent bg-clip-text bg-gradient-to-r from-orange-500 to-red-600">Ignite</span> a Project?
          </motion.h2>
          <motion.p initial={{ opacity: 0, y: 20 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true, margin: '0px' }} transition={{ duration: 0.6, delay: 0.2 }} className="text-xl text-stone-400 mb-10">
            Currently based in {location}. Always open to discussing new opportunities, collaborations, or tech architectures.
          </motion.p>
          <motion.a initial={{ opacity: 0, y: 20 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true, margin: '0px' }} transition={{ duration: 0.6, delay: 0.3 }} whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }} href={`mailto:${email}`} className="inline-flex items-center gap-3 px-8 py-4 bg-stone-100 text-stone-950 font-bold rounded-lg uppercase tracking-widest transition-all hover:bg-white">
            Send a Message <ChevronRight size={20} className="text-orange-600" />
          </motion.a>
        </div>
      </LavaAnimate>
    </section>
  );
}

import React from 'react';
import { motion } from 'framer-motion';
import { Briefcase } from 'lucide-react';
import LavaAnimate from '../LavaAnimate';
import SectionHeader from './SectionHeader';

export default function Experience({ experience }) {
  return (
    <section className="py-24 w-full relative z-10">
      <LavaAnimate className="flex! w-full flex-col" particleCount={70} formedDelay={1800} meltAmount={3}>
        <div className="w-full">
          <SectionHeader title="Experience" />
          
          {/* Added mt-12 to pull content down from the header */}
          <div className="relative border-l border-stone-800 ml-4 md:ml-6 space-y-12 w-full mt-12">
