import React, { useEffect, useState } from 'react';
import { X, FileCode, Loader2, Copy, Check } from 'lucide-react';
import { useProjectVisualizerStore } from '../../stores/useProjectVisualizerStore';
import { projectVisualizerApi } from '../../services/api';

const syntaxHighlight = (code) => {
  if (!code) return '';
  
  // Basic Regex highlighters
  let html = code
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
    
  // Keywords (cyan)
  const keywords = /\b(const|let|var|function|class|import|export|return|if|else|for|while|async|await|try|catch|switch|case|default|break|continue|new|this|typeof|instanceof)\b/g;
  html = html.replace(keywords, '<span class="text-cyan-400">$1</span>');
  
  // Strings (green)
  const strings = /(&quot;.*?&quot;|&#39;.*?&#39;|`.*?`)/g;
  html = html.replace(strings, '<span class="text-green-400">$1</span>');
  
  // Numbers (orange)
  const numbers = /\b(\d+)\b/g;
  html = html.replace(numbers, '<span class="text-orange-400">$1</span>');
  
  // Comments (muted)
  const comments = /(\/\/.*|\/\*[\s\S]*?\*\/)/g;
  html = html.replace(comments, '<span class="text-slate-500 italic">$1</span>');
  
  return html;
};

const EnhancedFileViewer = () => {
  const { selectedFile, sessionId, setInspectorOpen, setSelectedFile } = useProjectVisualizerStore();
  const [content, setContent] = useState('');
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!selectedFile || !sessionId) return;
    
    const fetchContent = async () => {
      setLoading(true);
      setError(null);
      try {
        const text = await projectVisualizerApi.getFileContent(sessionId, selectedFile.relativePath);
        setContent(text);
      } catch (err) {
        setError('Failed to load file content.');
        setContent('');
      } finally {
        setLoading(false);
      }
    };
    
    fetchContent();
  }, [selectedFile, sessionId]);

  const handleCopy = () => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleBack = () => {
    setSelectedFile(null); // Goes back to module inspector if module was selected
  };

  if (!selectedFile) return null;

  return (
    <div className="flex flex-col h-full bg-[#0a0f1c]">
      {/* Header */}
      <div className="flex items-center justify-between p-4 border-b border-white/10 bg-[#0f172a]">
        <div className="flex items-center gap-3 overflow-hidden">
          <button 
            onClick={handleBack}
            className="p-1 hover:bg-white/10 rounded mr-1 text-slate-400 hover:text-white"
            title="Back to Module"
          >
            <X className="w-5 h-5" />
          </button>
          <FileCode className="w-5 h-5 text-violet-400 shrink-0" />
          <div className="flex flex-col min-w-0">
            <h3 className="font-mono text-sm text-white truncate" title={selectedFile.fileName}>
              {selectedFile.fileName}
            </h3>
            <span className="text-xs text-slate-500 truncate" title={selectedFile.relativePath}>
              {selectedFile.relativePath}
            </span>
          </div>
        </div>
        
        <div className="flex items-center gap-2 shrink-0 ml-4">
          <button
            onClick={handleCopy}
            disabled={loading || !content}
            className="p-2 rounded hover:bg-white/10 text-slate-400 hover:text-white transition-colors"
          >
            {copied ? <Check className="w-4 h-4 text-green-400" /> : <Copy className="w-4 h-4" />}
          </button>
          <button
            onClick={() => setInspectorOpen(false)}
            className="p-2 rounded hover:bg-white/10 text-slate-400 hover:text-white transition-colors"
          >
            <X className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-auto bg-[#050810] relative custom-scrollbar">
        {loading ? (
          <div className="absolute inset-0 flex items-center justify-center">
            <Loader2 className="w-8 h-8 animate-spin text-cyan-500" />
          </div>
        ) : error ? (
          <div className="p-6 text-red-400 font-medium text-sm flex items-center gap-2">
            <X className="w-4 h-4" /> {error}
          </div>
        ) : (
          <div className="flex text-sm font-mono leading-relaxed min-w-max">
            {/* Line Numbers */}
            <div className="flex flex-col items-end px-4 py-4 select-none border-r border-white/5 bg-[#0a0f1c] text-slate-600">
              {content.split('\n').map((_, i) => (
                <span key={i} className="px-1">{i + 1}</span>
              ))}
            </div>
            {/* Code */}
            <div className="px-4 py-4 text-slate-300">
              <pre dangerouslySetInnerHTML={{ __html: syntaxHighlight(content) }} />
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default EnhancedFileViewer;

import React, { useMemo } from 'react';
import { motion } from 'framer-motion';

const getLangColor = (lang) => {
  const map = {
    'JavaScript': '#f1e05a', 'JavaScript React': '#f1e05a',
    'TypeScript': '#3178c6', 'TypeScript React': '#3178c6',
    'Python': '#3572A5', 'Go': '#00ADD8', 'Rust': '#dea584',
    'Java': '#b07219', 'Ruby': '#701516', 'CSS': '#563d7c',
    'HTML': '#e34c26', 'PHP': '#4F5D95', 'C': '#555555',
    'C++': '#f34b7d', 'Swift': '#F05138', 'JSON': '#292929',
    'Markdown': '#083fa1', 'Shell': '#89e051'
  };
  return map[lang] || '#8b5cf6'; // fallback to violet
};

const LanguageBar = ({ languages }) => {
  const languageData = useMemo(() => {
    if (!languages) return [];
    
    // languages might be a Map or a plain object depending on how it serializes
    let entries = [];
    if (languages instanceof Map) {
      entries = Array.from(languages.entries());
    } else if (typeof languages === 'object') {
      entries = Object.entries(languages);
    }
    
    const total = entries.reduce((sum, [_, loc]) => sum + loc, 0);
    
    if (total === 0) return [];
    
    return entries
      .map(([lang, loc]) => ({
        lang,
        loc,
        pct: (loc / total) * 100,
        color: getLangColor(lang)
      }))
      .sort((a, b) => b.loc - a.loc); // sort largest first
  }, [languages]);

  if (languageData.length === 0) return null;

  return (
    <div className="w-full">
      {/* The Bar */}
      <div className="h-3 w-full rounded-full overflow-hidden flex bg-slate-800 border border-slate-700/50 shadow-inner">
        {languageData.map((data, i) => (
          <motion.div
            key={data.lang}
            initial={{ width: 0 }}
            animate={{ width: `${Math.max(data.pct, 0.5)}%` }} // Ensure visible even if small
            transition={{ duration: 1, delay: 0.5 + (i * 0.1) }}
            className="h-full relative group cursor-pointer"
            style={{ backgroundColor: data.color }}
          >
            {/* Tooltip */}
            <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-black text-white text-xs py-1 px-2 rounded opacity-0 group-hover:opacity-100 pointer-events-none whitespace-nowrap z-50 transition-opacity">
              {data.lang} • {data.pct.toFixed(1)}% ({data.loc.toLocaleString()} LOC)
            </div>
          </motion.div>
        ))}
      </div>

      {/* Legend */}
      <div className="flex flex-wrap gap-4 mt-3">
        {languageData.filter(d => d.pct >= 1).map((data) => (
          <div key={data.lang} className="flex items-center gap-1.5 text-xs text-slate-300">
            <span 
              className="w-2.5 h-2.5 rounded-full shadow-sm"
              style={{ backgroundColor: data.color }}
            />
            <span className="font-medium">{data.lang}</span>
            <span className="text-slate-500">{data.pct.toFixed(1)}%</span>
          </div>
        ))}
        {languageData.some(d => d.pct < 1) && (
          <div className="text-xs text-slate-500 flex items-center">
            + others
          </div>
        )}
      </div>
    </div>
  );
};

