import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../hooks/useAuth';
import { initializeSocket, disconnectSocket, getSocket, socketEvents } from '../services/socket';
import { SocketContext } from './SocketContext';

/**
 * Provider component that handles real-time web socket connections,
 * status updates of online users, and push notifications.
 *
 * @param {object} props - The component props.
 * @param {React.ReactNode} props.children - The children elements.
 * @returns {React.JSX.Element} The rendered Provider component.
 */
export function SocketProvider({ children }) {
  const { user } = useAuth();
  const [socket, setSocket] = useState(null);
  const [isConnected, setIsConnected] = useState(false);
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const unreadCount = notifications.filter((n) => !n.read).length;


  /**
   * Pushes a new notification to the state stack.
   *
   * @param {string} type - The notification type.
   * @param {object} data - Metadata payload of the notification.
   */
  const pushNotification = useCallback((type, data) => {
    setNotifications((prev) =>
      [
        {
          id: `${type}-${Date.now()}-${Math.random()}`,
          type,
          data,
          read: false,
          timestamp: new Date(),
        },
        ...prev,
      ].slice(0, 50)
    );
  }, []);

  /**
   * Marks a specific notification as read.
   *
   * @param {string} id - The notification ID.
   */
  const markRead = useCallback((id) => {
    setNotifications((prev) =>
      prev.map((n) => (n.id === id ? { ...n, read: true } : n))
    );
  }, []);

  /**
   * Marks all notifications as read.
   */
  const markAllRead = useCallback(() => {
    setNotifications((prev) =>
     prev.map((n) => ({ ...n, read: true }))
    );
  }, []);

  /**
   * Dismisses a specific notification.
   *
   * @param {string} id - The notification ID.
   */
  const dismissNotification = useCallback((id) => {
    setNotifications((prev) =>
      prev.filter((n) => n.id !== id)
    );
  }, []);

  /**
   * Clears all notifications.
   */
  const clearNotifications = useCallback(() => {
    setNotifications([]);
  }, []);

  // Initialize socket when user logs in
  useEffect(() => {
    let mounted = true;
    let cleanupHandlers = () => {};

    const setupSocket = async () => {
      if (user) {
        const socketInstance = await initializeSocket();
        if (mounted && socketInstance) {
          setSocket(socketInstance);

          const handleConnect = () => setIsConnected(true);
          const handleDisconnect = () => setIsConnected(false);
          const handleOnlineUsers = ({ users }) => setOnlineUsers(users);
          const handleUserOnline = ({ uid, name }) => {
            setOnlineUsers(prev => {
              if (!prev.some(u => u.uid === uid)) {
                return [...prev, { uid, name, status: 'online' }];
              }
              return prev;
            });
          };
          const handleUserOffline = ({ uid }) => {
            setOnlineUsers(prev => prev.filter(u => u.uid !== uid));
          };
          const handleStatusChanged = ({ uid, status }) => {
            setOnlineUsers(prev =>
              prev.map(u => u.uid === uid ? { ...u, status } : u)
            );
          };


          const handleNotification = (data) =>
            pushNotification('notification', data);

          const handleJobAlertNewJobs = (data) =>
             pushNotification('job_alert_new_jobs', data);

          const handleJobAlertEmailSent = (data) =>
            pushNotification('job_alert_email_sent', data);

          const handleJobAlertEmailFailed = (data) =>
            pushNotification('job_alert_email_failed', data);

          socketInstance.on('connect', handleConnect);
          socketInstance.on('disconnect', handleDisconnect);
          socketInstance.on('online_users', handleOnlineUsers);
          socketInstance.on('user_online', handleUserOnline);
          socketInstance.on('user_offline', handleUserOffline);
          socketInstance.on('user_status_changed', handleStatusChanged);
          socketInstance.on('notification', handleNotification);
          socketInstance.on('job_alert_new_jobs', handleJobAlertNewJobs);
          socketInstance.on('job_alert_email_sent', handleJobAlertEmailSent);
          socketInstance.on('job_alert_email_failed', handleJobAlertEmailFailed);

          if (socketInstance.connected) handleConnect();

          cleanupHandlers = () => {
            socketInstance.off('connect', handleConnect);
            socketInstance.off('disconnect', handleDisconnect);
            socketInstance.off('online_users', handleOnlineUsers);
            socketInstance.off('user_online', handleUserOnline);
            socketInstance.off('user_offline', handleUserOffline);
            socketInstance.off('user_status_changed', handleStatusChanged);
            socketInstance.off('notification', handleNotification);
            socketInstance.off('job_alert_new_jobs', handleJobAlertNewJobs);
            socketInstance.off('job_alert_email_sent', handleJobAlertEmailSent);
            socketInstance.off('job_alert_email_failed', handleJobAlertEmailFailed);
          };

          // Get initial online users
          socketEvents.getOnlineUsers();
        }
      } else {
        disconnectSocket();
        setSocket(null);
        setIsConnected(false);
        setOnlineUsers([]);
        setNotifications([]);
      }
    };

    setupSocket();

    return () => {
      mounted = false;
      cleanupHandlers();
      if (!user) {
        disconnectSocket();
      }
    };
  }, [user]);

  /**
   * Subscribes to a socket event with a callback, returning an unsubscribe cleanup function.
   *
   * @param {string} event - The socket event name.
   * @param {Function} callback - The event handler callback function.
   * @returns {Function} An unsubscribe function to remove the listener.
   */
  const subscribe = useCallback((event, callback) => {
    const currentSocket = getSocket();
    if (currentSocket) {
      currentSocket.on(event, callback);
      return () => currentSocket.off(event, callback);
    }
    return () => {};
  }, [socket]);

  /**
   * Emits a socket event with data to the server.
   *
   * @param {string} event - The socket event name.
   * @param {object} data - The message payload to emit.
   */
  const emit = useCallback((event, data) => {
    const currentSocket = getSocket();
    if (currentSocket?.connected) {
      currentSocket.emit(event, data);
    }
  }, [socket]);

  const value = {
    socket,
    isConnected,
    onlineUsers,
    notifications,
    unreadCount,
    markRead,
    markAllRead,
    dismissNotification,
    clearNotifications,
    subscribe,
    emit,
    ...socketEvents
  };

  return (
    <SocketContext.Provider value={value}>
      {children}
    </SocketContext.Provider>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';

let faceLandmarksDetectionPromise = null;

const loadTensorFlow = async () => {
    if (!faceLandmarksDetectionPromise) {
        faceLandmarksDetectionPromise = (async () => {
            const tf = await import('@tensorflow/tfjs');
            const fld = await import('@tensorflow-models/face-landmarks-detection');
            await tf.ready();
            return fld;
        })();
    }
    return faceLandmarksDetectionPromise;
};

const calculateConfidenceMetrics = (predictions, frameWidth = 640, frameHeight = 480) => {
    if (!predictions || predictions.length === 0) {
        return {
            faceDetected: false,
            confidence: 0,
            eyeContact: 0,
            headStability: 0,
            overallScore: 0
        };
    }

    const face = predictions[0];
    const keypoints = face.keypoints;

    const leftEye = keypoints.filter(k => k.name?.includes('leftEye'));
    const rightEye = keypoints.filter(k => k.name?.includes('rightEye'));
    const nose = keypoints.find(k => k.name === 'noseTip');

    let eyeContact = 70;
    if (leftEye.length > 0 && rightEye.length > 0) {
        const leftCenter = leftEye.reduce((acc, p) => ({ x: acc.x + p.x, y: acc.y + p.y }), { x: 0, y: 0 });
        const rightCenter = rightEye.reduce((acc, p) => ({ x: acc.x + p.x, y: acc.y + p.y }), { x: 0, y: 0 });
        leftCenter.x /= leftEye.length;
        leftCenter.y /= leftEye.length;
        rightCenter.x /= rightEye.length;
        rightCenter.y /= rightEye.length;

        const eyeDistance = Math.abs(rightCenter.x - leftCenter.x);
        const eyeSymmetry = Math.abs(leftCenter.y - rightCenter.y);
        eyeContact = Math.min(100, Math.max(0, 100 - eyeSymmetry * 2));
    }

    let headStability = 80;
    if (nose) {
        const centerX = frameWidth / 2;
        const centerY = frameHeight / 2;
        const deviation = Math.sqrt(Math.pow(nose.x - centerX, 2) + Math.pow(nose.y - centerY, 2));
        headStability = Math.max(0, 100 - deviation * 0.3);
    }

    const confidence = face.box ? Math.min(100, (face.box.width * face.box.height) / 500) : 70;

    const overallScore = Math.round((eyeContact * 0.3) + (headStability * 0.3) + (confidence * 0.4));

    return {
        faceDetected: true,
        confidence: Math.round(confidence),
        eyeContact: Math.round(eyeContact),
        headStability: Math.round(headStability),
        overallScore
    };
};

export const useFaceDetection = (videoRef, isActive = false) => {
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState(null);
    const [metrics, setMetrics] = useState({
        faceDetected: false,
        confidence: 0,
        eyeContact: 0,
        headStability: 0,
        overallScore: 0
    });
    const [modelReady, setModelReady] = useState(false);

    const detectorRef = useRef(null);
    const animationFrameRef = useRef(null);
    const metricsHistoryRef = useRef([]);

    const initializeDetector = useCallback(async () => {
        try {
            setIsLoading(true);
            setError(null);

            const fld = await loadTensorFlow();
            const model = fld.SupportedModels.MediaPipeFaceMesh;
            const detectorConfig = {
                runtime: 'tfjs',
                refineLandmarks: true,
                maxFaces: 1
            };

            detectorRef.current = await fld.createDetector(model, detectorConfig);
            setModelReady(true);
            setIsLoading(false);
        } catch (err) {
            console.error('Failed to initialize face detector:', err);
            setError('Failed to load face detection model');
            setIsLoading(false);
        }
    }, []);

    const detectFace = useCallback(async () => {
        if (!detectorRef.current || !videoRef.current || !isActive) return;

        const video = videoRef.current;
        if (video.readyState < 2) {
            animationFrameRef.current = requestAnimationFrame(detectFace);
            return;
        }

        try {
            const predictions = await detectorRef.current.estimateFaces(video, { flipHorizontal: true });
            const frameWidth = video.videoWidth || video.clientWidth || 640;
            const frameHeight = video.videoHeight || video.clientHeight || 480;
            const newMetrics = calculateConfidenceMetrics(predictions, frameWidth, frameHeight);

            metricsHistoryRef.current.push(newMetrics);
            if (metricsHistoryRef.current.length > 30) {
                metricsHistoryRef.current.shift();
            }

            setMetrics(newMetrics);
        } catch (err) {
            console.error('Face detection error:', err);
        }

        animationFrameRef.current = requestAnimationFrame(detectFace);
    }, [videoRef, isActive]);

    const getAverageMetrics = useCallback(() => {
        const history = metricsHistoryRef.current;
        if (history.length === 0) {
            return { averageConfidence: 0, eyeContactPercentage: 0, headMovementStability: 0, overallExpressionScore: 0 };
        }

        const validHistory = history.filter(m => m.faceDetected);
        if (validHistory.length === 0) {
            return { averageConfidence: 0, eyeContactPercentage: 0, headMovementStability: 0, overallExpressionScore: 0 };
        }

        return {
            averageConfidence: Math.round(validHistory.reduce((sum, m) => sum + m.confidence, 0) / validHistory.length),
            eyeContactPercentage: Math.round(validHistory.reduce((sum, m) => sum + m.eyeContact, 0) / validHistory.length),
            headMovementStability: Math.round(validHistory.reduce((sum, m) => sum + m.headStability, 0) / validHistory.length),
            overallExpressionScore: Math.round(validHistory.reduce((sum, m) => sum + m.overallScore, 0) / validHistory.length)
        };
    }, []);

    const resetMetrics = useCallback(() => {
        metricsHistoryRef.current = [];
        setMetrics({ faceDetected: false, confidence: 0, eyeContact: 0, headStability: 0, overallScore: 0 });
    }, []);

    useEffect(() => {
        initializeDetector();

        return () => {
            if (animationFrameRef.current) {
                cancelAnimationFrame(animationFrameRef.current);
            }
            if (detectorRef.current) {
                detectorRef.current.dispose?.();
            }
        };
    }, [initializeDetector]);

    useEffect(() => {
        if (isActive && modelReady) {
            detectFace();
        } else if (animationFrameRef.current) {
            cancelAnimationFrame(animationFrameRef.current);
        }

        return () => {
            if (animationFrameRef.current) {
                cancelAnimationFrame(animationFrameRef.current);
            }
        };
    }, [isActive, modelReady, detectFace]);

    return {
        isLoading,
        error,
        metrics,
        modelReady,
        getAverageMetrics,
        resetMetrics
    };
};

export default useFaceDetection;

/**
 * useVoiceToText — Reusable hook for Web Speech API voice-to-text.
 *
 * Implements issue #28: Voice-to-Text for Mock Interviews
 *
 * Features:
 *  - Browser / device compatibility detection
 *  - interim + final transcript accumulation
 *  - Auto-restart on network/no-speech errors
 *  - Language selection support
 *  - Exposes isListening, transcript, interimTranscript, error, isSupported
 */
import { useState, useRef, useCallback, useEffect } from 'react';

/**
 * Returns true when the Web Speech API is available in the current browser.
 */
export const isSpeechRecognitionSupported = () =>
    typeof window !== 'undefined' && !!(window.SpeechRecognition || window.webkitSpeechRecognition);

/**
 * @param {object} options
 * @param {string}   [options.lang='en-US']        BCP-47 language tag
 * @param {boolean}  [options.continuous=true]      Keep listening until stopped
 * @param {boolean}  [options.interimResults=true]  Emit interim (non-final) results
 * @param {Function} [options.onFinalTranscript]    Called with the accumulated final string
 * @param {Function} [options.onError]              Called with an error message string
 */
export function useVoiceToText({
    lang = 'en-US',
    continuous = true,
    interimResults = true,
    onFinalTranscript,
    onError,
} = {}) {
    const [isListening, setIsListening] = useState(false);
    const [transcript, setTranscript] = useState('');           // final only
    const [interimTranscript, setInterimTranscript] = useState(''); // live preview
    const [error, setError] = useState('');
    const [isSupported] = useState(isSpeechRecognitionSupported);

    const recognitionRef = useRef(null);
    const isListeningRef = useRef(false);
    const finalAccumulatorRef = useRef('');

    // Sync ref so event handlers always see current value
    useEffect(() => {
        isListeningRef.current = isListening;
    }, [isListening]);

    const stopListening = useCallback(() => {
        isListeningRef.current = false;
        setIsListening(false);
        setInterimTranscript('');

        if (recognitionRef.current) {
            try { recognitionRef.current.stop(); } catch (_) { /* ignore */ }
            recognitionRef.current = null;
        }
    }, []);

    const startListening = useCallback(() => {
        if (!isSupported) {
            const msg = 'Speech recognition is not supported in this browser. Please use Chrome or Edge.';
            setError(msg);
            onError?.(msg);
            return;
        }

        if (isListeningRef.current || recognitionRef.current) {
            return; // Prevent duplicate instances on rapid re-entry
        }

        // Reset state
        finalAccumulatorRef.current = '';
        setTranscript('');
        setInterimTranscript('');
        setError('');
        isListeningRef.current = true;
        setIsListening(true);

        const SpeechRec = window.SpeechRecognition || window.webkitSpeechRecognition;
        const recognition = new SpeechRec();
        recognition.lang = lang;
        recognition.continuous = continuous;
        recognition.interimResults = interimResults;

        recognition.onresult = (event) => {
            let finalChunk = '';
            let interim = '';

            for (let i = event.resultIndex; i < event.results.length; i++) {
                const result = event.results[i];
                if (result.isFinal) {
                    finalChunk += result[0].transcript + ' ';
                } else {
                    interim += result[0].transcript;
                }
            }

            if (finalChunk) {
                finalAccumulatorRef.current += finalChunk;
                setTranscript(finalAccumulatorRef.current);
                onFinalTranscript?.(finalAccumulatorRef.current);
            }
            setInterimTranscript(interim);
        };

        recognition.onerror = (event) => {
            // Auto-restart on transient errors
            const transient = ['no-speech', 'network', 'aborted'];
            if (isListeningRef.current && transient.includes(event.error)) {
                setTimeout(() => {
                    try { recognition.start(); } catch (_) { /* ignore */ }
                }, 150);
                return;
            }

            const messages = {
                'not-allowed': 'Microphone access denied. Please allow microphone permission in your browser settings.',
                'service-not-allowed': 'Speech service blocked. Try Chrome or Edge on desktop.',
                'audio-capture': 'No microphone detected. Please connect a microphone and try again.',
                'language-not-supported': `Language "${lang}" is not supported by your browser's speech recognition.`,
            };
            const msg = messages[event.error] || `Speech recognition error: ${event.error}`;
            setError(msg);
            onError?.(msg);
            stopListening();
        };

        recognition.onend = () => {
            if (isListeningRef.current) {
                if (continuous) {
                    // Auto-restart if continuous
                    setTimeout(() => {
                        if (!isListeningRef.current || recognitionRef.current !== recognition) return;
                        try { recognition.start(); } catch (_) { /* ignore */ }
                    }, 150);
                } else {
                    stopListening();
                }
            }
        };

        recognitionRef.current = recognition;

        try {
            recognition.start();
        } catch (err) {
            const msg = `Failed to start speech recognition: ${err.message}`;
            setError(msg);
            onError?.(msg);
            stopListening();
        }
    }, [isSupported, lang, continuous, interimResults, onFinalTranscript, onError, stopListening]);

    const resetTranscript = useCallback(() => {
        finalAccumulatorRef.current = '';
        setTranscript('');
        setInterimTranscript('');
    }, []);

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            isListeningRef.current = false;
            if (recognitionRef.current) {
                try { recognitionRef.current.stop(); } catch (_) { /* ignore */ }
            }
        };
    }, []);

    return {
        isListening,
        transcript,
        interimTranscript,
        error,
        isSupported,
        startListening,
        stopListening,
        resetTranscript,
    };
}

import { useSearchParams } from 'react-router-dom';
