            </motion.div>
          )}
          </AnimatePresence>

          {/* Hero Content */}
          <main className="flex-1 flex flex-col items-center justify-center px-4 text-center">
            <span className="text-sm font-semibold text-gray-600 tracking-wider mb-4 uppercase">
              AI-Powered Career Acceleration
            </span>
            
            <div className="flex flex-col items-center">
              <h1 className="text-6xl md:text-7xl lg:text-8xl font-normal text-gray-500 leading-normal md:leading-none tracking-tighter">
                Dream Job.
              </h1>
              <h1 className="text-6xl md:text-7xl lg:text-8xl font-normal  md:leading-none tracking-tighter z-10" style={{ color: '#202A36', marginTop: '-12px' }}>
                On Autopilot.
              </h1>
            </div>

            <p className="text-lg md:text-xl text-gray-600 mb-6 max-w-2xl mt-6">
              The intelligent platform that enhances your resume, matches you with perfect opportunities, and lands your dream job.
            </p>

            <div className="flex items-center gap-4">
              <button 
                onClick={() => window.location.href='/jobs'}
                className="px-6 py-3 rounded-full bg-gray-300 text-gray-800 font-medium hover:bg-gray-400 transition-colors">
                Explore Jobs
              </button>
              <button 
                onClick={() => window.location.href='/register'}
                className="px-6 py-3 rounded-full text-white font-medium transition-colors" 
                style={{ backgroundColor: '#202A36' }} 
                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#1a2229'} 
                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = '#202A36'}
              >
                Get Started Free
              </button>
            </div>
          </main>
        </div>
    </section>
  );
}

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import {
  Bell,
  Plus,
  Search,
  Briefcase,
  MapPin,
  Mail,
  ExternalLink,
  Loader2,
  AlertCircle,
  Sparkles,
  Zap
} from 'lucide-react';
import toast from 'react-hot-toast';
import { jobAlertsApi, jobsApi } from '../services/api';
import { JobAlertModal, JobAlertsList } from '../components';
import { SkeletonStatCards, SkeletonJobList } from '../components/ui/Skeleton'

export default function JobAlerts() {
  const [activeTab, setActiveTab] = useState('alerts'); // 'alerts' | 'search'
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [searchLoading, setSearchLoading] = useState(false);

  const hoverBorderClassMap = {
    indigo: 'hover:border-primary/30',
    green: 'hover:border-green-500/30',
    purple: 'hover:border-purple-500/30',
    blue: 'hover:border-blue-500/30'
  };

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const response = await jobAlertsApi.getStats();
      setStats(response.stats);
    } catch (err) {
      console.error('Failed to fetch stats:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = async (e) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    setSearchLoading(true);
    try {
      const response = await jobsApi.search(searchQuery);
      const jobs = response.data || response.jobs || [];
      setSearchResults(jobs);
      if (jobs.length === 0) {
        toast('No jobs found for this search', { icon: '📭' });
      }
    } catch (err) {
      toast.error(err.message || 'Search failed');
    } finally {
      setSearchLoading(false);
    }
  };

  const handleCreateAlertFromSearch = () => {
    setIsModalOpen(true);
  };

  return (
    <div className="min-h-screen bg-background">
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-0 right-1/4 w-96 h-96 bg-purple-500/10 rounded-full blur-3xl" />
        <div className="absolute bottom-1/4 left-1/4 w-96 h-96 bg-primary/10 rounded-full blur-3xl" />
      </div>

      {/* Hero Section */}
      <div className="relative pt-8 pb-8">
        <div className="max-w-6xl mx-auto px-4">
          <div className="flex items-center justify-between mb-8">
            <div>
              <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-purple-500/10 border border-purple-500/20 text-purple-400 text-sm mb-4">
                <Zap className="w-4 h-4" />
                Automated Job Notifications
              </div>
              <h1 className="text-4xl font-bold text-foreground flex items-center gap-3">
                <Bell className="w-10 h-10 text-purple-400" />
                Job Alerts
              </h1>
              <p className="mt-3 text-muted-foreground max-w-xl">
                Set up personalized job alerts and never miss an opportunity.
                We'll email you when new jobs match your criteria.
              </p>
            </div>
            <button
              onClick={() => setIsModalOpen(true)}
              className="flex items-center gap-2 px-6 py-3 bg-card text-foreground border border-border rounded-xl font-semibold hover:bg-muted/20 transition-all cursor-pointer"
            >
              <Plus className="w-5 h-5" />
              Create Alert
            </button>
          </div>

          {/* Quick Stats */}
          {loading ? (
            <motion.div
              className="grid grid-cols-4 gap-4"
              variants={{ animate: { transition: { staggerChildren: 0.08 } } }}
              initial="initial"
              animate="animate"
            >
              <SkeletonStatCards count={4} />
            </motion.div>
          ) : stats && (
            <motion.div
              className="grid grid-cols-4 gap-4"
              variants={{ animate: { transition: { staggerChildren: 0.08 } } }}
              initial="initial"
              animate="animate"
            >
              {[
                { value: stats.totalAlerts || 0, label: 'Total Alerts', color: 'indigo' },
                { value: stats.activeAlerts || 0, label: 'Active Alerts', color: 'green' },
                { value: stats.totalJobsFound || 0, label: 'Jobs Found', color: 'purple' },
                { value: stats.totalEmailsSent || 0, label: 'Emails Sent', color: 'blue' }
              ].map((stat, idx) => (
                <motion.div
                  key={idx}
                  variants={{
                    initial: { opacity: 0, y: 12 },
                    animate: { opacity: 1, y: 0, transition: { duration: 0.22, ease: 'easeOut' } }
                  }}
                  className={`bg-background/50 border border-border rounded-xl p-4 ${hoverBorderClassMap[stat.color] || 'hover:border-border'} transition-colors`}
                >
                  <div className={`text-3xl font-bold text-foreground`}>{stat.value}</div>
                  <div className="text-muted-foreground text-sm">{stat.label}</div>
                </motion.div>
              ))}
            </motion.div>
          )}
        </div>
      </div>

      {/* Tabs */}
      <div className="relative max-w-6xl mx-auto px-4 mt-4">
        <div className="flex gap-2 border-b border-border">
          {[
            { id: 'alerts', label: 'My Alerts', icon: Bell },
            { id: 'search', label: 'Search Jobs', icon: Search },
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center gap-2 px-6 py-3 rounded-t-xl font-medium transition-all cursor-pointer ${
                activeTab === tab.id
                  ? 'bg-card text-foreground border border-border border-b-transparent translate-y-[1px]'
                  : 'text-muted-foreground hover:text-foreground border border-transparent'
              }`}
            >
              <tab.icon className="w-4 h-4" />
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Content */}
      <div className="relative max-w-6xl mx-auto px-4 pb-8">
        <div className="bg-card border border-border border-t-0 rounded-b-xl rounded-tr-xl p-6">
          {activeTab === 'alerts' && (
            <JobAlertsList />
          )}

          {activeTab === 'search' && (
            <div className="space-y-6">
              {/* Search Form */}
              <div className="bg-muted/30 border border-border rounded-xl p-6">
                <form onSubmit={handleSearch} className="flex gap-4">
                  <div className="flex-1 relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
                    <input
                      type="text"
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      placeholder="Search jobs by title, skills, or company..."
                      className="w-full pl-12 pr-4 py-3 bg-background border border-border rounded-xl text-foreground placeholder-muted-foreground focus:ring-2 focus:ring-primary focus:border-transparent focus:outline-none"
                    />
                  </div>
                  <button
                    type="submit"
                    disabled={searchLoading}
                    className="px-6 py-3 bg-foreground text-background rounded-xl font-medium hover:bg-foreground/95 transition-colors disabled:opacity-50 flex items-center gap-2 cursor-pointer"
                  >
                    {searchLoading ? (
                      <Loader2 className="w-5 h-5 animate-spin" />
                    ) : (
                      <Search className="w-5 h-5" />
                    )}
                    Search
                  </button>
                </form>

                {searchQuery && !searchLoading && (
                  <div className="mt-4 pt-4 border-t border-border flex items-center justify-between">
                    <p className="text-sm text-muted-foreground">
                      Want to get notified about "{searchQuery}" jobs?
                    </p>
                    <button
                      onClick={handleCreateAlertFromSearch}
                      className="text-sm text-primary font-medium hover:text-primary/85 flex items-center gap-1 cursor-pointer"
                    >
                      <Sparkles className="w-4 h-4" />
                      Create Alert
                    </button>
                  </div>
                )}
              </div>

              {/* Search Results */}
              {searchLoading ? (
                <SkeletonJobList count={4} />
              ) : searchResults.length > 0 ? (
                <div className="space-y-4">
                  <h3 className="text-lg font-semibold text-foreground">
                    Search Results ({searchResults.length} jobs)
                  </h3>
                  <motion.div
                    className="space-y-4"
                    variants={{
                      animate: { transition: { staggerChildren: 0.07 } }
                    }}
                    initial="initial"
                    animate="animate"
                  >
                    {searchResults.map((job, index) => (
                      <JobCard key={job.id || index} job={job} index={index} />
                    ))}
                  </motion.div>
                </div>
              ) : null}

              {/* Empty State */}
              {!searchLoading && searchResults.length === 0 && !searchQuery && (
                <div className="text-center py-16">
                  <div className="w-20 h-20 bg-muted/50 rounded-full flex items-center justify-center mx-auto mb-4">
                    <Search className="w-10 h-10 text-muted-foreground" />
                  </div>
                  <h3 className="text-lg font-medium text-foreground">Search for Jobs</h3>
                  <p className="text-muted-foreground mt-2 max-w-md mx-auto">
                    Enter a job title, skill, or company name to find matching opportunities.
                    You can then create an alert to get notified about new matches.
                  </p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Modal */}
      <JobAlertModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSuccess={fetchStats}
      />
    </div>
  );
}

// Job Card Component
function JobCard({ job, index }) {
  const handleApply = () => {
    if (job.applyLink) {
      window.open(job.applyLink, '_blank');
    }
  };

  const handleEmail = () => {
    if (job.recruiterEmail) {
      window.location.href = `mailto:${job.recruiterEmail}?subject=Application for ${job.title}`;
    }
  };

  return (
    <motion.div
      variants={{
        initial: { opacity: 0, y: 12 },
        animate: { opacity: 1, y: 0, transition: { duration: 0.22, ease: 'easeOut' } }
      }}
      className="bg-muted/50 rounded-xl border border-border p-5 hover:border-primary/30 transition-all"
    >
      <div className="flex items-start gap-4">
        {/* Company Logo or Initial */}
        <div className="w-14 h-14 rounded-lg bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-foreground font-bold text-xl shrink-0">
          {job.company?.charAt(0) || 'J'}
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-start justify-between gap-4">
            <div>
              <span className="text-xs text-muted-foreground/80 font-medium">#{index + 1}</span>
              <h3 className="font-semibold text-foreground text-lg">{job.title}</h3>
              <p className="text-primary font-medium">{job.company}</p>
            </div>

            {/* Action Buttons */}
            <div className="flex gap-2 shrink-0">
              {job.applyLink && (
                <button
                  onClick={handleApply}
                  className="flex items-center gap-1.5 px-4 py-2 bg-card text-foreground rounded-lg border border-border font-medium hover:bg-muted/20 transition-colors text-sm cursor-pointer"
                >
                  <ExternalLink className="w-4 h-4" />
                  Apply
                </button>
              )}
              {job.recruiterEmail && (
                <button
                  onClick={handleEmail}
                  className="flex items-center gap-1.5 px-4 py-2 bg-card text-foreground rounded-lg border border-border font-medium hover:bg-muted/60 transition-colors text-sm cursor-pointer"
                >
                  <Mail className="w-4 h-4" />
                  Email
                </button>
              )}
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-3 mt-3 text-sm text-muted-foreground">
            <span className="flex items-center gap-1">
              <MapPin className="w-4 h-4" />
              {job.location || 'Remote'}
            </span>
            <span className="flex items-center gap-1">
              <Briefcase className="w-4 h-4" />
              {job.employmentType || 'Full-time'}
            </span>
            {job.salary?.min != null && (
              <span className="text-green-400 font-medium">
                ${job.salary.min.toLocaleString()}{job.salary.max != null ? ` - $${job.salary.max.toLocaleString()}` : '+'} / {job.salary.period || 'year'}
              </span>
            )}
          </div>

          {job.description && (
            <p className="mt-3 text-muted-foreground text-sm line-clamp-2">
              {job.description.length > 200
                ? `${job.description.substring(0, 200)}...`
                : job.description}
            </p>
          )}
        </div>
      </div>
    </motion.div>
  );
}

import { useState, useEffect } from 'react'
import { Link, useSearchParams } from 'react-router-dom'
import toast from 'react-hot-toast'
import { motion, AnimatePresence } from 'framer-motion'
import { formatDistanceToNow } from 'date-fns'
import {
  Search,
  MapPin,
  Briefcase,
  Clock,
  DollarSign,
  Building2,
  ExternalLink,
  Bookmark,
  BookmarkCheck,
  Filter,
  X,
  Loader2,
  TrendingUp,
  Zap,
  Target,
  Sparkles
} from 'lucide-react'
import { jobsApi, jobTrackerApi } from '../services/api'
import Button from '../components/Button'
import MatchScoreBadge from '../components/MatchScoreBadge'
import { SkeletonJobList } from '../components/ui/Skeleton'

const JOB_TYPES = ['All Types', 'Full-time', 'Part-time', 'Contract', 'Internship', 'Remote']
const EXPERIENCE_LEVELS = ['All Levels', 'Entry Level', 'Mid Level', 'Senior Level', 'Lead/Manager']
const POPULAR_SEARCHES = [
  'Software Engineer',
  'Frontend Developer',
  'Backend Developer',
  'Full Stack Developer',
  'Data Scientist',
  'Product Manager',
  'UX Designer',
  'DevOps Engineer'
]

export default function JobSearch() {
  const [searchParams, setSearchParams] = useSearchParams()
  const [searchQuery, setSearchQuery] = useState(searchParams.get('q') || '')
  const [jobs, setJobs] = useState([])
  const [loading, setLoading] = useState(false)
  const [hasSearched, setHasSearched] = useState(false)
  const [savedJobs, setSavedJobs] = useState(new Set())
  const [showFilters, setShowFilters] = useState(false)
  const [filters, setFilters] = useState({
    jobType: JOB_TYPES.includes(searchParams.get('jobType')) ? searchParams.get('jobType') : 'All Types',
    experienceLevel: EXPERIENCE_LEVELS.includes(searchParams.get('experienceLevel')) ? searchParams.get('experienceLevel') : 'All Levels',
    location: searchParams.get('location') || ''
  })

  const isAnyFilterActive =
    filters.jobType !== 'All Types' ||
    filters.experienceLevel !== 'All Levels' ||
    filters.location !== ''

  const clearAllFilters = async () => {
    const clearedFilters = {
      jobType: 'All Types',
      experienceLevel: 'All Levels',
      location: ''
    }
    setFilters(clearedFilters)

    const params = {}
    if (searchQuery.trim()) {
      params.q = searchQuery
    }
    setSearchParams(params)

    if (searchQuery.trim()) {
      setLoading(true)
      setHasSearched(true)
      try {
        const response = await jobsApi.search(searchQuery, clearedFilters)
        setJobs(response.data || [])
        toast.success('Filters cleared!')
      } catch (error) {
        toast.error(error.message || 'Failed to search jobs')
        setJobs([])
      } finally {
        setLoading(false)
      }
    } else {
      toast.success('Filters cleared!')
    }
  }

  // Load saved jobs on mount
  useEffect(() => {
    loadSavedJobs()
  }, [])

  const loadSavedJobs = async () => {
    try {
      const response = await jobTrackerApi.getAll()
      const savedIds = new Set((response.trackedJobs || []).map(j => j.jobId))
      setSavedJobs(savedIds)
    } catch (error) {
      console.error('Failed to load saved jobs:', error)
    }
  }

  const handleSearch = async (e) => {
    e?.preventDefault()
    if (!searchQuery.trim()) {
      return
    }

    setLoading(true)
    setHasSearched(true)

    // Only persist non-default filter values for cleaner URLs
    const params = { q: searchQuery }
    if (filters.jobType !== 'All Types') params.jobType = filters.jobType
    if (filters.experienceLevel !== 'All Levels') params.experienceLevel = filters.experienceLevel
    if (filters.location) params.location = filters.location
    setSearchParams(params)

    try {
      const response = await jobsApi.search(searchQuery, filters)
      setJobs(response.data || [])

      if (response.data?.length === 0) {
        toast('No jobs found. Try different keywords.', { icon: '🔍' })
      } else {
        toast.success(`Found ${response.data.length} jobs!`)
      }
    } catch (error) {
      toast.error(error.message || 'Failed to search jobs')
      setJobs([])
    } finally {
      setLoading(false)
    }
  }

  const handleQuickSearch = (query) => {
    setSearchQuery(query)
    setTimeout(() => {
      handleSearch()
    }, 100)
  }

  const handleResetFilters = () => {
    const defaultFilters = { jobType: 'All Types', experienceLevel: 'All Levels', location: '' }
    setFilters(defaultFilters)
    setSearchParams({ q: searchQuery })

    if (hasSearched && searchQuery.trim()) {
      setLoading(true)
      jobsApi.search(searchQuery, defaultFilters)
        .then(response => {
          setJobs(response.data || [])
          toast.success('Filters reset successfully')
        })
        .catch(error => {
          toast.error(error.message || 'Failed to search jobs')
          setJobs([])
        })
        .finally(() => {
          setLoading(false)
        })
    } else {
      toast.success('Filters reset')
    }
  }

  const handleSaveJob = async (job) => {
    const jobId = job.job_id || job.id

    if (savedJobs.has(jobId)) {
      toast('Job already saved to tracker', { icon: '📌' })
      return
    }

    try {
      await jobTrackerApi.track({
        jobId: jobId,
        title: job.job_title || job.title,
        company: job.employer_name || job.company,
        location: job.job_city || job.location?.city || 'Remote',
        jobType: job.job_employment_type || job.employmentType || 'Full-time',
        applyLink: job.job_apply_link || job.applyLink,
        salary: job.job_salary_min ? `$${job.job_salary_min} - $${job.job_salary_max}` : null,
        description: job.job_description || job.description,
        status: 'saved'
      })

      setSavedJobs(prev => new Set([...prev, jobId]))
      toast.success('Job saved to tracker!')
    } catch (error) {
      toast.error('Failed to save job')
    }
  }
  const saveRecentlyViewedJob = (job) => {
  const recentJobs =
    JSON.parse(localStorage.getItem('recentJobs')) || [];

  const filteredJobs = recentJobs.filter(
    (item) =>
      (item.job_id || item.id) !==
      (job.job_id || job.id)
  );

  const updatedJobs = [
    {
      ...job,
      viewedAt: new Date().toISOString(),
    },
    ...filteredJobs,
  ].slice(0, 15);

  localStorage.setItem(
    'recentJobs',
    JSON.stringify(updatedJobs)
  );
};

  const formatSalary = (job) => {
    if (job.job_min_salary && job.job_max_salary) {
      return `$${(job.job_min_salary / 1000).toFixed(0)}k - $${(job.job_max_salary / 1000).toFixed(0)}k`
    }
    if (job.job_salary_min && job.job_salary_max) {
      return `$${job.job_salary_min} - $${job.job_salary_max}`
    }
    return null
  }

  const formatDate = (dateString) => {
    if (!dateString) return 'Recently'
    const date = new Date(dateString)
    if (Number.isNaN(date.getTime())) return 'Recently'
    return formatDistanceToNow(date, { addSuffix: true })
  }

  const getMatchScore = (job) => {
    const score = job.matchScore ?? job.match_score ?? job.matchPercentage ?? job.match_percentage
    const numericScore = typeof score === 'string' ? Number(score) : score
    return typeof numericScore === 'number' && Number.isFinite(numericScore) ? numericScore : null
  }

  return (
    <div className="min-h-screen bg-background">
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 left-0 w-96 h-96 bg-primary/10 rounded-full blur-3xl" />
        <div className="absolute bottom-1/4 right-0 w-96 h-96 bg-purple-500/10 rounded-full blur-3xl" />
      </div>

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header Section */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center mb-10"
        >
          <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-primary/10 border border-primary/20 text-primary text-sm mb-4">
            <Sparkles className="w-4 h-4" />
            AI-Powered Job Search
          </div>
          <h1 className="text-4xl md:text-5xl font-bold text-foreground mb-3">
            Find Your Dream Job
          </h1>
          <p className="text-lg text-muted-foreground max-w-2xl mx-auto">
            Search thousands of opportunities and accelerate your career with careerpilot
          </p>
        </motion.div>

        {/* Search Section */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="mb-8"
        >
          <div className="p-6 rounded-2xl bg-background/50 border border-border backdrop-blur-sm">
            <form onSubmit={handleSearch} className="space-y-4">
              {/* Main Search Bar */}
              <div className="flex gap-3">
                <div className="flex-1 relative">
                  <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-muted-foreground w-5 h-5" />
                  <input
                    type="text"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Job title, keywords, or company..."
className="w-full pl-12 pr-10 py-4 bg-muted/50 border border-border rounded-xl text-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary focus:border-transparent transition-all"
/>
{searchQuery && (
  <button
    type="button"
    onClick={() => setSearchQuery('')}
    aria-label="Clear search"
    className="absolute right-4 top-1/2 transform -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
  >
    <X className="w-5 h-5" />
  </button>
)}
                </div>
                <Button
                  type="submit"
                  variant="primary"
                  disabled={loading}
                  className="!px-8 !py-4 !text-lg !rounded-xl flex items-center gap-2"
                >
                  {loading ? (
                    <Loader2 className="w-5 h-5 animate-spin" />
                  ) : (
                    <Search className="w-5 h-5" />
                  )}
                  Search
                </Button>
                <button
                  type="button"
                  onClick={() => setShowFilters(!showFilters)}
                  aria-label="Toggle Filters"
                  className={`px-4 py-4 rounded-xl border transition-all cursor-pointer ${showFilters
                    ? 'bg-primary/20 border-primary/30 text-primary'
                    : 'bg-muted/50 border-border text-muted-foreground hover:bg-muted'
                    }`}
                >
                  <Filter className="w-5 h-5" />
                </button>
              </div>

              {/* Filters Panel */}
              <AnimatePresence>
                {showFilters && (
                  <motion.div
                    initial={{ height: 0, opacity: 0 }}
                    animate={{ height: 'auto', opacity: 1 }}
                    exit={{ height: 0, opacity: 0 }}
                    className="overflow-hidden"
                  >
                    <div className="pt-4 border-t border-border">
                      <div className="flex items-center justify-between mb-4">
                        <h3 className="font-semibold text-lg text-foreground">Filters</h3>
                        {isAnyFilterActive && (
                          <button
                            type="button"
                            onClick={clearAllFilters}
                            className="text-sm text-red-500 hover:text-red-700 font-medium transition-colors duration-200 flex items-center gap-1 cursor-pointer"
                            aria-label="Clear all filters"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                            </svg>
                            Clear All
                          </button>
                        )}
                      </div>
                      <div className="grid md:grid-cols-3 gap-4">
                      <div>
                        <label htmlFor="job-type-select" className="block text-sm font-medium text-muted-foreground mb-2">
                          Job Type
                        </label>
                        <select
                          id="job-type-select"
                          value={filters.jobType}
                          onChange={(e) => setFilters({ ...filters, jobType: e.target.value })}
                          className="w-full px-4 py-3 bg-muted/50 border border-border rounded-lg text-foreground focus:ring-2 focus:ring-primary"
                        >
                          {JOB_TYPES.map(type => (
                            <option key={type} value={type}>{type}</option>
                          ))}
                        </select>
                      </div>
                      <div>
                        <label htmlFor="experience-level-select" className="block text-sm font-medium text-muted-foreground mb-2">
                          Experience Level
                        </label>
                        <select
                          id="experience-level-select"
                          value={filters.experienceLevel}
                          onChange={(e) => setFilters({ ...filters, experienceLevel: e.target.value })}
                          className="w-full px-4 py-3 bg-muted/50 border border-border rounded-lg text-foreground focus:ring-2 focus:ring-primary"
                        >
                          {EXPERIENCE_LEVELS.map(level => (
                            <option key={level} value={level}>{level}</option>
                          ))}
                        </select>
                      </div>
                      <div>
                        <label htmlFor="location-input" className="block text-sm font-medium text-muted-foreground mb-2">
                          Location
                        </label>
                        <div className="relative">
                          <MapPin className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
                          <input
                            id="location-input"
                            type="text"
                            value={filters.location}
                            onChange={(e) => setFilters({ ...filters, location: e.target.value })}
                            placeholder="City, state, or remote"
                            className="w-full pl-10 pr-4 py-3 bg-muted/50 border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary"
                          />
                        </div>
                      </div>
                    </div>
                    <div className="mt-4 flex justify-end">
                      <button
                        type="button"
                        onClick={handleResetFilters}
                        className="px-4 py-2.5 bg-muted/40 hover:bg-muted/60 border border-border rounded-xl text-sm font-medium text-muted-foreground hover:text-foreground transition-all duration-200 flex items-center gap-2 backdrop-blur-md shadow-sm cursor-pointer hover:border-primary/30"
                      >
                        <X className="w-4 h-4 text-muted-foreground hover:text-foreground transition-colors" />
                        Reset Filters
                      </button>
                    </div>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </form>


            {/* Popular Searches */}
            {!hasSearched && (
              <div className="mt-6 pt-4 border-t border-border">
                <p className="text-sm text-muted-foreground mb-3 flex items-center gap-2">
                  <TrendingUp className="w-4 h-4" />
                  Trending searches
                </p>
                <div className="flex flex-wrap gap-2">
                  {POPULAR_SEARCHES.map(search => (
                    <button
                      key={search}
                      onClick={() => handleQuickSearch(search)}
                      className="px-4 py-2 bg-muted hover:bg-primary/20 hover:text-primary hover:border-primary/30 border border-border rounded-full text-sm text-muted-foreground transition-all cursor-pointer"
                    >
                      {search}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </motion.div>

        {/* Results Section */}
        {loading ? (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="space-y-4"
          >
            <SkeletonJobList count={5} />
          </motion.div>
        ) : hasSearched && jobs.length === 0 ? (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="text-center py-20"
          >
            <div className="w-20 h-20 bg-muted rounded-full flex items-center justify-center mx-auto mb-4">
              <Search className="w-10 h-10 text-muted-foreground/80" />
            </div>
            <h3 className="text-xl font-semibold text-foreground mb-2">No jobs found</h3>
            <p className="text-muted-foreground mb-6">Try adjusting your search terms or filters</p>
            <Button variant="ghost" onClick={() => setHasSearched(false)}>
              Clear Search
            </Button>
          </motion.div>
        ) : hasSearched && jobs.length > 0 ? (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.2 }}
          >
            {/* Results Header */}
            <div className="flex justify-between items-center mb-6">
              <p className="text-muted-foreground">
                Found <span className="font-semibold text-foreground">{jobs.length}</span> jobs for "{searchQuery}"
              </p>
              <Link to="/job-tracker">
                <Button variant="ghost" className="flex items-center gap-2">
                  <Bookmark className="w-4 h-4" />
                  Saved Jobs ({savedJobs.size})
                </Button>
              </Link>
            </div>

            {/* Job Cards */}
            <div className="space-y-4">
              {jobs.map((job, index) => (
                <motion.div
                  key={job.job_id || job.id || index}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.05 }}
                >
                  <div className="p-6 rounded-xl bg-background/50 border border-border hover:border-border transition-all group">
                    <div className="flex justify-between items-start">
                      <div className="flex gap-4">
                        {/* Company Logo */}
                        <div className="w-14 h-14 bg-gradient-to-br from-primary/20 to-secondary/20 rounded-xl flex items-center justify-center shrink-0 border border-border">
                          {job.employer_logo ? (
                            <img
                              src={job.employer_logo}
                              alt={job.employer_name}
                              className="w-10 h-10 object-contain rounded"
                              onError={(e) => {
                                e.target.style.display = 'none'
                                e.target.nextSibling.style.display = 'flex'
                              }}
                            />
                          ) : null}
                          <Building2 className={`w-6 h-6 text-primary ${job.employer_logo ? 'hidden' : ''}`} />
                        </div>

                        <div className="flex-1">
                          <div className="flex flex-wrap items-start gap-3">
                            <h3 className="text-lg font-semibold text-foreground group-hover:text-primary transition-colors">
                              {job.job_title || job.title}
                            </h3>
                            <MatchScoreBadge score={getMatchScore(job)} />
                          </div>
                          <p className="text-muted-foreground font-medium">
                            {job.employer_name || job.company}
                          </p>

                          {/* Job Meta */}
                          <div className="flex flex-wrap items-center gap-4 mt-3 text-sm text-muted-foreground">
                            <span className="flex items-center gap-1">
                              <MapPin className="w-4 h-4" />
                              {job.job_city || job.location?.city || 'Remote'}{job.job_state ? `, ${job.job_state}` : ''}
                            </span>
                            <span className="flex items-center gap-1">
                              <Briefcase className="w-4 h-4" />
                              {job.job_employment_type || job.employmentType || 'Full-time'}
                            </span>
                            {formatSalary(job) && (
                              <span className="flex items-center gap-1 text-green-400 font-medium">
                                <DollarSign className="w-4 h-4" />
                                {formatSalary(job)}
                              </span>
                            )}
                            <span className="flex items-center gap-1">
                              <Clock className="w-4 h-4" />
                              {formatDate(job.job_posted_at_datetime_utc)}
                            </span>
                          </div>

                          {/* Job Description Preview */}
                          <p className="text-muted-foreground text-sm mt-3 line-clamp-2">
                            {(job.job_description || job.description || '').substring(0, 200)}...
                          </p>

                          {/* Tags */}
                          {job.job_required_skills && job.job_required_skills.length > 0 && (
                            <div className="flex flex-wrap gap-2 mt-3">
                              {job.job_required_skills.slice(0, 5).map((skill, i) => (
                                <span
                                  key={i}
                                  className="px-2 py-1 bg-primary/20 text-primary border border-primary/30 rounded-md text-xs font-medium"
                                >
                                  {skill}
                                </span>
                              ))}
                            </div>
                          )}
                        </div>
                      </div>

                      {/* Actions */}
                      <div className="flex flex-col gap-2 ml-4">
                        <button
                          onClick={() => handleSaveJob(job)}
                          className={`p-2 rounded-lg transition-colors cursor-pointer ${savedJobs.has(job.job_id || job.id)
                            ? 'bg-primary/20 text-primary border border-primary/30'
                            : 'bg-muted text-muted-foreground hover:bg-primary/20 hover:text-primary border border-border'
                            }`}
                          title={savedJobs.has(job.job_id || job.id) ? 'Saved' : 'Save to tracker'}
                        >
                          {savedJobs.has(job.job_id || job.id) ? (
                            <BookmarkCheck className="w-5 h-5" />
                          ) : (
                            <Bookmark className="w-5 h-5" />
                          )}
                        </button>
                      </div>
                    </div>

                    {/* Apply Button */}
                    <div className="flex justify-end mt-4 pt-4 border-t border-border">
                      <a
  href={job.job_apply_link || job.applyLink}
  onClick={() => saveRecentlyViewedJob(job)}
  target="_blank"
  rel="noopener noreferrer"
  className="inline-flex items-center gap-2 px-6 py-2.5 bg-card hover:bg-muted/20 text-foreground rounded-lg font-medium transition-colors"
>
                        Apply Now
                        <ExternalLink className="w-4 h-4" />
                      </a>
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          </motion.div>
        ) : (
          /* Initial State - No Search Yet */
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.3 }}
            className="grid md:grid-cols-3 gap-6 mt-12"
          >
            <div className="text-center p-8 rounded-xl bg-background/50 border border-border hover:border-primary/30 transition-all group">
              <div className="w-14 h-14 bg-primary/20 rounded-2xl flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                <Zap className="w-7 h-7 text-primary" />
              </div>
              <h3 className="text-lg font-semibold text-foreground mb-2">Quick Apply</h3>
              <p className="text-muted-foreground text-sm">
                Apply to multiple jobs with your optimized resume in just one click
              </p>
            </div>

            <div className="text-center p-8 rounded-xl bg-background/50 border border-border hover:border-green-500/30 transition-all group">
              <div className="w-14 h-14 bg-green-500/20 rounded-2xl flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                <Target className="w-7 h-7 text-green-400" />
              </div>
              <h3 className="text-lg font-semibold text-foreground mb-2">Smart Matching</h3>
              <p className="text-muted-foreground text-sm">
                AI-powered job recommendations based on your skills and experience
              </p>
            </div>

            <div className="text-center p-8 rounded-xl bg-background/50 border border-border hover:border-purple-500/30 transition-all group">
              <div className="w-14 h-14 bg-purple-500/20 rounded-2xl flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                <TrendingUp className="w-7 h-7 text-purple-400" />
              </div>
              <h3 className="text-lg font-semibold text-foreground mb-2">Track Progress</h3>
              <p className="text-muted-foreground text-sm">
                Monitor all your applications and get insights on your job search
              </p>
            </div>
          </motion.div>
        )}
      </div>
    </div>
  )
}

import { useState, useEffect } from "react";
import { DragDropContext, Droppable, Draggable } from "@hello-pangea/dnd";
import { motion } from "framer-motion";
import { toast } from "react-hot-toast";
import {
  Briefcase,
  MapPin,
  DollarSign,
  Calendar,
  Trash2,
  ExternalLink,
  Plus,
  Filter,
} from "lucide-react";
import Layout from "../components/Layout";
import { jobTrackerApi } from "../services/api";
import Button from "../components/Button";
import Card from "../components/Card";
import EmptyJobState from "../components/EmptyJobState";
import CompanyResearch from "../components/CompanyResearch";
import { Sparkles } from "lucide-react";
import { SkeletonDashboard } from "../components/ui/Skeleton.jsx";

const JobTracker = () => {
  const [trackedJobs, setTrackedJobs] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [filterStatus, setFilterStatus] = useState("all");
  const [updateLoading, setUpdateLoading] = useState({});
  const [researchCompany, setResearchCompany] = useState(null);

  const statusOptions = [
    {
      value: "saved",
      label: "Saved",
      color: "bg-muted-foreground",
      icon: "📌",
    },
    { value: "applied", label: "Applied", color: "bg-blue-500", icon: "✉️" },
    {
      value: "interviewing",
      label: "Interviewing",
      color: "bg-yellow-500",
      icon: "🎤",
    },
    { value: "offered", label: "Offered", color: "bg-green-500", icon: "🎉" },
    { value: "rejected", label: "Rejected", color: "bg-red-500", icon: "❌" },
  ];

  useEffect(() => {
    fetchJobs();
    fetchStats();
  }, []);

  const fetchJobs = async () => {
    try {
      setLoading(true);
      const data = await jobTrackerApi.getAll();
      setTrackedJobs(data.trackedJobs || []);
    } catch (error) {
      console.error("Error fetching jobs:", error);
      toast.error("Failed to load tracked jobs", { id: "tracked-jobs-load-error" });
    } finally {
      setLoading(false);
    }
  };

  const fetchStats = async () => {
    try {
      const data = await jobTrackerApi.getStats();
      setStats(data.stats);
    } catch (error) {
      console.error("Error fetching stats:", error);
    }
  };

  const handleStatusUpdate = async (jobId, newStatus) => {
    try {
      setUpdateLoading((prev) => ({ ...prev, [jobId]: true }));
      await jobTrackerApi.updateStatus(jobId, newStatus);

      setTrackedJobs((prev) =>
        prev.map((job) =>
          job.id === jobId
            ? { ...job, status: newStatus, updatedAt: new Date() }
            : job,
        ),
      );

      toast.success("Status updated!");
      fetchStats();
    } catch (error) {
      console.error("Error updating status:", error);
      toast.error("Failed to update status", { id: `tracked-job-update-error-${jobId}` });
    } finally {
      setUpdateLoading((prev) => ({ ...prev, [jobId]: false }));
    }
  };

  const onDragEnd = async (result) => {
    const { destination, source, draggableId } = result;

    if (!destination) return;

    if (
      destination.droppableId === source.droppableId &&
      destination.index === source.index
    ) {
      return;
    }

    const newStatus = destination.droppableId;
    
    // Optimistic UI update
    setTrackedJobs((prev) =>
      prev.map((job) =>
        job.id === draggableId
          ? { ...job, status: newStatus, updatedAt: new Date() }
          : job,
      ),
    );

    // Backend update
    try {
      await jobTrackerApi.updateStatus(draggableId, newStatus);
      toast.success("Status updated!");
      fetchStats();
    } catch (error) {
      console.error("Error updating status:", error);
      toast.error("Failed to update status");
      // Revert on failure
      fetchJobs();
    }
  };

  const handleDelete = async (jobId) => {
    if (
      !window.confirm(
        "Are you sure you want to remove this job from your tracker?",
      )
    ) {
      return;
    }

    try {
      await jobTrackerApi.delete(jobId);
      setTrackedJobs((prev) => prev.filter((job) => job.id !== jobId));
      toast.success("Job removed from tracker");
      fetchStats();
    } catch (error) {
      console.error("Error deleting job:", error);
      toast.error("Failed to remove job", { id: `tracked-job-delete-error-${jobId}` });
    }
  };

  const getStatusInfo = (status) => {
    return (
      statusOptions.find((opt) => opt.value === status) || statusOptions[0]
    );
  };

  const formatDate = (date) => {
    if (!date) return "N/A";
    return new Date(date).toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    });
  };

  if (loading) {
    return (
      <Layout>
        <div className="min-h-screen bg-background py-8 px-4">
          <div className="max-w-7xl mx-auto">
            <SkeletonDashboard />
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="min-h-screen bg-background py-8 px-4">
        <div className="max-w-7xl mx-auto">
          {/* Header */}
          <div className="mb-8">
            <h1 className="text-4xl font-bold text-foreground mb-2">
              Job Tracker
            </h1>
            <p className="text-muted-foreground">
              Track your job applications in one place
            </p>
          </div>

          {/* Stats Cards */}
          {stats && (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-8">
              <Card className="p-6 bg-background/50 border-border">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-muted-foreground text-sm mb-1">Total</p>
                    <p className="text-3xl font-bold text-foreground">
                      {stats.total}
                    </p>
                  </div>
                  <div className="text-3xl">📊</div>
                </div>
              </Card>
              <Card className="p-6 bg-background/50 border-border">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-muted-foreground text-sm mb-1">Saved</p>
                    <p className="text-3xl font-bold text-foreground">
                      {stats.saved}
                    </p>
                  </div>
                  <div className="text-3xl">📌</div>
                </div>
              </Card>
              <Card className="p-6 bg-background/50 border-border">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-muted-foreground text-sm mb-1">
                      Applied
                    </p>
                    <p className="text-3xl font-bold text-foreground">
                      {stats.applied}
                    </p>
                  </div>
                  <div className="text-3xl">✉️</div>
                </div>
              </Card>
              <Card className="p-6 bg-background/50 border-border">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-muted-foreground text-sm mb-1">
                      Interviewing
                    </p>
                    <p className="text-3xl font-bold text-foreground">
                      {stats.interviewing}
                    </p>
                  </div>
                  <div className="text-3xl">🎤</div>
                </div>
              </Card>
              <Card className="p-6 bg-background/50 border-border">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-muted-foreground text-sm mb-1">
                      Offered
                    </p>
                    <p className="text-3xl font-bold text-foreground">
                      {stats.offered}
                    </p>
                  </div>
                  <div className="text-3xl">🎉</div>
                </div>
              </Card>
            </div>
          )}

          {/* Filter Buttons */}
          <div className="flex flex-wrap gap-2 mb-6">
            <button
              onClick={() => setFilterStatus("all")}
              className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                filterStatus === "all"
                  ? "bg-primary text-primary-foreground"
                  : "bg-muted text-foreground hover:bg-muted/80"
              }`}
            >
              All Columns
            </button>
            {statusOptions.map((status) => (
              <button
                key={status.value}
                onClick={() => setFilterStatus(status.value)}
                className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                  filterStatus === status.value
                    ? "bg-primary text-primary-foreground"
                    : "bg-muted text-foreground hover:bg-muted/80"
                }`}
              >
                {status.icon} {status.label}
              </button>
            ))}
          </div>

          {/* Kanban Board */}
          {trackedJobs.length === 0 ? (
            <Card className="p-12 text-center bg-background/50 border-border">
              <div className="max-w-md mx-auto">
                <Briefcase className="w-16 h-16 text-muted-foreground/80 mx-auto mb-4" />
                <h3 className="text-xl font-semibold text-foreground mb-2">
                  No Tracked Jobs Yet
                </h3>
                <p className="text-muted-foreground mb-6">
                  Start tracking jobs from the job search page
                </p>
                <Button
                  onClick={() => (window.location.href = "/jobs")}
                  className="mx-auto"
                >
                  <Plus className="w-5 h-5 mr-2" />
                  Find Jobs
                </Button>
              </div>
            </Card>
          ) : (
            <DragDropContext onDragEnd={onDragEnd}>
              <div className="flex gap-6 overflow-x-auto pb-8 min-h-[60vh] snap-x scrollbar-thin scrollbar-thumb-primary/20 scrollbar-track-transparent">
                {statusOptions
                  .filter((status) => filterStatus === "all" || status.value === filterStatus)
                  .map((status) => {
                  const columnJobs = trackedJobs.filter((j) => j.status === status.value);

                  return (
                    <div key={status.value} className="shrink-0 w-80 bg-muted/20 rounded-2xl p-4 flex flex-col snap-start border border-border/40 shadow-sm">
