                                          <div className="flex items-center gap-1.5">
                                            <DollarSign className="w-3.5 h-3.5 text-foreground/40" /> {job.salary}
                                          </div>
                                        )}
                                        <div className="flex items-center gap-1.5">
                                          <Calendar className="w-3.5 h-3.5 text-foreground/40" /> 
                                          Added {formatDate(job.createdAt)}
                                        </div>
                                      </div>

                                      <div className="flex gap-2 mt-auto pt-3 border-t border-border/50">
                                        {job.applyLink && (
                                          <a
                                            href={job.applyLink}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="flex-1 bg-primary text-background hover:bg-primary/90 py-1.5 rounded-md text-xs font-bold text-center transition-colors flex items-center justify-center gap-1"
                                          >
                                            <ExternalLink className="w-3 h-3" /> Apply
                                          </a>
                                        )}
                                        <button
                                          onClick={() =>
                                            setResearchCompany({
                                              name: job.company,
                                              industry: job.industry || "",
                                            })
                                          }
                                          className="flex-1 bg-primary/10 hover:bg-primary/20 text-primary py-1.5 rounded-md text-[11px] font-bold text-center transition-colors flex items-center justify-center gap-1"
                                        >
                                          <Sparkles className="w-3 h-3" /> AI Research
                                        </button>
                                      </div>
                                    </Card>
                                  </div>
                                )}
                              </Draggable>
                            ))}
                            {provided.placeholder}
                          </div>
                        )}
                      </Droppable>
                    </div>
                  );
                })}
              </div>
            </DragDropContext>
          )}
        </div>
      </div>
      {researchCompany && (
        <CompanyResearch
          companyName={researchCompany.name}
          industry={researchCompany.industry}
          onClose={() => setResearchCompany(null)}
        />
      )}
    </Layout>
  );
};

export default JobTracker;

import { useState, useEffect } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import toast from 'react-hot-toast'
import { signInWithCustomToken, signOut } from 'firebase/auth'
import { ShieldCheck } from 'lucide-react'
import { auth } from '../config/firebase'
import Navbar from '../components/Navbar'
import Input from '../components/Input'
import Button from '../components/Button'
import Card from '../components/Card'
import { twoFactorApi } from '../services/api'

export default function LinkedInCallback() {
    const [searchParams] = useSearchParams()
    const navigate = useNavigate()
    const [status, setStatus] = useState('Signing you in...')
    const [step, setStep] = useState('loading') // 'loading', 'totp'
    const [totpToken, setTotpToken] = useState('')
    const [useBackup, setUseBackup] = useState(false)
    const [totpLoading, setTotpLoading] = useState(false)

    useEffect(() => {
        const handleCallback = async () => {
            const code = searchParams.get('code')
            const error = searchParams.get('error')

            if (error) {
                const messages = {
                    linkedin_denied: 'LinkedIn sign-in was cancelled.',
                    linkedin_invalid_state: 'Invalid session. Please try again.',
                    linkedin_token_failed: 'Could not connect to LinkedIn. Please try again.',
                    linkedin_profile_failed: 'Could not fetch your LinkedIn profile. Please try again.',
                };

                toast.error(messages[error] || 'LinkedIn sign-in failed.')
                navigate('/login')
                return
            }

            if (!code) {
                toast.error('Something went wrong. Please try again.')
                navigate('/login')
                return
            }

            try {
                setStatus('Completing sign-in...')

                const apiBase = import.meta.env.VITE_API_URL || '/api'
                const resp = await fetch(`${apiBase}/auth/linkedin/token?code=${encodeURIComponent(code)}`)
                if (!resp.ok) {
                    const body = await resp.json().catch(() => ({}))
                    throw new Error(body.error || 'Token exchange failed')
                }
                const { token, isNew } = await resp.json()

                await signInWithCustomToken(auth, token)
                
                // Fetch two-factor status to prevent 2FA bypass
                const tfaStatus = await twoFactorApi.getStatus()
                if (tfaStatus && tfaStatus.enabled) {
                    setStep('totp')
                    toast.success('Two-factor authentication required')
                } else {
                    toast.success('Signed in successfully!')
                    navigate('/dashboard')
                }
            } catch (err) {
                console.error('Custom token sign-in failed:', err);
                toast.error('Failed to sign in. Please try again.')
                navigate('/login')
            }
        }

        handleCallback()
    }, [searchParams, navigate]) // Added dependencies

    const handleTotpSubmit = async (e) => {
        e.preventDefault()
        if (!totpToken.trim()) return

        setTotpLoading(true)
        try {
            if (useBackup) {
                await twoFactorApi.verifyBackup(totpToken)
            } else {
                await twoFactorApi.verify(totpToken)
            }
            toast.success('Verification successful!')
            navigate('/dashboard')
        } catch (error) {
            toast.error(error.message || 'Invalid code — please try again')
        } finally {
            setTotpLoading(false)
        }
    }

    const handleCancel = async () => {
        try {
            await signOut(auth)
        } catch (e) {
            console.error('Signout error:', e)
        }
        navigate('/login')
    }

    if (step === 'loading') {
        return (
            <div className="min-h-screen bg-black flex items-center justify-center">
              <div className="text-center">
                <div className="w-8 h-8 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin mx-auto mb-4" />
                <p className="text-neutral-400 text-sm">{status}</p>
              </div>
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-background relative overflow-hidden">
          {/* Background Effect */}
          <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-primary/20 rounded-full blur-[120px] pointer-events-none" />
          <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-secondary/20 rounded-full blur-[120px] pointer-events-none" />
          
          <Navbar />

          <div className="max-w-md mx-auto pt-24 md:pt-32 px-4 relative z-10">
            <Card className="border-border/50 bg-card/60 backdrop-blur-xl">
              <div className="flex flex-col items-center mb-6">
                <div className="p-3 rounded-full bg-primary/10 border border-primary/20 mb-4">
                  <ShieldCheck className="w-6 h-6 text-primary" />
                </div>
                <h1 className="text-2xl font-bold text-center text-foreground">
                  Two-Factor Verification
                </h1>
                <p className="text-muted-foreground text-sm text-center mt-2 font-medium">
                  {useBackup
                    ? 'Enter one of your backup codes to continue.'
                    : 'Open your authenticator app and enter the 6-digit code.'}
                </p>
              </div>

              <form onSubmit={handleTotpSubmit}>
                <Input
                  label={useBackup ? 'Backup code' : 'Authenticator code'}
                  type="text"
                  name="totpToken"
                  value={totpToken}
                  onChange={(e) => setTotpToken(useBackup ? e.target.value.toUpperCase() : e.target.value.replace(/\D/g, '').slice(0, 6))}
                  placeholder={useBackup ? 'XXXX-XXXX' : '000000'}
                  className="font-mono tracking-widest text-center text-lg font-bold"
                  maxLength={useBackup ? 9 : 6}
                  required
                />

                <Button
                  type="submit"
                  loading={totpLoading}
                  disabled={useBackup ? totpToken.replace(/[^A-Z0-9]/g, '').length !== 8 : totpToken.length !== 6}
                  className="w-full mt-4 font-bold"
                >
                  Verify &amp; Sign In
                </Button>
              </form>

              <button
                type="button"
                onClick={() => {
                  setUseBackup(v => !v)
                  setTotpToken('')
                }}
                className="w-full text-center text-sm text-muted-foreground hover:text-foreground transition-colors mt-4 font-bold"
              >
                {useBackup ? 'Use authenticator app instead' : 'Use a backup code instead'}
              </button>

              <button
                type="button"
                onClick={handleCancel}
                className="w-full text-center text-sm text-primary hover:text-primary/80 transition-colors mt-4 font-bold"
              >
                Cancel and return to Login
              </button>
            </Card>
          </div>
        </div>
    )
}

import { useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import {
  Linkedin, Sparkles, Target, Copy, Check,
  ChevronDown, ChevronUp, TrendingUp, Zap,
  AlertCircle, CheckCircle2, Star
} from 'lucide-react'
import { enhanceApi } from '../services/api'
import { toast } from 'react-hot-toast'

const IMPACT_CONFIG = {
  High:   { color: 'text-red-400',    bg: 'bg-red-500/10',    border: 'border-red-500/30'    },
  Medium: { color: 'text-yellow-400', bg: 'bg-yellow-500/10', border: 'border-yellow-500/30' },
  Low:    { color: 'text-green-400',  bg: 'bg-green-500/10',  border: 'border-green-500/30'  },
}

function ScoreRing({ score, label, size = 'md' }) {
  const safeScore = isNaN(Number(score)) ? 0 : Math.max(0, Math.min(100, Math.round(Number(score))))
  const r = size === 'lg' ? 44 : 28
  const stroke = size === 'lg' ? 7 : 5
  const dim = (r + stroke) * 2
  const circ = 2 * Math.PI * r
  const color =
    safeScore >= 75 ? 'stroke-green-400' :
    safeScore >= 50 ? 'stroke-yellow-400' : 'stroke-red-400'
  const textColor =
    safeScore >= 75 ? 'text-green-400' :
    safeScore >= 50 ? 'text-yellow-400' : 'text-red-400'

  return (
    <div className="flex flex-col items-center gap-1">
      <div className="relative flex items-center justify-center">
        <svg width={dim} height={dim} className="-rotate-90" viewBox={`0 0 ${dim} ${dim}`}>
          <circle
            cx={r + stroke} cy={r + stroke} r={r}
            fill="none" strokeWidth={stroke}
            stroke="currentColor" className="text-muted/30"
          />
          <circle
            cx={r + stroke} cy={r + stroke} r={r}
            fill="none" strokeWidth={stroke}
            strokeDasharray={circ}
            strokeDashoffset={circ * (1 - safeScore / 100)}
            strokeLinecap="round"
            className={`transition-all duration-700 ${color}`}
          />
        </svg>
        <span className={`absolute text-sm font-bold ${textColor}`}>{safeScore}%</span>
      </div>
      <p className="text-xs text-muted-foreground text-center">{label}</p>
    </div>
  )
}

function HeadlineCard({ headline, index, copied, onCopy }) {
  return (
    <motion.div
      initial={{ opacity: 0, x: -12 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ delay: index * 0.08 }}
      className="flex items-start gap-3 bg-background/60 border border-border rounded-xl p-4 hover:border-primary/40 transition"
    >
      <span className="shrink-0 w-6 h-6 rounded-full bg-primary/15 text-primary text-xs font-bold flex items-center justify-center mt-0.5">
        {index + 1}
      </span>
      <p className="text-sm text-foreground font-medium flex-1 leading-relaxed">{headline}</p>
      <button
        onClick={() => onCopy(headline, `hl-${index}`)}
        className="ml-2 text-muted-foreground hover:text-primary transition shrink-0"
        title="Copy"
      >
        {copied === `hl-${index}` ? <Check className="w-4 h-4 text-green-400" /> : <Copy className="w-4 h-4" />}
      </button>
    </motion.div>
  )
}

export default function LinkedInOptimizer() {
  const [profileText, setProfileText] = useState('')
  const [targetRole, setTargetRole] = useState('')
  const [results, setResults] = useState(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)
  const [copiedIndex, setCopiedIndex] = useState(null)
  const [copiedSkill, setCopiedSkill] = useState(null)
  const [aboutExpanded, setAboutExpanded] = useState(false)
  const [aboutCopied, setAboutCopied] = useState(false)

  const handleOptimize = async (e) => {
    e.preventDefault()
    
    // Safety check: minimum length validation
    const trimmedProfile = profileText.trim()
    const trimmedRole = targetRole.trim()
    
    if (trimmedProfile.length < 50) {
      setError('Please paste a substantial portion of your LinkedIn profile (at least 50 characters) for optimization.')
      return
    }
    
    // targetRole is optional, default to General career growth if empty
    const finalRole = trimmedRole || 'General career growth'

    setLoading(true)
    setError(null)
    setResults(null)
    try {
      const response = await enhanceApi.optimizeLinkedIn({ 
        profileText: trimmedProfile, 
        targetRole: finalRole 
      })
      setResults(response)
    } catch (err) {
      console.error('LinkedIn optimization error:', err)
      setError(err.message || 'Failed to optimize your profile. Please try again.')
    } finally {
      setLoading(false)
    }
  }

  const copyToClipboard = async (text, key) => {
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(text)
        setCopiedIndex(key)
        setTimeout(() => setCopiedIndex(null), 2000)
      } else {
        throw new Error('Clipboard API not supported')
      }
    } catch (err) {
      console.warn('Clipboard write failed:', err)
      // Fallback selection copy
      try {
        const textarea = document.createElement('textarea')
        textarea.value = text
        document.body.appendChild(textarea)
        textarea.select()
        document.execCommand('copy')
        document.body.removeChild(textarea)
        setCopiedIndex(key)
        setTimeout(() => setCopiedIndex(null), 2000)
      } catch (fallbackErr) {
        toast.error('Could not copy to clipboard. Please copy manually.')
      }
    }
  }

  const copyKeywordToClipboard = async (keyword) => {
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(keyword)
        setCopiedSkill(keyword)
        setTimeout(() => setCopiedSkill((current) => (current === keyword ? null : current)), 2000)
      } else {
        throw new Error('Clipboard API not supported')
      }
    } catch (err) {
      console.warn('Clipboard write failed:', err)
      try {
        const textarea = document.createElement('textarea')
        textarea.value = keyword
        document.body.appendChild(textarea)
        textarea.select()
        document.execCommand('copy')
        document.body.removeChild(textarea)
        setCopiedSkill(keyword)
        setTimeout(() => setCopiedSkill((current) => (current === keyword ? null : current)), 2000)
      } catch (fallbackErr) {
        toast.error('Could not copy keyword to clipboard. Please copy manually.')
      }
    }
  }

  const copyAbout = async () => {
    if (!results?.aboutRewrite) return
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(results.aboutRewrite)
        setAboutCopied(true)
        setTimeout(() => setAboutCopied(false), 2000)
      } else {
        throw new Error('Clipboard API not supported')
      }
    } catch (err) {
      console.warn('Clipboard write failed:', err)
      // Fallback selection copy
      try {
        const textarea = document.createElement('textarea')
        textarea.value = results.aboutRewrite
        document.body.appendChild(textarea)
        textarea.select()
        document.execCommand('copy')
        document.body.removeChild(textarea)
        setAboutCopied(true)
        setTimeout(() => setAboutCopied(false), 2000)
      } catch (fallbackErr) {
        toast.error('Could not copy to clipboard. Please copy manually.')
      }
    }
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Ambient blobs */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 right-0 w-96 h-96 bg-blue-500/10 rounded-full blur-3xl" />
        <div className="absolute bottom-1/4 left-0 w-96 h-96 bg-sky-500/10 rounded-full blur-3xl" />
      </div>

      <div className="relative max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-10">

        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center mb-10"
        >
          <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-blue-500/10 border border-blue-500/20 text-blue-400 text-sm mb-4">
            <Linkedin className="w-4 h-4" />
            AI LinkedIn Profile Optimizer
          </div>
          <h1 className="text-4xl md:text-5xl font-bold text-foreground mb-3">
            Stand Out on LinkedIn
          </h1>
          <p className="text-lg text-muted-foreground max-w-2xl mx-auto">
            Paste your LinkedIn profile text and get AI-powered headline rewrites, an About section overhaul, and skills gap insights vs industry peers.
          </p>
        </motion.div>

        {/* Input Form */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="bg-card/50 backdrop-blur-sm rounded-2xl border border-border shadow-xl mb-10 overflow-hidden"
        >
          <div className="bg-blue-600 px-6 py-4 flex items-center gap-2 text-white font-semibold">
            <Linkedin className="w-5 h-5" />
            Paste Your Profile Details
