import React, { useEffect, useState, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import {
  GitBranch, Star, GitFork, AlertCircle, ArrowLeft,
  Map, Grid3X3, AlertTriangle, Users, Search,
  Loader2, ChevronDown, Box, Info, Scale,
  Sparkles, CheckCircle2
} from 'lucide-react';
import toast from 'react-hot-toast';
import { useProjectVisualizerStore } from '../../stores/useProjectVisualizerStore';
import { projectVisualizerApi } from '../../services/api';

import ArchitectureCanvas from '../../components/visualizer/ArchitectureCanvas';
import ModuleInspector from '../../components/visualizer/ModuleInspector';
import StatsOverview from '../../components/visualizer/StatsOverview';
import LanguageBar from '../../components/visualizer/LanguageBar';
import RiskCard from '../../components/visualizer/RiskCard';
import RiskSummaryChart from '../../components/visualizer/RiskSummaryChart';
import SuggestionCard from '../../components/visualizer/SuggestionCard';
import ContributorGrid from '../../components/visualizer/ContributorGrid';
import CommitTimeline from '../../components/visualizer/CommitTimeline';
import VisualizerChat from '../../components/visualizer/VisualizerChat';
import AnalysisProgress from '../../components/visualizer/AnalysisProgress';
import { cn } from '../../lib/utils';

const Dashboard = () => {
  const { sessionId } = useParams();
  const navigate = useNavigate();
  const { 
    sessionId: storeSessionId, 
    status,
    activeTab, 
    setActiveTab,
    setAnalysisData,
    setStatus,
    setContributors,
    setCommits,
    modules,
    risks,
    suggestions,
    contributors,
    commits,
    github,
    repoOwner,
    repoName,
    setSelectedModule,
    setInspectorOpen,
    architectureSummary
  } = useProjectVisualizerStore();

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);
  const [moduleSearch, setModuleSearch] = useState('');
  const [riskFilter, setRiskFilter] = useState('all'); // all, critical, high, medium, low

  // Load Data if not in store
  useEffect(() => {
    if (!sessionId) return;
    
    if (storeSessionId !== sessionId || status !== 'complete') {
      loadAnalysisData(sessionId);
    } else {
      // Data is in store, let's lazy load the extra github data if missing
      if (!contributors || contributors.length === 0) {
        loadExtraData(sessionId);
      }
    }
  }, [sessionId, storeSessionId, status]); // eslint-disable-line react-hooks/exhaustive-deps

  const loadAnalysisData = async (id) => {
    try {
      setIsLoading(true);
      setError(null);
      const data = await projectVisualizerApi.getAnalysis(id);
      setAnalysisData(data);
      
      // Kick off extra loading
      loadExtraData(id);
    } catch (err) {
      console.error(err);
      setError("Failed to load analysis data or analysis not found.");
      setStatus('error');
    } finally {
      setIsLoading(false);
    }
  };

  const loadExtraData = async (id) => {
    try {
      projectVisualizerApi.getContributors(id).then(res => {
         if (res && res.length) setContributors(res);
      }).catch(e => console.warn('Failed to load contributors', e));
      
      projectVisualizerApi.getCommits(id).then(res => {
         if (res && res.length) setCommits(res);
      }).catch(e => console.warn('Failed to load commits', e));
    } catch (e) {
      // silent fail for extra data
    }
  };

  // Derived state for Modules tab
  const filteredModules = useMemo(() => {
    if (!modules) return [];
    let filtered = modules;
    if (moduleSearch) {
      const q = moduleSearch.toLowerCase();
      filtered = filtered.filter(m => 
        m.name.toLowerCase().includes(q) || 
        m.path.toLowerCase().includes(q)
      );
    }
    // Sort by file count desc by default
    return filtered.sort((a, b) => b.fileCount - a.fileCount);
  }, [modules, moduleSearch]);

  // Derived state for Risks tab
  const filteredRisks = useMemo(() => {
    if (!risks) return [];
    let filtered = risks;
    if (riskFilter !== 'all') {
      filtered = filtered.filter(r => r.severity === riskFilter);
    }
    
    // Sort by severity (critical -> high -> medium -> low)
    const order = { critical: 0, high: 1, medium: 2, low: 3 };
    return filtered.sort((a, b) => order[a.severity] - order[b.severity]);
  }, [risks, riskFilter]);

  if (isLoading || status === 'analyzing') {
    return <AnalysisProgress status={status === 'analyzing' ? 'analyzing' : 'complete'} />;
  }

  if (error) {
    return (
      <div className="min-h-screen bg-[#050505] flex flex-col items-center justify-center p-4">
        <AlertCircle className="w-16 h-16 text-red-500 mb-6" />
        <h2 className="text-2xl font-bold text-white mb-2">Analysis Error</h2>
        <p className="text-slate-400 mb-8 max-w-md text-center">{error}</p>
        <button 
          onClick={() => navigate('/project-visualizer')}
          className="px-6 py-3 bg-white/10 hover:bg-white/20 text-white rounded-xl transition-colors"
        >
          Back to Visualizer
        </button>
      </div>
    );
  }

  const tabs = [
    { id: 'architecture', label: 'Architecture', icon: Map, color: 'text-cyan-400', bg: 'bg-cyan-500/10' },
    { id: 'modules', label: 'Modules', icon: Grid3X3, color: 'text-violet-400', bg: 'bg-violet-500/10' },
    { id: 'risks', label: 'Risks', icon: AlertTriangle, color: 'text-orange-400', bg: 'bg-orange-500/10', count: risks?.length },
    { id: 'contributors', label: 'Contributors', icon: Users, color: 'text-pink-400', bg: 'bg-pink-500/10' }
  ];

  return (
    <div className="min-h-screen bg-[#050505] text-white flex flex-col overflow-hidden font-sans">
      
      {/* Header */}
      <header className="shrink-0 bg-[#0a0f1c] border-b border-white/5 py-4 px-6 flex flex-col md:flex-row md:items-center justify-between gap-4 sticky top-0 z-30 shadow-xl">
        <div className="flex flex-col gap-2">
          <button 
            onClick={() => navigate('/project-visualizer')}
            className="flex items-center gap-1.5 text-sm font-medium text-slate-400 hover:text-white transition-colors group w-max"
          >
            <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
            Back to Search
          </button>
          
          <div className="flex items-center gap-3 mt-1">
            <div className="p-2 bg-gradient-to-br from-cyan-500/20 to-violet-500/20 rounded-lg border border-white/10 shadow-inner">
              <GitBranch className="w-6 h-6 text-cyan-400" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">
                <span className="text-slate-400 font-medium">{repoOwner}</span>
                <span className="text-slate-500 mx-1">/</span>
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-300">{repoName}</span>
              </h1>
            </div>
          </div>
        </div>

        {/* Tab Navigation */}
        <div className="flex items-center p-1 bg-black/40 rounded-xl border border-white/5 overflow-x-auto custom-scrollbar md:w-auto w-full">
          {tabs.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={cn(
                "relative flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-medium transition-all duration-300 shrink-0",
                activeTab === tab.id 
                  ? "text-white shadow-sm" 
                  : "text-slate-400 hover:text-slate-200 hover:bg-white/5"
              )}
            >
              {activeTab === tab.id && (
                <motion.div 
                  layoutId="activeTab"
                  className={cn("absolute inset-0 rounded-lg", tab.bg)}
                  transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
                />
              )}
              <tab.icon className={cn("w-4 h-4 relative z-10", activeTab === tab.id ? tab.color : "")} />
              <span className="relative z-10">{tab.label}</span>
              
              {tab.count !== undefined && (
                <span className={cn(
                  "relative z-10 ml-1.5 px-2 py-0.5 rounded-full text-[10px] font-bold",
                  activeTab === tab.id ? "bg-white/20" : "bg-white/10"
                )}>
                  {tab.count}
                </span>
              )}
            </button>
          ))}
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto overflow-x-hidden relative custom-scrollbar pb-[80px]">
        <div className="p-4 md:p-6 lg:p-8 max-w-[1600px] mx-auto w-full h-full">
          <AnimatePresence mode="wait">
            
            {/* ARCHITECTURE TAB */}
            {activeTab === 'architecture' && (
              <motion.div 
                key="architecture"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.3 }}
                className="flex flex-col gap-6 h-full"
              >
                <StatsOverview />
                <LanguageBar languages={github?.languages} />
                
                {architectureSummary && (
                   <div className="bg-white/5 border border-white/10 rounded-2xl p-6 relative overflow-hidden group">
                     <div className="absolute top-0 right-0 w-64 h-64 bg-violet-500/5 rounded-full blur-3xl pointer-events-none" />
                     <h3 className="text-lg font-semibold text-white mb-3 flex items-center gap-2">
                       <Sparkles className="w-5 h-5 text-violet-400" /> AI Architecture Summary
                     </h3>
                     <p className="text-slate-300 leading-relaxed max-w-5xl whitespace-pre-wrap text-sm">
                       {architectureSummary}
                     </p>
                   </div>
                )}
                
                <div className="flex-1 min-h-[600px] rounded-2xl overflow-hidden shadow-2xl border border-white/10">
                  <ArchitectureCanvas />
                </div>
              </motion.div>
            )}

            {/* MODULES TAB */}
            {activeTab === 'modules' && (
              <motion.div 
                key="modules"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.3 }}
                className="h-full flex flex-col"
              >
                <div className="flex items-center justify-between mb-6">
                  <h2 className="text-2xl font-bold text-white flex items-center gap-3">
                    <Grid3X3 className="w-6 h-6 text-violet-400" />
                    Project Modules ({modules?.length || 0})
                  </h2>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input
                      type="text"
                      placeholder="Search modules..."
                      value={moduleSearch}
                      onChange={(e) => setModuleSearch(e.target.value)}
                      className="pl-9 pr-4 py-2 rounded-xl bg-white/5 border border-white/10 text-white placeholder-slate-500 focus:outline-none focus:border-violet-500/50 transition-colors w-64"
                    />
                  </div>
                </div>

                <div className="bg-white/5 border border-white/10 rounded-2xl overflow-hidden flex-1">
                  <div className="overflow-x-auto h-full custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                      <thead>
                        <tr className="bg-white/5 text-slate-400 text-sm font-medium border-b border-white/10">
                          <th className="p-4 whitespace-nowrap">Module Name</th>
                          <th className="p-4 whitespace-nowrap">Path</th>
                          <th className="p-4 whitespace-nowrap">Type</th>
                          <th className="p-4 whitespace-nowrap text-right">Files</th>
                          <th className="p-4 whitespace-nowrap text-right">LOC</th>
                          <th className="p-4 whitespace-nowrap text-right">Dependencies</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-white/5">
                        {filteredModules.map(mod => (
                          <tr 
                            key={mod.name}
                            onClick={() => {
                              setSelectedModule(mod);
                              setInspectorOpen(true);
                            }}
                            className="hover:bg-white/5 transition-colors cursor-pointer group"
                          >
                            <td className="p-4">
                              <div className="flex items-center gap-3">
                                <Box className="w-5 h-5 text-slate-500 group-hover:text-violet-400 transition-colors" />
                                <span className="font-semibold text-white">{mod.name}</span>
                              </div>
                            </td>
                            <td className="p-4 text-slate-400 font-mono text-xs">{mod.path}</td>
                            <td className="p-4">
                              <span className="px-2.5 py-1 rounded-full bg-slate-800 text-slate-300 text-xs font-bold uppercase tracking-wider">
                                {mod.type}
                              </span>
                            </td>
                            <td className="p-4 text-right text-slate-300 font-medium">{mod.fileCount}</td>
                            <td className="p-4 text-right text-slate-400">{mod.loc.toLocaleString()}</td>
                            <td className="p-4 text-right text-slate-400">
                              {mod.dependencies ? mod.dependencies.length : 0}
                            </td>
                          </tr>
                        ))}
                        {filteredModules.length === 0 && (
                          <tr>
                            <td colSpan="6" className="p-8 text-center text-slate-500">
                              No modules found matching your search.
                            </td>
                          </tr>
                        )}
                      </tbody>
                    </table>
                  </div>
                </div>
              </motion.div>
            )}

            {/* RISKS TAB */}
            {activeTab === 'risks' && (
              <motion.div 
                key="risks"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.3 }}
                className="h-full flex flex-col gap-6"
              >
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                  {/* Chart */}
                  <div className="lg:col-span-1">
                    <RiskSummaryChart risks={risks} />
                  </div>
                  
                  {/* AI Suggestions */}
                  <div className="lg:col-span-2 bg-white/5 border border-white/10 rounded-2xl p-6">
                    <h3 className="text-lg font-semibold text-white mb-6 flex items-center gap-2">
                      <Sparkles className="w-5 h-5 text-violet-400" /> AI Improvement Suggestions
                    </h3>
                    
                    {suggestions && suggestions.length > 0 ? (
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {suggestions.map((sug, i) => (
                          <SuggestionCard key={i} suggestion={sug} index={i} />
                        ))}
                      </div>
                    ) : (
                      <div className="h-40 flex items-center justify-center text-slate-500 border border-dashed border-white/10 rounded-xl">
                        No AI suggestions generated for this repository.
                      </div>
                    )}
                  </div>
                </div>
                
                {/* Detailed Risks List */}
                <div className="mt-4">
                  <div className="flex items-center justify-between mb-6">
                    <h3 className="text-xl font-bold text-white flex items-center gap-2">
                      <AlertTriangle className="w-5 h-5 text-orange-400" />
                      Detailed Hotspots ({filteredRisks.length})
                    </h3>
                    
                    <div className="flex items-center gap-2 bg-black/30 p-1 rounded-lg border border-white/10">
                      {['all', 'critical', 'high', 'medium', 'low'].map(f => (
                        <button
                          key={f}
                          onClick={() => setRiskFilter(f)}
                          className={cn(
                            "px-3 py-1.5 rounded-md text-xs font-bold uppercase tracking-wider transition-colors",
                            riskFilter === f 
                              ? "bg-white/10 text-white" 
                              : "text-slate-500 hover:text-slate-300"
                          )}
                        >
                          {f}
                        </button>
                      ))}
                    </div>
                  </div>
                  
                  {filteredRisks.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                      {filteredRisks.map((risk, i) => (
                        <RiskCard key={i} risk={risk} />
                      ))}
                    </div>
                  ) : (
                    <div className="bg-white/5 border border-white/10 rounded-2xl p-12 text-center flex flex-col items-center justify-center">
                      <CheckCircle2 className="w-12 h-12 text-green-500/50 mb-4" />
                      <p className="text-slate-400">No risks matching the selected filter.</p>
                    </div>
                  )}
                </div>
              </motion.div>
            )}

            {/* CONTRIBUTORS TAB */}
            {activeTab === 'contributors' && (
              <motion.div 
                key="contributors"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.3 }}
                className="h-full flex flex-col gap-6"
              >
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                  <div className="lg:col-span-2">
                    <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-3">
                      <Users className="w-6 h-6 text-pink-400" />
                      Top Contributors
                    </h2>
                    <ContributorGrid contributors={contributors} />
                  </div>
                  
                  <div className="lg:col-span-1">
                    <CommitTimeline commits={commits} />
                  </div>
                </div>
              </motion.div>
            )}

          </AnimatePresence>
        </div>
      </main>

      {/* Slide-in Inspector Panel */}
      <ModuleInspector />
      
      {/* Docked Chat */}
      <VisualizerChat />
      
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import {
  GitBranch, Search, Zap, Users, Bot, AlertTriangle, 
  ArrowRight, History, Loader2, Trash2, Clock, Star, GitFork
} from 'lucide-react';
import toast from 'react-hot-toast';
import { useProjectVisualizerStore } from '../../stores/useProjectVisualizerStore';
import { projectVisualizerApi } from '../../services/api';
import { cn } from '../../lib/utils';

const Landing = () => {
  const [url, setUrl] = useState('');
  const [history, setHistory] = useState([]);
  const [isLoadingHistory, setIsLoadingHistory] = useState(true);
  
  const navigate = useNavigate();
  const { setStatus, setAnalysisData, setRepoUrl, status, reset } = useProjectVisualizerStore();

  useEffect(() => {
    reset();
    loadHistory();
  }, []);

  const loadHistory = async () => {
    try {
      setIsLoadingHistory(true);
      const data = await projectVisualizerApi.getHistory();
      if (data?.success !== false) {
        setHistory(data);
      }
    } catch (e) {
      console.warn("Failed to load history");
    } finally {
      setIsLoadingHistory(false);
    }
  };

  const handleDeleteHistory = async (id, e) => {
    e.stopPropagation();
    try {
      await projectVisualizerApi.deleteHistory(id);
      setHistory(prev => prev.filter(h => h._id !== id));
      toast.success('History deleted');
    } catch (e) {
      toast.error('Failed to delete history');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!url.includes('github.com')) {
      toast.error('Please enter a valid GitHub repository URL');
      return;
    }

    try {
      setStatus('analyzing');
      setRepoUrl(url);
      
      toast.loading('Analyzing repository...', { id: 'analyze' });
      
      const result = await projectVisualizerApi.analyze(url);
      
      toast.success('Analysis complete!', { id: 'analyze' });
      
      setAnalysisData(result);
      navigate(`/project-visualizer/dashboard/${result.sessionId}`);
      
    } catch (error) {
      setStatus('error');
      toast.error(error.message || 'Failed to analyze repository', { id: 'analyze' });
    }
  };

  const features = [
    {
      title: "Architecture Map",
      desc: "Interactive visual module dependency graph",
      icon: <GitBranch className="w-6 h-6 text-cyan-400" />,
      color: "from-cyan-500/20 to-cyan-500/0"
    },
    {
      title: "Risk & Hotspots",
      desc: "Identify complexity, coupling, and missing tests",
      icon: <AlertTriangle className="w-6 h-6 text-orange-400" />,
      color: "from-orange-500/20 to-orange-500/0"
    },
    {
      title: "Contributor Insights",
      desc: "Who owns what, activity patterns and history",
      icon: <Users className="w-6 h-6 text-pink-400" />,
      color: "from-pink-500/20 to-pink-500/0"
    },
    {
      title: "AI Onboarding",
      desc: "Ask questions, get starting points for contribution",
      icon: <Bot className="w-6 h-6 text-violet-400" />,
      color: "from-violet-500/20 to-violet-500/0"
    }
  ];

  return (
    
    <div className="min-h-screen bg-background text-foreground overflow-x-hidden relative">
      
      {/* Background Gradients */}
      <div className="absolute top-[-20%] left-[-10%] w-[50%] h-[50%] rounded-full bg-cyan-600/10 blur-[120px] pointer-events-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] rounded-full bg-violet-600/10 blur-[120px] pointer-events-none" />
      
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-20 pb-24 relative z-10">
        
        {/* Header Section */}
        <div className="text-center max-w-3xl mx-auto mb-16">
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
            
            className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-muted border border-border mb-8"
          >
            <Zap className="w-4 h-4 text-cyan-400" />
           
            <span className="text-sm font-medium text-muted-foreground">Repo-to-Map in 10 seconds</span>
          </motion.div>
          
          <motion.h1
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.1 }}
            className="text-5xl md:text-7xl font-bold tracking-tight mb-6"
          >
            Project{' '}
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-violet-500">
              Visualizer
            </span>
          </motion.h1>
          
          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.5, delay: 0.2 }}
            
            className="text-xl text-muted-foreground"
          >
            Paste a GitHub repo → get a visual architecture map + AI onboarding in seconds.
          </motion.p>
        </div>

        {/* URL Input Form */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.3 }}
          className="max-w-2xl mx-auto mb-24"
        >
          <form onSubmit={handleSubmit} className="relative group">
            <div className="absolute -inset-1 bg-gradient-to-r from-cyan-500 to-violet-500 rounded-2xl blur opacity-25 group-hover:opacity-40 transition duration-500"></div>
            
            <div className="relative flex items-center bg-muted border border-border rounded-2xl p-2 pl-6 shadow-2xl">
              <Search className="w-6 h-6 text-muted-foreground mr-4 shrink-0" />
              <input
                type="text"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                placeholder="https://github.com/owner/repository"
                
                className="w-full bg-transparent border-none outline-none text-lg text-foreground placeholder:text-muted-foreground"
                disabled={status === 'analyzing'}
              />
              <button
                type="submit"
                disabled={status === 'analyzing' || !url}
                className={cn(
                  "ml-4 px-8 py-4 rounded-xl font-semibold text-white flex items-center gap-2 transition-all shrink-0",
                  status === 'analyzing'
                    ? "bg-muted cursor-not-allowed text-muted-foreground"
                    : "bg-gradient-to-r from-cyan-500 to-violet-500 hover:shadow-lg hover:shadow-cyan-500/25 active:scale-95"
                )}
              >
                {status === 'analyzing' ? (
                  <>
                    <Loader2 className="w-5 h-5 animate-spin" />
                    Analyzing...
                  </>
                ) : (
                  <>
                    Visualize <ArrowRight className="w-5 h-5" />
                  </>
                )}
              </button>
            </div>
          </form>
        </motion.div>

        {/* Feature Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-5xl mx-auto mb-24">
          {features.map((feature, i) => (
            <motion.div
              key={i}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.4 + i * 0.1 }}
              
              className="relative p-6 rounded-2xl bg-muted border border-border overflow-hidden group hover:border-primary/50 transition-colors"
            >
              <div className={cn("absolute inset-0 bg-gradient-to-br opacity-0 group-hover:opacity-100 transition-opacity duration-500", feature.color)} />
              <div className="relative z-10 flex items-start gap-4">
                
                <div className="p-3 rounded-xl bg-background border border-border">
                  {feature.icon}
                </div>
                <div>
                
                  <h3 className="text-xl font-semibold text-foreground mb-2">{feature.title}</h3>
                 
                  <p className="text-muted-foreground leading-relaxed">{feature.desc}</p>
                </div>
              </div>
            </motion.div>
          ))}
        </div>

        {/* How It Works */}
        <motion.div 
           initial={{ opacity: 0 }}
           animate={{ opacity: 1 }}
           transition={{ duration: 0.5, delay: 0.8 }}
           className="text-center mb-24"
        >
           
           <h2 className="text-3xl font-bold text-foreground mb-12">How it works</h2>
           <div className="flex flex-col md:flex-row items-center justify-center gap-8 max-w-4xl mx-auto">
             {[
               { num: "1", text: "Paste any public GitHub repository URL" },
               { num: "2", text: "Our AI engine analyzes the structure and codebase" },
               { num: "3", text: "Explore the visual map and chat with the repository" }
             ].map((step, i) => (
                <div key={i} className="flex flex-col items-center flex-1">
                  <div className="w-12 h-12 rounded-full bg-cyan-500/20 text-cyan-400 flex items-center justify-center text-xl font-bold mb-4 border border-cyan-500/30">
                    {step.num}
                  </div>
                  
                  <p className="text-muted-foreground">{step.text}</p>
                </div>
             ))}
           </div>
        </motion.div>

        {/* Recent Analysis History */}
        {!isLoadingHistory && history.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 1 }}
            className="max-w-4xl mx-auto"
          >
            
            <div className="flex items-center gap-2 mb-6 text-muted-foreground">
              <History className="w-5 h-5" />
              <h2 className="text-xl font-semibold">Recent Analyses</h2>
            </div>
            
            <div className="grid gap-4">
              {history.map((item) => (
                <div
                  key={item._id}
                  onClick={() => navigate(`/project-visualizer/dashboard/${item.sessionId}`)}
                 
                  className="flex items-center justify-between p-4 rounded-xl bg-muted border border-border hover:bg-accent cursor-pointer transition-all group"
                >
                  <div className="flex items-center gap-4">
                  
                    <div className="p-3 rounded-lg bg-background border border-border">
                      <GitBranch className="w-6 h-6 text-cyan-400" />
                    </div>
                    <div>
                      
                      <h3 className="font-semibold text-lg text-foreground group-hover:text-cyan-400 transition-colors">
                        {item.repoOwner} / {item.repoName}
                      </h3>
                     
                      <div className="flex items-center gap-4 text-sm text-muted-foreground mt-1">
                        <span className="flex items-center gap-1">
                          <Clock className="w-4 h-4" />
                          {new Date(item.lastAnalyzed).toLocaleDateString()}
                        </span>
                        {item.github?.stars !== undefined && (
                          <span className="flex items-center gap-1">
                            <Star className="w-4 h-4 text-yellow-500" />
                            {item.github.stars}
                          </span>
                        )}
                        {item.stats?.totalFiles !== undefined && (
                          <span className="flex items-center gap-1">
                            <GitFork className="w-4 h-4" />
                            {item.stats.totalFiles} files
                          </span>
                        )}
                      </div>
                    </div>
                  </div>
                  
                  <button
                    onClick={(e) => handleDeleteHistory(item._id, e)}
                    className="p-2 rounded-lg text-muted-foreground hover:text-red-400 hover:bg-red-400/10 transition-colors opacity-0 group-hover:opacity-100"
                  >
                    <Trash2 className="w-5 h-5" />
                  </button>
                </div>
              ))}
            </div>
          </motion.div>
        )}

      </div>
    </div>
  );
};

export default Landing;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Github, Loader2, GitMerge, Clock, Search, ExternalLink } from 'lucide-react';
import { analyzerApi } from '../../services/api';
import { useAnalyzerStore } from '../../stores/useAnalyzerStore';
import toast from 'react-hot-toast';

export default function RepoAnalyzerDashboard() {
  const [urlInput, setUrlInput] = useState('');
  const [history, setHistory] = useState([]);
  const [loadingHistory, setLoadingHistory] = useState(true);
  const navigate = useNavigate();
  
  const { 
    setRepoUrl, 
    setSessionId, 
    setGraph, 
    isLoading,
    setIsLoading
  } = useAnalyzerStore();

  useEffect(() => {
    loadHistory();
  }, []);

  const loadHistory = async () => {
    try {
      setLoadingHistory(true);
      const data = await analyzerApi.getHistory();
      setHistory(data);
    } catch (error) {
      console.error(error);
      toast.error('Failed to load analysis history');
    } finally {
      setLoadingHistory(false);
    }
  };

  const handleIngest = async (url) => {
    const targetUrl = url || urlInput.trim();
    if (!targetUrl) return;

    if (!targetUrl.includes('github.com')) {
      toast.error('Please enter a valid GitHub repository URL');
      return;
    }

    try {
      setIsLoading(true);
      const res = await analyzerApi.ingest(targetUrl);
      
      setSessionId(res.sessionId);
      setGraph(res.nodes, res.edges);
      setRepoUrl(targetUrl);
      
      toast.success('Repository ingested successfully!');
      navigate('/repo-analyzer/workspace');
    } catch (error) {
      console.error(error);
      toast.error('Failed to ingest repository. Make sure it is public.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    handleIngest();
  };

  return (
    <div className="min-h-[calc(100vh-4rem)] bg-[#050816] text-white p-6 md:p-10">
      <div className="max-w-5xl mx-auto">
        <div className="mb-12">
          <div className="flex items-center gap-3 mb-6">
            <div className="p-3 bg-blue-500/10 rounded-xl">
              <GitMerge className="w-6 h-6 text-blue-500" />
            </div>
            <div>
              <h1 className="text-2xl font-bold">Analyzer Dashboard</h1>
              <p className="text-slate-400 text-sm mt-1">Ingest a new repository or open a previously analyzed one.</p>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="relative group">
            <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-xl blur opacity-25 group-hover:opacity-40 transition duration-1000 group-hover:duration-200"></div>
            <div className="relative flex items-center bg-[#0f172a] rounded-xl border border-slate-700/50 p-2">
              <Search className="w-5 h-5 text-slate-500 ml-3" />
              <input
                type="text"
                value={urlInput}
                onChange={(e) => setUrlInput(e.target.value)}
                placeholder="Paste GitHub Repository URL (e.g., https://github.com/expressjs/express)"
                className="flex-1 bg-transparent border-none focus:outline-none text-slate-200 px-4 py-3 placeholder:text-slate-500"
              />
              <button
                type="submit"
                disabled={isLoading || (!urlInput.trim() && !isLoading)}
                className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-medium rounded-lg disabled:opacity-50 transition-colors flex items-center gap-2 cursor-pointer"
              >
                {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <GitMerge className="w-4 h-4" />}
                Analyze Now
              </button>
            </div>
          </form>
        </div>

        <div>
          <h2 className="text-xl font-semibold mb-6 flex items-center gap-2">
            <Clock className="w-5 h-5 text-slate-400" />
            Analysis History
          </h2>

          {loadingHistory ? (
            <div className="flex items-center justify-center py-20">
              <Loader2 className="w-8 h-8 animate-spin text-slate-500" />
            </div>
          ) : history.length === 0 ? (
            <div className="text-center py-20 bg-[#0f172a]/50 rounded-2xl border border-slate-800 border-dashed">
              <Github className="w-12 h-12 text-slate-600 mx-auto mb-4" />
              <p className="text-slate-400 font-medium">No repositories analyzed yet.</p>
              <p className="text-sm text-slate-500 mt-1">Paste a URL above to get started.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {history.map((item) => {
                const repoName = item.repoUrl.replace('https://github.com/', '').replace(/\/$/, '');
                return (
                  <motion.div
                    key={item._id}
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="p-5 rounded-xl bg-[#0f172a] border border-slate-800 hover:border-blue-500/50 hover:bg-[#1e293b]/50 transition-all group cursor-pointer"
                    onClick={() => handleIngest(item.repoUrl)}
                  >
                    <div className="flex justify-between items-start mb-4">
                      <div className="p-2 bg-slate-800 rounded-lg group-hover:bg-blue-500/10 group-hover:text-blue-400 transition-colors">
                        <Github className="w-5 h-5" />
                      </div>
                      <span className="text-xs text-slate-500 font-mono flex items-center gap-1">
                        <Clock className="w-3 h-3" />
                        {new Date(item.lastAnalyzed).toLocaleDateString()}
                      </span>
                    </div>
                    <h3 className="font-semibold text-slate-200 truncate mb-1" title={repoName}>
                      {repoName}
                    </h3>
                    <p className="text-xs text-slate-500 truncate mb-4">
                      {item.repoUrl}
                    </p>
                    <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-800/50">
                      <span className="text-sm font-medium text-slate-400 group-hover:text-blue-400 transition-colors">
                        Re-Analyze Workspace
                      </span>
                      <ExternalLink className="w-4 h-4 text-slate-600 group-hover:text-blue-400 transition-colors" />
                    </div>
                  </motion.div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

