import React, { useRef, useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { useNavigate } from 'react-router-dom'
import {
  ArrowLeft, ArrowRight, CheckCircle, Plus, Trash2,
  Save, FileText, User, Briefcase, GraduationCap, Code, Star
} from 'lucide-react'
import { resumeApi } from '../services/api'
import { toast } from 'react-hot-toast'
import { cn } from '@/lib/utils'
import PhoneInput from '../components/PhoneInput'
import {
  validatePersonalStep,
  validateEducationStep,
  validateExperienceStep,
  hasErrors,
} from '../utils/resumeValidation'

const STEPS = [
  { id: 'personal',   title: 'Personal Info', icon: User },
  { id: 'education',  title: 'Education',     icon: GraduationCap },
  { id: 'experience', title: 'Experience',    icon: Briefcase },
  { id: 'projects',   title: 'Projects',      icon: Code },
  { id: 'skills',     title: 'Skills',        icon: Star },
  { id: 'preview',    title: 'Preview',       icon: FileText },
]

// ─────────────────── small helpers ───────────────────────────────────────────
/** Red border class when an error exists for a field key. */
function errBorder(errors, key) {
  return errors?.[key] ? 'border-red-500 focus:ring-red-400/30' : 'border-border'
}

/** Inline error message below a field. */
function FieldError({ msg }) {
  if (!msg) return null
  return (
    <p className="text-red-500 text-sm mt-1" role="alert">{msg}</p>
  )
}

// ─────────────────── component ───────────────────────────────────────────────
export default function ResumeBuilder() {
  const navigate   = useNavigate()
  const firstErrRef = useRef(null)

  const [currentStep, setCurrentStep] = useState(0)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [targetRole, setTargetRole]   = useState('')

  // ── form state ──────────────────────────────────────────────────────────────
  const [personal, setPersonal] = useState({
    name: '', email: '', phone: '', linkedin: '', github: '', portfolio: '', summary: '',
  })
  // phone is stored split: country code + digit string
  const [phoneCode,   setPhoneCode]   = useState('+91')
  const [phoneDigits, setPhoneDigits] = useState('')

  const [education, setEducation] = useState([
    { school: '', degree: '', field: '', startDate: '', endDate: '', gpa: '', description: '' }
  ])
  const [experience, setExperience] = useState([
    { title: '', company: '', location: '', startDate: '', endDate: '', current: false, description: '' }
  ])
  const [projects, setProjects] = useState([
    { name: '', tech: '', link: '', description: '' }
  ])
  const [skills, setSkills] = useState('')

  // ── error state ─────────────────────────────────────────────────────────────
  const [personalErrors,   setPersonalErrors]   = useState({})
  const [educationErrors,  setEducationErrors]  = useState([])   // array per entry
  const [experienceErrors, setExperienceErrors] = useState([])   // array per entry

  // ── helpers: update array entries immutably ─────────────────────────────────
  function updateEdu(index, key, value) {
    setEducation(prev => {
      const next = [...prev]
      next[index] = { ...next[index], [key]: value }
      return next
    })
    // Clear the matching error on change
    setEducationErrors(prev => {
      const next = [...prev]
      if (next[index]) { next[index] = { ...next[index], [key]: '' } }
      return next
    })
  }

  function updateExp(index, key, value) {
    setExperience(prev => {
      const next = [...prev]
      next[index] = { ...next[index], [key]: value }
      return next
    })
    setExperienceErrors(prev => {
      const next = [...prev]
      if (next[index]) { next[index] = { ...next[index], [key]: '' } }
      return next
    })
  }

  function updatePersonal(key, value) {
    setPersonal(prev => ({ ...prev, [key]: value }))
    if (personalErrors[key]) {
      setPersonalErrors(prev => ({ ...prev, [key]: '' }))
    }
  }

  // ── list management ──────────────────────────────────────────────────────────
  const addEducation    = () => setEducation(p => [...p, { school: '', degree: '', field: '', startDate: '', endDate: '', gpa: '', description: '' }])
  const removeEducation = i  => { setEducation(p => p.filter((_, idx) => idx !== i)); setEducationErrors(p => p.filter((_, idx) => idx !== i)) }

  const addExperience    = () => setExperience(p => [...p, { title: '', company: '', location: '', startDate: '', endDate: '', current: false, description: '' }])
  const removeExperience = i  => { setExperience(p => p.filter((_, idx) => idx !== i)); setExperienceErrors(p => p.filter((_, idx) => idx !== i)) }

  const addProject    = () => setProjects(p => [...p, { name: '', tech: '', link: '', description: '' }])
  const removeProject = i  => setProjects(p => p.filter((_, idx) => idx !== i))

  // ── step validation ──────────────────────────────────────────────────────────
  function validateCurrentStep() {
    switch (currentStep) {
      case 0: {
        const errs = validatePersonalStep(personal, targetRole, phoneDigits)
        setPersonalErrors(errs)
        return !hasErrors(errs)
      }
      case 1: {
        const errs = validateEducationStep(education)
        setEducationErrors(errs)
        return !hasErrors(errs)
      }
      case 2: {
        const errs = validateExperienceStep(experience)
        setExperienceErrors(errs)
        return !hasErrors(errs)
      }
      default:
        return true
    }
  }

  function handleNext() {
    if (!validateCurrentStep()) {
      // Focus first invalid field
      setTimeout(() => {
        const el = document.querySelector('[aria-invalid="true"], .border-red-500')
        el?.focus()
        el?.scrollIntoView({ behavior: 'smooth', block: 'center' })
      }, 50)
      return
    }
    setCurrentStep(s => Math.min(s + 1, STEPS.length - 1))
  }

  const handlePrev = () => setCurrentStep(s => Math.max(s - 1, 0))

  // ── markdown preview & generate ──────────────────────────────────────────────
  const generateMarkdown = () => {
    // Compose full phone string
    const fullPhone = phoneDigits ? `${phoneCode} ${phoneDigits}` : ''
    let md = `# ${personal.name || 'Your Name'}\n\n`

    const contact = []
    if (personal.email)     contact.push(`[${personal.email}](mailto:${personal.email})`)
    if (fullPhone)          contact.push(fullPhone)
    if (personal.linkedin)  contact.push(`[LinkedIn](${personal.linkedin})`)
    if (personal.github)    contact.push(`[GitHub](${personal.github})`)
    if (personal.portfolio) contact.push(`[Portfolio](${personal.portfolio})`)
    md += `${contact.join(' | ')}\n\n`

    if (personal.summary) md += `## SUMMARY\n\n${personal.summary}\n\n`

    if (education.some(e => e.school)) {
      md += `## EDUCATION\n\n`
      education.forEach(e => {
        if (!e.school) return
        md += `**${e.degree}${e.field ? ' in ' + e.field : ''}** | ${e.school} | ${e.startDate} - ${e.endDate}\n`
        if (e.gpa) md += `- GPA: ${e.gpa}\n`
        if (e.description) md += `- ${e.description}\n`
        md += '\n'
      })
    }

    if (experience.some(e => e.title)) {
      md += `## EXPERIENCE\n\n`
      experience.forEach(e => {
        if (!e.title) return
        md += `**${e.title}** | ${e.company} | ${e.location} | ${e.startDate} - ${e.current ? 'Present' : e.endDate}\n`
        const bullets = e.description.split('\n').filter(b => b.trim())
        bullets.forEach(b => { md += `- ${b.replace(/^- /, '').trim()}\n` })
        md += '\n'
      })
    }

    if (projects.some(p => p.name)) {
      md += `## PROJECTS\n\n`
      projects.forEach(p => {
        if (!p.name) return
        md += `**${p.name}** | ${p.tech}\n`
        const bullets = p.description.split('\n').filter(b => b.trim())
        bullets.forEach(b => { md += `- ${b.replace(/^- /, '').trim()}\n` })
        if (p.link) md += `- [Project Link](${p.link})\n`
        md += '\n'
      })
    }

    if (skills) md += `## SKILLS\n\n${skills}\n\n`

    return md
  }

  const handleGenerate = async () => {
    try {
      setIsSubmitting(true)
      const markdown = generateMarkdown()
      const response = await resumeApi.create({
        originalText: markdown,
        jobRole: targetRole || 'Software Engineer',
        title:   `${personal.name || 'My'} Resume - ${new Date().toLocaleDateString()}`,
      })
      toast.success('Resume created successfully!')
      navigate(`/enhance/${response.data.id}`)
    } catch (error) {
      toast.error(error.message || 'Failed to create resume')
    } finally {
      setIsSubmitting(false)
    }
  }

  // ── shared input class builder ────────────────────────────────────────────────
  const inputCls = (errorKey, errors = personalErrors) =>
    cn(
      'w-full bg-background/50 border rounded-xl px-4 py-2 transition-colors',
      'focus:outline-none focus:ring-2 focus:ring-primary/30',
      errors?.[errorKey] ? 'border-red-500 focus:ring-red-400/30' : 'border-border'
    )

  const inputClsArr = (errors) => (errorKey) =>
    cn(
      'w-full bg-background/50 border rounded-lg px-4 py-2 transition-colors',
      'focus:outline-none focus:ring-2 focus:ring-primary/30',
      errors?.[errorKey] ? 'border-red-500 focus:ring-red-400/30' : 'border-border'
    )

  // ── step renderers ────────────────────────────────────────────────────────────
  const renderStep = () => {
    switch (currentStep) {

      /* ── Step 0: Personal Info ── */
      case 0:
        return (
          <div className="space-y-4">
            <h2 className="text-2xl font-semibold mb-6">Personal Information</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

              {/* Full Name */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="name">
                  Full Name <span className="text-red-500">*</span>
                </label>
                <input
                  id="name"
                  type="text"
                  className={inputCls('name')}
                  value={personal.name}
                  onChange={e => updatePersonal('name', e.target.value)}
                  placeholder="John Doe"
                  aria-invalid={!!personalErrors.name}
                  aria-describedby={personalErrors.name ? 'name-error' : undefined}
                />
                <FieldError msg={personalErrors.name} />
              </div>

              {/* Target Job Role */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="targetRole">
                  Target Job Role <span className="text-red-500">*</span>
                </label>
                <input
                  id="targetRole"
                  type="text"
                  className={inputCls('targetRole')}
                  value={targetRole}
                  onChange={e => {
                    setTargetRole(e.target.value)
                    if (personalErrors.targetRole) setPersonalErrors(p => ({ ...p, targetRole: '' }))
                  }}
                  placeholder="Software Engineer"
                  aria-invalid={!!personalErrors.targetRole}
                />
                <FieldError msg={personalErrors.targetRole} />
              </div>

              {/* Email */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="email">
                  Email <span className="text-red-500">*</span>
                </label>
                <input
                  id="email"
                  type="email"
                  className={inputCls('email')}
                  value={personal.email}
                  onChange={e => updatePersonal('email', e.target.value)}
                  placeholder="john@example.com"
                  aria-invalid={!!personalErrors.email}
                />
                <FieldError msg={personalErrors.email} />
              </div>

              {/* Phone */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="phone-number">
                  Phone <span className="text-red-500">*</span>
                </label>
                <PhoneInput
                  countryCode={phoneCode}
                  onCountryChange={code => {
                    setPhoneCode(code)
                    if (personalErrors.phone) setPersonalErrors(p => ({ ...p, phone: '' }))
                  }}
                  digits={phoneDigits}
                  onDigitsChange={d => {
                    setPhoneDigits(d)
                    if (personalErrors.phone) setPersonalErrors(p => ({ ...p, phone: '' }))
                  }}
                  error={personalErrors.phone}
                />
              </div>

              {/* LinkedIn */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="linkedin">LinkedIn URL</label>
                <input
                  id="linkedin"
                  type="url"
                  className={inputCls('linkedin')}
                  value={personal.linkedin}
                  onChange={e => updatePersonal('linkedin', e.target.value)}
                  placeholder="https://www.linkedin.com/in/johndoe"
                  aria-invalid={!!personalErrors.linkedin}
                />
                <FieldError msg={personalErrors.linkedin} />
              </div>

              {/* GitHub */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="github">GitHub URL</label>
                <input
                  id="github"
                  type="url"
                  className={inputCls('github')}
                  value={personal.github}
                  onChange={e => updatePersonal('github', e.target.value)}
                  placeholder="https://github.com/johndoe"
                  aria-invalid={!!personalErrors.github}
                />
                <FieldError msg={personalErrors.github} />
              </div>
            </div>

            {/* Summary */}
            <div className="pt-2">
              <label className="block text-sm font-medium mb-1" htmlFor="summary">Professional Summary</label>
              <textarea
                id="summary"
                className="w-full bg-background/50 border border-border rounded-xl px-4 py-2 min-h-[100px] focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                value={personal.summary}
                onChange={e => updatePersonal('summary', e.target.value)}
                placeholder="A brief summary of your professional background..."
              />
            </div>
          </div>
        )

      /* ── Step 1: Education ── */
      case 1:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-semibold mb-6">Education</h2>
            {education.map((edu, index) => {
              const errs = educationErrors[index] || {}
              const ic = inputClsArr(errs)
              return (
                <div key={index} className="bg-background/30 p-5 rounded-xl border border-border relative">
                  <button
                    onClick={() => removeEducation(index)}
                    className="absolute top-4 right-4 text-muted-foreground hover:text-red-500 transition-colors"
                    aria-label="Remove education entry"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        School <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="text"
                        className={ic('school')}
                        value={edu.school}
                        onChange={e => updateEdu(index, 'school', e.target.value)}
                        placeholder="University Name"
                        aria-invalid={!!errs.school}
                      />
                      <FieldError msg={errs.school} />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        Degree <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="text"
                        className={ic('degree')}
                        value={edu.degree}
                        onChange={e => updateEdu(index, 'degree', e.target.value)}
                        placeholder="B.S., M.S., etc."
                        aria-invalid={!!errs.degree}
                      />
                      <FieldError msg={errs.degree} />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">Field of Study</label>
                      <input
                        type="text"
                        className={ic('field')}
                        value={edu.field}
                        onChange={e => updateEdu(index, 'field', e.target.value)}
                        placeholder="Computer Science"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">GPA (Optional)</label>
                      <input
                        type="text"
                        className={ic('gpa')}
                        value={edu.gpa}
                        onChange={e => updateEdu(index, 'gpa', e.target.value)}
                        placeholder="3.8/4.0"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        Start Date <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="month"
                        className={ic('startDate')}
                        value={edu.startDate}
                        onChange={e => updateEdu(index, 'startDate', e.target.value)}
                        aria-invalid={!!errs.startDate}
                      />
                      <FieldError msg={errs.startDate} />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        End Date <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="month"
                        className={ic('endDate')}
                        value={edu.endDate}
                        onChange={e => updateEdu(index, 'endDate', e.target.value)}
                        aria-invalid={!!errs.endDate}
                      />
                      <FieldError msg={errs.endDate} />
                    </div>

                  </div>
                </div>
              )
            })}
            <button onClick={addEducation} className="flex items-center gap-2 text-primary hover:text-primary/80 transition-colors">
              <Plus className="w-4 h-4" /> Add Education
            </button>
          </div>
        )

      /* ── Step 2: Experience ── */
      case 2:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-semibold mb-6">Experience</h2>
            {experience.map((exp, index) => {
              const errs = experienceErrors[index] || {}
              const ic = inputClsArr(errs)
              return (
                <div key={index} className="bg-background/30 p-5 rounded-xl border border-border relative">
                  <button
                    onClick={() => removeExperience(index)}
                    className="absolute top-4 right-4 text-muted-foreground hover:text-red-500 transition-colors"
                    aria-label="Remove experience entry"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        Job Title <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="text"
                        className={ic('title')}
                        value={exp.title}
                        onChange={e => updateExp(index, 'title', e.target.value)}
                        placeholder="Software Engineer"
                        aria-invalid={!!errs.title}
                      />
                      <FieldError msg={errs.title} />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        Company <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="text"
                        className={ic('company')}
                        value={exp.company}
                        onChange={e => updateExp(index, 'company', e.target.value)}
                        placeholder="Tech Corp"
                        aria-invalid={!!errs.company}
                      />
                      <FieldError msg={errs.company} />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">Location</label>
                      <input
                        type="text"
                        className={ic('location')}
                        value={exp.location}
                        onChange={e => updateExp(index, 'location', e.target.value)}
                        placeholder="San Francisco, CA"
                      />
                    </div>

                    {/* Date row */}
                    <div className="flex items-start gap-4 md:col-span-2">
                      <div className="flex-1">
                        <label className="block text-sm font-medium mb-1">
                          Start Date <span className="text-red-500">*</span>
                        </label>
                        <input
                          type="month"
                          className={ic('startDate')}
                          value={exp.startDate}
                          onChange={e => updateExp(index, 'startDate', e.target.value)}
                          aria-invalid={!!errs.startDate}
                        />
                        <FieldError msg={errs.startDate} />
                      </div>
                      <div className="flex-1">
                        <label className="block text-sm font-medium mb-1">End Date</label>
                        <input
                          type="month"
                          disabled={exp.current}
                          className={cn(ic('endDate'), 'disabled:opacity-50 disabled:cursor-not-allowed')}
                          value={exp.current ? '' : exp.endDate}
                          onChange={e => updateExp(index, 'endDate', e.target.value)}
                          aria-invalid={!!errs.endDate}
                        />
                        <FieldError msg={errs.endDate} />
                      </div>
                    </div>

                    {/* Currently working here */}
                    <div className="md:col-span-2 flex items-center gap-2">
                      <input
                        type="checkbox"
                        id={`current-${index}`}
                        checked={exp.current}
                        onChange={e => {
                          updateExp(index, 'current', e.target.checked)
                          if (e.target.checked) updateExp(index, 'endDate', '')
                        }}
                        className="rounded border-border accent-primary"
                      />
                      <label htmlFor={`current-${index}`} className="text-sm">I currently work here</label>
                    </div>

                    <div className="md:col-span-2">
                      <label className="block text-sm font-medium mb-1">Description (Bullet points)</label>
                      <textarea
                        className="w-full bg-background/50 border border-border rounded-lg px-4 py-2 min-h-[100px] focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                        value={exp.description}
                        onChange={e => updateExp(index, 'description', e.target.value)}
                        placeholder={`- Developed feature X resulting in Y% improvement\n- Led a team of...`}
                      />
                    </div>

                  </div>
                </div>
              )
            })}
            <button onClick={addExperience} className="flex items-center gap-2 text-primary hover:text-primary/80 transition-colors">
              <Plus className="w-4 h-4" /> Add Experience
            </button>
          </div>
        )

      /* ── Step 3: Projects ── */
      case 3:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-semibold mb-6">Projects</h2>
            {projects.map((proj, index) => (
              <div key={index} className="bg-background/30 p-5 rounded-xl border border-border relative">
                <button
                  onClick={() => removeProject(index)}
                  className="absolute top-4 right-4 text-muted-foreground hover:text-red-500 transition-colors"
                  aria-label="Remove project"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium mb-1">Project Name</label>
                    <input
                      type="text"
                      className="w-full bg-background/50 border border-border rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                      value={proj.name}
                      onChange={e => { const n = [...projects]; n[index].name = e.target.value; setProjects(n) }}
                      placeholder="E-commerce App"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Technologies Used</label>
                    <input
                      type="text"
                      className="w-full bg-background/50 border border-border rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                      value={proj.tech}
                      onChange={e => { const n = [...projects]; n[index].tech = e.target.value; setProjects(n) }}
                      placeholder="React, Node.js, MongoDB"
                    />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium mb-1">Link (Optional)</label>
                    <input
                      type="url"
                      className="w-full bg-background/50 border border-border rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                      value={proj.link}
                      onChange={e => { const n = [...projects]; n[index].link = e.target.value; setProjects(n) }}
                      placeholder="https://github.com/..."
                    />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium mb-1">Description (Bullet points)</label>
                    <textarea
                      className="w-full bg-background/50 border border-border rounded-lg px-4 py-2 min-h-[100px] focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                      value={proj.description}
                      onChange={e => { const n = [...projects]; n[index].description = e.target.value; setProjects(n) }}
                      placeholder="- Built a full-stack application..."
                    />
                  </div>
                </div>
              </div>
            ))}
            <button onClick={addProject} className="flex items-center gap-2 text-primary hover:text-primary/80 transition-colors">
              <Plus className="w-4 h-4" /> Add Project
            </button>
          </div>
        )

      /* ── Step 4: Skills ── */
      case 4:
        return (
          <div className="space-y-4">
            <h2 className="text-2xl font-semibold mb-6">Skills</h2>
            <div>
              <label className="block text-sm font-medium mb-1" htmlFor="skills">Technical Skills &amp; Competencies</label>
              <textarea
                id="skills"
                className="w-full bg-background/50 border border-border rounded-xl px-4 py-2 min-h-[150px] focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                value={skills}
                onChange={e => setSkills(e.target.value)}
                placeholder={'**Languages:** JavaScript, Python, Java\n**Frameworks:** React, Node.js, Express\n**Tools:** Git, Docker, AWS'}
              />
              <p className="text-xs text-muted-foreground mt-2">Format exactly as you want it to appear (Markdown supported).</p>
            </div>
          </div>
        )

      /* ── Step 5: Preview ── */
      case 5:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-semibold mb-6">Preview &amp; Generate</h2>
            <div className="bg-background border border-border rounded-xl p-6 h-[500px] overflow-y-auto font-mono text-sm whitespace-pre-wrap">
              {generateMarkdown()}
            </div>
          </div>
        )

      default:
        return null
    }
  }

  // ── render ────────────────────────────────────────────────────────────────────
  return (
    <div className="min-h-screen pt-20 pb-12 bg-background flex flex-col">
      <div className="max-w-4xl mx-auto w-full px-4 sm:px-6 lg:px-8 flex-1 flex flex-col">

        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-white/60">
            Resume Builder
          </h1>
          <p className="text-muted-foreground mt-2">Build a professional resume from scratch.</p>
        </div>

        {/* Progress Stepper */}
        <div className="mb-8 flex items-center justify-between relative">
          <div className="absolute left-0 top-1/2 w-full h-0.5 bg-border -z-10 transform -translate-y-1/2" />
          {STEPS.map((step, index) => {
            const isActive    = index === currentStep
            const isCompleted = index < currentStep
            const StepIcon    = step.icon
            return (
              <div key={step.id} className="flex flex-col items-center">
                <div className={cn(
                  'w-10 h-10 rounded-full flex items-center justify-center border-2 transition-colors',
                  isActive    ? 'bg-primary border-primary text-primary-foreground' :
                  isCompleted ? 'bg-primary/20 border-primary text-primary' :
                                'bg-background border-border text-muted-foreground'
                )}>
                  {isCompleted ? <CheckCircle className="w-5 h-5" /> : <StepIcon className="w-5 h-5" />}
                </div>
                <span className={cn(
                  'text-xs mt-2 hidden sm:block',
                  isActive ? 'text-primary font-medium' : 'text-muted-foreground'
                )}>
                  {step.title}
                </span>
              </div>
            )
          })}
        </div>

        {/* Content Area */}
        <div className="flex-1 bg-card/50 backdrop-blur-xl border border-white/5 rounded-3xl p-6 sm:p-8 shadow-2xl relative overflow-hidden">
          <div className="absolute -top-40 -right-40 w-80 h-80 bg-primary/10 rounded-full blur-3xl opacity-50 pointer-events-none" />
          <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-blue-500/10 rounded-full blur-3xl opacity-50 pointer-events-none" />

          <AnimatePresence mode="wait">
            <motion.div
              key={currentStep}
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              transition={{ duration: 0.3 }}
              className="relative z-10"
            >
              {renderStep()}
            </motion.div>
          </AnimatePresence>
        </div>

        {/* Navigation Actions */}
        <div className="mt-8 flex justify-between items-center">
          <button
            onClick={handlePrev}
            disabled={currentStep === 0}
            className="px-6 py-2.5 rounded-full bg-secondary text-secondary-foreground hover:bg-secondary/80 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex items-center gap-2"
          >
            <ArrowLeft className="w-4 h-4" /> Back
          </button>

          {currentStep === STEPS.length - 1 ? (
            <button
              onClick={handleGenerate}
              disabled={isSubmitting}
              className="px-6 py-2.5 rounded-full bg-primary text-primary-foreground hover:bg-primary/90 hover:scale-105 active:scale-95 disabled:opacity-50 disabled:hover:scale-100 transition-all shadow-lg shadow-primary/25 flex items-center gap-2 font-medium"
            >
              {isSubmitting ? (
                <>
                  <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin" />
                  Generating...
                </>
              ) : (
                <>
                  <Save className="w-4 h-4" /> Generate &amp; Enhance
                </>
              )}
            </button>
          ) : (
            <button
              onClick={handleNext}
              className="px-6 py-2.5 rounded-full bg-white text-black hover:bg-gray-200 hover:scale-105 active:scale-95 transition-all shadow-lg flex items-center gap-2 font-medium"
            >
              Next <ArrowRight className="w-4 h-4" />
            </button>
          )}
        </div>

      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useParams, Link, useNavigate } from 'react-router-dom'
import { motion } from 'framer-motion'
import toast from 'react-hot-toast'
import ReactMarkdown from 'react-markdown'
import { resumeApi, enhanceApi } from '../services/api'
import Button from '../components/Button'
import Card from '../components/Card'
import CustomSection from '../components/CustomSection'
import { sectionsToMarkdown } from '../components/customSectionUtils'
import { SkeletonList } from '../components/ui/Skeleton'
import ResumeVersions from '../components/ResumeVersions'
import AtsProgressChart from '../components/AtsProgressChart'
import { Loader2 } from 'lucide-react'

export default function ResumeView() {
  const { resumeId } = useParams()
  const navigate = useNavigate()

  const [resume, setResume] = useState(null)
  const [loading, setLoading] = useState(false)
  const [downloading, setDownloading] = useState(false)
  const [activeTab, setActiveTab] = useState('preview') // 'preview' | 'versions' | 'ats'
  const [previewTab, setPreviewTab] = useState('enhanced') // 'enhanced' | 'original'
  const [scoreData, setScoreData] = useState(null)
  const [scoring, setScoring] = useState(false)
  const [scoringStep, setScoringStep] = useState(0)

  useEffect(() => {
    let interval
    if (scoring) {
      interval = setInterval(() => {
        setScoringStep((prev) => (prev + 1) % 4)
      }, 2500)
    } else {
      setScoringStep(0)
    }
    return () => clearInterval(interval)
  }, [scoring])
  // ── Custom sections – persisted per-resume in localStorage ───────────────
  const STORAGE_KEY = `resume_custom_sections_${resumeId}`
  const [customSections, setCustomSections] = useState(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY)
      return saved ? JSON.parse(saved) : []
    } catch {
      return []
    }
  })

  const handleSectionsChange = (sections) => {
    setCustomSections(sections)
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(sections))
    } catch {
      // storage quota exceeded – silently ignore
    }
  }

  useEffect(() => {
    fetchResume()
  }, [resumeId])

  const fetchResume = async () => {
    try {
      const response = await resumeApi.getById(resumeId)
      setResume(response.data)

      // Set default tab based on available content
      if (!response.data.enhancedText) {
        setPreviewTab('original')
      } else {
        setPreviewTab('enhanced')
      }
    } catch (error) {
      toast.error('Failed to load resume')
      navigate('/dashboard')
    } finally {
      setLoading(false)
    }
  }

  const handleCopy = async (text) => {
    try {
      await navigator.clipboard.writeText(text)
      toast.success('Copied to clipboard!')
    } catch (error) {
      console.error('Clipboard copy failed:', error)
      toast.error('Failed to copy to clipboard')
    }
  }

  const handleDownloadPdf = async () => {
    try {
      setDownloading(true)
      const blob = await resumeApi.downloadPdf(resumeId, previewTab)

      // Create download link
      const url = window.URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `${resume?.title || 'resume'}_${previewTab}.pdf`
      document.body.appendChild(a)
      a.click()

      // Cleanup
      window.URL.revokeObjectURL(url)
      document.body.removeChild(a)

      toast.success('PDF downloaded successfully!')
    } catch (error) {
      toast.error(error.message || 'Failed to download PDF')
    } finally {
      setDownloading(false)
    }
  }

  const handleAnalyzeResume = async () => {
    try {
      setScoring(true)

      const resumeText =
        previewTab === 'enhanced'
          ? resume?.enhancedText
          : resume?.originalText

      if (!resumeText || !resumeText.trim()) {
        toast.error('No resume text available to analyze.')
        return
      }

      const result = await enhanceApi.scoreResume(resumeText)

      if (!result.success) {
        throw new Error(result.message || 'Failed to analyze resume')
      }

      setScoreData(result.data)
      toast.success('Resume analyzed successfully!')

      // Log score to ATS history
      try {
        await resumeApi.logAtsHistory(resumeId, {
          jobRole: resume?.jobRole || 'Software Engineer',
          atsScore: result.data.overallScore,
          scoreBreakdown: {
            summary: result.data.sections?.summary?.score || 0,
            skills: result.data.sections?.skills?.score || 0,
            experience: result.data.sections?.experience?.score || 0,
            education: result.data.sections?.education?.score || 0,
            projects: result.data.sections?.projects?.score || 0
          },
          missingKeywords: [],
          improvementsCount: result.data.topSuggestions?.length || 0
        })
      } catch (historyErr) {
        console.error('Failed to log ATS score run:', historyErr)
      }
    } catch (error) {
      console.error('Resume analysis error:', error)

      if (error.message === 'Not authenticated') {
        toast.error('Session expired. Please log in again.')
      } else if (error.status === 429) {
        const retryMsg = error.retryAfter
          ? ` Try again in ${Math.ceil(error.retryAfter / 60)} minutes.`
          : ' Try again tomorrow.'
        toast.error(`Daily AI limit reached.${retryMsg}`)
      } else if (error.status === 401 || error.status === 403) {
        toast.error('Authentication error. Please log in again.')
      } else if (error.status >= 500) {
        toast.error('Analysis service temporarily unavailable. Please try again.')
      } else if (!navigator.onLine || error.message?.includes('Failed to fetch')) {
        toast.error('Network error. Check your connection and try again.')
      } else {
        toast.error(error.message || 'Failed to analyze resume. Please try again.')
      }
    } finally {
      setScoring(false)
    }
  }

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    })
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-background">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4 }}
            className="space-y-6"
          >
            {/* Header Skeleton */}
            <div className="flex items-start justify-between mb-8">
              <div className="space-y-2">
                <div className="h-8 bg-muted rounded-lg w-1/2 animate-pulse" />
                <div className="h-4 bg-muted rounded-lg w-1/3 animate-pulse" />
              </div>
              <div className="h-10 bg-muted rounded-lg w-32 animate-pulse" />
            </div>

            {/* Tabs Skeleton */}
            <div className="flex gap-4 border-b border-border">
              {[...Array(3)].map((_, i) => (
                <div key={i} className="h-10 bg-muted rounded w-28 animate-pulse" />
              ))}
            </div>

            {/* Content Skeleton */}
            <SkeletonList count={5} />
          </motion.div>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-background">
      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <div className="flex flex-col sm:flex-row justify-between items-start gap-4 mb-6">
          <div>
            <h1 className="text-2xl font-bold text-foreground">{resume?.title}</h1>
            <p className="text-muted-foreground">
              {resume?.jobRole && `Target: ${resume.jobRole}`}
            </p>
            <p className="text-sm text-muted-foreground mt-1">
              Last modified: {formatDate(resume?.lastModified || resume?.createdAt)}
            </p>
          </div>
          <div className="flex gap-2">
            <Link to={`/enhance/${resumeId}`}>
              <Button variant="primary">
                {resume?.enhancedText ? 'Re-enhance' : 'Enhance'}
              </Button>
            </Link>
            <Link to="/dashboard">
              <Button variant="outline">Back to Dashboard</Button>
            </Link>
          </div>
        </div>

        {/* Tab Navigation */}
        <div className="border-b border-border mb-6">
          <nav className="flex gap-8">
            <button
              onClick={() => setActiveTab('preview')}
              className={`pb-4 text-sm font-semibold border-b-2 transition-all cursor-pointer ${activeTab === 'preview'
                  ? 'border-primary text-primary'
                  : 'border-transparent text-muted-foreground hover:text-foreground'
                }`}
            >
              Resume Preview
            </button>
            <button
              onClick={() => setActiveTab('versions')}
              className={`pb-4 text-sm font-semibold border-b-2 transition-all cursor-pointer ${activeTab === 'versions'
                  ? 'border-primary text-primary'
                  : 'border-transparent text-muted-foreground hover:text-foreground'
                }`}
            >
              Versions & Snapshots
            </button>
            <button
              onClick={() => setActiveTab('ats')}
              className={`pb-4 text-sm font-semibold border-b-2 transition-all cursor-pointer ${activeTab === 'ats'
                  ? 'border-primary text-primary'
                  : 'border-transparent text-muted-foreground hover:text-foreground'
                }`}
            >
              ATS Progression
            </button>
          </nav>
        </div>

        {/* Content Tabs */}
        {activeTab === 'preview' && (
          <div className="space-y-6">
            <Card>
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6 pb-4 border-b border-border/60">
                <div className="flex items-center gap-3">
                  <h2 className="text-lg font-bold text-foreground">
                    {previewTab === 'enhanced' ? 'AI-Enhanced Resume' : 'Original Resume'}
                  </h2>
                  {resume?.enhancedText && (
                    <div className="flex bg-muted rounded-xl p-0.5 border border-border">
                      <button
                        onClick={() => setPreviewTab('enhanced')}
                        className={`px-3 py-1 text-xs font-semibold rounded-lg transition-all ${
                          previewTab === 'enhanced' ? 'bg-primary text-primary-foreground shadow' : 'text-muted-foreground hover:text-foreground'
                        }`}
                      >
                        AI Enhanced
                      </button>
                      <button
                        onClick={() => setPreviewTab('original')}
                        className={`px-3 py-1 text-xs font-semibold rounded-lg transition-all ${
                          previewTab === 'original' ? 'bg-primary text-primary-foreground shadow' : 'text-muted-foreground hover:text-foreground'
                        }`}
                      >
                        Original
                      </button>
                    </div>
                  )}
                </div>
                <div className="flex gap-2 flex-wrap">
                 <Button
  variant="primary"
  onClick={handleDownloadPdf}
  disabled={downloading}
>
  {downloading ? (
    <div className="flex items-center gap-2">
      <Loader2 className="w-4 h-4 animate-spin" />
      Generating PDF...
    </div>
  ) : (
    'Download PDF'
  )}
</Button>
                  <Button
                    variant="primary"
                    onClick={handleAnalyzeResume}
                    disabled={scoring}
                  >
                    {scoring ? 'Analyzing...' : 'Analyze Resume'}
                  </Button>
                  <Button
                    variant="secondary"
                    onClick={() =>
                      handleCopy(
                        previewTab === 'enhanced'
                          ? resume?.enhancedText
                          : resume?.originalText,
                      )
                    }
                  >
                    Copy to Clipboard
                  </Button>
                  {customSections.length > 0 && (
                    <Button
                      variant="outline"
                      onClick={() => {
                        const base =
                          previewTab === 'enhanced'
                            ? resume?.enhancedText
                            : resume?.originalText
                        handleCopy((base || '') + '\n\n' + sectionsToMarkdown(customSections))
                      }}
                    >
                      Copy with Custom Sections
                    </Button>
                  )}
                </div>
              </div>

              <div className="bg-card border border-border/40 rounded-lg p-6 min-h-96 overflow-auto shadow-lg" style={{ maxWidth: '210mm', margin: '0 auto' }}>
                {previewTab === 'enhanced' && resume?.enhancedText ? (
                  <div className="resume-preview max-w-none text-foreground text-sm leading-tight">
                    <ReactMarkdown
                      components={{
                        h1: ({ node, ...props }) => (
                          <div className="text-foreground text-center py-2 px-4 mb-1 text-2xl font-bold border-b-2 border-black">
                            {props.children}
                          </div>
                        ),
                        h2: ({ node, ...props }) => (
                          <h2 className="text-xs font-bold text-foreground border-b border-black pb-0.5 mt-3 mb-1 uppercase tracking-wide">
                            {props.children}
                          </h2>
                        ),
                        h3: ({ node, ...props }) => (
                          <h3 className="text-xs font-bold text-foreground mt-1.5 mb-0.5">
                            {props.children}
                          </h3>
                        ),
                        p: ({ node, ...props }) => (
                          <p className="text-xs text-foreground mb-0.5 leading-snug">
                            {props.children}
                          </p>
                        ),
                        ul: ({ node, ...props }) => (
                          <ul className="list-none pl-0 space-y-0 mb-1">
                            {props.children}
                          </ul>
                        ),
                        li: ({ node, ...props }) => (
                          <li className="text-xs text-foreground flex items-start gap-1 leading-snug">
                            <span className="text-muted-foreground">◦</span>
                            <span>{props.children}</span>
                          </li>
                        ),
                        strong: ({ node, ...props }) => (
                          <strong className="font-bold text-foreground">
                            {props.children}
                          </strong>
                        ),
                        em: ({ node, ...props }) => (
                          <em className="text-muted-foreground text-xs font-normal">
                            {props.children}
                          </em>
                        ),
                        hr: () => null,
                        a: ({ node, ...props }) => (
                          <a className="text-blue-600 hover:underline text-xs" href={props.href} target="_blank" rel="noopener noreferrer">
                            {props.children}
                          </a>
                        ),
                      }}
                    >
                      {resume.enhancedText}
                    </ReactMarkdown>
                  </div>
                ) : (
                  <pre className="whitespace-pre-wrap text-xs text-foreground/80 font-mono">
                    {resume?.originalText}
                  </pre>
                )}
              </div>
            </Card>

            {/* Animated Scanner Loader during AI Scoring */}
            {scoring && (
              <Card className="mt-6 border-primary/20 bg-primary/5 relative overflow-hidden animate-pulse">
                <div className="flex flex-col items-center py-10 px-4">
                  {/* Animated Glowing ATS Radar Scanner */}
                  <div className="relative w-24 h-24 mb-6">
                    <motion.div
                      animate={{ scale: [1, 1.2, 1], opacity: [0.3, 0.8, 0.3] }}
                      transition={{ duration: 2, repeat: Infinity }}
                      className="absolute inset-0 rounded-full bg-primary/20"
                    />
                    <div className="absolute inset-2 rounded-full border-4 border-dashed border-primary/40 animate-spin" />
                    <div className="absolute inset-4 rounded-full border border-primary/60 flex items-center justify-center">
                      <svg className="w-8 h-8 text-primary animate-pulse" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                      </svg>
                    </div>
                  </div>

                  <h3 className="text-xl font-bold text-foreground mb-2">Analyzing Your Resume</h3>
                  
                  {/* Animated active scoring message */}
                  <motion.p
                    key={scoringStep}
                    initial={{ opacity: 0, y: 5 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -5 }}
                    className="text-sm font-semibold text-primary tracking-wide text-center"
                  >
                    {scoringStep === 0 && "🤖 Initializing AI ATS parser..."}
                    {scoringStep === 1 && "🔍 Analyzing keyword relevance & density..."}
                    {scoringStep === 2 && "⚡ Measuring impact statements & formatting..."}
                    {scoringStep === 3 && "📈 Compiling score and suggestions..."}
                  </motion.p>
                  
                  <p className="text-xs text-muted-foreground mt-4 text-center max-w-sm">
                    This might take a few seconds as the AI evaluates your resume against industry benchmarks and formats custom suggestions.
                  </p>
                </div>
              </Card>
            )}

            {scoreData && (
              <Card className="mt-6">
                <h3 className="text-2xl font-bold mb-6">
                  Resume Analysis
                </h3>

                <div className="flex flex-col items-center mb-8">
                  <div className="w-32 h-32 rounded-full border-8 border-primary flex items-center justify-center text-3xl font-bold">
                    {scoreData.overallScore}
                  </div>

                  <p className="mt-3 text-muted-foreground">
                    Overall Resume Score
                  </p>
                </div>

                <div className="space-y-4">
                  {Object.entries(scoreData.sections).map(([section, value]) => (
                    <div key={section}>
                      <div className="flex justify-between mb-1">
                        <span className="capitalize font-medium">
                          {section}
                        </span>
                        <span>{value.score}/100</span>
                      </div>

                      <div className="w-full bg-muted rounded-full h-3">
                        <div
                          className="bg-primary h-3 rounded-full"
                          style={{ width: `${value.score}%` }}
                        />
                      </div>

                      <p className="text-sm text-muted-foreground mt-1">
                        {value.feedback}
                      </p>
                    </div>
                  ))}
                </div>

                <div className="mt-8">
                  <h4 className="font-semibold mb-3">
                    Top Suggestions
                  </h4>

                  <ul className="space-y-2">
                    {scoreData.topSuggestions.map((tip, index) => (
                      <li
                        key={index}
                        className="bg-muted p-3 rounded-lg"
                      >
                        • {tip}
                      </li>
                    ))}
                  </ul>
                </div>
              </Card>
            )}

            {/* Metadata */}
            {resume?.preferences && Object.keys(resume.preferences).length > 0 && (
              <Card className="mt-6">
                <h3 className="text-lg font-medium text-foreground mb-4">Enhancement Settings Used</h3>
                <div className="grid sm:grid-cols-2 gap-4 text-sm">
                  {resume.jobRole && (
                    <div>
                      <span className="text-muted-foreground">Target Role:</span>
                      <span className="ml-2 text-foreground">{resume.jobRole}</span>
                    </div>
                  )}
                  {resume.preferences.yearsOfExperience && (
                    <div>
                      <span className="text-muted-foreground">Experience:</span>
                      <span className="ml-2 text-foreground">
                        {resume.preferences.yearsOfExperience} years
                      </span>
                    </div>
                  )}
                  {resume.preferences.skills?.length > 0 && (
                    <div className="sm:col-span-2">
                      <span className="text-muted-foreground">Skills:</span>
                      <span className="ml-2 text-foreground">
                        {resume.preferences.skills.join(', ')}
                      </span>
                    </div>
                  )}
                  {resume.preferences.industry && (
                    <div>
                      <span className="text-muted-foreground">Industry:</span>
                      <span className="ml-2 text-foreground">{resume.preferences.industry}</span>
                    </div>
                  )}
                  {resume.preferences.profileInfo && (
                    <div className="sm:col-span-2 pt-2 border-t border-border">
                      <span className="text-muted-foreground block mb-2">Profile Links:</span>
                      <div className="flex flex-wrap gap-3">
                        {resume.preferences.profileInfo.linkedinUrl && (
                          <a href={resume.preferences.profileInfo.linkedinUrl} target="_blank" rel="noopener noreferrer" className="text-primary hover:text-primary/80 text-xs">
                            LinkedIn ↗
                          </a>
                        )}
                        {resume.preferences.profileInfo.githubUrl && (
                          <a href={resume.preferences.profileInfo.githubUrl} target="_blank" rel="noopener noreferrer" className="text-primary hover:text-primary/80 text-xs">
                            GitHub ↗
                          </a>
                        )}
                        {resume.preferences.profileInfo.portfolioUrl && (
                          <a href={resume.preferences.profileInfo.portfolioUrl} target="_blank" rel="noopener noreferrer" className="text-primary hover:text-primary/80 text-xs">
                            Portfolio ↗
                          </a>
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </Card>
            )}

            {/* Custom Sections */}
            <Card className="mt-6">
              <CustomSection
                sections={customSections}
                onSectionsChange={handleSectionsChange}
              />
            </Card>
          </div>
        )}

        {activeTab === 'versions' && (
          <Card>
            <ResumeVersions
              resumeId={resumeId}
              currentOriginalText={resume?.originalText}
              currentEnhancedText={resume?.enhancedText}
              currentJobRole={resume?.jobRole}
              currentAtsScore={resume?.atsScore}
              onRestore={(updatedResume) => {
                setResume(updatedResume)
                if (!updatedResume.enhancedText) {
                  setPreviewTab('original')
                } else {
                  setPreviewTab('enhanced')
                }
                setActiveTab('preview')
              }}
            />
          </Card>
        )}

        {activeTab === 'ats' && (
          <Card>
            <AtsProgressChart resumeId={resumeId} />
          </Card>
        )}
      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import toast from 'react-hot-toast'
import {
  Shield,
  ShieldCheck,
  ShieldOff,
  Copy,
  Download,
  RefreshCw,
  KeyRound,
  CheckCircle2,
  ChevronDown,
  ChevronUp
} from 'lucide-react'
import { twoFactorApi } from '../services/api'
import Button from '../components/Button'
import Input from '../components/Input'
import Card from '../components/Card'
import { SkeletonPage } from '../components/ui/Skeleton'

// ── sub-components ─────────────────────────────────────────────────────────────

function SectionHeader({ icon: Icon, title, description }) {
  return (
    <div className="flex items-start gap-4 mb-6">
      <div className="p-2.5 rounded-xl bg-indigo-500/10 border border-indigo-500/20 shrink-0">
        <Icon className="w-5 h-5 text-indigo-400" />
      </div>
      <div>
        <h2 className="text-base font-semibold text-foreground">{title}</h2>
        <p className="text-sm text-muted-foreground mt-0.5">{description}</p>
      </div>
    </div>
  )
}

function StatusBadge({ enabled }) {
  return (
    <span
      className={`
        inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium
        ${enabled
          ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20'
          : 'bg-muted text-muted-foreground border border-neutral-700'
        }
      `}
    >
      {enabled ? (
        <><CheckCircle2 className="w-3 h-3" /> Active</>
      ) : (
        <><ShieldOff className="w-3 h-3" /> Not enabled</>
      )}
    </span>
  )
}

function BackupCodeGrid({ codes, onCopy, onDownload }) {
  return (
    <div className="mt-4">
      <div className="p-4 rounded-xl bg-amber-500/5 border border-amber-500/20 mb-4">
        <p className="text-xs text-amber-400 font-medium">
          Save these codes somewhere safe. Each code can only be used once.
          You won't be able to view them again.
        </p>
      </div>
      <div className="grid grid-cols-2 gap-2 mb-4">
        {codes.map((code, i) => (
          <div
            key={i}
            className="px-4 py-2.5 rounded-lg bg-card/60 backdrop-blur-sm border border-border font-mono text-sm text-center text-foreground tracking-widest"
          >
            {code}
          </div>
        ))}
      </div>
      <div className="flex gap-2">
        <Button variant="secondary" size="sm" onClick={onCopy}>
          <Copy className="w-4 h-4" />
          Copy all
        </Button>
        <Button variant="secondary" size="sm" onClick={onDownload}>
          <Download className="w-4 h-4" />
          Download
        </Button>
      </div>
    </div>
  )
}

// ── main page ──────────────────────────────────────────────────────────────────

export default function SecuritySettings() {
  // 'disabled' | 'setup' | 'enabled'
  const [view, setView] = useState('disabled')
  const [loading, setLoading] = useState(true)

  // Setup flow
  const [qrDataUrl, setQrDataUrl] = useState('')
  const [rawSecret, setRawSecret] = useState('')
  const [setupToken, setSetupToken] = useState('')
  const [setupLoading, setSetupLoading] = useState(false)

  // Enabled view
  const [backupCodesRemaining, setBackupCodesRemaining] = useState(0)
  const [newCodes, setNewCodes] = useState([])
  const [showCodesFor, setShowCodesFor] = useState(null) // 'enable' | 'regenerate'

  // Disable confirmation
  const [disableOpen, setDisableOpen] = useState(false)
  const [disableToken, setDisableToken] = useState('')
  const [disableLoading, setDisableLoading] = useState(false)
  const [useBackupToDisable, setUseBackupToDisable] = useState(false)
  const [disableBackupCode, setDisableBackupCode] = useState('')
  const [disableBackupLoading, setDisableBackupLoading] = useState(false)

  // Regenerate confirmation
  const [regenOpen, setRegenOpen] = useState(false)
  const [regenToken, setRegenToken] = useState('')
  const [regenLoading, setRegenLoading] = useState(false)

  useEffect(() => {
    fetchStatus()
  }, [])

  const fetchStatus = async () => {
    setLoading(true)
    try {
      const data = await twoFactorApi.getStatus()
      setView(data.enabled ? 'enabled' : 'disabled')
      setBackupCodesRemaining(data.backupCodesRemaining)
    } catch (error) {
      toast.error('Failed to load security settings')
    } finally {
      setLoading(false)
    }
  }

  // ── handlers ──

  const handleStartSetup = async () => {
    setSetupLoading(true)
    try {
      const data = await twoFactorApi.setup()
      setQrDataUrl(data.qrDataUrl)
      setRawSecret(data.secret)
      setSetupToken('')
      setView('setup')
    } catch (error) {
      toast.error(error.message || 'Failed to start setup')
    } finally {
      setSetupLoading(false)
    }
  }

  const handleConfirmSetup = async (e) => {
    e.preventDefault()
    if (!setupToken.trim()) return

    setSetupLoading(true)
    try {
      const data = await twoFactorApi.enable(rawSecret, setupToken.trim())
      setNewCodes(data.backupCodes)
      setShowCodesFor('enable')
      setView('enabled')
      setBackupCodesRemaining(data.backupCodes.length)
      toast.success('Two-factor authentication enabled')
    } catch (error) {
      toast.error(error.message || 'Invalid code — please try again')
    } finally {
      setSetupLoading(false)
    }
  }

  const handleDisable = async (e) => {
    e.preventDefault()
    if (!disableToken.trim()) return

    setDisableLoading(true)
    try {
      await twoFactorApi.disable(disableToken.trim())
      setView('disabled')
      setDisableOpen(false)
      setDisableToken('')
      setNewCodes([])
      setShowCodesFor(null)
      toast.success('Two-factor authentication disabled')
    } catch (error) {
      toast.error(error.message || 'Invalid code — please try again')
    } finally {
      setDisableLoading(false)
    }
  }

  const handleDisableWithBackup = async (e) => {
    e.preventDefault()
    if (!disableBackupCode.trim()) return

    setDisableBackupLoading(true)
    try {
      await twoFactorApi.disableWithBackup(disableBackupCode.trim().toUpperCase())
      setView('disabled')
      setDisableOpen(false)
      setDisableBackupCode('')
      setNewCodes([])
      setShowCodesFor(null)
      toast.success('Two-factor authentication disabled')
    } catch (error) {
      toast.error(error.message || 'Invalid backup code')
    } finally {
      setDisableBackupLoading(false)
    }
  }

  const handleRegenerate = async (e) => {
    e.preventDefault()
    if (!regenToken.trim()) return

    setRegenLoading(true)
    try {
      const data = await twoFactorApi.regenerateBackupCodes(regenToken.trim())
      setNewCodes(data.backupCodes)
      setShowCodesFor('regenerate')
      setBackupCodesRemaining(data.backupCodes.length)
      setRegenOpen(false)
      setRegenToken('')
      toast.success('Backup codes regenerated')
    } catch (error) {
      toast.error(error.message || 'Invalid code — please try again')
    } finally {
      setRegenLoading(false)
    }
  }

  const handleCopyCodes = (codes) => {
    navigator.clipboard.writeText(codes.join('\n'))
    toast.success('Codes copied to clipboard')
  }

  const handleDownloadCodes = (codes) => {
    const blob = new Blob(
      [`careerpilot 2FA Backup Codes\n${'─'.repeat(30)}\n${codes.join('\n')}\n\nEach code can only be used once.`],
      { type: 'text/plain' }
    )
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = 'careerpilot-backup-codes.txt'
    a.click()
    URL.revokeObjectURL(url)
  }

  // ── render ──

  if (loading) {
    return <SkeletonPage width="max-w-2xl" rows={3} />
  }

  return (
    <div className="max-w-2xl mx-auto px-4 py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-foreground">Account Security</h1>
        <p className="text-muted-foreground mt-1 text-sm">
          Manage authentication and access settings for your account.
        </p>
      </div>

      {/* ── Two-Factor Authentication card ───────────────────────────────────── */}
     <Card className="relative overflow-hidden bg-card/80 backdrop-blur-sm border border-border shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:shadow-xl hover:border-primary/20 transition-all duration-300">
       <div className="absolute inset-0 bg-gradient-to-br from-sky-300/5 via-cyan-200/5 to-transparent opacity-0 hover:opacity-100 transition-opacity duration-300 pointer-events-none" />
        <div className="flex items-center justify-between mb-6">
          <SectionHeader
            icon={Shield}
            title="Two-Factor Authentication"
            description="Add a second layer of security to your account using an authenticator app."
          />
          <StatusBadge enabled={view === 'enabled'} />
        </div>

        {/* ── DISABLED state ─────────────────────────────────────────────────── */}
        {view === 'disabled' && (
          <div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-6">
              {[
                { icon: ShieldCheck, label: 'Stronger account security' },
                { icon: KeyRound, label: 'Protect against credential theft' },
                { icon: RefreshCw, label: 'Backup codes for recovery' }
              ].map(({ icon: Icon, label }) => (
                <div
                  key={label}
                  className="flex items-center gap-2.5 p-3 rounded-lg bg-card/60 backdrop-blur-sm border border-border"
                >
                  <Icon className="w-4 h-4 text-indigo-400 flex-shrink-0" />
                  <span className="text-xs text-muted-foreground">{label}</span>
                </div>
              ))}
            </div>

            <Button
              variant="gradient"
              loading={setupLoading}
              onClick={handleStartSetup}
            >
              <Shield className="w-4 h-4" />
              Enable Two-Factor Authentication
            </Button>
          </div>
        )}

        {/* ── SETUP state ────────────────────────────────────────────────────── */}
        {view === 'setup' && (
          <form onSubmit={handleConfirmSetup}>
            <div className="space-y-6">
              <div className="flex items-start gap-3 p-4 rounded-xl bg-card/60 backdrop-blur-sm border border-border">
                <span className="w-6 h-6 rounded-full bg-indigo-500 text-foreground text-xs font-bold flex items-center justify-center flex-shrink-0 mt-0.5">
                  1
                </span>
                <div>
                  <p className="text-sm font-medium text-foreground mb-1">
                    Install an authenticator app
                  </p>
                  <p className="text-xs text-muted-foreground">
                    Use Google Authenticator, Authy, or any TOTP-compatible app.
                  </p>
                </div>
              </div>

              <div className="flex items-start gap-3 p-4 rounded-xl bg-card/60 backdrop-blur-sm border border-border">
                <span className="w-6 h-6 rounded-full bg-indigo-500 text-foreground text-xs font-bold flex items-center justify-center flex-shrink-0 mt-0.5">
                  2
                </span>
                <div className="w-full">
                  <p className="text-sm font-medium text-foreground mb-3">
                    Scan this QR code
                  </p>
                  {qrDataUrl && (
                    <div className="flex flex-col items-center gap-3">
                      <div className="p-3 bg-white rounded-xl inline-block">
                        <img src={qrDataUrl} alt="2FA QR Code" className="w-40 h-40" />
                      </div>
                      <details className="w-full">
                        <summary className="text-xs text-muted-foreground cursor-pointer select-none hover:text-muted-foreground/80 transition-colors">
                          Can't scan? Enter the key manually
                        </summary>
                        <p className="mt-2 px-3 py-2 rounded-lg bg-neutral-900 border border-border font-mono text-xs text-muted-foreground break-all">
                          {rawSecret}
                        </p>
                      </details>
                    </div>
                  )}
                </div>
              </div>

              <div className="flex items-start gap-3 p-4 rounded-xl bg-card/60 backdrop-blur-sm border border-border">
                <span className="w-6 h-6 rounded-full bg-indigo-500 text-foreground text-xs font-bold flex items-center justify-center flex-shrink-0 mt-0.5">
                  3
                </span>
                <div className="w-full">
                  <p className="text-sm font-medium text-foreground mb-3">
                    Enter the 6-digit code to confirm
                  </p>
                  <Input
                    type="text"
                    name="setupToken"
                    value={setupToken}
                    onChange={(e) => setSetupToken(e.target.value.replace(/\D/g, '').slice(0, 6))}
                    placeholder="000000"
                    className="font-mono tracking-widest text-center text-lg"
                    maxLength={6}
                  />
                </div>
              </div>

              <div className="flex gap-3">
                <Button
                  type="submit"
                  variant="gradient"
                  loading={setupLoading}
                  disabled={setupToken.length !== 6}
                >
                  <ShieldCheck className="w-4 h-4" />
                  Confirm &amp; Enable
                </Button>
                <Button
                  type="button"
                  variant="secondary"
                  onClick={() => {
                    setView('disabled')
                    setSetupToken('')
                  }}
                >
                  Cancel
                </Button>
              </div>
            </div>
          </form>
        )}

        {/* ── ENABLED state ──────────────────────────────────────────────────── */}
        {view === 'enabled' && (
          <div className="space-y-4">
            {/* Backup codes just received (after enable or regenerate) */}
            {newCodes.length > 0 && (
              <div className="p-4 rounded-xl bg-card/60 backdrop-blur-sm border border-border">
                <p className="text-sm font-semibold text-foreground mb-1">
                  {showCodesFor === 'enable' ? 'Your backup codes' : 'New backup codes'}
                </p>
                <BackupCodeGrid
                  codes={newCodes}
                  onCopy={() => handleCopyCodes(newCodes)}
                  onDownload={() => handleDownloadCodes(newCodes)}
                />
                <button
                  onClick={() => { setNewCodes([]); setShowCodesFor(null) }}
                  className="mt-3 text-xs text-muted-foreground hover:text-muted-foreground/80 transition-colors"
                >
                  I've saved these codes — dismiss
                </button>
              </div>
            )}

            {/* Backup codes remaining */}
            {newCodes.length === 0 && (
              <div className="flex items-center justify-between p-4 rounded-xl bg-card/60 backdrop-blur-sm border border-border">
                <div className="flex items-center gap-3">
                  <KeyRound className="w-4 h-4 text-muted-foreground" />
                  <div>
                    <p className="text-sm text-foreground font-medium">Backup codes</p>
                    <p className="text-xs text-muted-foreground">
                      {backupCodesRemaining} of 10 codes remaining
                    </p>
                  </div>
                </div>
                {backupCodesRemaining <= 2 && (
                  <span className="text-xs text-amber-400 bg-amber-500/10 border border-amber-500/20 px-2 py-1 rounded-full">
                    Running low
                  </span>
                )}
              </div>
            )}

            {/* Regenerate backup codes */}
            <div className="rounded-xl border border-border overflow-hidden">
              <button
                type="button"
                onClick={() => { setRegenOpen(v => !v); setDisableOpen(false) }}
                className="w-full flex items-center justify-between px-4 py-3.5 bg-card/60 backdrop-blur-sm hover:bg-card/80 transition-colors"
              >
                <div className="flex items-center gap-2.5">
                  <RefreshCw className="w-4 h-4 text-muted-foreground" />
                  <span className="text-sm text-foreground">Regenerate backup codes</span>
                </div>
                {regenOpen
                  ? <ChevronUp className="w-4 h-4 text-muted-foreground" />
                  : <ChevronDown className="w-4 h-4 text-muted-foreground" />
                }
              </button>
              {regenOpen && (
                <form
                  onSubmit={handleRegenerate}
                  className="px-4 pb-4 pt-3 border-t border-border bg-card/60 backdrop-blur-sm space-y-3"
                >
                  <p className="text-xs text-muted-foreground">
                    This will invalidate your existing codes. Enter your current authenticator code to proceed.
                  </p>
                  <Input
                    type="text"
                    name="regenToken"
                    value={regenToken}
                    onChange={(e) => setRegenToken(e.target.value.replace(/\D/g, '').slice(0, 6))}
                    placeholder="6-digit code"
                    className="font-mono tracking-widest text-center"
                    maxLength={6}
                  />
                  <Button
                    type="submit"
                    variant="secondary"
                    size="sm"
                    loading={regenLoading}
                    disabled={regenToken.length !== 6}
                  >
                    <RefreshCw className="w-4 h-4" />
                    Generate new codes
                  </Button>
                </form>
              )}
            </div>

            {/* Disable 2FA */}
            <div className="rounded-xl border border-red-500/20 overflow-hidden">
              <button
                type="button"
                onClick={() => { setDisableOpen(v => !v); setRegenOpen(false) }}
                className="w-full flex items-center justify-between px-4 py-3.5 bg-red-500/5 hover:bg-red-500/10 transition-colors"
              >
                <div className="flex items-center gap-2.5">
                  <ShieldOff className="w-4 h-4 text-red-400" />
                  <span className="text-sm text-red-400">Disable two-factor authentication</span>
                </div>
                {disableOpen
                  ? <ChevronUp className="w-4 h-4 text-red-500/60" />
                  : <ChevronDown className="w-4 h-4 text-red-500/60" />
                }
              </button>
              {disableOpen && (
                <div className="px-4 pb-4 pt-3 border-t border-red-500/20 bg-red-500/5 space-y-3">
                  <div className="flex gap-2 mb-3">
                    <button
                      type="button"
                      onClick={() => { setUseBackupToDisable(false); setDisableToken(''); setDisableBackupCode('') }}
                      className={`flex-1 py-1.5 px-3 rounded-lg text-xs font-medium transition-colors ${
                        !useBackupToDisable
                          ? 'bg-red-500/20 text-red-400 border border-red-500/30'
                          : 'bg-muted text-muted-foreground border border-neutral-700 hover:bg-muted/80'
                      }`}
                    >
                      Use Authenticator
                    </button>
                    <button
                      type="button"
                      onClick={() => { setUseBackupToDisable(true); setDisableToken(''); setDisableBackupCode('') }}
                      className={`flex-1 py-1.5 px-3 rounded-lg text-xs font-medium transition-colors ${
                        useBackupToDisable
                          ? 'bg-red-500/20 text-red-400 border border-red-500/30'
                          : 'bg-muted text-muted-foreground border border-neutral-700 hover:bg-muted/80'
                      }`}
                    >
                      Use Backup Code
                    </button>
                  </div>

                  {!useBackupToDisable ? (
                    <form onSubmit={handleDisable} className="space-y-3">
                      <p className="text-xs text-red-400/80">
                        This will remove 2FA protection from your account. Enter your current authenticator code to confirm.
                      </p>
                      <Input
                        type="text"
                        name="disableToken"
                        value={disableToken}
                        onChange={(e) => setDisableToken(e.target.value.replace(/\D/g, '').slice(0, 6))}
                        placeholder="6-digit code"
                        className="font-mono tracking-widest text-center"
                        maxLength={6}
                      />
                      <Button
                        type="submit"
                        variant="danger"
                        size="sm"
                        loading={disableLoading}
                        disabled={disableToken.length !== 6}
                      >
                        <ShieldOff className="w-4 h-4" />
                        Disable 2FA
                      </Button>
                    </form>
                  ) : (
                    <form onSubmit={handleDisableWithBackup} className="space-y-3">
                      <p className="text-xs text-red-400/80">
                        Lost access to your authenticator? Use a backup code to disable 2FA. This will consume one backup code.
                      </p>
                      <Input
                        type="text"
                        name="disableBackupCode"
                        value={disableBackupCode}
                        onChange={(e) => setDisableBackupCode(e.target.value.toUpperCase().replace(/[^A-F0-9]/g, '').slice(0, 9))}
                        placeholder="XXXX-XXXX"
                        className="font-mono tracking-widest text-center"
                        maxLength={9}
                      />
                      <Button
                        type="submit"
                        variant="danger"
                        size="sm"
                        loading={disableBackupLoading}
                        disabled={disableBackupCode.replace(/[^A-F0-9]/g, '').length !== 8}
                      >
                        <ShieldOff className="w-4 h-4" />
                        Disable 2FA with Backup Code
                      </Button>
                    </form>
                  )}
                </div>
              )}
            </div>
          </div>
        )}
      </Card>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { Bell, Mail, MessageSquare, FileText, Save, Cpu } from 'lucide-react'
import { notificationApi, aiApi } from '../services/api'
import { encryptKey, decryptKey } from '../utils/encryption'
import Button from '../components/Button'
import toast from 'react-hot-toast'
import { SkeletonList } from '../components/ui/Skeleton'

export default function Settings() {
  const [preferences, setPreferences] = useState({
    jobAlerts: true,
    directMessages: true,
    proposalUpdates: true,
  })
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)

  // AI Settings State
  const [aiProvider, setAiProvider] = useState('')
  const [aiKey, setAiKey] = useState('')
  const [aiModel, setAiModel] = useState('')
  const [aiModelsList, setAiModelsList] = useState([])
  const [loadingModels, setLoadingModels] = useState(false)
  const [loadingAiSettings, setLoadingAiSettings] = useState(true)
  const [savingAi, setSavingAi] = useState(false)

  useEffect(() => {
    loadPreferences()
    loadAiSettings()
  }, [])

  useEffect(() => {
    if (aiProvider === 'openrouter') {
      loadAiModels()
    } else {
      setAiModelsList([])
    }
  }, [aiProvider])

  const loadAiSettings = async () => {
    try {
      const aiConfigStr = localStorage.getItem('aiConfig')
      if (aiConfigStr) {
        const config = JSON.parse(aiConfigStr)
        setAiProvider(config.provider || '')
        setAiModel(config.model || '')
        setAiKey(decryptKey(config.apiKey) || '')
      } else {
        const openRouterKey = localStorage.getItem('openRouterApiKey')
        if (openRouterKey) {
          setAiProvider('openrouter')
          setAiKey(decryptKey(openRouterKey) || '')
        }
      }
    } catch (error) {
      console.error('Failed to parse AI config', error)
    } finally {
      setLoadingAiSettings(false)
    }
  }

  const loadAiModels = async () => {
    setLoadingModels(true)
    try {
      const res = await aiApi.getModels('openrouter')
      if (res.success) {
        setAiModelsList(res.models)
      }
    } catch (error) {
      toast.error('Failed to load OpenRouter models')
    } finally {
      setLoadingModels(false)
    }
  }

  const loadPreferences = async () => {
    try {
      const data = await notificationApi.getPreferences()
      setPreferences(data.preferences)
    } catch (error) {
      toast.error('Failed to load preferences')
    } finally {
      setLoading(false)
    }
  }

  const handleSave = async () => {
    setSaving(true)
    try {
      await notificationApi.updatePreferences(preferences)
      toast.success('Preferences saved!')
    } catch (error) {
      toast.error('Failed to save preferences')
    } finally {
      setSaving(false)
    }
  }

  const handleSaveAiSettings = async () => {
    setSavingAi(true)
    try {
      const aiConfig = {
        provider: aiProvider,
        apiKey: encryptKey(aiKey),
        model: aiModel
      }
      localStorage.setItem('aiConfig', JSON.stringify(aiConfig))

      // Keep legacy key updated if using OpenRouter
      if (aiProvider === 'openrouter' && aiKey) {
        localStorage.setItem('openRouterApiKey', encryptKey(aiKey))
      } else if (!aiKey) {
        localStorage.removeItem('openRouterApiKey')
      }

      toast.success('AI Configuration saved locally!')
    } catch (error) {
      toast.error('Failed to save AI Configuration')
    } finally {
      setSavingAi(false)
    }
  }

  const Toggle = ({ value, onChange }) => (
    <button
      role="switch"
      aria-checked={value}
      onClick={() => onChange(!value)}
      className={`relative w-12 h-6 rounded-full transition-colors cursor-pointer ${value ? 'bg-indigo-500' : 'bg-muted'
        }`}
    >
      <span className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${value ? 'left-7' : 'left-1'
        }`} />
    </button>
  )

  if (loading) return (
    <div className="min-h-screen bg-background">
      <div className="max-w-2xl mx-auto px-4 py-8">
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.4 }}
          className="space-y-6"
        >
          {/* Header Skeleton */}
          <div className="space-y-2 mb-8">
            <div className="h-9 bg-muted rounded-lg w-1/3 animate-pulse" />
            <div className="h-4 bg-muted rounded-lg w-2/3 animate-pulse" />
          </div>

          {/* Settings Skeleton */}
          <div className="p-6 rounded-2xl bg-card border border-border space-y-6">
            <div className="h-5 bg-muted rounded-lg w-1/4 animate-pulse" />
            <SkeletonList count={3} />
          </div>
        </motion.div>
      </div>
    </div>
  )

  return (
    <div className="min-h-screen bg-background">
      <div className="max-w-2xl mx-auto px-4 py-8">
        <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}>
          <h1 className="text-3xl font-bold text-foreground mb-2">Settings</h1>
          <p className="text-muted-foreground mb-8">Manage your email notification preferences</p>

          <div className="relative overflow-hidden p-6 rounded-2xl bg-card/80 backdrop-blur-sm border border-border shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:shadow-xl hover:border-primary/20 transition-all duration-300 space-y-6">
            <h2 className="text-lg font-semibold text-foreground flex items-center gap-2">
              <Bell className="w-5 h-5 text-indigo-400" />
              Email Notifications
            </h2>

            {/* Job Alerts */}
            <div className="flex items-center justify-between py-4 border-b border-border">
              <div className="flex items-center gap-3">
                <Mail className="w-5 h-5 text-indigo-400" />
                <div>
                  <p className="text-foreground font-medium">Job Alerts</p>
                  <p className="text-muted-foreground text-sm">Get notified when new jobs match your alerts</p>
                </div>
              </div>
              <Toggle
                value={preferences.jobAlerts}
                onChange={(val) => setPreferences({ ...preferences, jobAlerts: val })}
              />
            </div>

            {/* Direct Messages */}
            <div className="flex items-center justify-between py-4 border-b border-border">
              <div className="flex items-center gap-3">
                <MessageSquare className="w-5 h-5 text-purple-400" />
                <div>
                  <p className="text-foreground font-medium">Direct Messages</p>
                  <p className="text-muted-foreground text-sm">Get notified when you receive a DM</p>
                </div>
              </div>
              <Toggle
                value={preferences.directMessages}
                onChange={(val) => setPreferences({ ...preferences, directMessages: val })}
              />
            </div>

            {/* Proposal Updates */}
            <div className="flex items-center justify-between py-4">
              <div className="flex items-center gap-3">
                <FileText className="w-5 h-5 text-green-400" />
                <div>
                  <p className="text-foreground font-medium">Proposal Updates</p>
                  <p className="text-muted-foreground text-sm">Get notified on fellowship proposal changes</p>
                </div>
              </div>
              <Toggle
                value={preferences.proposalUpdates}
                onChange={(val) => setPreferences({ ...preferences, proposalUpdates: val })}
              />
            </div>

            <Button
              onClick={handleSave}
              loading={saving}
              variant="gradient"
              className="w-full flex items-center justify-center gap-2"
            >
              <Save className="w-4 h-4" />
              Save Preferences
            </Button>
          </div>

          <div className="relative overflow-hidden p-6 rounded-2xl bg-card/80 backdrop-blur-sm border border-border shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:shadow-xl hover:border-primary/20 transition-all duration-300 space-y-6 mt-8">
            <h2 className="text-lg font-semibold text-foreground flex items-center gap-2">
              <Cpu className="w-5 h-5 text-pink-400" />
              AI Configuration (Bring Your Own Key)
            </h2>
            <p className="text-muted-foreground text-sm mb-4">
              Override the default server AI by providing your own API credentials. Your keys are stored in localstorage.
            </p>

            {loadingAiSettings ? (
              <p className="text-muted-foreground text-sm">Loading settings...</p>
            ) : (
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-foreground mb-1">Provider</label>
                  <select
                    value={aiProvider}
                    onChange={(e) => {
                      setAiProvider(e.target.value)
                      if (e.target.value !== 'openrouter') {
                        setAiModel('')
                      }
                    }}
                    className="w-full bg-background border border-border rounded-lg px-4 py-2 text-foreground focus:outline-none focus:border-indigo-500"
                  >
                    <option value="">Server Default (Gemini)</option>
                    <option value="gemini">Google Gemini</option>
                    <option value="openai">OpenAI</option>
                    <option value="openrouter">OpenRouter (100+ Models)</option>
                    <option value="groq">Groq</option>
                  </select>
                </div>

                {aiProvider && (
                  <div>
                    <label className="block text-sm font-medium text-foreground mb-1">API Key</label>
                    <input
                      type="password"
                      value={aiKey}
                      onChange={(e) => setAiKey(e.target.value)}
                      placeholder={`Enter your ${aiProvider} API key`}
                      className="w-full bg-neutral-800 border border-border rounded-lg px-4 py-2 text-foreground focus:outline-none focus:border-indigo-500"
                    />
                  </div>
                )}

                {aiProvider === 'openrouter' && (
                  <div>
                    <label className="block text-sm font-medium text-foreground mb-1">Model Selection</label>
                    <select
                      value={aiModel}
                      onChange={(e) => setAiModel(e.target.value)}
                      disabled={loadingModels}
                      className="w-full bg-background border border-border rounded-lg px-4 py-2 text-foreground focus:outline-none focus:border-indigo-500"
                    >
                      <option value="">Default (gpt-4o-mini)</option>
                      {aiModelsList.map(m => (
                        <option key={m.id} value={m.id}>{m.name}</option>
                      ))}
                    </select>
                    {loadingModels && <p className="text-xs text-muted-foreground mt-1">Loading OpenRouter models...</p>}
                  </div>
                )}
              </div>
            )}

            <Button
              onClick={handleSaveAiSettings}
              variant="outline"
              loading={savingAi}
              className="w-full flex items-center justify-center gap-2 mt-4 text-foreground border-neutral-700 hover:bg-muted"
            >
              <Save className="w-4 h-4" />
              Save AI Settings
            </Button>
          </div>
        </motion.div>
      </div>
    </div>
  )
}

import React, { useState, useRef, useEffect, Suspense, useMemo } from "react";
import { templates } from '../data/templates';
import DeployModal from "../components/portfolio/DeployModal";
import ThemeSelector from "../components/portfolio/ThemeSelector";
import { useTheme } from "../hooks/useTheme";
import { motion, AnimatePresence } from "framer-motion";
import { Moon, Sun, ChevronDown, Check, Eye, Star, Sparkles } from "lucide-react";
import SwissTypography from "../components/portfolio/templates/Swiss_Typography/index";
import LiquidGlass from "../components/portfolio/templates/Liquid_Glass/index";
import MidnightGradient from "../components/portfolio/templates/Midnight_Gradient/index";
import PlayingCardsPortfolio from "../components/portfolio/templates/Playing_Cards";
import CherryBlossom from "../components/portfolio/templates/Cherry_Blossom/index";
import Navbar from '../components/Navbar'
import { X } from "lucide-react";
import { useSearchParams } from "react-router-dom";
// import Hero from "../components/portfolio/templates/Holographic/Hero";
// import ChooseAdventurePortfolio from "../components/portfolio/templates/Choose_Adventure/index";
// import RetroProjects from "../components/portfolio/templates/2D_Retro_8bit/Projects";
// import FantasyRPGProjects from "../components/portfolio/templates/Fantasy_RPG/Projects";


function FilterSelect({ value, onChange, options, className = "" }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  const selectedLabel = options.find((o) => o.value === value)?.label ?? value;

  useEffect(() => {
    function handleClickOutside(e) {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  return (
    <div ref={ref} className={`relative ${className}`}>
      <button
        type="button"
        onClick={() => setOpen((prev) => !prev)}
        className={`
          flex items-center justify-between gap-3 min-w-[160px] px-4 py-2.5
          rounded-xl border text-sm font-medium text-foreground
          bg-card backdrop-blur-sm
          transition-all duration-300 cursor-pointer select-none
          ${open
            ? "border-cyan-400 shadow-[0_0_12px_rgba(34,211,238,0.45)] ring-1 ring-cyan-400/30"
            : "border-border hover:border-cyan-500/60 hover:shadow-[0_0_8px_rgba(34,211,238,0.25)]"
          }
        `}
      >
        <span>{selectedLabel}</span>
        <ChevronDown
          className={`w-4 h-4 text-cyan-400 transition-transform duration-300 ${open ? "rotate-180" : ""}`}
        />
      </button>

      <AnimatePresence>
        {open && (
          <motion.ul
            initial={{ opacity: 0, y: -6, scale: 0.97 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -6, scale: 0.97 }}
            transition={{ duration: 0.18, ease: "easeOut" }}
            className="
              absolute z-50 left-0 top-[calc(100%+6px)] min-w-full
              bg-card border border-border
              shadow-[0_0_20px_rgba(34,211,238,0.2)]
              rounded-xl overflow-hidden py-1
            "
          >
            {options.map((opt) => {
              const isSelected = opt.value === value;
              return (
                <li
                  key={opt.value}
                  onClick={() => { onChange(opt.value); setOpen(false); }}
                  className={`
                    flex items-center justify-between gap-3
                    px-4 py-2.5 text-sm cursor-pointer select-none
                    transition-all duration-200
                    ${isSelected
                      ? "bg-cyan-500/20 text-cyan-300 font-semibold"
                      : "text-foreground hover:bg-cyan-500 hover:text-white"
                    }
                  `}
                >
                  <span>{opt.label}</span>
                  {isSelected && <Check className="w-3.5 h-3.5 text-cyan-400 shrink-0" />}
                </li>
              );
            })}
          </motion.ul>
        )}
      </AnimatePresence>
    </div>
  );
}

const TemplateHeroPreview = ({ templateId, portfolioData }) => {
  const Component = useMemo(() => {
    if (!templateId) return null;
    return React.lazy(() => import(`../components/portfolio/templates/${templateId}/index.jsx`));
  }, [templateId]);

  if (!templateId) return null;
  return (
    <Suspense fallback={<div className="w-full h-full bg-muted/50" />}>
      <Component portfolioData={portfolioData} />
    </Suspense>
  );
};

function TemplateCard({ template, hovered, onHover, onLeave, onUse, aiDraft }) {
  return (
    <motion.div
      onMouseEnter={() => onHover(template.id)}
      onMouseLeave={onLeave}
      animate={hovered ? "hover" : "rest"}
      initial="rest"
      variants={{
        rest: {
          y: 0,
          scale: 1,
          boxShadow: "0 4px 20px rgba(0,0,0,0.25)",
          borderColor: "rgba(255,255,255,0.08)",
          transition: { duration: 0.4, ease: [0.25, 0.46, 0.45, 0.94] },
        },
        hover: {
          y: -10,
          scale: 1.02,
          boxShadow: "0 28px 52px rgba(0,0,0,0.50), 0 0 0 1px rgba(99,102,241,0.55)",
          borderColor: "rgba(99,102,241,0.65)",
          transition: { type: "spring", stiffness: 280, damping: 22 },
        },
      }}
      className="bg-card rounded-2xl overflow-hidden border border-border flex flex-col justify-between cursor-pointer"
    >
      <div className="overflow-hidden relative bg-background h-52">
        {template.isComplete ? (
          <div className="absolute top-0 left-0 origin-top-left pointer-events-none" style={{ width: '1280px', height: '800px', transform: 'scale(0.3)' }}>
            <TemplateHeroPreview templateId={template.id} portfolioData={aiDraft} />
          </div>
        ) : (
          <motion.img
            src={template.image}
            alt={template.title}
            className="w-full h-52 object-cover object-top"
            variants={{
              rest: { scale: 1, transition: { duration: 0.5, ease: [0.25, 0.46, 0.45, 0.94] } },
              hover: { scale: 1.08, transition: { type: "spring", stiffness: 200, damping: 25 } },
            }}
          />
        )}
        <motion.div
          className="absolute inset-0 bg-gradient-to-t from-black/50 via-transparent to-transparent pointer-events-none"
          variants={{ rest: { opacity: 0 }, hover: { opacity: 1 } }}
          transition={{ duration: 0.3 }}
        />
      </div>

      <div className="p-5 flex-1">
        <h2 className="text-2xl font-semibold text-foreground">{template.title}</h2>
        <p className="text-muted-foreground mt-1 text-sm">By {template.author}</p>
        <div className="flex flex-wrap gap-2 mt-3">
          {[template.category, template.colorScheme, template.layout].map((tag) => (
            <span key={tag} className="text-xs bg-muted text-muted-foreground px-2.5 py-1 rounded-full">
              {tag}
            </span>
          ))}
        </div>
      </div>

      <div className="px-5 pb-5">
        <div className="flex justify-between text-sm text-muted-foreground mb-4">
          <span className="flex items-center gap-1.5">
            <Star className="w-3.5 h-3.5 text-amber-400 fill-amber-400" />
            {template.rating}
          </span>
          <span className="flex items-center gap-1.5">
            <Eye className="w-3.5 h-3.5" />
            {template.views.toLocaleString()}
          </span>
        </div>

        <AnimatePresence>
          {hovered && (
            <motion.div
              key="cta-group"
              initial={{ opacity: 0, y: 14 }}
              animate={{
                opacity: 1, y: 0,
                transition: { type: "spring", stiffness: 340, damping: 26, delay: 0.05 },
              }}
              exit={{
                opacity: 0, y: 10,
                transition: { duration: 0.16, ease: "easeIn" },
              }}
              className="flex gap-2 w-full mt-4"
            >
              <button
                onClick={(e) => { e.stopPropagation(); onUse(template.title, false); }}
                className="flex-1 bg-primary text-primary-foreground py-2.5 rounded-xl font-semibold text-sm cursor-pointer hover:scale-[1.02] active:scale-[0.98] transition-transform"
              >
                Use Theme
              </button>
              <button
                onClick={(e) => { e.stopPropagation(); onUse(template.id, true); }}
                className="flex-1 bg-muted text-foreground border border-border py-2.5 rounded-xl font-semibold text-sm cursor-pointer hover:bg-accent hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-2"
              >
                <Eye className="w-4 h-4" /> Preview
              </button>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </motion.div>
  );
}

